# ── [MOP-P07] DELTA CANDLE COMPRESSION ─────────────────────────────────────
# Stores candle[0] raw; candles[1:] as int16 deltas scaled x1e5. ~40% RAM saving.
_CANDLE_SCALE = 1e5

def _compress_candles(candles: list) -> dict:
    """[MOP-P07] Compress OHLCV list → delta-encoded dict. Transparent to consumers."""
    if not candles:
        return {"anchor": [], "deltas": [], "n": 0}
    ncols  = len(candles[0])
    anchor = [float(candles[0][j]) for j in range(ncols)]
    deltas = []
    for i in range(1, len(candles)):
        row = []
        for j in range(ncols):
            d = float(candles[i][j]) - float(candles[i-1][j])
            row.append(int(max(-32767, min(32767, round(d * _CANDLE_SCALE)))))
        deltas.append(row)
    return {"anchor": anchor, "deltas": deltas, "n": len(candles)}

def _decompress_candles(data: dict) -> list:
    """[MOP-P07] Reconstruct OHLCV list from delta-encoded dict."""
    if not data or not data.get("anchor"):
        return []
    anchor  = data["anchor"]
    result  = [list(anchor)]
    prev    = list(anchor)
    for drow in data.get("deltas", []):
        row = [round(prev[j] + drow[j] / _CANDLE_SCALE, 8) for j in range(len(drow))]
        result.append(row)
        prev = row
    return result
# ── END MOP-P07 ─────────────────────────────────────────────────────────────
# Ceiling: env MAX_RAM_MB (default 60 MB delta for 127 MB containers on fps.ms/Pterodactyl).
# The gate measures DELTA above idle baseline RSS — not absolute RSS.
# Baseline (Python + PIL + aiohttp + telegram-bot) is ~55-65 MB on a 127 MB container.
# 60 MB delta → peak total ~115-125 MB — safely under the 127 MB OOM-kill threshold.
# Override: MAX_RAM_MB=200 for Termux (no hard container limit).
_MAX_RAM_MB   = int(os.getenv("MAX_RAM_MB", "60"))
MAX_RAM_BYTES = _MAX_RAM_MB * 1024 * 1024

# FIX #1 — Semaphore lazy-init: original was None deferred to main(), causing
# AttributeError if any handler ran before main() completed initialization.
_ANALYSIS_SEMAPHORE: Optional[asyncio.Semaphore] = None

def _get_semaphore() -> asyncio.Semaphore:
    """Return the analysis semaphore, creating it lazily inside the running loop."""
    global _ANALYSIS_SEMAPHORE
    if _ANALYSIS_SEMAPHORE is None:
        _ANALYSIS_SEMAPHORE = asyncio.Semaphore(MAX_CONCURRENT_ANALYSES)
    return _ANALYSIS_SEMAPHORE

# FIX #6 — /proc/self/status is Linux-only; crashes on macOS/Windows/Docker slim.
def _current_rss() -> int:
    """RSS in bytes — cross-platform. Linux /proc → resource module → 0 fallback."""
    try:
        with open("/proc/self/status") as _f:
            for _line in _f:
                if _line.startswith("VmRSS:"):
                    return int(_line.split()[1]) * 1024
    except OSError as _e:
        log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
    try:
        import resource
        return resource.getrusage(resource.RUSAGE_SELF).ru_maxrss * 1024
    except Exception as _e:
        log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
    return 0   # unknown platform — gate becomes no-op (safe)

def _force_gc() -> None:
    """Three-generation GC sweep — catches reference cycles missed by a single pass."""
    gc.collect(0)
    gc.collect(1)
    gc.collect(2)

# ── Baseline RSS — captured once on the first analysis call, after all imports
# are loaded.  The RAM gate checks DELTA above this baseline, not absolute RSS.
# This prevents false-triggers on Termux/mobile where the idle Python+PIL process
# already consumes more than the old 90 MB ceiling before any fetch starts.
_BASELINE_RSS: int = 0   # populated by _capture_baseline()

def _capture_baseline() -> None:
    """Snapshot idle-process RSS after a full GC.  Called once before first analysis."""
    global _BASELINE_RSS
    _force_gc()
    _BASELINE_RSS = _current_rss()
    log.info(
        f"[MEM] Baseline RSS captured: {_BASELINE_RSS // 1024 // 1024} MB  "
        f"(ceiling: +{MAX_RAM_BYTES // 1024 // 1024} MB delta  →  "
        f"abs limit ~{(_BASELINE_RSS + MAX_RAM_BYTES) // 1024 // 1024} MB)"
    )

def _analysis_rss() -> int:
    """Return RSS delta above idle baseline — measures analysis memory growth only."""
    return max(0, _current_rss() - _BASELINE_RSS)

# MEM-FIX: _wait_for_memory now accepts timeout_s so optional TFs use a
# short 5 s fast-check instead of the full 30 s blocking wait. Required TFs
# (4h, 1h) still use 30 s to ensure core data is never silently skipped.
async def _wait_for_memory(label: str = "", timeout_s: int = 30) -> bool:
    """Pause until analysis-delta RSS < MAX_RAM_BYTES.
    Returns True = safe to proceed, False = timeout expired.

    timeout_s controls max wait duration:
      30 s (default) — required TFs (4h, 1h): wait hard before raising
       5 s            — optional TFs (1d, 1w, 5m, 1m): fast-fail → caller skips gracefully

    Uses _analysis_rss() (delta above idle baseline) so the gate measures
    only memory consumed by the analysis, not the baseline Python/PIL process.
    This fixes false-triggers on Termux/mobile where idle RSS > old 90 MB ceiling.
    """
    global _BASELINE_RSS
    if _BASELINE_RSS == 0:
        _capture_baseline()   # lazy-init: snapshot idle cost before first analysis

    _force_gc()
    if _analysis_rss() < MAX_RAM_BYTES:
        return True

    log.warning(
        f"[MEM] Pressure at [{label}] — "
        f"delta={_analysis_rss()//1024//1024}MB  abs={_current_rss()//1024//1024}MB, waiting… "
        f"(timeout={timeout_s}s)"
    )
    max_attempts = max(1, int(timeout_s / 0.25))   # MEM-FIX: dynamic loop count
    for attempt in range(max_attempts):
        _force_gc()
        await asyncio.sleep(0.25)
        delta = _analysis_rss()
        if delta < MAX_RAM_BYTES:
            log.info(
                f"[MEM] Cleared [{label}] after {(attempt+1)*0.25:.1f}s "
                f"— delta={delta//1024//1024}MB"
            )
            return True
        if attempt % 20 == 19:          # log every 5 s
            log.warning(
                f"[MEM] Still waiting [{label}] "
                f"{(attempt+1)*0.25:.0f}s — delta={delta//1024//1024}MB"
            )

    log.warning(
        f"[MEM] TIMEOUT [{label}] — delta={_analysis_rss()//1024//1024}MB "
        f"after {timeout_s}s. Ceiling=+{MAX_RAM_BYTES//1024//1024}MB delta."
    )
    return False


async def _funnel_pause(label: str = "") -> None:
    """Small GC + sleep window between units of work to flatten RAM spikes."""
    _force_gc()
    pause_s = FETCH_FUNNEL_PAUSE_MS / 1000.0
    if pause_s > 0:
        await asyncio.sleep(pause_s)


def _subset_cache_key(base: str, tf: str, exchange_subset: Optional[List[Dict]] = None) -> str:
    if not exchange_subset:
        return f"{base}:{tf}:ALL"
    names = "|".join(sorted(str(ex.get("name", "?")) for ex in exchange_subset))
    return f"{base}:{tf}:{names}"


async def _run_funnel_workers(items: List[Dict], worker, label: str, batch_size: int = 1, timeout_s: int = 8) -> List[Dict]:
    """Serial / chunked worker runner for tight-memory containers."""
    if not items:
        return []
    batch_size = max(1, int(batch_size or 1))
    out: List[Dict] = []
    total = len(items)
    for start in range(0, total, batch_size):
        chunk = items[start:start + batch_size]
        if not await _wait_for_memory(f"{label}:{start+1}/{total}", timeout_s=timeout_s):
            log.warning(f"[FUNNEL] Memory wait timeout before {label}:{start+1}/{total} — continuing carefully")
        if len(chunk) == 1:
            try:
                r = await worker(chunk[0])
                if isinstance(r, dict) and r is not None:
                    out.append(r)
            except Exception as e:
                log.debug(f"[FUNNEL] {label} single worker error: {e}")
        else:
            try:
                results = await asyncio.gather(*(worker(item) for item in chunk), return_exceptions=True)
            except Exception as e:
                log.debug(f"[FUNNEL] {label} chunk gather error: {e}")
                results = []
            for r in results:
                if isinstance(r, dict) and r is not None:
                    out.append(r)
        if start + batch_size < total:
            await _funnel_pause(label)
    return out

