# [C04] STRUCTURED OBSERVABILITY STACK
# JSON-structured per-analysis logs + admin Telegram alert system.
# Covers: layer timing, gate pass rates, memory deltas, API health,
# and hard failure alerts (RAM timeout, consecutive API failure, etc.)
# ══════════════════════════════════════════════════════════════

# ── JSON Structured Logger ────────────────────────────────────
_STRUCTURED_LOG_FILE: str = os.getenv("STRUCT_LOG_FILE", "mop_ict_structured.jsonl")
# Hard cap for tiny servers: rotate the JSONL file when it grows beyond this size.
# Override via env var if you want more/less retention.
_STRUCTURED_LOG_MAX_BYTES: int = int(os.getenv("STRUCT_LOG_MAX_BYTES", str(128 * 1024)))
_ADMIN_CHAT_ID: Optional[str] = os.getenv("ADMIN_CHAT_ID", None)  # set to your Telegram chat ID
_API_FAILURE_COUNT: Dict[str, int] = {}   # exchange → consecutive failure count
_API_FAILURE_THRESHOLD: int = 3           # alert after 3 consecutive failures

def _write_structured_log(event: str, data: Dict) -> None:
    """
    [C04] Write a JSON-Lines structured log entry to disk.
    Format: { "ts": ISO8601, "event": str, ...data }
    Silently drops on I/O failure to never block the analysis pipeline.
    """
    # Observability must never crash the pipeline.
    # However, it *must* be storage-safe on constrained servers.
    try:
        # Rotate if file is too large (best-effort, never blocking).
        try:
            if _STRUCTURED_LOG_MAX_BYTES > 0 and os.path.exists(_STRUCTURED_LOG_FILE):
                if os.path.getsize(_STRUCTURED_LOG_FILE) >= _STRUCTURED_LOG_MAX_BYTES:
                    os.replace(_STRUCTURED_LOG_FILE, _STRUCTURED_LOG_FILE + ".1")
        except OSError:
            # If rotation fails, continue without structured logging rather than risk blocking.
            return

        entry = {
            "ts": datetime.datetime.utcnow().isoformat() + "Z",
            "event": str(event),
        }

        # Keep this JSONL light and parse-friendly.
        for k, v in (data or {}).items():
            if isinstance(v, (str, int, float, bool)) or v is None:
                entry[k] = v
            elif isinstance(v, (list, tuple)):
                # keep short lists; stringify large/complex ones
                entry[k] = v if len(v) <= 32 else str(v)
            elif isinstance(v, dict):
                # dicts can explode in size; keep as compact string snapshot
                entry[k] = str(v)
            else:
                entry[k] = str(v)

        with open(_STRUCTURED_LOG_FILE, "a", encoding="utf-8") as f:
            f.write(json.dumps(entry, separators=(",", ":"), ensure_ascii=False) + "\n")
    except Exception:
        return


def log_analysis_event(
    symbol: str,
    event: str,
    grade: str = "",
    conf: float = 0.0,
    gate_pass: Optional[List[bool]] = None,
    mem_delta_mb: float = 0.0,
    layer_ms: Optional[Dict[str, float]] = None,
    error: str = "",
) -> None:
    """
    [C04] Structured analysis event logger.
    Call at signal completion, gate failure, RAM timeout, or error.
    """
    gate_vec = "".join("1" if g else "0" for g in gate_pass) if gate_pass else ""
    gate_pass_count = sum(gate_pass) if gate_pass else 0
    _write_structured_log(event, {
        "symbol":          symbol,
        "grade":           grade,
        "confidence":      round(conf, 2),
        "gate_vector":     gate_vec,
        "gates_passed":    gate_pass_count,
        "mem_delta_mb":    round(mem_delta_mb, 1),
        "layer_ms":        str(layer_ms or {}),
        "error":           error,
    })


def record_api_failure(exchange: str) -> bool:
    """
    [C04] Track consecutive API failures per exchange.
    Returns True if threshold exceeded (triggers admin alert).
    """
    _API_FAILURE_COUNT[exchange] = _API_FAILURE_COUNT.get(exchange, 0) + 1
    if _API_FAILURE_COUNT[exchange] >= _API_FAILURE_THRESHOLD:
        _write_structured_log("API_FAILURE_ALERT", {
            "exchange":    exchange,
            "consecutive": _API_FAILURE_COUNT[exchange],
            "alert":       f"Exchange {exchange} failed {_API_FAILURE_COUNT[exchange]}× consecutively",
        })
        return True
    return False


def reset_api_failure(exchange: str) -> None:
    """[C04] Reset consecutive failure counter on successful fetch."""
    _API_FAILURE_COUNT[exchange] = 0


async def send_admin_alert(app, message: str) -> None:
    """
    [C04] Send a critical alert to the admin Telegram chat.
    Only fires if ADMIN_CHAT_ID env var is set.
    Silently no-ops if not configured or if send fails.
    """
    if not _ADMIN_CHAT_ID:
        return
    try:
        await app.bot.send_message(
            chat_id=_ADMIN_CHAT_ID,
            text=f"⚠️ MOP·ICT ALERT\n{message}\n{datetime.datetime.utcnow().isoformat()}Z",
        )
    except Exception as e:
        log.warning(f"[C04 ADMIN ALERT] Failed to send: {e}")


