# ── On-chain / external fetch cache ──────────────────────────
_ONCHAIN_CACHE: Dict = {}
_ONCHAIN_CACHE_TTL = 300   # 5-min TTL
_ONCHAIN_CACHE_MAX = 200   # max keys before forced eviction

# ── [TV-FREE] Last result cache — stores slim TV-relevant fields per symbol ──
# Used by /tvcheck and /pine to generate TradingView cross-check guides
# without re-running the full 20-layer pipeline.
_LAST_RESULT_CACHE: Dict[str, dict] = {}   # symbol → slim result dict (max 20 entries)

# ── [G1] Aggressor Trade Cache — real taker CVD ───────────────
_AGG_TRADES_CACHE: Dict[str, Tuple[list, float]] = {}   # symbol → (trades_list, ts)
_AGG_TRADES_TTL  = 30.0   # 30-second TTL — matches SMT price cache
_AGG_TRADES_MAX  = 150    # max unique symbols cached

async def fetch_agg_trades(session: aiohttp.ClientSession, symbol: str, limit: int = 500) -> list:
    """
    [G1] Fetch aggressor-tagged trades from Binance aggTrades endpoint.
    Each trade: {price, qty, isBuyerMaker, time}
    isBuyerMaker=False → taker BUY aggressor (buyer hit the ask)
    isBuyerMaker=True  → taker SELL aggressor (seller hit the bid)
    Returns list of dicts or [] on failure.
    """
    key = symbol.upper()
    cached = _AGG_TRADES_CACHE.get(key)
    if cached and (time.time() - cached[1]) < _AGG_TRADES_TTL:
        return cached[0]
    url = f"https://api.binance.com/api/v3/aggTrades?symbol={key}USDT&limit={limit}"
    try:
        async with session.get(url, timeout=aiohttp.ClientTimeout(total=5)) as r:
            if r.status == 200:
                raw = await r.json(content_type=None)
                trades = [
                    {
                        "price":        float(t.get("p", 0)),
                        "qty":          float(t.get("q", 0)),
                        "isBuyerMaker": bool(t.get("m", True)),
                        "time":         int(t.get("T", 0)),
                    }
                    for t in raw if t.get("p") and t.get("q")
                ]
                _now = time.time()
                # Evict expired entries; if still over cap, evict oldest
                if len(_AGG_TRADES_CACHE) >= _AGG_TRADES_MAX:
                    expired_k = [k for k, v in _AGG_TRADES_CACHE.items() if (_now - v[1]) >= _AGG_TRADES_TTL]
                    for k in expired_k:
                        del _AGG_TRADES_CACHE[k]
                    if len(_AGG_TRADES_CACHE) >= _AGG_TRADES_MAX:
                        oldest_k = sorted(_AGG_TRADES_CACHE, key=lambda k: _AGG_TRADES_CACHE[k][1])
                        for k in oldest_k[:len(_AGG_TRADES_CACHE) - _AGG_TRADES_MAX // 2]:
                            del _AGG_TRADES_CACHE[k]
                _AGG_TRADES_CACHE[key] = (trades, _now)
                return trades
    except Exception as e:
        log.debug(f"[G1 AGG_TRADES] {symbol}: {e}")
    return []

def compute_cvd_real(agg_trades: list, ohlcv_fallback: list = None, window: int = 50) -> Dict:
    """
    [G1] Real Cumulative Volume Delta from aggressor-tagged trades.
    Positive CVD = net taker BUY pressure. Negative = net taker SELL pressure.
    Falls back to OHLCV proxy if agg_trades unavailable.

    Returns:
      cvd_value        : cumulative signed volume
      cvd_slope        : second-half minus first-half CVD
      aggressor_ratio  : taker_buy_vol / total_vol (0.0–1.0)
      cvd_divergence   : True if price and CVD diverge (leading reversal)
      cvd_data_source  : 'REAL_AGTRADES' or 'OHLCV_PROXY'
    """
    # ── Use real aggTrades if available ───────────────────────
    if agg_trades and len(agg_trades) >= 10:
        deltas  = []
        buy_vol = 0.0
        sel_vol = 0.0
        for t in agg_trades[-min(window * 10, len(agg_trades)):]:
            qty = t["qty"]
            if not t["isBuyerMaker"]:   # taker BUY
                deltas.append(qty)
                buy_vol += qty
            else:                        # taker SELL
                deltas.append(-qty)
                sel_vol += qty

        total_vol      = buy_vol + sel_vol
        aggressor_ratio = round(buy_vol / max(total_vol, 1e-9), 4)
        cvd            = round(sum(deltas), 2)
        half           = len(deltas) // 2
        slope          = round(sum(deltas[half:]) - sum(deltas[:half]), 2) if half > 0 else 0.0

        # Price direction from last vs first trade price
        prices_start = agg_trades[-min(window * 10, len(agg_trades))]["price"]
        prices_end   = agg_trades[-1]["price"]
        price_up     = prices_end > prices_start * 1.003
        price_down   = prices_end < prices_start * 0.997
        cvd_up       = slope > 0
        cvd_down     = slope < 0

        bearish_div = price_up   and cvd_down
        bullish_div = price_down and cvd_up
        divergence  = bearish_div or bullish_div
        div_dir     = "BEARISH" if bearish_div else "BULLISH" if bullish_div else "NONE"

        # Gate signal: strong buy if ratio > 0.55, strong sell if < 0.45
        if aggressor_ratio > 0.60:
            gate_signal = "STRONG_BUY_FLOW"
        elif aggressor_ratio > 0.55:
            gate_signal = "BUY_FLOW"
        elif aggressor_ratio < 0.40:
            gate_signal = "STRONG_SELL_FLOW"
        elif aggressor_ratio < 0.45:
            gate_signal = "SELL_FLOW"
        else:
            gate_signal = "NEUTRAL"

        return {
            "cvd_value":         cvd,
            "cvd_slope":         slope,
            "aggressor_ratio":   aggressor_ratio,
            "buy_volume":        round(buy_vol, 4),
            "sell_volume":       round(sel_vol, 4),
            "cvd_divergence":    divergence,
            "cvd_divergence_dir": div_dir,
            "cvd_gate_signal":   gate_signal,
            "cvd_data_source":   "REAL_AGGTRADES",
            "cvd_note": (
                f"{'⚠️ REAL CVD DIV [' + div_dir + '] — reversal signal' if divergence else '✅ Real CVD aligned'}"
                f" | Aggressor: {aggressor_ratio:.1%} ({gate_signal})"
                f" | CVD={cvd:+.0f}"
            ),
        }

    # ── Fallback to OHLCV proxy ────────────────────────────────
    if ohlcv_fallback:
        base = compute_cvd(ohlcv_fallback, window=window)
        base["cvd_data_source"] = "OHLCV_PROXY"
        base["aggressor_ratio"] = 0.5   # unknown from OHLCV
        base["cvd_gate_signal"] = "NEUTRAL"
        return base

    return {
        "cvd_value": 0.0, "cvd_slope": 0.0, "aggressor_ratio": 0.5,
        "buy_volume": 0.0, "sell_volume": 0.0,
        "cvd_divergence": False, "cvd_divergence_dir": "NONE",
        "cvd_gate_signal": "NEUTRAL", "cvd_data_source": "UNAVAILABLE",
        "cvd_note": "CVD: no data available",
    }

