# ── [G10] BTC Rolling Correlation per altcoin ─────────────────
# Tracks 30-bar rolling price-change history per symbol for correlation to BTC.
# Research (ScienceDirect 2024): corr > 0.80 = BTC-tracking; < 0.50 = decoupled.
_BTC_CORR_HISTORY: Dict[str, "deque"] = collections.defaultdict(lambda: deque(maxlen=30))

def compute_btc_rolling_correlation(base: str, change_pct: float, btc_change_pct: float) -> Dict:
    """
    [G10] Compute rolling 30-bar Pearson correlation between altcoin and BTC.
    Append latest change_pct to history; compute correlation against BTC history.

    Regimes:
      HIGH_CORR  (> 0.80): altcoin tracks BTC — anchor bias to BTC structure
      MED_CORR   (0.50–0.80): mixed — normal signal weight
      LOW_CORR   (< 0.50): decoupled / altcoin season — alt ICT signals dominate

    BTC is its own reference → returns SELF_REFERENCE, corr=1.0.
    """
    key = base.upper()

    # BTC is its own reference — skip correlation
    if key == "BTC":
        return {
            "btc_correlation":  1.0,
            "btc_corr_regime":  "SELF_REFERENCE",
            "btc_corr_note":    "BTC is its own reference — no correlation gate",
            "btc_corr_conf_mod": 1.0,
            "history_len":      0,
        }

    # Append current data point to per-symbol history
    _BTC_CORR_HISTORY[key].append(change_pct)
    _BTC_CORR_HISTORY["BTC"].append(btc_change_pct)

    alt_hist = list(_BTC_CORR_HISTORY[key])
    btc_hist = list(_BTC_CORR_HISTORY["BTC"])
    n = min(len(alt_hist), len(btc_hist))

    if n < 5:
        return {
            "btc_correlation":   0.0,
            "btc_corr_regime":   "INSUFFICIENT_DATA",
            "btc_corr_note":     f"BTC corr: collecting data ({n}/30 bars)",
            "btc_corr_conf_mod": 1.0,
            "history_len":       n,
        }

    # Pearson correlation on last n bars
    a = alt_hist[-n:]
    b = btc_hist[-n:]
    mean_a = sum(a) / n
    mean_b = sum(b) / n
    cov = sum((a[i] - mean_a) * (b[i] - mean_b) for i in range(n)) / max(n - 1, 1)
    std_a = math.sqrt(sum((x - mean_a)**2 for x in a) / max(n - 1, 1)) or 1e-9
    std_b = math.sqrt(sum((x - mean_b)**2 for x in b) / max(n - 1, 1)) or 1e-9
    corr  = round(max(-1.0, min(1.0, cov / (std_a * std_b))), 4)

    # Regime classification and confidence modifier
    if corr > 0.80:
        regime   = "HIGH_CORR"
        # Altcoin heavily tracks BTC — BTC macro structure gates this signal
        conf_mod = 1.0   # neutral; modified further in pipeline based on BTC bias
        note     = f"⚠️ BTC corr={corr:.2f} HIGH — alt tracks BTC macro structure"
    elif corr < 0.50:
        regime   = "LOW_CORR"
        # Decoupled — alt's own ICT signals carry full weight (bonus)
        conf_mod = 1.05  # slight boost: own structure is independently valid
        note     = f"✅ BTC corr={corr:.2f} LOW — alt decoupled, own ICT signals dominant"
    else:
        regime   = "MED_CORR"
        conf_mod = 1.0
        note     = f"BTC corr={corr:.2f} MIXED — standard signal weighting"

    return {
        "btc_correlation":   corr,
        "btc_corr_regime":   regime,
        "btc_corr_note":     note,
        "btc_corr_conf_mod": conf_mod,
        "history_len":       n,
    }

# ── Upgrade #1 — Hurst Exponent (R/S analysis) ───────────────
def compute_hurst_exponent(closes: List[float], min_n: int = 20,
                            rolling_window: Optional[int] = None) -> Dict:
    """
    [v7.0-U1] Rolling Hurst Exponent via R/S analysis.
    rolling_window: if set, compute H on last N bars only (time-varying).
    Research (Frontiers 2025): rolling H gives 12.3% RMSE improvement over static H.
    H > 0.55 = trending (persistent)
    H < 0.45 = mean-reverting
    H ≈ 0.5  = random walk
    """
    # ── Rolling window: use last N bars if specified ──────────
    if rolling_window is not None and len(closes) > rolling_window:
        closes = closes[-rolling_window:]
    n = len(closes)
    if n < min_n:
        return {"hurst": 0.5, "hurst_note": "Insufficient data", "hurst_regime": "RANDOM"}
    try:
        lags = [max(2, n // k) for k in [8, 4, 2, 1] if n // k >= 4]
        lags = sorted(set(lags))
        rs_vals = []
        for lag in lags:
            chunks = [closes[i:i+lag] for i in range(0, n - lag + 1, lag)]
            if not chunks:
                continue
            rs_chunk = []
            for chunk in chunks:
                mean_c = sum(chunk) / len(chunk)
                deviations = [x - mean_c for x in chunk]
                # O(N) running cumulative-sum — no list of sliced sums
                running = 0.0
                cum_min = 0.0
                cum_max = 0.0
                for d in deviations:
                    running += d
                    if running > cum_max: cum_max = running
                    if running < cum_min: cum_min = running
                rng = cum_max - cum_min
                std_c = math.sqrt(sum((x - mean_c)**2 for x in chunk) / len(chunk))
                if std_c > 0:
                    rs_chunk.append(rng / std_c)
            if rs_chunk:
                rs_vals.append((lag, sum(rs_chunk) / len(rs_chunk)))
        if len(rs_vals) < 2:
            return {"hurst": 0.5, "hurst_note": "Insufficient lags", "hurst_regime": "RANDOM"}
        # log-log regression — filter both arrays together so indices stay aligned
        _valid_pairs = [(x[0], x[1]) for x in rs_vals if x[1] > 0]
        log_lags = [math.log(p[0]) for p in _valid_pairs]
        log_rs   = [math.log(p[1]) for p in _valid_pairs]
        if len(log_lags) != len(log_rs) or len(log_lags) < 2:
            return {"hurst": 0.5, "hurst_note": "Regression failed", "hurst_regime": "RANDOM"}
        n_pts = len(log_lags)
        sum_x  = sum(log_lags); sum_y  = sum(log_rs)
        sum_xy = sum(log_lags[i]*log_rs[i] for i in range(n_pts))
        sum_x2 = sum(x**2 for x in log_lags)
        denom  = n_pts*sum_x2 - sum_x**2
        h = (n_pts*sum_xy - sum_x*sum_y) / denom if denom != 0 else 0.5
        h = round(max(0.0, min(1.0, h)), 4)
        if h > 0.55:
            regime = "TRENDING"
        elif h < 0.45:
            regime = "MEAN_REVERTING"
        else:
            regime = "RANDOM"
        return {
            "hurst":        h,
            "hurst_regime": regime,
            "hurst_note":   f"H={h:.3f} → {regime} (>0.55=Trend, <0.45=MeanRev)"
        }
    except Exception as e:
        return {"hurst": 0.5, "hurst_note": f"Error: {e}", "hurst_regime": "RANDOM"}


# ── [v7.0-U1b] GARCH(1,1) Conditional Variance ───────────────
# Research: MDPI 2022, ScienceDirect 2024, Frontiers 2025 all validate GARCH for crypto.
# AR(1)-CGARCH(1,1) is the most accurate for BTC (UJFE 2022).
# h_t = omega + alpha * e^2_(t-1) + beta * h_(t-1)
# Literature-validated BTC starting values: omega=1e-6, alpha=0.10, beta=0.85
_GARCH_STATE: Dict[str, Dict] = {}   # symbol → {h: float, last_return: float}

# ── [G2] FVG Age Weighting constants ─────────────────────────
FVG_HALF_LIFE  = 30      # bars: weight halves every 30 bars (4H = ~5 trading days)
FVG_MIN_WEIGHT = 0.35    # aged FVGs retain 35% weight — never fully discarded
FVG_MAX_TESTS  = 3       # auto-expire after 3 price tests without fill
_FVG_AGE_REGISTRY: Dict[str, List[Dict]] = {}   # symbol → [{fvg_low,high,bias,formation_bar,test_count}]

def compute_fvg_age_weight(bars_since_formation: int) -> float:
    """
    [G2] Exponential decay: weight = max(FVG_MIN_WEIGHT, exp(-bars / FVG_HALF_LIFE))
    Fresh FVG (0 bars): weight = 1.0
    30 bars old: weight ≈ 0.50
    90 bars old: weight ≈ 0.35 (floor)
    """
    raw = math.exp(-bars_since_formation / max(FVG_HALF_LIFE, 1))
    return round(max(FVG_MIN_WEIGHT, raw), 4)

def update_fvg_age_registry(symbol: str, fvg_low: float, fvg_high: float,
                             bias: str, current_bar: int, current_price: float) -> Dict:
    """
    [G2] Register or update FVG in age registry.
    Returns the weight for the most relevant fresh FVG and ages existing ones.
    """
    key = symbol.upper()
    if key not in _FVG_AGE_REGISTRY:
        _FVG_AGE_REGISTRY[key] = []

    # Register new FVG if not already present (deduplicate within 0.1%)
    is_new = True
    for existing in _FVG_AGE_REGISTRY[key]:
        if abs(existing["fvg_low"] - fvg_low) < fvg_low * 0.001:
            is_new = False
            break
    if is_new and fvg_low > 0 and fvg_high > fvg_low:
        _FVG_AGE_REGISTRY[key].append({
            "fvg_low":       round(fvg_low, 8),
            "fvg_high":      round(fvg_high, 8),
            "bias":          bias,
            "formation_bar": current_bar,
            "test_count":    0,
            "active":        True,
        })
        _FVG_AGE_REGISTRY[key] = _FVG_AGE_REGISTRY[key][-20:]  # cap at 20

    # Compute weight + test count updates for current FVG
    best_weight  = FVG_MIN_WEIGHT
    stacked_bonus = 0.0
    valid_count  = 0
    for entry in _FVG_AGE_REGISTRY[key]:
        if not entry["active"]:
            continue
        age   = max(0, current_bar - entry["formation_bar"])
        weight = compute_fvg_age_weight(age)
        # Test count: did price enter the zone?
        if entry["fvg_low"] <= current_price <= entry["fvg_high"]:
            entry["test_count"] += 1
        # Auto-expire: age > 150 and 3+ tests
        if age > 150 and entry["test_count"] >= FVG_MAX_TESTS:
            entry["active"] = False
            continue
        valid_count += 1
        # Track best weight for current bias
        if entry["bias"] == bias:
            best_weight = max(best_weight, weight)
    # Stacked bonus: 2+ valid FVGs in same direction
    same_dir = [e for e in _FVG_AGE_REGISTRY[key] if e["active"] and e["bias"] == bias]
    if len(same_dir) >= 2:
        stacked_bonus = min(0.6, 0.3 * (len(same_dir) - 1))

    return {
        "fvg_weight":      round(best_weight, 4),
        "fvg_stacked":     len(same_dir),
        "stacked_bonus":   round(stacked_bonus, 3),
        "fvg_total_score": round(min(1.0, best_weight + stacked_bonus), 4),
        "active_fvgs":     valid_count,
        "fvg_age_note":    f"FVG weight={best_weight:.2f} (stacked={len(same_dir)} +{stacked_bonus:.2f})",
    }

def compute_garch_variance(
    closes:   List[float],
    symbol:   str  = "DEFAULT",
    omega:    float = 1e-6,    # long-run variance floor
    alpha:    float = 0.10,    # ARCH term — sensitivity to shocks
    beta:     float = 0.85,    # GARCH term — persistence
    warmup:   int   = 20,      # bars to warm up h before using
) -> Dict:
    """
    [v7.0-U1b] True GARCH(1,1) conditional variance estimator.
    Updates iteratively: h_t = omega + alpha*e^2_(t-1) + beta*h_(t-1)
    Uses per-symbol state so h carries across analyses (volatility memory).

    Returns:
      garch_h       : current conditional variance h_t
      garch_vol     : annualised conditional volatility (sqrt(h)*sqrt(252))
      garch_regime  : EXPLOSIVE / HIGH_VOL / NORMAL / LOW_VOL
      garch_persist : alpha + beta (persistence measure; >0.9 = very persistent)
    """
    if len(closes) < max(warmup, 5):
        return {
            "garch_h":       1e-4,
            "garch_vol":     0.15,
            "garch_regime":  "NORMAL",
            "garch_persist": round(alpha + beta, 4),
            "garch_note":    "GARCH: insufficient data — using default h",
        }
    try:
        # Compute log-returns
        returns = [
            math.log(closes[i] / closes[i-1])
            for i in range(1, len(closes))
            if closes[i-1] > 0 and closes[i] > 0
        ]
        if len(returns) < warmup:
            return {
                "garch_h":       1e-4, "garch_vol": 0.15,
                "garch_regime":  "NORMAL",
                "garch_persist": round(alpha + beta, 4),
                "garch_note":    "GARCH: too few returns",
            }

        mu = sum(returns) / len(returns)

        # ── Retrieve or initialize per-symbol state ────────────
        state  = _GARCH_STATE.get(symbol, {})
        # Initial h = sample variance of first warmup bars
        sample_var = sum((r - mu)**2 for r in returns[:warmup]) / max(warmup - 1, 1)
        h = state.get("h", max(sample_var, omega / (1 - alpha - beta + 1e-9)))

        # ── Iterate GARCH update over all available returns ────
        for r in returns:
            e_sq = (r - mu) ** 2
            h = omega + alpha * e_sq + beta * h
            h = max(h, 1e-10)   # floor to prevent numerical collapse

        # ── Store updated state per symbol ─────────────────────
        _GARCH_STATE[symbol] = {"h": h}

        # Persistence and regime
        persist     = round(alpha + beta, 4)
        garch_vol   = round(math.sqrt(h) * math.sqrt(252) * 100, 4)   # annualised %

        if persist >= 0.99:
            regime = "EXPLOSIVE"          # near unit root — extreme persistence
        elif garch_vol > 80:
            regime = "HIGH_VOL"
        elif garch_vol < 20:
            regime = "LOW_VOL"
        else:
            regime = "NORMAL"

        return {
            "garch_h":       round(h, 10),
            "garch_vol":     garch_vol,
            "garch_regime":  regime,
            "garch_persist": persist,
            "garch_note": (
                f"GARCH(1,1) h={h:.2e} | vol={garch_vol:.1f}% ann | "
                f"persist={persist:.3f} | {regime}"
            ),
        }
    except Exception as e:
        return {
            "garch_h":       1e-4, "garch_vol": 0.15,
            "garch_regime":  "NORMAL", "garch_persist": round(alpha + beta, 4),
            "garch_note":    f"GARCH error: {e}",
        }

# ── Upgrade #2 — Realized Volatility Ratio ───────────────────
def compute_realized_vol_ratio(closes: List[float], atr_pct: float, window: int = 20) -> Dict:
    """
    Upgrade #8 — Realized Volatility Ratio (RVR).
    RVR > 1.2 = realized exceeds implied → trending regime.
    RVR < 0.8 = mean-reverting regime.
    """
    if len(closes) < window + 1:
        return {"rvr": 1.0, "rvr_note": "Insufficient data", "rvr_regime": "NORMAL"}
    returns = [math.log(closes[i] / closes[i-1]) for i in range(len(closes)-window, len(closes)) if closes[i-1] > 0]
    if not returns:
        return {"rvr": 1.0, "rvr_note": "No returns", "rvr_regime": "NORMAL"}
    realized_var = sum(r**2 for r in returns)
    realized_vol = math.sqrt(realized_var) * 100
    implied_proxy = atr_pct / 100 * math.sqrt(window)
    rvr = round(realized_vol / max(implied_proxy, 1e-9), 4)
    regime = "TRENDING" if rvr > 1.2 else "MEAN_REVERTING" if rvr < 0.8 else "NORMAL"
    return {
        "rvr":        rvr,
        "rvr_regime": regime,
        "rvr_note":   f"RVR={rvr:.3f} ({regime})"
    }


# ── Upgrade #3 — Parkinson Volatility ────────────────────────
def compute_parkinson_volatility(highs: List[float], lows: List[float], window: int = 20) -> float:
    """
    Upgrade #10 — Parkinson volatility estimator (uses H/L range).
    5× more efficient than close-to-close. Better for 24/7 crypto.
    """
    n = min(window, len(highs), len(lows))
    if n < 2:
        return 0.0
    try:
        val = (1.0 / (4 * n * math.log(2))) * sum(
            math.log(highs[-n+i] / lows[-n+i])**2
            for i in range(n) if lows[-n+i] > 0 and highs[-n+i] > lows[-n+i]
        )
        return round(math.sqrt(val) * 100, 4) if val >= 0 else 0.0
    except Exception:
        return 0.0


# ══════════════════════════════════════════════════════════════
# PATCH 1 — compute_adaptive_atr_buffer()
# Thesis §2: regime-sensitive SL buffer (0.25/0.40/0.65 × ATR)
# Replaces flat 0.1× ATR that was 4× too tight for crypto.
# ══════════════════════════════════════════════════════════════
def compute_adaptive_atr_buffer(atr: float, atr_pct: float,
                                 atr_percentile: float = 50.0,
                                 tf: str = "4h") -> Dict:
    """
    ATR-regime-adaptive SL buffer.

    Low vol  (pctile < 30)  : 0.25 × ATR  — tight environment, wicks smaller
    Normal   (pctile 30-70) : 0.40 × ATR  — standard buffer
    High vol (pctile > 70)  : 0.65 × ATR  — expansion wicks are brutal
    TF multiplier: 1d=1.20× 4h=1.00× 1h=0.80× 15m=0.65× 5m=0.50× 1m=0.40×
    """
    if atr <= 0:
        return {"buffer": 0.0, "buffer_pct": 0.0, "regime": "UNKNOWN", "multiplier": 0.4}

    if atr_percentile < 30:
        base_mult = 0.25
        regime    = "LOW_VOL"
    elif atr_percentile < 70:
        base_mult = 0.40
        regime    = "NORMAL"
    else:
        base_mult = 0.65
        regime    = "HIGH_VOL_EXPANSION"

    tf_mult = {
        "1d": 1.20, "4h": 1.00, "1h": 0.80,
        "15m": 0.65, "5m": 0.50, "1m": 0.40,
    }.get(tf.lower(), 1.00)

    final_mult = round(base_mult * tf_mult, 4)
    buffer_abs = round(atr * final_mult, 8)
    price_ref  = atr / max(atr_pct / 100.0, 1e-9)
    buffer_pct = round(buffer_abs / max(price_ref, 1e-9) * 100, 4)

    return {
        "buffer":     buffer_abs,
        "buffer_pct": buffer_pct,
        "multiplier": final_mult,
        "regime":     regime,
        "note": (f"ATR buffer: {final_mult:.2f}×ATR={buffer_abs:.6f} "
                 f"({regime}, pctile={atr_percentile:.0f}, tf={tf})"),
    }


# ══════════════════════════════════════════════════════════════
# PATCH 2 — compute_sl_tiers()
# Thesis §2: 3-tier structural SL — OB wick → swing → HTF inv.
# Replaces mechanical +0.5/+1.0 ATR offsets.
# ══════════════════════════════════════════════════════════════
def compute_sl_tiers(
    entry: float,
    bias: str,
    ob_low: float,
    ob_high: float,
    swing_highs: list,
    swing_lows: list,
    atr: float,
    atr_percentile: float = 50.0,
    tf: str = "4h",
) -> Dict:
    """
    Three-tier structurally-anchored SL system.

    TIER 1 — OB Structural (Primary / inv_sl):
      BULLISH: ob_low  − adaptive_buffer   (OB wick low  = protected low)
      BEARISH: ob_high + adaptive_buffer   (OB wick high = protected high)

    TIER 2 — Swing Structure (Backup / sl2):
      BULLISH: nearest swing_low below ob_low  − small buffer
      BEARISH: nearest swing_high above ob_high + small buffer

    TIER 3 — HTF Invalidation (Maximum / sl3):
      BULLISH: lowest swing_low  in last 10 swing lows
      BEARISH: highest swing_high in last 10 swing highs

    All tiers guaranteed on the correct side of entry.
    """
    atr_pct_proxy = atr / max(entry, 1e-9) * 100
    buf_data  = compute_adaptive_atr_buffer(atr, atr_pct_proxy, atr_percentile, tf)
    buf       = buf_data["buffer"]
    tiny_buf  = atr * 0.15

    if bias == "BULLISH":
        # ── Tier 1: OB structural low
        raw_sl1 = (ob_low - buf) if ob_low > 0 else (entry - atr * 0.5)
        sl1     = min(raw_sl1, entry - atr * 0.3)

        # ── Tier 2: nearest swing low below OB (or below entry if no OB)
        anchor = ob_low if ob_low > 0 else entry
        below  = [sl[1] for sl in swing_lows if sl[1] < anchor] if swing_lows else []
        sl2    = round(min(below[-3:]) - tiny_buf, 8) if below else round(sl1 - atr * 0.5, 8)
        sl2    = min(sl2, sl1 - atr * 0.1)

        # ── Tier 3: lowest HTF swing low
        all_lows = [sl[1] for sl in swing_lows[-10:]] if swing_lows else [entry * 0.95]
        sl3 = round(min(all_lows) - tiny_buf, 8)
        sl3 = min(sl3, sl2 - atr * 0.2)

    else:  # BEARISH
        # ── Tier 1: OB structural high
        raw_sl1 = (ob_high + buf) if ob_high > 0 else (entry + atr * 0.5)
        sl1     = max(raw_sl1, entry + atr * 0.3)

        # ── Tier 2: nearest swing high above OB
        anchor = ob_high if ob_high > 0 else entry
        above  = [sh[1] for sh in swing_highs if sh[1] > anchor] if swing_highs else []
        sl2    = round(max(above[-3:]) + tiny_buf, 8) if above else round(sl1 + atr * 0.5, 8)
        sl2    = max(sl2, sl1 + atr * 0.1)

        # ── Tier 3: highest HTF swing high
        all_highs = [sh[1] for sh in swing_highs[-10:]] if swing_highs else [entry * 1.05]
        sl3 = round(max(all_highs) + tiny_buf, 8)
        sl3 = max(sl3, sl2 + atr * 0.2)

    # Sanity: reject non-finite or non-positive
    for v in [sl1, sl2, sl3]:
        if not math.isfinite(v) or v <= 0:
            sl1 = entry * (0.97 if bias == "BULLISH" else 1.03)
            sl2 = entry * (0.95 if bias == "BULLISH" else 1.05)
            sl3 = entry * (0.93 if bias == "BULLISH" else 1.07)
            break

    return {
        "sl1":           round(sl1, 8),
        "sl2":           round(sl2, 8),
        "sl3":           round(sl3, 8),
        "risk_dist_sl1": round(abs(entry - sl1), 8),
        "risk_dist_sl2": round(abs(entry - sl2), 8),
        "risk_dist_sl3": round(abs(entry - sl3), 8),
        "buffer_data":   buf_data,
        "sl_note": (
            f"SL1(OB)={round(sl1,4)} | SL2(swing)={round(sl2,4)} | "
            f"SL3(HTF)={round(sl3,4)} | buf={buf_data['multiplier']:.2f}×ATR "
            f"({buf_data['regime']})"
        ),
    }


# ── Upgrade #4 — Garman-Klass Volatility ────────────────────
def compute_garman_klass_volatility(opens: List[float], highs: List[float],
                                     lows: List[float], closes: List[float],
                                     window: int = 20) -> float:
    """
    Upgrade #11 — Garman-Klass volatility (uses O/H/L/C).
    More accurate for daily candles where opening gaps matter.
    """
    n = min(window, len(opens), len(highs), len(lows), len(closes))
    if n < 2:
        return 0.0
    try:
        total = 0.0
        for i in range(-n, 0):
            h, l, o, c = highs[i], lows[i], opens[i], closes[i]
            if l <= 0 or o <= 0:
                continue
            hl_term = 0.5 * math.log(h / l)**2 if h > l else 0
            co_term = (2 * math.log(2) - 1) * math.log(c / o)**2
            total += hl_term - co_term
        return round(math.sqrt(total / n) * 100, 4) if total >= 0 else 0.0
    except Exception:
        return 0.0


# ── Upgrade #5 — Volatility of Volatility (VoV) ──────────────
def compute_vol_of_vol(atrs: List[float], window: int = 20) -> Dict:
    """
    Upgrade #9 — Volatility of Volatility.
    High VoV = unstable regime. Low VoV = stable (ICT entries more reliable).
    """
    if len(atrs) < window:
        return {"vov": 0.0, "vov_note": "Insufficient data", "vov_stable": True}
    recent = atrs[-window:]
    mean_a = sum(recent) / len(recent)
    vov = math.sqrt(sum((a - mean_a)**2 for a in recent) / len(recent))
    vov_pct = round(vov / max(mean_a, 1e-9) * 100, 3)
    stable = vov_pct < 20.0
    return {
        "vov":        vov_pct,
        "vov_note":   f"VoV={vov_pct:.2f}% ({'STABLE' if stable else 'UNSTABLE'})",
        "vov_stable": stable,
    }


# ── Upgrade #6 — Shannon Entropy of Returns ──────────────────
def compute_shannon_entropy(closes: List[float], bins: int = 10, window: int = 50) -> Dict:
    """
    Upgrade #17 — Shannon Entropy of recent price returns.
    Low entropy = structured regime (good for direction). High = noise.
    """
    if len(closes) < window + 1:
        return {"entropy": 1.0, "entropy_note": "Insufficient data", "entropy_regime": "HIGH"}
    returns = [closes[i] / closes[i-1] - 1 for i in range(len(closes)-window, len(closes)) if closes[i-1] > 0]
    if not returns:
        return {"entropy": 1.0, "entropy_note": "No returns", "entropy_regime": "HIGH"}
    min_r, max_r = min(returns), max(returns)
    if max_r == min_r:
        return {"entropy": 0.0, "entropy_note": "No variation", "entropy_regime": "LOW"}
    step = (max_r - min_r) / bins
    counts = [0] * bins
    for r in returns:
        idx = min(int((r - min_r) / step), bins - 1)
        counts[idx] += 1
    n = len(returns)
    entropy = -sum((c / n) * math.log2(c / n) for c in counts if c > 0)
    max_entropy = math.log2(bins)
    norm_entropy = round(entropy / max_entropy if max_entropy > 0 else 1.0, 4)
    regime = "LOW" if norm_entropy < 0.6 else "HIGH"
    return {
        "entropy":        norm_entropy,
        "entropy_note":   f"Entropy={norm_entropy:.3f} ({'structured' if regime == 'LOW' else 'noisy'})",
        "entropy_regime": regime,
    }


# ── Upgrade #7 — CUSUM Regime Change Alert ───────────────────
def compute_cusum_alert(atrs: List[float], window: int = 20, k: float = 0.5) -> Dict:
    """
    Upgrade #13 — CUSUM control chart on ATR for regime change detection.
    Detects calm→volatile or volatile→calm before ATR percentile catches it.
    """
    if len(atrs) < window + 5:
        return {"cusum_alert": False, "cusum_note": "Insufficient data"}
    baseline = atrs[-window-5:-5]
    mu = sum(baseline) / len(baseline)
    std = math.sqrt(sum((a - mu)**2 for a in baseline) / len(baseline)) or 1e-9
    cusum_pos = 0.0
    cusum_neg = 0.0
    h = 5.0  # decision threshold
    for a in atrs[-5:]:
        z = (a - mu) / std
        cusum_pos = max(0, cusum_pos + z - k)
        cusum_neg = max(0, cusum_neg - z - k)
    alert = cusum_pos > h or cusum_neg > h
    direction = "VOLATILE" if cusum_pos > h else "CALM" if cusum_neg > h else "STABLE"
    return {
        "cusum_alert":     alert,
        "cusum_direction": direction,
        "cusum_pos":       round(cusum_pos, 3),
        "cusum_neg":       round(cusum_neg, 3),
        "cusum_note":      f"CUSUM: {'⚠️ REGIME CHANGE → ' + direction if alert else '✅ Stable regime'}",
    }


# ── [F09] GATE 14 — Regime Coherence Gate ────────────────────
def compute_regime_coherence_gate(
    upg_hurst:    Dict,
    upg_autocorr: Dict,
    upg_cusum:    Dict,
    upg_entropy:  Dict,
    upg_rvr:      Dict,
    upg_vov:      Dict,
    bias:         str,
    upg_garch:    Optional[Dict] = None,   # [v7.0] GARCH regime signal
) -> Dict:
    """
    [v7.0-U3] Gate 14 — Regime Coherence Gate (upgraded to 7 signals).
    Requires ≥4 of 7 upgrade signals to be non-adversarial:
      1. Hurst ≥ 0.5  (trending or random — not mean-reverting)
      2. Autocorrelation = MOMENTUM (positive serial correlation)
      3. CUSUM alert = STABLE (no regime change in progress)
      4. Shannon entropy ≤ 0.75 (structured, not pure noise)
      5. RVR ≥ 0.8  (realized vol ≥ implied proxy)
      6. VoV STABLE (volatility-of-volatility not spiking)
      7. GARCH regime ≠ EXPLOSIVE (not near unit-root instability) [v7.0]

    CUSUM veto: if CUSUM fires (regime change in progress), gate14 fails
    regardless of score — directional trading in a regime transition is
    the highest-risk condition. (Thesis: CUSUM counts as 1.5x signal.)
    """
    checks = {}

    # 1. Hurst (rolling 40-bar window — time-varying per thesis upgrade)
    h = upg_hurst.get("hurst", 0.5)
    checks["hurst_ok"] = h >= 0.50

    # 2. Autocorrelation momentum
    checks["autocorr_ok"] = upg_autocorr.get("autocorr_regime", "RANDOM") == "MOMENTUM"

    # 3. CUSUM stable (VETO: if alert fires, force gate fail regardless of score)
    cusum_alert = upg_cusum.get("cusum_alert", False)
    checks["cusum_ok"] = not cusum_alert

    # 4. Low entropy (structured market)
    checks["entropy_ok"] = upg_entropy.get("entropy", 1.0) <= 0.75

    # 5. RVR not collapsing
    checks["rvr_ok"] = upg_rvr.get("rvr", 1.0) >= 0.80

    # 6. VoV stable
    checks["vov_ok"] = upg_vov.get("vov_stable", True)

    # 7. [v7.0] GARCH regime not explosive (near unit-root = extreme instability)
    if upg_garch:
        checks["garch_ok"] = upg_garch.get("garch_regime", "NORMAL") != "EXPLOSIVE"
    else:
        checks["garch_ok"] = True   # default pass if GARCH data unavailable

    score = sum(1 for v in checks.values() if v)

    # CUSUM veto — regime transition in progress overrides score
    cusum_veto = cusum_alert
    gate14_pass = (score >= 4) and (not cusum_veto)

    fired  = [k for k, v in checks.items() if v]
    failed = [k for k, v in checks.items() if not v]

    return {
        "gate14_pass":    gate14_pass,
        "gate14_score":   score,
        "gate14_checks":  checks,
        "gate14_fired":   fired,
        "gate14_failed":  failed,
        "gate14_cusum_veto": cusum_veto,
        "gate14_note": (
            f"Gate14 Regime Coherence: {score}/7 signals "
            f"{'✅ PASS' if gate14_pass else '❌ FAIL'}"
            f"{' | ⚠️ CUSUM VETO' if cusum_veto else ''}"
            f" | Failed: {', '.join(failed) if failed else 'none'}"
        ),
    }


# ── Upgrade #8 — Autocorrelation Filter (Ljung-Box proxy) ────
def compute_autocorrelation(closes: List[float], lag: int = 1, window: int = 30) -> Dict:
    """
    Upgrade #15 — Return autocorrelation proxy.
    Positive → momentum regime (BOS valid). Negative → mean-reversion.
    """
    if len(closes) < window + lag + 1:
        return {"autocorr": 0.0, "autocorr_regime": "RANDOM", "autocorr_note": "Insufficient data"}
    returns = [closes[i] / closes[i-1] - 1 for i in range(len(closes)-window, len(closes)) if closes[i-1] > 0]
    n = len(returns)
    if n < lag + 2:
        return {"autocorr": 0.0, "autocorr_regime": "RANDOM", "autocorr_note": "Insufficient returns"}
    mean_r = sum(returns) / n
    var_r  = sum((r - mean_r)**2 for r in returns) / n
    if var_r == 0:
        return {"autocorr": 0.0, "autocorr_regime": "RANDOM", "autocorr_note": "Zero variance"}
    cov = sum((returns[i] - mean_r) * (returns[i-lag] - mean_r) for i in range(lag, n)) / (n - lag)
    ac = round(cov / var_r, 4)
    regime = "MOMENTUM" if ac > 0.1 else "MEAN_REVERTING" if ac < -0.1 else "RANDOM"
    return {
        "autocorr":        ac,
        "autocorr_regime": regime,
        "autocorr_note":   f"AutoCorr(lag={lag})={ac:.3f} → {regime}",
    }


# ── Upgrade #9 — Mean Reversion Z-Score Gate ─────────────────
def compute_vwap_zscore(closes: List[float], vwap_val: float, window: int = 20) -> Dict:
    """
    Upgrade #47 — Z-score of price vs VWAP.
    Z > +2.0 = overbought. Z < -2.0 = oversold.
    """
    if len(closes) < window or vwap_val <= 0:
        return {"vwap_zscore": 0.0, "vwap_z_note": "Insufficient data", "vwap_z_signal": "NEUTRAL"}
    recent = closes[-window:]
    mean_c = sum(recent) / len(recent)
    std_c  = math.sqrt(sum((c - mean_c)**2 for c in recent) / len(recent)) or 1e-9
    z = round((closes[-1] - vwap_val) / std_c, 3)
    signal = "OVERBOUGHT" if z > 2.0 else "OVERSOLD" if z < -2.0 else "NEUTRAL"
    return {
        "vwap_zscore":  z,
        "vwap_z_note":  f"VWAP Z={z:.2f} ({signal})",
        "vwap_z_signal": signal,
    }


# ── Upgrade #10 — OI Rate of Change ──────────────────────────
def compute_oi_roc(oi_current: float, oi_history: List[float], lookback: int = 4) -> Dict:
    """
    Upgrade #24 — Open Interest Rate of Change.
    Spike in OI ROC + price stagnation = squeeze setup.
    """
    if not oi_history or len(oi_history) < lookback or oi_current <= 0:
        return {"oi_roc": 0.0, "oi_roc_note": "OI data unavailable", "oi_squeeze": False}
    oi_prev = oi_history[-lookback] if len(oi_history) >= lookback else oi_history[0]
    oi_roc = round((oi_current - oi_prev) / max(abs(oi_prev), 1e-9) * 100, 3)
    squeeze = abs(oi_roc) > 5.0
    return {
        "oi_roc":      oi_roc,
        "oi_roc_note": f"OI ROC={oi_roc:+.2f}% ({'⚠️ SQUEEZE SETUP' if squeeze else 'Normal'})",
        "oi_squeeze":  squeeze,
    }


# ── [v7.0-U2] CVD — Cumulative Volume Delta ──────────────────
# Thesis P1 Gap: CVD is the strongest short-term directional signal in crypto.
# Approximation: signed_vol = ((close-low)-(high-close))/(high-low) * volume
# (Canonical VWAP directional volume proxy — no tick data required.)
# CVD divergence from price = leading indicator of exhaustion / reversal.

def compute_cvd(ohlcv: list, window: int = 50) -> Dict:
    """
    [v7.0-U2] Cumulative Volume Delta (CVD) from OHLCV.
    Uses directional volume proxy: signed_vol = ((C-L)-(H-C))/(H-L) × Vol
    Positive delta = net buyer aggression. Negative = net seller aggression.

    Returns:
      cvd_value       : rolling CVD over `window` bars
      cvd_slope       : direction of CVD trend (positive/negative/flat)
      cvd_divergence  : True if price and CVD diverge (leading reversal signal)
      cvd_divergence_dir : BEARISH (price up, CVD down) / BULLISH (price down, CVD up)
      cvd_note        : human-readable summary
    """
    default = {
        "cvd_value": 0.0, "cvd_slope": 0.0,
        "cvd_divergence": False, "cvd_divergence_dir": "NONE",
        "cvd_note": "CVD: insufficient data",
    }
    if not ohlcv or len(ohlcv) < 10:
        return default
    try:
        recent = ohlcv[-min(window, len(ohlcv)):]
        deltas = []
        for c in recent:
            if len(c) < 5:
                continue
            o, h, l, cl, vol = float(c[0]), float(c[1]), float(c[2]), float(c[3]), float(c[4])
            hl = h - l
            if hl <= 0 or vol <= 0:
                deltas.append(0.0)
                continue
            # Directional volume: positive = buyers dominant, negative = sellers
            signed_vol = ((cl - l) - (h - cl)) / hl * vol
            deltas.append(signed_vol)

        if not deltas:
            return default

        # Cumulative sum
        cvd = sum(deltas)

        # CVD slope: compare second half vs first half
        half = len(deltas) // 2
        cvd_first  = sum(deltas[:half])  if half > 0 else 0.0
        cvd_second = sum(deltas[half:])  if half > 0 else 0.0
        slope = cvd_second - cvd_first   # positive = CVD accelerating up

        # Price direction over same window
        prices_start = float(recent[0][3]) if len(recent[0]) >= 4 else 0
        prices_end   = float(recent[-1][3]) if len(recent[-1]) >= 4 else 0
        price_up   = prices_end > prices_start * 1.003   # >0.3% price move
        price_down = prices_end < prices_start * 0.997

        # Divergence: price and CVD moving in opposite directions
        cvd_up   = slope > 0
        cvd_down = slope < 0

        bearish_div = price_up   and cvd_down   # distribution: price up, buyers exhausted
        bullish_div = price_down and cvd_up     # accumulation: price down, sellers exhausted

        divergence     = bearish_div or bullish_div
        divergence_dir = ("BEARISH" if bearish_div else "BULLISH" if bullish_div else "NONE")

        return {
            "cvd_value":         round(cvd, 2),
            "cvd_slope":         round(slope, 2),
            "cvd_divergence":    divergence,
            "cvd_divergence_dir": divergence_dir,
            "cvd_note": (
                f"{'⚠️ CVD DIVERGENCE [' + divergence_dir + '] — reversal signal' if divergence else '✅ CVD aligned with price'}"
                f" | CVD={cvd:+.0f} slope={slope:+.0f}"
            ),
        }
    except Exception as e:
        return {**default, "cvd_note": f"CVD error: {e}"}


