# ████  v8.0 NEW FUNCTIONS — 50-CONFLUENCE ARCHITECTURE  ████
# Parabolic SAR · FOMC 2026 Calendar · Range Position ·
# Spot/Futures CVD Divergence · 50-Confluence Scorer
# ══════════════════════════════════════════════════════════════

def compute_parabolic_sar(
    highs: List[float],
    lows: List[float],
    af_start: float = 0.02,
    af_step: float = 0.02,
    af_max: float = 0.20,
) -> Dict:
    """
    [v8.0-C15] Parabolic SAR — trend direction and value.
    Returns sar_value, sar_above_price (True=bearish), sar_direction, sar_note.
    """
    default = {
        "sar_value": 0.0, "sar_above_price": False,
        "sar_direction": "UNKNOWN", "sar_note": "SAR: insufficient data",
    }
    if not highs or not lows or len(highs) < 5 or len(lows) < 5:
        return default
    n = min(len(highs), len(lows))
    highs = highs[-n:]
    lows  = lows[-n:]
    try:
        # Initial direction: bullish if last close > first
        rising  = highs[-1] > highs[0]
        sar     = lows[0]  if rising else highs[0]
        ep      = highs[0] if rising else lows[0]
        af      = af_start
        for i in range(1, n):
            sar_new = sar + af * (ep - sar)
            if rising:
                sar_new = min(sar_new, lows[i-1], lows[max(0, i-2)])
                if lows[i] < sar_new:
                    rising  = False
                    sar_new = ep
                    ep      = lows[i]
                    af      = af_start
                else:
                    if highs[i] > ep:
                        ep = highs[i]
                        af = min(af + af_step, af_max)
            else:
                sar_new = max(sar_new, highs[i-1], highs[max(0, i-2)])
                if highs[i] > sar_new:
                    rising  = True
                    sar_new = ep
                    ep      = highs[i]
                    af      = af_start
                else:
                    if lows[i] < ep:
                        ep = lows[i]
                        af = min(af + af_step, af_max)
            sar = sar_new
        price_ref     = (highs[-1] + lows[-1]) / 2
        sar_above     = sar > price_ref
        direction     = "BEARISH" if sar_above else "BULLISH"
        icon          = "🔴" if sar_above else "🟢"
        return {
            "sar_value":       round(sar, 8),
            "sar_above_price": sar_above,
            "sar_direction":   direction,
            "sar_note":        f"{icon} SAR={sar:.4f} {'ABOVE' if sar_above else 'BELOW'} price → {direction}",
        }
    except Exception as e:
        return {**default, "sar_note": f"SAR error: {e}"}


# ── [v8.0-C46] FOMC 2026 Calendar ────────────────────────────
# Hard block: 2h before 2:00 PM ET / 4h after (= UTC 19:00–23:00 on event days)
# FOMC 2026 confirmed schedule (Federal Reserve published calendar)
# REC-7: These are fallback dates. Live dates are fetched from FRED/BLS on startup.
_FOMC_DATES_2026: set = {
    (1, 28), (1, 29),   # Jan 28–29
    (3, 18), (3, 19),   # Mar 18–19
    (5,  6), (5,  7),   # May 6–7
    (6, 17), (6, 18),   # Jun 17–18
    (7, 29), (7, 30),   # Jul 29–30
    (9, 16), (9, 17),   # Sep 16–17
    (10, 28),(10, 29),  # Oct 28–29
    (12,  9),(12, 10),  # Dec 9–10
}
# High-impact macro dates 2026 (CPI / NFP / PCE / PPI approximate schedule)
_MACRO_HIGH_IMPACT_DATES_2026: set = {
    # CPI releases (approx — second Wednesday each month)
    (1,14),(2,11),(3,11),(4,10),(5,13),(6,11),(7,15),(8,12),(9,9),(10,14),(11,12),(12,11),
    # NFP releases (first Friday each month)
    (1,9),(2,6),(3,6),(4,3),(5,1),(6,5),(7,10),(8,7),(9,4),(10,2),(11,6),(12,4),
    # PCE releases (approx last Friday each month)
    (1,30),(2,27),(3,27),(4,24),(5,29),(6,26),(7,31),(8,28),(9,25),(10,30),(11,25),(12,18),
}
# REC-7: Live refresh state — populated by refresh_fomc_calendar() at startup + daily
_FOMC_CALENDAR_REFRESHED: bool = False
_FOMC_CALENDAR_REFRESH_TS: float = 0.0

def refresh_fomc_calendar() -> None:
    """
    REC-7/12: Fetch live FOMC dates from Fed website AND live CPI/NFP/PCE dates from BLS.
    Updates _FOMC_DATES_2026 and _MACRO_HIGH_IMPACT_DATES_2026 in-place.
    Falls back to hardcoded sets on any error.
    Called once on startup + every 24h.
    """
    global _FOMC_CALENDAR_REFRESHED, _FOMC_CALENDAR_REFRESH_TS
    import re as _re
    import time as _time
    import urllib.request as _ur

    _MONTH_MAP = {
        "january":1,"february":2,"march":3,"april":4,"may":5,"june":6,
        "july":7,"august":8,"september":9,"october":10,"november":11,"december":12,
    }
    _year = datetime.datetime.utcnow().year

    # ── Part 1: FOMC dates from Federal Reserve ──────────────────────────
    try:
        _fed_url = "https://www.federalreserve.gov/monetarypolicy/fomccalendars.htm"
        with _ur.urlopen(_fed_url, timeout=8) as _resp:
            _html = _resp.read().decode("utf-8", errors="ignore")
        _pat = re.compile(
            r'(January|February|March|April|May|June|July|August|September|October|November|December)'
            r'\s+(\d{1,2})(?:[–\-](\d{1,2}))?,?\s*' + str(_year),
            re.IGNORECASE,
        )
        _new_dates: set = set()
        for m in _pat.finditer(_html):
            mon  = _MONTH_MAP.get(m.group(1).lower(), 0)
            day1 = int(m.group(2))
            day2 = int(m.group(3)) if m.group(3) else day1
            if mon:
                for d in range(day1, day2 + 1):
                    _new_dates.add((mon, d))
        if len(_new_dates) >= 8:
            _FOMC_DATES_2026.clear()
            _FOMC_DATES_2026.update(_new_dates)
            _FOMC_CALENDAR_REFRESHED = True
            _FOMC_CALENDAR_REFRESH_TS = _time.time()
            log.info(f"[FOMC] Live FOMC calendar refreshed: {len(_new_dates)} dates for {_year}")
        else:
            log.warning(f"[FOMC] Fed parse returned {len(_new_dates)} dates — keeping fallback")
    except Exception as _fe:
        log.debug(f"[FOMC] Fed fetch non-critical: {_fe}")

    # ── Part 2 (REC-12): BLS release calendar for CPI/PPI/NFP/PCE ───────
    # BLS publishes a machine-readable release schedule at:
    # https://www.bls.gov/schedule/news_release/cpi.htm  (CPI)
    # https://www.bls.gov/schedule/news_release/empsit.htm (NFP)
    # We parse the text for date patterns like "February 11, 2026".
    _BLS_ENDPOINTS = {
        "CPI": "https://www.bls.gov/schedule/news_release/cpi.htm",
        "NFP": "https://www.bls.gov/schedule/news_release/empsit.htm",
        "PCE": "https://www.bea.gov/news/schedule",   # BEA PCE
    }
    _new_macro: set = set()
    _pat_date = re.compile(
        r'(January|February|March|April|May|June|July|August|September|October|November|December)'
        r'\s+(\d{1,2}),?\s*' + str(_year),
        re.IGNORECASE,
    )
    for _label, _url in _BLS_ENDPOINTS.items():
        try:
            with _ur.urlopen(_url, timeout=6) as _r:
                _txt = _r.read().decode("utf-8", errors="ignore")
            for m in _pat_date.finditer(_txt):
                mon = _MONTH_MAP.get(m.group(1).lower(), 0)
                day = int(m.group(2))
                if mon:
                    _new_macro.add((mon, day))
        except Exception as _ble:
            log.debug(f"[MACRO-CAL] {_label} fetch non-critical: {_ble}")

    if len(_new_macro) >= 6:   # at least 6 macro dates = reasonable parse
        _MACRO_HIGH_IMPACT_DATES_2026.clear()
        _MACRO_HIGH_IMPACT_DATES_2026.update(_new_macro)
        log.info(f"[MACRO-CAL] Live macro calendar refreshed: {len(_new_macro)} dates for {_year}")
    else:
        log.debug(f"[MACRO-CAL] Only {len(_new_macro)} macro dates found — keeping hardcoded fallback")



def check_fomc_calendar_2026(utc_now: datetime.datetime = None) -> Dict:
    """
    [v8.0-C46/C47] FOMC date-aware hard block.
    Blocks 2h before 14:00 ET (19:00 UTC) through 4h after (23:00 UTC) on FOMC days.
    Also blocks ±1h around CPI/NFP/PCE on their release days.
    ET = UTC-5 (standard) / UTC-4 (daylight). Uses UTC-5 conservative offset.
    """
    if utc_now is None:
        utc_now = datetime.datetime.utcnow()
    month = utc_now.month
    day   = utc_now.day
    hour  = utc_now.hour

    # FOMC hard block: 19:00–23:00 UTC on event day
    if (month, day) in _FOMC_DATES_2026:
        if 17 <= hour <= 23:   # 2h pre-window + 4h post = 17:00–23:00 UTC
            return {
                "fomc_block":       True,
                "fomc_block_type":  "FOMC_HARD_BLOCK",
                "fomc_note":        f"⛔ FOMC HARD BLOCK — {month}/{day} FOMC event. No trades 17:00–23:00 UTC.",
                "fomc_event_date":  f"{month}/{day}",
            }
        else:
            return {
                "fomc_block":       False,
                "fomc_block_type":  "FOMC_DAY_SAFE_WINDOW",
                "fomc_note":        f"⚠️ FOMC day ({month}/{day}) — outside blackout window. Caution: -10pts",
                "fomc_event_date":  f"{month}/{day}",
            }

    # High-impact macro ±1h block
    if (month, day) in _MACRO_HIGH_IMPACT_DATES_2026:
        # CPI/NFP typically 08:30 ET = 13:30 UTC; PCE 08:30 ET = 13:30 UTC
        if 12 <= hour <= 15:
            return {
                "fomc_block":       True,
                "fomc_block_type":  "MACRO_EVENT_BLOCK",
                "fomc_note":        f"⛔ MACRO EVENT HARD BLOCK — CPI/NFP/PCE release window ({month}/{day} 12–15 UTC).",
                "fomc_event_date":  f"{month}/{day}",
            }
        else:
            return {
                "fomc_block":       False,
                "fomc_block_type":  "MACRO_DAY_CAUTION",
                "fomc_note":        f"⚠️ Macro event day ({month}/{day}) — outside release window. Caution.",
                "fomc_event_date":  f"{month}/{day}",
            }

    return {
        "fomc_block":       False,
        "fomc_block_type":  "CLEAR",
        "fomc_note":        "✅ No FOMC/macro event today — calendar clear.",
        "fomc_event_date":  "",
    }


def compute_range_position(
    price: float,
    range_high: float,
    range_low: float,
    bias: str,
) -> Dict:
    """
    [v8.0-C38] Range position gate.
    BULLISH entries blocked in top 35% of range.
    BEARISH entries blocked in bottom 35% of range.
    """
    default = {
        "range_pos_pct": 50.0, "range_block": False,
        "range_pos_note": "Range position: no range data",
    }
    if range_high <= range_low or price <= 0:
        return default
    try:
        rng  = range_high - range_low
        pos  = (price - range_low) / rng * 100.0  # 0 = bottom, 100 = top
        pos  = round(max(0.0, min(100.0, pos)), 1)
        # Block: long entries in top 35% / short entries in bottom 35%
        bull_block = (bias == "BULLISH") and (pos > 65.0)
        bear_block = (bias == "BEARISH") and (pos < 35.0)
        blocked    = bull_block or bear_block
        if blocked:
            icon = "⛔"
            note = f"{icon} RANGE BLOCK — entry at {pos:.0f}% of range ({'top zone' if bull_block else 'bottom zone'}) for {bias}"
        elif (bias == "BULLISH" and pos <= 35.0) or (bias == "BEARISH" and pos >= 65.0):
            icon = "✅"
            note = f"{icon} Range position ideal — {pos:.0f}% ({'discount' if bias=='BULLISH' else 'premium'} zone)"
        else:
            icon = "⚠️"
            note = f"{icon} Range position neutral — {pos:.0f}% of range"
        return {
            "range_pos_pct":   pos,
            "range_block":     blocked,
            "range_high":      range_high,
            "range_low":       range_low,
            "range_pos_note":  note,
        }
    except Exception as e:
        return {**default, "range_pos_note": f"Range pos error: {e}"}


def check_spot_futures_cvd_divergence(
    spot_cvd_value: float,
    futures_cvd_value: float,
    bias: str,
) -> Dict:
    """
    [v8.0-C19] Spot vs Futures CVD divergence detector.
    Identifies institutional distribution (futures pumped, spot sold).
    Hard block if divergence > 30% of combined absolute volume.
    """
    abs_combined = abs(spot_cvd_value) + abs(futures_cvd_value)
    if abs_combined < 1e-9:
        return {
            "sf_divergence":      False,
            "sf_divergence_pct":  0.0,
            "sf_divergence_block": False,
            "sf_cvd_note":        "Spot/Futures CVD: no volume data",
        }
    spot_dir    = 1 if spot_cvd_value >= 0 else -1
    futures_dir = 1 if futures_cvd_value >= 0 else -1
    diverging   = spot_dir != futures_dir
    div_pct     = round(abs(spot_cvd_value - futures_cvd_value) / max(abs_combined, 1e-9) * 100, 1)
    hard_block  = diverging and div_pct > 30.0
    # Distribution signal: futures positive (longs piling in), spot negative (smart $ leaving)
    distribution = futures_cvd_value > 0 and spot_cvd_value < 0
    accumulation = futures_cvd_value < 0 and spot_cvd_value > 0
    if hard_block and distribution and bias == "BULLISH":
        note = f"⛔ SPOT/FUTURES CVD HARD BLOCK — Institutional distribution: Futures +{futures_cvd_value:,.0f} / Spot {spot_cvd_value:,.0f} (div={div_pct:.0f}%)"
    elif hard_block and accumulation and bias == "BEARISH":
        note = f"⛔ SPOT/FUTURES CVD HARD BLOCK — Institutional accumulation: Futures {futures_cvd_value:,.0f} / Spot +{spot_cvd_value:,.0f} (div={div_pct:.0f}%)"
    elif diverging:
        note = f"⚠️ Spot/Futures CVD diverging — div={div_pct:.0f}% (below hard block threshold of 30%)"
    else:
        note = f"✅ Spot/Futures CVD aligned — div={div_pct:.0f}%"
    return {
        "sf_divergence":       diverging,
        "sf_divergence_pct":   div_pct,
        "sf_distribution":     distribution,
        "sf_accumulation":     accumulation,
        "sf_divergence_block": hard_block,
        "sf_cvd_note":         note,
    }


def compute_50_confluence_score(
    # Dept 1 — Trend
    price: float, ma50: float, ma200: float, ema20: float, ema50_slope: float,
    daily_bias: str, weekly_bias: str, bos_confirmed: bool,
    # Dept 2 — Momentum
    macd_histogram: float, macd_dif: float, macd_dea: float,
    macd_divergence: bool, rsi: float, rsi_divergence: bool,
    stoch_rsi: float, stoch_rising: bool, sar_above_price: bool,
    # Dept 3 — Volume / Order Flow
    volume_vs_ma20: float, cvd_direction: str, sf_divergence_pct: float,
    obv_rising: bool, price_vs_vwap: str, vol_spike_at_break: bool,
    funding_z: float,
    # Dept 4 — Volatility
    adx: float, di_plus: float, di_minus: float, atr_pct: float,
    bb_expanding: bool, hurst: float,
    # Dept 5 — ICT/SMC
    ob_valid: bool, fvg_present: bool, ote_valid: bool,
    liq_swept: bool, range_pos_pct: float, smc_score: float,
    wyckoff_ok: bool, elliott_ok: bool,
    # Dept 6 — Range & Location
    range_pos_ok: bool, near_pdh: bool, near_pwh: bool, near_round_num: bool,
    # Dept 7 — MTF
    htf_ltf_match: bool, daily_candle_match: bool,
    weekly_trend_match: bool, ma_stack_ok: bool,
    # Dept 8 — Macro
    fomc_block: bool, macro_event_block: bool, news_velocity_ok: bool,
    fgi_boundary: bool, opex_near: bool,
    # Core
    bias: str,
    # [v9.0-T4B] Regime-adaptive weights — optional, None = no adjustment
    regime: str = None,
) -> Dict:
    """
    [v8.0] 50-Confluence Scoring Engine.
    RED = 2pts · YELLOW = 1pt · Max = 75pts
    Hard blocks override score regardless of total.
    [v9.0-T4B] regime parameter enables adaptive weight modulation.
    Research: Tickeron FLM continuous learning, Holly nightly rescore.
    Regime-aware: trending markets weight momentum more, ranging weight
    mean-reversion more. Score range 0–75 preserved via normalization.
    """
    # ── [v9.0-T4B] Regime-adaptive point multipliers ─────────────
    # Applied per scoring category. Additive points multiplied before
    # sum — total re-normalized to 0–75 cap at end.
    # TRENDING: momentum signals carry 25% more weight
    # RANGING: mean-reversion signals carry 20% more weight
    # VOLATILE: reduce all signal confidence slightly
    # ACCUMULATION: structure signals carry 10% bonus
    _REGIME_WEIGHTS = {
        "TRENDING":     {"momentum": 1.25, "reversal": 0.75, "structure": 1.10, "vol_filt": 1.0},
        "RANGING":      {"momentum": 0.80, "reversal": 1.20, "structure": 1.0,  "vol_filt": 0.90},
        "VOLATILE":     {"momentum": 0.90, "reversal": 0.90, "structure": 0.90, "vol_filt": 1.10},
        "ACCUMULATION": {"momentum": 1.10, "reversal": 1.10, "structure": 1.15, "vol_filt": 1.0},
        "DISTRIBUTION": {"momentum": 0.85, "reversal": 1.10, "structure": 1.05, "vol_filt": 1.0},
        "EXPANSION":    {"momentum": 1.20, "reversal": 0.80, "structure": 1.10, "vol_filt": 1.0},
    }
    _rw = _REGIME_WEIGHTS.get(str(regime or "").upper(), None)
    _rm  = lambda cat: _rw[cat] if _rw and cat in _rw else 1.0   # multiplier fn

    def _pts(val: bool, base: int, category: str = "structure") -> int:
        """Apply regime-adaptive multiplier and round. Minimum 0, maximum base*1.5."""
        if not val: return 0
        return max(0, min(int(base * 1.5), round(base * _rm(category))))

    score    = 0
    details  = {}
    blocks   = []

    # ── DEPT 1: TREND STRUCTURE (C1–C8) ─────────────────────
    is_bull = (bias == "BULLISH")

    # C1 — MA50/MA200 full stack (RED, 2pts) [structure]
    c1 = (is_bull and price > ma50 > ma200) or (not is_bull and price < ma50 < ma200)
    score += _pts(c1, 2, "structure"); details["C1_ma_stack"] = c1

    # C2 — MA50 position (RED, 2pts) [structure]
    c2 = (is_bull and price > ma50) or (not is_bull and price < ma50)
    if not c2: blocks.append("C2: Price wrong side of MA50")
    score += _pts(c2, 2, "structure"); details["C2_ma50"] = c2

    # C3 — MA200 position (RED, 2pts) [structure]
    c3 = (is_bull and price > ma200) or (not is_bull and price < ma200)
    score += _pts(c3, 2, "structure"); details["C3_ma200"] = c3

    # C4 — EMA20 filter (YELLOW, 1pt) [structure]
    c4 = (is_bull and price > ema20) or (not is_bull and price < ema20)
    score += _pts(c4, 1, "structure"); details["C4_ema20"] = c4

    # C5 — EMA50 slope (YELLOW, 1pt) [momentum]
    c5 = (is_bull and ema50_slope > 0) or (not is_bull and ema50_slope < 0)
    score += _pts(c5, 1, "momentum"); details["C5_ema50_slope"] = c5

    # C6 — Daily HTF bias (RED, 2pts) [structure] — hard block, no multiplier
    c6 = (is_bull and daily_bias == "BULLISH") or (not is_bull and daily_bias == "BEARISH")
    if not c6: blocks.append("C6: Daily HTF bias conflict")
    score += 2 if c6 else 0; details["C6_daily_bias"] = c6

    # C7 — Weekly structure (YELLOW, 1pt) [structure]
    c7 = (is_bull and weekly_bias == "BULLISH") or (not is_bull and weekly_bias == "BEARISH")
    score += _pts(c7, 1, "structure"); details["C7_weekly"] = c7

    # C8 — BOS confirmed (RED, 2pts) [structure]
    score += _pts(bos_confirmed, 2, "structure"); details["C8_bos"] = bos_confirmed

    # ── DEPT 2: MOMENTUM (C9–C16) ───────────────────────────
    # C9 — MACD histogram (RED, 2pts) [momentum] — hard block, no multiplier
    c9 = (is_bull and macd_histogram > 0) or (not is_bull and macd_histogram < 0)
    if not c9: blocks.append("C9: MACD histogram opposes bias — HARD BLOCK")
    score += 2 if c9 else 0; details["C9_macd_hist"] = c9

    # C10 — MACD signal cross (YELLOW, 1pt) [momentum]
    c10 = (is_bull and macd_dif > macd_dea) or (not is_bull and macd_dif < macd_dea)
    score += _pts(c10, 1, "momentum"); details["C10_macd_cross"] = c10

    # C11 — MACD divergence (RED, 2pts) [reversal]
    c11 = not macd_divergence   # True = no adverse divergence
    score += _pts(c11, 2, "reversal"); details["C11_macd_div"] = c11

    # C12 — RSI band (YELLOW, 1pt) [momentum]
    c12 = (is_bull and 40 <= rsi <= 72) or (not is_bull and 28 <= rsi <= 60)
    score += _pts(c12, 1, "momentum"); details["C12_rsi_band"] = c12

    # C13 — RSI divergence (RED, 2pts) [reversal]
    score += _pts(rsi_divergence, 2, "reversal"); details["C13_rsi_div"] = rsi_divergence

    # C14 — StochRSI (YELLOW, 1pt) [momentum]
    c14 = (is_bull and stoch_rsi > 20 and stoch_rising) or (not is_bull and stoch_rsi < 80 and not stoch_rising)
    score += _pts(c14, 1, "momentum"); details["C14_stochrsi"] = c14

    # C15 — SAR direction (RED, 2pts) [momentum] — hard block, no multiplier
    c15 = (is_bull and not sar_above_price) or (not is_bull and sar_above_price)
    if not c15: blocks.append("C15: SAR opposes bias — HARD BLOCK")
    score += 2 if c15 else 0; details["C15_sar"] = c15

    # C16 — Momentum alignment score (RED, 2pts) — hard block, no multiplier
    mom_score_3 = sum([c9, c10, c15])
    c16 = mom_score_3 >= 2
    if not c16: blocks.append("C16: Momentum alignment 0–1/3 — HARD BLOCK")
    score += 2 if c16 else 0; details["C16_momentum_align"] = c16

    # ── DEPT 3: VOLUME & ORDER FLOW (C17–C23) ───────────────
    # C17 — Volume vs MA20 (YELLOW, 1pt) [vol_filt]
    c17 = volume_vs_ma20 >= 1.0
    score += _pts(c17, 1, "vol_filt"); details["C17_vol_ma"] = c17

    # C18 — Real CVD direction (RED, 2pts)
    c18 = (is_bull and cvd_direction in ("BUY_FLOW","STRONG_BUY_FLOW","POSITIVE")) or \
          (not is_bull and cvd_direction in ("SELL_FLOW","STRONG_SELL_FLOW","NEGATIVE"))
    score += 2 if c18 else 0; details["C18_cvd"] = c18

    # C19 — Spot/Futures CVD divergence (RED, 2pts)
    c19 = sf_divergence_pct <= 30.0
    if not c19: blocks.append(f"C19: Spot/Futures CVD divergence {sf_divergence_pct:.0f}% > 30% — HARD BLOCK")
    score += 2 if c19 else 0; details["C19_sf_div"] = c19

    # C20 — OBV trend (YELLOW, 1pt)
    score += 1 if obv_rising == is_bull else 0; details["C20_obv"] = obv_rising == is_bull

    # C21 — VWAP position (YELLOW, 1pt)
    c21 = (is_bull and price_vs_vwap in ("ABOVE","ABOVE_1SD")) or \
          (not is_bull and price_vs_vwap in ("BELOW","BELOW_1SD"))
    score += 1 if c21 else 0; details["C21_vwap"] = c21

    # C22 — Volume spike at break (RED, 2pts)
    score += 2 if vol_spike_at_break else 0; details["C22_vol_spike"] = vol_spike_at_break

    # C23 — Funding Z-Score (RED, 2pts)
    c23 = (is_bull and funding_z < 1.5) or (not is_bull and funding_z > -1.5)
    score += 2 if c23 else 0; details["C23_funding_z"] = c23

    # ── DEPT 4: VOLATILITY & REGIME (C24–C29) ───────────────
    # C24 — ADX (RED, 2pts)
    c24 = adx >= 20
    if adx < 15: blocks.append("C24: ADX < 15 — chop regime HARD BLOCK")
    score += 2 if c24 else 0; details["C24_adx"] = c24

    # C25 — DI+/DI- direction (RED, 2pts)
    c25 = (is_bull and di_plus > di_minus) or (not is_bull and di_minus > di_plus)
    if not c25: blocks.append("C25: DI direction opposes bias — HARD BLOCK")
    score += 2 if c25 else 0; details["C25_di"] = c25

    # C26 — ATR regime (YELLOW, 1pt)
    c26 = 0.8 <= atr_pct <= 5.0
    score += 1 if c26 else 0; details["C26_atr_regime"] = c26

    # C27 — Bollinger expanding (YELLOW, 1pt)
    score += 1 if bb_expanding else 0; details["C27_bb"] = bb_expanding

    # C28 — (GARCH — advisory, YELLOW, 1pt)
    score += 1; details["C28_garch"] = True  # gated separately in pipeline

    # C29 — Hurst (YELLOW, 1pt)
    c29 = hurst >= 0.55
    score += 1 if c29 else 0; details["C29_hurst"] = c29

    # ── DEPT 5: ICT/SMC (C30–C37) ───────────────────────────
    # C30 — OB valid (RED, 2pts)
    score += 2 if ob_valid else 0; details["C30_ob"] = ob_valid

    # C31 — FVG present (RED, 2pts)
    score += 2 if fvg_present else 0; details["C31_fvg"] = fvg_present

    # C32 — OTE zone (YELLOW, 1pt)
    score += 1 if ote_valid else 0; details["C32_ote"] = ote_valid

    # C33 — Liquidity swept (RED, 2pts)
    if not liq_swept: blocks.append("C33: No liquidity sweep before entry — HARD BLOCK")
    score += 2 if liq_swept else 0; details["C33_liq_swept"] = liq_swept

    # C34 — Range equilibrium (YELLOW, 1pt)
    c34 = (is_bull and range_pos_pct <= 50.0) or (not is_bull and range_pos_pct >= 50.0)
    score += 1 if c34 else 0; details["C34_equilibrium"] = c34

    # C35 — SMC minimum (RED, 2pts)
    c35 = smc_score >= 55
    score += 2 if c35 else 0; details["C35_smc_min"] = c35

    # C36 — Wyckoff (YELLOW, 1pt)
    score += 1 if wyckoff_ok else 0; details["C36_wyckoff"] = wyckoff_ok

    # C37 — Elliott wave (YELLOW, 1pt)
    score += 1 if elliott_ok else 0; details["C37_elliott"] = elliott_ok

    # ── DEPT 6: RANGE & LOCATION (C38–C41) ──────────────────
    # C38 — Range position (RED, 2pts)
    if not range_pos_ok: blocks.append("C38: Entry at range extreme — HARD BLOCK")
    score += 2 if range_pos_ok else 0; details["C38_range_pos"] = range_pos_ok

    # C39 — PDH/PDL (YELLOW, 1pt)
    score += 1 if not near_pdh else 0; details["C39_pdh"] = not near_pdh

    # C40 — PWH/PWL (YELLOW, 1pt)
    score += 1 if not near_pwh else 0; details["C40_pwh"] = not near_pwh

    # C41 — Round number (YELLOW, 1pt)
    score += 1 if not near_round_num else 0; details["C41_round_num"] = not near_round_num

    # ── DEPT 7: MULTI-TIMEFRAME (C42–C45) ───────────────────
    # C42 — HTF/LTF bias match (RED, 2pts)
    if not htf_ltf_match: blocks.append("C42: HTF/LTF bias mismatch — HARD BLOCK")
    score += 2 if htf_ltf_match else 0; details["C42_htf_ltf"] = htf_ltf_match

    # C43 — Daily candle direction (RED, 2pts)
    if not daily_candle_match: blocks.append("C43: Daily candle opposes bias")
    score += 2 if daily_candle_match else 0; details["C43_daily_candle"] = daily_candle_match

    # C44 — Weekly trend (YELLOW, 1pt)
    score += 1 if weekly_trend_match else 0; details["C44_weekly_trend"] = weekly_trend_match

    # C45 — MTF MA stack (RED, 2pts)
    if not ma_stack_ok: blocks.append("C45: MTF MA stack misaligned — HARD BLOCK")
    score += 2 if ma_stack_ok else 0; details["C45_ma_stack"] = ma_stack_ok

    # ── DEPT 8: MACRO & NEWS (C46–C50) ──────────────────────
    # C46 — FOMC (RED, 2pts)
    if fomc_block: blocks.append("C46: FOMC active window — HARD BLOCK")
    score += 2 if not fomc_block else 0; details["C46_fomc"] = not fomc_block

    # C47 — Macro event (RED, 2pts)
    if macro_event_block: blocks.append("C47: Macro event window — HARD BLOCK")
    score += 2 if not macro_event_block else 0; details["C47_macro"] = not macro_event_block

    # C48 — News velocity (YELLOW, 1pt)
    score += 1 if news_velocity_ok else 0; details["C48_news_vel"] = news_velocity_ok

    # C49 — Fear/Greed boundary (YELLOW, 1pt)
    score += 1 if not fgi_boundary else 0; details["C49_fgi"] = not fgi_boundary

    # C50 — OpEx proximity (YELLOW, 1pt)
    score += 1 if not opex_near else 0; details["C50_opex"] = not opex_near

    # ── GRADE & VERDICT ──────────────────────────────────────
    # [v9.0-T4B] Regime-adaptive normalization: if weights inflated score > 75, cap and rescale.
    # This preserves the 0–75 contract — grade thresholds remain unchanged.
    if score > 75:
        score = 75
    hard_blocked = len(blocks) > 0
    if hard_blocked:
        grade50 = "F"
    elif score >= 60: grade50 = "A"
    elif score >= 50: grade50 = "B"
    elif score >= 40: grade50 = "C"
    elif score >= 30: grade50 = "D"
    else:             grade50 = "F"

    signal_state = "BLOCKED" if (hard_blocked or grade50 == "F") else \
                   "DEFERRED" if grade50 == "D" else \
                   "WARNING"  if grade50 in ("B","C") else "ACTIVE"

    # [v9.0-T1C] Probability hint per grade — Tickeron-style odds range
    _prob_hints = {
        "A": "72–85%", "B": "60–72%", "C": "50–60%",
        "D": "40–50%", "F": "<40%",
    }
    return {
        "conf50_score":    score,
        "conf50_max":      75,
        "conf50_grade":    grade50,
        "conf50_blocks":   blocks,
        "conf50_hard_blocked": hard_blocked,
        "conf50_signal_state": signal_state,
        "conf50_details":  details,
        "conf50_probability_hint": _prob_hints.get(grade50, "—"),   # [v9.0]
        "conf50_note":     (
            f"⛔ BLOCKED ({len(blocks)} hard blocks)" if hard_blocked else
            f"Score {score}/75 Grade {grade50} — {signal_state}"
        ),
    }

