# ══════════════════════════════════════════════════════════════
# [v9.0-T1B] COMPOSITE SIGNAL PROBABILITY ENGINE
# Research source: Tickeron FLM — "Odds of Success %" per signal
# Fuses 5 independent confidence dimensions into a single
# calibrated probability estimate (40–85% realistic range).
# ══════════════════════════════════════════════════════════════
def compute_signal_probability(
    conf50_score: float,          # 0–75  (50-confluence engine)
    ai_score: float,              # 0–100 (Layer 8 AI ensemble)
    smc_score: float,             # 0–100 (SMC confluence)
    gate_pass_count: int,         # 0–10  (gate pass ratio)
    win_prob_raw: float,          # 0–1.0 (Monte Carlo / historical)
    bias: str = "BULLISH",
    gate_fp_rate: float = None,   # [MOP-P02] 6th factor: fingerprint historical TP rate (None = unused)
) -> Dict:
    """
    6-factor composite probability — Tickeron-parity signal odds.
    [MOP-P02] 6th factor added: gate fingerprint historical TP rate.
    When gate_fp_rate is available (>=3 historical outcomes), weights shift:
      28% conf50 · 23% ai_score · 18% smc · 13% gate_ratio · 8% win_prob · 10% fp_rate
    When gate_fp_rate is None, falls back to original 5-factor weights (unchanged).
    Calibrated to 40–85% range.
    """
    _c50   = max(0.0, min(1.0, (conf50_score or 0) / 75.0))
    _ai    = max(0.0, min(1.0, (ai_score     or 0) / 100.0))
    _smc   = max(0.0, min(1.0, (smc_score    or 0) / 100.0))
    _gates = max(0.0, min(1.0, (gate_pass_count or 0) / 10.0))
    _mc    = max(0.0, min(1.0, float(win_prob_raw or 0.5)))

    if gate_fp_rate is not None:
        # 6-factor blend — fingerprint memory active
        _fp = max(0.0, min(1.0, float(gate_fp_rate)))
        composite = (
            0.28 * _c50   +
            0.23 * _ai    +
            0.18 * _smc   +
            0.13 * _gates +
            0.08 * _mc    +
            0.10 * _fp
        )
        fp_note = f" · FP={gate_fp_rate:.0%}"
    else:
        # Original 5-factor blend — no fingerprint data yet
        composite = (
            0.30 * _c50   +
            0.25 * _ai    +
            0.20 * _smc   +
            0.15 * _gates +
            0.10 * _mc
        )
        fp_note = ""

    probability = round(40.0 + composite * 45.0, 1)
    probability = max(40.0, min(85.0, probability))

    if probability >= 72:
        tier = "HIGH";     tier_icon = "🟢"
    elif probability >= 60:
        tier = "MODERATE"; tier_icon = "🟡"
    else:
        tier = "LOW";      tier_icon = "🔴"

    return {
        "signal_probability":     probability,
        "signal_probability_pct": f"{probability:.1f}%",
        "probability_tier":       tier,
        "probability_tier_icon":  tier_icon,
        "gate_fp_rate":           gate_fp_rate,
        "probability_note": (
            f"{tier_icon} {probability:.1f}% odds · {tier} "
            f"(50C={conf50_score:.0f}/75 · AI={ai_score:.0f}/100 · "
            f"SMC={smc_score:.0f}/100 · Gates={gate_pass_count}/10{fp_note})"
        ),
    }


# ── [v7.0-U2b] Funding Rate Z-Score ──────────────────────────
# Thesis P2: Funding Z-score (how extreme vs 30-day history) precedes reversals.
_FUNDING_HISTORY: Dict[str, deque] = collections.defaultdict(lambda: deque(maxlen=720))  # ~30d of 1h samples

def compute_funding_zscore(symbol: str, funding_rate: float) -> Dict:
    """
    [v7.0-U2b] Funding Rate Z-Score vs 30-day rolling history.
    Extreme positive Z (>2.0) = crowded longs → flush risk.
    Extreme negative Z (<-2.0) = crowded shorts → squeeze risk.
    """
    key = symbol.upper()
    _FUNDING_HISTORY[key].append(funding_rate)
    history = list(_FUNDING_HISTORY[key])
    if len(history) < 10:
        return {"funding_zscore": 0.0, "funding_z_signal": "NEUTRAL",
                "funding_z_note": "Funding Z: insufficient history"}
    mu  = sum(history) / len(history)
    std = math.sqrt(sum((x - mu)**2 for x in history) / max(len(history) - 1, 1)) or 1e-9
    z   = round((funding_rate - mu) / std, 3)
    if z > 2.0:
        signal = "CROWDED_LONG"
        note   = f"⚠️ Funding Z={z:.2f} CROWDED LONGS — long flush risk elevated"
    elif z < -2.0:
        signal = "CROWDED_SHORT"
        note   = f"⚠️ Funding Z={z:.2f} CROWDED SHORTS — short squeeze risk elevated"
    elif z > 1.0:
        signal = "ELEVATED_LONG"
        note   = f"Funding Z={z:.2f} — elevated longs (caution)"
    elif z < -1.0:
        signal = "ELEVATED_SHORT"
        note   = f"Funding Z={z:.2f} — elevated shorts (squeeze watch)"
    else:
        signal = "NEUTRAL"
        note   = f"Funding Z={z:.2f} — neutral positioning"
    return {"funding_zscore": z, "funding_z_signal": signal, "funding_z_note": note}


# ── Upgrade #11 — Liquidation Heatmap Proxy ──────────────────
def compute_liquidation_heatmap(price: float, funding_rate: float, oi: float, liq_clusters: list = None) -> Dict:
    """
    Upgrade #25 — Estimated liquidation cluster levels for common leverage ratios.
    These are ICT 'external liquidity' targets.

    [FREE API UPGRADE] Phase 1: if real liq_clusters from Coinalyze are provided,
    derive nearest_long_liq / nearest_short_liq from real data instead of math.
    Math estimates remain as fallback when clusters absent.
    """
    lev_ratios = [10, 20, 50]
    liq_longs  = {}
    liq_shorts = {}
    for lev in lev_ratios:
        liq_longs[f"{lev}x"]  = round(price * (1 - 1/lev), 4)
        liq_shorts[f"{lev}x"] = round(price * (1 + 1/lev), 4)

    # [FREE API] Phase 1 — override nearest levels with real cluster data
    nearest_long_liq  = liq_longs["10x"]    # math fallback
    nearest_short_liq = liq_shorts["10x"]   # math fallback
    real_cluster_note = ""
    if liq_clusters:
        long_clusters  = [c for c in liq_clusters if c.get("side") in ("buy", "long")  and c["price"] < price]
        short_clusters = [c for c in liq_clusters if c.get("side") in ("sell", "short") and c["price"] > price]
        if long_clusters:
            # nearest long liquidation = largest cluster below price (SL magnet)
            nearest_long_liq = max(long_clusters, key=lambda c: c["size_usd"])["price"]
        if short_clusters:
            # nearest short liquidation = largest cluster above price (TP magnet)
            nearest_short_liq = min(short_clusters, key=lambda c: c["size_usd"])["price"]
        real_cluster_note = f" [REAL: {len(liq_clusters)} clusters]"

    return {
        "liq_long_levels":   liq_longs,
        "liq_short_levels":  liq_shorts,
        "nearest_long_liq":  nearest_long_liq,
        "nearest_short_liq": nearest_short_liq,
        "liq_heatmap_note":  f"10x longs liq@{nearest_long_liq:.2f} | 10x shorts liq@{nearest_short_liq:.2f}{real_cluster_note}",
        "liq_clusters_real": bool(liq_clusters),
        "liq_clusters_count": len(liq_clusters) if liq_clusters else 0,
    }


# ══════════════════════════════════════════════════════════════
# [C01] OTE — OPTIMAL TRADE ENTRY ENGINE (Fibonacci 0.618/0.705/0.79)
# ICT methodology: OTE zone is the 0.618–0.79 retracement of the
# most recent displacement impulse leg.  0.705 = mathematical sweet
# spot between the two golden-ratio extensions.
# Cross-referenced with the LTF Order Block for highest-confluence entry.
# ══════════════════════════════════════════════════════════════
def compute_ote_zone(
    ohlcv:      List,
    bias:       str,
    atr:        float,
    lookback:   int = 30,
) -> Dict:
    """
    [C01] Optimal Trade Entry (OTE) Fibonacci retracement engine.

    Identifies the most recent displacement impulse leg, then computes
    the 0.618, 0.705, and 0.79 retracement levels as the OTE entry zone.

    Returns:
      ote_valid       : True if a clean impulse leg was found
      ote_low         : bottom of OTE zone (min of 0.618/0.79 retracement)
      ote_high        : top of OTE zone
      ote_705         : 0.705 sweet-spot price
      ote_fib_618     : 0.618 retracement level
      ote_fib_705     : 0.705 retracement level
      ote_fib_79      : 0.790 retracement level
      impulse_origin  : origin price of detected impulse
      impulse_end     : end price of detected impulse
      ote_note        : human-readable summary
    """
    empty = {
        "ote_valid": False, "ote_low": 0.0, "ote_high": 0.0,
        "ote_705": 0.0, "ote_fib_618": 0.0, "ote_fib_705": 0.0,
        "ote_fib_79": 0.0, "impulse_origin": 0.0, "impulse_end": 0.0,
        "ote_note": "OTE: no valid impulse found",
    }
    if len(ohlcv) < max(lookback, 10) or atr <= 0:
        return empty

    try:
        window = ohlcv[-lookback:]
        closes = [c[3] for c in window]
        highs  = [c[1] for c in window]
        lows   = [c[2] for c in window]

        # ── Find the dominant impulse leg matching the bias ──────
        # BULLISH: look for the most recent strong up-move (swing low → swing high)
        # BEARISH: look for the most recent strong down-move (swing high → swing low)
        best_origin = 0.0
        best_end    = 0.0
        best_range  = 0.0
        MIN_IMPULSE_ATR = 1.8   # impulse must be at least 1.8× ATR

        if bias == "BULLISH":
            for i in range(len(window) - 5, 4, -1):
                swing_lo = min(lows[max(0, i-8):i])
                swing_hi = max(highs[i:min(len(window), i+5)])
                rng = swing_hi - swing_lo
                if rng >= MIN_IMPULSE_ATR * atr and rng > best_range:
                    # Confirm bullish body in the impulse zone
                    if closes[i] > closes[max(0, i-3)]:
                        best_range  = rng
                        best_origin = swing_lo
                        best_end    = swing_hi
                        break
        else:  # BEARISH
            for i in range(len(window) - 5, 4, -1):
                swing_hi = max(highs[max(0, i-8):i])
                swing_lo = min(lows[i:min(len(window), i+5)])
                rng = swing_hi - swing_lo
                if rng >= MIN_IMPULSE_ATR * atr and rng > best_range:
                    if closes[i] < closes[max(0, i-3)]:
                        best_range  = rng
                        best_origin = swing_hi
                        best_end    = swing_lo
                        break

        if best_range == 0.0:
            return {**empty, "ote_note": "OTE: impulse leg below 1.8×ATR threshold"}

        rng = abs(best_end - best_origin)

        if bias == "BULLISH":
            # Retracement INTO the move (price pulling back from swing high)
            fib_618 = round(best_end - rng * 0.618, 8)
            fib_705 = round(best_end - rng * 0.705, 8)
            fib_79  = round(best_end - rng * 0.790, 8)
            ote_lo  = min(fib_618, fib_79)
            ote_hi  = max(fib_618, fib_79)
        else:
            # Retracement INTO the move (price pulling back UP from swing low)
            fib_618 = round(best_end + rng * 0.618, 8)
            fib_705 = round(best_end + rng * 0.705, 8)
            fib_79  = round(best_end + rng * 0.790, 8)
            ote_lo  = min(fib_618, fib_79)
            ote_hi  = max(fib_618, fib_79)

        note = (
            f"OTE ({'BULL' if bias == 'BULLISH' else 'BEAR'}) | "
            f"Impulse {round(best_origin,4)}→{round(best_end,4)} "
            f"({round(rng/atr,1)}×ATR) | "
            f"0.618={round(fib_618,4)} 0.705={round(fib_705,4)} "
            f"0.79={round(fib_79,4)}"
        )

        return {
            "ote_valid":      True,
            "ote_low":        ote_lo,
            "ote_high":       ote_hi,
            "ote_705":        fib_705,
            "ote_fib_618":    fib_618,
            "ote_fib_705":    fib_705,
            "ote_fib_79":     fib_79,
            "impulse_origin": round(best_origin, 8),
            "impulse_end":    round(best_end, 8),
            "ote_note":       note,
        }
    except Exception as e:
        return {**empty, "ote_note": f"OTE error: {e}"}


# ══════════════════════════════════════════════════════════════
# [C02/C03] SORTINO RATIO + CALMAR RATIO HELPERS
# Industry-standard risk-adjusted return metrics.
# Sortino: penalises only downside deviation (not upside vol).
# Calmar:  return ÷ maximum drawdown — preferred by fund allocators.
# ══════════════════════════════════════════════════════════════
def compute_sortino_ratio(pnls: List[float], target_return: float = 0.0,
                          periods_per_year: int = 252) -> float:
    """
    [C02] Sortino Ratio = (mean_return - target) / downside_deviation * sqrt(N).
    Only penalises returns below `target_return` (default 0).
    Returns 0.0 on insufficient data.
    """
    if len(pnls) < 5:
        return 0.0
    try:
        mean_r    = sum(pnls) / len(pnls)
        downside  = [min(0.0, r - target_return) ** 2 for r in pnls]
        dd_std    = math.sqrt(sum(downside) / max(len(downside) - 1, 1))
        if dd_std < 1e-12:
            return 0.0
        return round((mean_r / dd_std) * math.sqrt(periods_per_year), 4)
    except Exception:
        return 0.0


def compute_calmar_ratio(pnls: List[float], periods_per_year: int = 252) -> float:
    """
    [C03] Calmar Ratio = annualised_return / max_drawdown.
    A Calmar > 2.0 is considered fund-grade (comparable to Sharpe > 1.5).
    Returns 0.0 on insufficient data or zero drawdown.
    """
    if len(pnls) < 5:
        return 0.0
    try:
        total_return = sum(pnls)
        ann_return   = total_return * (periods_per_year / len(pnls))
        # Max drawdown from equity curve
        eq, peak, max_dd = 1.0, 1.0, 1e-9
        for p in pnls:
            eq  *= (1 + p)
            if eq > peak:
                peak = eq
            dd = (peak - eq) / peak
            if dd > max_dd:
                max_dd = dd
        return round(ann_return / max_dd, 4)
    except Exception:
        return 0.0


# ══════════════════════════════════════════════════════════════
# [C10] DEFLATED SHARPE RATIO — Anti-Overfitting Gate
# Bailey & López de Prado (2014): adjusts Sharpe for number of
# backtests tried, non-normality of returns, and series length.
# DSR < 0 → strategy likely overfitted.  DSR > 0.95 → robust.
# ══════════════════════════════════════════════════════════════
def compute_deflated_sharpe(
    pnls:           List[float],
    n_trials:       int   = 1,
    periods_per_year: int = 252,
) -> Dict:
    """
    [C10] Deflated Sharpe Ratio.

    DSR(SR*) = Φ[ (SR_hat - SR*) * sqrt(T-1) / sqrt(1 - γ3*SR_hat + (γ4-1)/4*SR_hat²) ]

    where SR* = expected maximum Sharpe under repeated trials.
    Φ = standard normal CDF.

    Returns DSR score, benchmark SR*, and interpretation.
    """
    empty = {"dsr": 0.0, "sr_hat": 0.0, "sr_star": 0.0,
             "dsr_pass": False, "dsr_note": "DSR: insufficient data"}
    if len(pnls) < 10:
        return empty
    try:
        T       = len(pnls)
        mean_r  = sum(pnls) / T
        var_r   = sum((r - mean_r) ** 2 for r in pnls) / max(T - 1, 1)
        std_r   = math.sqrt(var_r) if var_r > 0 else 1e-9

        # Observed Sharpe (annualised)
        sr_hat  = round((mean_r / std_r) * math.sqrt(periods_per_year), 4)

        # Third/fourth standardised moments (skewness/excess kurtosis)
        def _moment(pnls_, k):
            m = sum(pnls_) / len(pnls_)
            s = math.sqrt(sum((r - m)**2 for r in pnls_) / max(len(pnls_)-1, 1))
            if s < 1e-12:
                return 0.0
            return sum(((r - m) / s) ** k for r in pnls_) / len(pnls_)

        gamma3 = _moment(pnls, 3)   # skewness
        gamma4 = _moment(pnls, 4)   # kurtosis

        # SR* — expected maximum SR under n_trials (Bonferroni-like correction)
        # Simplified form: SR* ≈ (1 - γ_E + γ_E * ln(n_trials)) where γ_E = Euler–Mascheroni
        euler_mascheroni = 0.5772156649
        sr_star = math.sqrt(2) * math.sqrt(
            (1 - euler_mascheroni) * math.log(max(n_trials, 1)) + euler_mascheroni
        ) if n_trials > 1 else 0.0
        sr_star = round(sr_star, 4)

        # Deflation denominator
        denom_sq = 1.0 - gamma3 * sr_hat + (gamma4 - 1) / 4.0 * sr_hat ** 2
        denom    = math.sqrt(max(denom_sq, 1e-9))

        # Standard normal CDF (erf approximation)
        z    = (sr_hat - sr_star) * math.sqrt(max(T - 1, 1)) / denom
        dsr  = round(0.5 * (1.0 + math.erf(z / math.sqrt(2))), 4)

        dsr_pass = dsr >= 0.95
        note = (
            f"DSR={dsr:.3f} (SR_hat={sr_hat:.2f} SR*={sr_star:.2f} "
            f"trials={n_trials} T={T}) — "
            f"{'✅ ROBUST' if dsr_pass else '⚠️ POSSIBLE OVERFIT'}"
        )
        return {
            "dsr":      dsr,
            "sr_hat":   sr_hat,
            "sr_star":  sr_star,
            "dsr_pass": dsr_pass,
            "dsr_note": note,
        }
    except Exception as e:
        return {**empty, "dsr_note": f"DSR error: {e}"}


# ── Upgrade #12 — Fourier Cycle Detector ─────────────────────
def compute_fourier_cycles(closes: List[float], window: int = 64) -> Dict:
    """
    Upgrade #49 — Fast Fourier Transform to find dominant price cycles.
    Identifies cycle peak/trough timing.
    """
    n = min(window, len(closes))
    if n < 8:
        return {"dominant_cycle_bars": 0, "fourier_note": "Insufficient data", "next_cycle_turn": "UNKNOWN"}
    data = closes[-n:]
    mean_d = sum(data) / n
    centered = [x - mean_d for x in data]
    # Manual DFT (simplified — real magnitudes only)
    magnitudes = []
    for k in range(1, n // 2):
        real = sum(centered[t] * math.cos(2 * math.pi * k * t / n) for t in range(n))
        imag = sum(centered[t] * math.sin(2 * math.pi * k * t / n) for t in range(n))
        magnitudes.append((math.sqrt(real**2 + imag**2), n // k))
    if not magnitudes:
        return {"dominant_cycle_bars": 0, "fourier_note": "No cycles found", "next_cycle_turn": "UNKNOWN"}
    dom_mag, dom_cycle = max(magnitudes, key=lambda x: x[0])
    # Estimate where in current cycle we are
    pos_in_cycle = n % dom_cycle if dom_cycle > 0 else 0
    bars_to_turn = dom_cycle - pos_in_cycle
    return {
        "dominant_cycle_bars": dom_cycle,
        "bars_to_next_turn":   bars_to_turn,
        "cycle_magnitude":     round(dom_mag, 2),
        "fourier_note":        f"Dom cycle={dom_cycle} bars, ~{bars_to_turn} bars to next turn",
        "next_cycle_turn":     f"~{bars_to_turn} bars",
    }


# ── Upgrade #13 — Tail Risk Regime Indicator (TRRI) ──────────
def compute_trri(closes: List[float], window: int = 50) -> Dict:
    """
    Upgrade #50 — Tail Risk Regime Indicator.
    TRRI < 0.5 = left-tail dominated (crash risk elevated).
    Feeds into Kelly sizing as tail-risk multiplier.
    """
    if len(closes) < window + 1:
        return {"trri": 1.0, "trri_note": "Insufficient data", "tail_risk": "NORMAL"}
    returns = sorted([closes[i] / closes[i-1] - 1 for i in range(len(closes)-window, len(closes)) if closes[i-1] > 0])
    if not returns:
        return {"trri": 1.0, "trri_note": "No returns", "tail_risk": "NORMAL"}
    n = len(returns)
    p5_idx  = max(0, int(n * 0.05))
    p95_idx = min(n-1, int(n * 0.95))
    p5  = abs(returns[p5_idx])
    p95 = abs(returns[p95_idx])
    trri = round(p5 / max(p95, 1e-9), 4)
    tail_risk = "ELEVATED" if trri < 0.5 else "NORMAL"
    kelly_mult = round(max(0.5, min(1.0, trri)), 4)
    return {
        "trri":          trri,
        "trri_note":     f"TRRI={trri:.3f} ({'⚠️ Crash risk elevated' if tail_risk == 'ELEVATED' else '✅ Symmetric risk'})",
        "tail_risk":     tail_risk,
        "kelly_trri_mult": kelly_mult,
    }


# ── Upgrade #14 — Cross-Sectional Momentum (Sector Rotation) ─
def compute_cross_sectional_momentum(returns_map: Dict[str, float]) -> Dict:
    """
    Upgrade #46 — Rank coins by 14-day return for sector rotation signal.
    BTC rank=1 → macro confidence for BTC longs.
    """
    if not returns_map:
        return {"cs_rank": {}, "btc_rank": 0, "cs_note": "No data"}
    sorted_coins = sorted(returns_map.items(), key=lambda x: x[1], reverse=True)
    ranks = {coin: i+1 for i, (coin, _) in enumerate(sorted_coins)}
    btc_rank = ranks.get("BTC", len(ranks))
    n = len(ranks)
    note = (f"BTC ranked #{btc_rank}/{n} — " +
            ("✅ macro confidence high" if btc_rank == 1 else
             "⚠️ altcoin rotation, BTC long headwind" if btc_rank > n//2 else
             "➡️ mid-pack rotation"))
    return {
        "cs_rank":  ranks,
        "btc_rank": btc_rank,
        "cs_note":  note,
    }


# ── Upgrade #15 — Market Regime Transition Matrix ────────────
_REGIME_TRANSITION_WINDOW = 50
_REGIME_TRANSITION_LOG: deque = deque(maxlen=_REGIME_TRANSITION_WINDOW)  # O(1) append+trim

def update_regime_transition(regime: str) -> Dict:
    """
    Upgrade #39 — Track regime transition probabilities.
    If TRENDING → CHOPPY prob is high recently, reduce position sizing.
    """
    _REGIME_TRANSITION_LOG.append(regime)   # deque auto-evicts oldest at maxlen — no pop(0)
    log_len = len(_REGIME_TRANSITION_LOG)
    if log_len < 3:
        return {"transition_probs": {}, "regime_warning": False, "transition_note": "Collecting data"}
    # Count transitions
    transitions = {}
    for i in range(1, log_len):
        key = (_REGIME_TRANSITION_LOG[i-1], _REGIME_TRANSITION_LOG[i])
        transitions[key] = transitions.get(key, 0) + 1
    # Compute probs from TRENDING
    trending_total = sum(v for (s, _), v in transitions.items() if s == "TREND_EXPANSION")
    t_to_choppy = transitions.get(("TREND_EXPANSION", "DEAD_ZONE"), 0) + transitions.get(("TREND_PULLBACK", "DEAD_ZONE"), 0)
    t_to_choppy_prob = round(t_to_choppy / max(trending_total, 1), 3) if trending_total > 0 else 0
    warning = t_to_choppy_prob > 0.35
    return {
        "transition_probs":   {str(k): v for k, v in transitions.items()},
        "t_to_choppy_prob":   t_to_choppy_prob,
        "regime_warning":     warning,
        "transition_note":    f"TREND→CHOPPY prob={t_to_choppy_prob:.1%} ({'⚠️ High' if warning else '✅ OK'})",
    }


# ── Upgrade #16 — Execution Cost Ledger ──────────────────────
_EXECUTION_COST_LEDGER: Dict[str, float] = {}

def update_execution_cost_ledger(symbol: str, slip_pct: float, comm_pct: float = 0.04) -> Dict:
    """
    Upgrade #40 — Track accumulated execution costs per symbol.
    When total > 0.3% account, flag cost drag warning.
    """
    key = symbol
    _EXECUTION_COST_LEDGER[key] = _EXECUTION_COST_LEDGER.get(key, 0.0) + slip_pct + comm_pct
    total_cost = _EXECUTION_COST_LEDGER[key]
    warning = total_cost > 0.30
    return {
        "total_exec_cost_pct": round(total_cost, 4),
        "cost_drag_warning":   warning,
        "exec_cost_note":      f"Exec costs: {total_cost:.3f}% ({'⚠️ DRAG WARNING' if warning else '✅ OK'})",
    }


# ── Upgrade #17 — Intraday Seasonality Score ─────────────────
def compute_intraday_seasonality(session: str) -> Dict:
    """
    Upgrade #36 — Hour-of-day execution quality score.
    Based on known crypto market microstructure patterns.
    """
    _session_scores = {
        "LONDON":    85,
        "NEW_YORK":  90,
        "OVERLAP":   95,
        "ASIA":      60,
        "OFF_HOURS": 45,
    }
    score = _session_scores.get(session.upper(), 50)
    grade = "EXCELLENT" if score >= 90 else "GOOD" if score >= 75 else "FAIR" if score >= 55 else "POOR"
    return {
        "seasonality_score": score,
        "seasonality_grade": grade,
        "seasonality_note":  f"Session {session} → Execution quality {score}/100 ({grade})",
    }


# ── Upgrade #18 — GEX (Gamma Exposure Proxy) ─────────────────
def compute_gex_proxy(funding_rate: float, oi: float, price: float) -> Dict:
    """
    Upgrade #48 — Options Gamma Exposure proxy from funding + OI.
    Positive GEX → price pins to nearby level. Negative → explosive moves.
    """
    if price <= 0 or oi <= 0:
        return {"gex_proxy": 0.0, "gex_note": "No OI data", "gex_regime": "NEUTRAL"}
    # Proxy: positive funding + high OI = positive GEX (crowded longs, dealer hedges buy dips)
    oi_normalized = oi / max(price, 1e-9)
    gex = round(funding_rate * oi_normalized * 1000, 4)
    regime = "POSITIVE_GEX" if gex > 0.5 else "NEGATIVE_GEX" if gex < -0.5 else "NEUTRAL"
    return {
        "gex_proxy":  gex,
        "gex_regime": regime,
        "gex_note":   f"GEX={gex:.3f} ({regime}) — {'Pin risk near current level' if regime == 'POSITIVE_GEX' else 'Explosive moves amplified' if regime == 'NEGATIVE_GEX' else 'Neutral GEX'}",
    }


# ── Upgrade #19 — Wyckoff Phase Classifier ───────────────────
def compute_wyckoff_phase(closes: List[float], volumes: List[float], window: int = 40) -> Dict:
    """
    Upgrade #42 — Wyckoff Phase Classification.
    Accumulation → Markup → Distribution → Markdown.
    """
    if len(closes) < window or len(volumes) < window:
        return {"wyckoff_phase": "UNKNOWN", "wyckoff_note": "Insufficient data"}
    c = closes[-window:]
    v = volumes[-window:]
    half = window // 2
    price_trend = c[-1] - c[0]
    price_trend_first = c[half] - c[0]
    price_trend_second = c[-1] - c[half]
    avg_vol_first  = sum(v[:half]) / half
    avg_vol_second = sum(v[half:]) / half
    # Heuristic Wyckoff phase detection
    if price_trend < 0 and avg_vol_second < avg_vol_first:
        phase = "ACCUMULATION"
    elif price_trend > 0 and price_trend_second > 0:
        phase = "MARKUP"
    elif price_trend > 0 and avg_vol_second < avg_vol_first:
        phase = "DISTRIBUTION"
    elif price_trend < 0 and price_trend_second < 0:
        phase = "MARKDOWN"
    else:
        phase = "CONSOLIDATION"
    return {
        "wyckoff_phase": phase,
        "wyckoff_note":  f"Wyckoff: {phase} (price_trend={'+' if price_trend > 0 else ''}{price_trend/max(abs(c[0]),1e-9)*100:.1f}%)",
    }


# ── Upgrade #20 — Elliott Wave Degree Estimator ──────────────
def compute_elliott_wave_position(closes: List[float], swing_highs: list, swing_lows: list) -> Dict:
    """
    [F03] Elliott Wave — real 5-wave impulse / 3-wave correction detector.
    Replaces the broken total_swings % 8 + 1 modulo hack.

    Method:
      • Interleave swing highs (H) and swing lows (L) in time order.
      • Classify alternating H-L sequence into impulse or corrective waves.
      • 5-wave impulse: L→H→L→H→L→H (3 up legs + 2 pullbacks) = bullish.
      • 3-wave correction: H→L→H (2 down + 1 up) = corrective.
      • Wave 3 identification: middle impulse leg longest (Elliott Rule 1).

    Returns wave_label, is_wave3, is_impulse, fib_valid, confidence.
    """
    if len(swing_highs) < 2 or len(swing_lows) < 2:
        return {"elliott_wave": "UNKNOWN", "elliott_note": "Insufficient swings",
                "is_wave3": False, "is_impulse": False}

    try:
        # Interleave swing H and L by index, sorted chronologically
        combined = [(idx, "H", val) for idx, val in swing_highs] + \
                   [(idx, "L", val) for idx, val in swing_lows]
        combined.sort(key=lambda x: x[0])

        if len(combined) < 5:
            return {"elliott_wave": "~Early", "elliott_note": "Insufficient alternating swings",
                    "is_wave3": False, "is_impulse": False}

        # Take last 8 pivot points for wave counting
        pts = combined[-8:]
        labels = [p[1] for p in pts]
        vals   = [p[2] for p in pts]

        # Identify last impulse sequence: H-L-H-L-H or L-H-L-H-L
        is_impulse = False
        is_wave3   = False
        wave_label = "CORRECTIVE"
        wave_num   = 0

        # Check for 5-wave structure in last 5 pivots
        if len(pts) >= 5:
            last5 = labels[-5:]
            last5_vals = vals[-5:]

            # Bullish impulse: L-H-L-H-L (with final L being the end of wave 4 / start of 5)
            bull_impulse = (last5[0] == "L" and last5[2] == "L" and last5[4] == "L" and
                            last5[1] == "H" and last5[3] == "H" and
                            last5_vals[1] > last5_vals[3] and  # Wave 3 H > Wave 1 H
                            last5_vals[4] > last5_vals[2])     # Wave 4 L > Wave 2 L (rule: W4 not below W1 top)
            # Bearish impulse: H-L-H-L-H
            bear_impulse = (last5[0] == "H" and last5[2] == "H" and last5[4] == "H" and
                            last5[1] == "L" and last5[3] == "L" and
                            last5_vals[1] < last5_vals[3] and
                            last5_vals[4] < last5_vals[2])

            if bull_impulse or bear_impulse:
                is_impulse = True
                # Identify if we're in Wave 3 (longest leg = Wave 3)
                # Leg sizes: wave1=pts[1]-pts[0], wave3=pts[3]-pts[2], wave5 forming
                if bull_impulse:
                    leg1 = abs(last5_vals[1] - last5_vals[0])
                    leg3 = abs(last5_vals[3] - last5_vals[2])
                    leg3_longest = leg3 > leg1
                    # Currently in Wave 5 if we see 5 pivots and price above W3 high
                    closes_now = closes[-1] if closes else last5_vals[-1]
                    in_wave5 = closes_now > last5_vals[3]  # above Wave 3 low
                    wave_num = 5 if in_wave5 else 3
                    is_wave3 = (wave_num == 3) or (leg3_longest and not in_wave5)
                    wave_label = f"~Wave {wave_num} (Bullish Impulse)"
                else:
                    leg1 = abs(last5_vals[1] - last5_vals[0])
                    leg3 = abs(last5_vals[3] - last5_vals[2])
                    leg3_longest = leg3 > leg1
                    closes_now = closes[-1] if closes else last5_vals[-1]
                    in_wave5 = closes_now < last5_vals[3]
                    wave_num = 5 if in_wave5 else 3
                    is_wave3 = (wave_num == 3) or (leg3_longest and not in_wave5)
                    wave_label = f"~Wave {wave_num} (Bearish Impulse)"
            else:
                # 3-wave correction: A-B-C
                wave_label = "~ABC Correction"
                wave_num = 0

        # Fibonacci validation: Wave 3 should be 1.618× Wave 1
        fib_valid = False
        if is_impulse and len(pts) >= 4:
            try:
                leg1 = abs(vals[-4] - vals[-5]) if len(vals) >= 5 else 0
                leg3 = abs(vals[-2] - vals[-3]) if len(vals) >= 3 else 0
                if leg1 > 0:
                    ratio = leg3 / leg1
                    fib_valid = 1.4 < ratio < 2.0   # within Fib 1.618 tolerance
            except Exception as _ew_err:
                log.debug(f"[ELLIOTT] Fib validation error: {_ew_err}")

        note = (
            f"Elliott: {wave_label} | "
            f"{'✅ Wave 3 — high-prob impulse' if is_wave3 else 'Impulse' if is_impulse else 'Corrective ABC'} | "
            f"{'Fib ✅' if fib_valid else ''}"
        ).strip(" |")

        return {
            "elliott_wave":     wave_label,
            "is_wave3":         is_wave3,
            "is_impulse":       is_impulse,
            "fib_valid":        fib_valid,
            "wave_num":         wave_num,
            "elliott_note":     note,
        }

    except Exception as e:
        return {"elliott_wave": "ERROR", "elliott_note": f"Elliott error: {e}",
                "is_wave3": False, "is_impulse": False}


# ── [F01] POC Migration Tracker — per-symbol keyed dict ──────
_POC_HISTORY: Dict[str, List[float]] = collections.defaultdict(list)

def track_poc_migration(poc_current: float, symbol: str = "UNKNOWN") -> Dict:
    """
    [F01 FIX] POC Migration per symbol — no more cross-symbol contamination.
    Was: single module-level list shared by BTC, ETH, SOL, etc.
    Now: defaultdict(list) keyed by symbol.
    POC rising 3 consecutive sessions → bullish value acceptance.
    """
    hist = _POC_HISTORY[symbol]
    hist.append(poc_current)
    if len(hist) > 10:
        hist.pop(0)
    if len(hist) < 3:
        return {"poc_migration": "NEUTRAL", "poc_migration_note": "Collecting data"}
    recent = hist[-3:]
    if recent[0] < recent[1] < recent[2]:
        migration = "BULLISH"
        note = "✅ POC rising 3 sessions → value accepted higher (BULLISH)"
    elif recent[0] > recent[1] > recent[2]:
        migration = "BEARISH"
        note = "⚠️ POC falling 3 sessions → value accepted lower (BEARISH)"
    else:
        migration = "NEUTRAL"
        note = "➡️ POC migration neutral"
    return {"poc_migration": migration, "poc_migration_note": note}


# ── [F01] Depth Imbalance Momentum — per-symbol keyed dict ───
_DEPTH_IMBALANCE_HISTORY: Dict[str, List[float]] = collections.defaultdict(list)

def compute_depth_imbalance_momentum(bid_depth: float, ask_depth: float, symbol: str = "UNKNOWN") -> Dict:
    """
    [F01 FIX] Depth imbalance per symbol — prevents cross-symbol contamination.
    Was: single module-level list shared across all symbols.
    Now: defaultdict(list) keyed by symbol, capped at 5 snapshots each.
    Rising bid imbalance = accumulation. Falling = distribution.
    """
    total = bid_depth + ask_depth
    imb = round(bid_depth / max(total, 1e-9), 4)
    hist = _DEPTH_IMBALANCE_HISTORY[symbol]
    hist.append(imb)
    if len(hist) > 5:
        hist.pop(0)
    if len(hist) < 3:
        return {"depth_momentum": "NEUTRAL", "depth_imb_note": "Collecting data"}
    trend = hist[-1] - hist[0]
    momentum = "ACCUMULATION" if trend > 0.05 else "DISTRIBUTION" if trend < -0.05 else "NEUTRAL"
    return {
        "depth_imb_current": imb,
        "depth_imb_trend":   round(trend, 4),
        "depth_momentum":    momentum,
        "depth_imb_note":    f"Depth imb={imb:.3f} trend={trend:+.3f} → {momentum}",
    }


# ── Upgrade #23 — 30-Day Momentum Ratio (was: SOPR Proxy) ───
def compute_sopr_proxy(current_price: float, price_30d_ago: float) -> Dict:
    """
    [F05 FIX] Renamed from SOPR proxy → MOM_30D (30-day momentum ratio).
    Original label 'SOPR' (Spent Output Profit Ratio) is an on-chain UTXO metric
    requiring real blockchain data — not derivable from price history alone.
    This metric is correctly: current_price / price_30d_ago = 30-day return.
    MOM_30D > 1.1 = strong uptrend (potential mean-reversion risk).
    MOM_30D < 0.9 = strong downtrend (potential accumulation zone).
    """
    if price_30d_ago <= 0:
        return {"sopr_proxy": 1.0, "mom_30d": 1.0, "sopr_note": "No historical price",
                "sopr_signal": "NEUTRAL"}
    mom = round(current_price / price_30d_ago, 4)
    signal = "PROFIT_TAKING" if mom > 1.1 else "ACCUMULATION" if mom < 0.9 else "NEUTRAL"
    return {
        "sopr_proxy":  mom,   # kept for backward compat with result dict keys
        "mom_30d":     mom,
        "sopr_note":   f"MOM_30D≈{mom:.3f} ({'30d uptrend — mean-rev risk' if signal == 'PROFIT_TAKING' else '30d downtrend — potential accumulation' if signal == 'ACCUMULATION' else 'neutral'})",
        "sopr_signal": signal,
    }


# ── Upgrade #24 — NVT Ratio Proxy ────────────────────────────
# [F06] Per-symbol circulating supply — BTC only valid; others return NEUTRAL
_CIRCULATING_SUPPLY: Dict[str, float] = {
    "BTC":  19_700_000,
    "ETH":  120_000_000,
    "BNB":  145_000_000,
    "SOL":  460_000_000,
    "XRP":  57_000_000_000,
    "ADA":  35_000_000_000,
    "AVAX": 380_000_000,
    "DOT":  1_400_000_000,
    "LINK": 590_000_000,
    "MATIC":9_300_000_000,
}
# REC-18: Live refresh — called once from TA module init and by APEX BTC-regime task every 6h.
_SUPPLY_LAST_REFRESH: float = 0.0
_SUPPLY_REFRESH_TTL:  int   = 21600  # 6 hours

def refresh_circulating_supply() -> int:
    """
    REC-18: Fetch live circulating supply for top-100 coins from CoinGecko.
    Updates _CIRCULATING_SUPPLY in-place so NVT/MVRV calculations use real data.
    Returns count of symbols updated. Falls back to hardcoded dict on failure.
    """
    global _SUPPLY_LAST_REFRESH
    import time as _t
    if (_t.time() - _SUPPLY_LAST_REFRESH) < _SUPPLY_REFRESH_TTL:
        return 0  # within TTL, skip
    try:
        import urllib.request as _ur, json as _j
        _url = (
            "https://api.coingecko.com/api/v3/coins/markets"
            "?vs_currency=usd&order=market_cap_desc&per_page=100&page=1"
            "&sparkline=false&price_change_percentage=24h"
        )
        with _ur.urlopen(_url, timeout=10) as _r:
            _coins = _j.loads(_r.read())
        _updated = 0
        for _c in _coins:
            _sym = (_c.get("symbol") or "").upper().strip()
            _cs  = _c.get("circulating_supply")
            if _sym and _cs and float(_cs) > 0:
                _CIRCULATING_SUPPLY[_sym] = float(_cs)
                _updated += 1
        _SUPPLY_LAST_REFRESH = _t.time()
        log.info(f"[SUPPLY] Refreshed circulating supply for {_updated} symbols from CoinGecko")
        return _updated
    except Exception as _se:
        log.debug(f"[SUPPLY] refresh non-critical: {_se}")
        return 0

# Run once at import time (non-blocking best-effort)
try:
    refresh_circulating_supply()
except Exception as _sri:
    log.debug(f"[SUPPLY] init refresh non-critical: {_sri}")


def compute_nvt_proxy(price: float, volume_30d_avg: float, circulating_supply: float = 19e6,
                      symbol: str = "BTC") -> Dict:
    """
    [F06 FIX] NVT Ratio per symbol — was hardcoded to BTC supply (19M) for all symbols.
    Now uses _CIRCULATING_SUPPLY dict. For unknown symbols, returns NEUTRAL (no fake NVT).
    NVT > 65 = overvalued relative to network usage. NVT < 30 = undervalued.
    Only meaningful for PoW/PoS chains with clear on-chain transaction volume.
    """
    base = symbol.replace("USDT","").replace("BUSD","").replace("PERP","").upper()
    supply = _CIRCULATING_SUPPLY.get(base)
    if supply is None:
        return {"nvt_proxy": 0.0, "nvt_note": f"NVT: no supply data for {base} → NEUTRAL",
                "nvt_signal": "NEUTRAL"}
    if volume_30d_avg <= 0 or price <= 0:
        return {"nvt_proxy": 0.0, "nvt_note": "No volume data", "nvt_signal": "NEUTRAL"}
    market_cap = price * supply
    nvt = round(market_cap / max(volume_30d_avg, 1e-9), 4)
    # Normalize to typical range (calibrated per symbol class)
    nvt_norm = round(nvt / 1e12 * 50, 2) if base == "BTC" else round(nvt / 1e10 * 50, 2)
    signal = "OVERVALUED" if nvt_norm > 65 else "UNDERVALUED" if nvt_norm < 30 else "FAIR"
    return {
        "nvt_proxy":  nvt_norm,
        "nvt_note":   f"NVT≈{nvt_norm:.1f} ({signal}) [{base}]",
        "nvt_signal": signal,
    }


# ── Upgrade #25 — Adverse Selection Score ────────────────────
def compute_adverse_selection_score(ohlcv: List, bias: str, entry_price: float, atrs: List[float], lookback: int = 5) -> Dict:
    """
    [F04 FIX] Adverse selection score — fill price corrected to next candle OPEN.
    Was: ohlcv[i][3] (close of candle i) as hypothetical fill → wrong.
    Fix: ohlcv[i+1][0] (open of NEXT candle) = realistic market order fill.
    If price moves adversely > 0.3×ATR in >60% of cases, entry is adversely selected.
    """
    if len(ohlcv) < lookback + 5 or not atrs:
        return {"adverse_score": 0.5, "adversely_selected": False, "adverse_note": "Insufficient data"}
    atr = atrs[-1] if atrs else 1.0
    adverse_count = 0
    total_checks = min(lookback, len(ohlcv) - 6)   # -6 because we need i+1 open
    if total_checks <= 0:
        return {"adverse_score": 0.5, "adversely_selected": False, "adverse_note": "Insufficient candles"}
    for i in range(-total_checks - 5, -5):
        # [F04] Use next candle OPEN as the actual fill price (not current close)
        entry_c  = float(ohlcv[i + 1][0])   # next candle open = realistic fill
        future_c = float(ohlcv[i + 5][3])   # 5 bars later close = outcome
        adverse_move = (future_c - entry_c) if bias == "BULLISH" else (entry_c - future_c)
        if adverse_move < -0.3 * atr:
            adverse_count += 1
    adverse_rate = round(adverse_count / total_checks, 3)
    adversely_selected = adverse_rate > 0.6
    return {
        "adverse_score":       adverse_rate,
        "adversely_selected":  adversely_selected,
        "adverse_note":        f"Adverse sel (next-open fill): {adverse_rate:.1%} ({'⚠️ HIGH' if adversely_selected else '✅ OK'})",
    }


# ── Upgrade #26 — Bid-Ask Bounce Filter (Roll Model) ─────────
def compute_roll_model_autocorr(closes: List[float], window: int = 20) -> Dict:
    """
    Upgrade #4 — Roll model: negative price-change autocorrelation = spread noise.
    Positive autocorrelation = informed directional flow.
    """
    if len(closes) < window + 2:
        return {"roll_spread_proxy": 0.0, "roll_note": "Insufficient data", "informed_flow": False}
    changes = [closes[i] - closes[i-1] for i in range(len(closes)-window, len(closes))]
    n = len(changes)
    if n < 3:
        return {"roll_spread_proxy": 0.0, "roll_note": "Insufficient changes", "informed_flow": False}
    mean_c = sum(changes) / n
    products = [(changes[i] - mean_c) * (changes[i-1] - mean_c) for i in range(1, n)]
    cov = sum(products) / (n - 1)
    # Roll model: spread proxy = 2*sqrt(|cov|) if cov < 0 (negatively autocorrelated)
    spread_proxy = 2 * math.sqrt(abs(cov)) if cov < 0 else 0.0
    informed_flow = cov > 0
    return {
        "roll_spread_proxy": round(spread_proxy, 6),
        "roll_cov":          round(cov, 8),
        "informed_flow":     informed_flow,
        "roll_note":         f"Roll spread≈{spread_proxy:.6f} | {'✅ Informed flow (directional)' if informed_flow else '➡️ Spread noise (uninformed)'}",
    }


# ── Upgrade #27 — Funding Rate Cross-Exchange Divergence ─────
def compute_funding_divergence(binance_fr: float, bybit_fr: float = 0.0, okx_fr: float = 0.0) -> Dict:
    """
    Upgrade #23 — Cross-exchange funding rate divergence.
    Divergence between exchanges precedes large moves.
    """
    frs = {"binance": binance_fr, "bybit": bybit_fr, "okx": okx_fr}
    valid = {k: v for k, v in frs.items() if v != 0.0}
    if len(valid) < 2:
        return {"funding_divergence": 0.0, "funding_div_note": "Single exchange data", "funding_div_signal": "NEUTRAL"}
    vals = list(valid.values())
    div = round(max(vals) - min(vals), 6)
    significant = div > 0.0002  # 0.02% divergence threshold
    signal = "DIVERGENT" if significant else "ALIGNED"
    return {
        "funding_divergence":   div,
        "funding_div_signal":   signal,
        "funding_rates_map":    valid,
        "funding_div_note":     f"FR divergence={div:.5f} ({'⚠️ DIVERGENT — large move likely' if significant else '✅ Aligned exchanges'})",
    }


# ── Upgrade #28 — Head & Shoulders Detector ──────────────────
def detect_head_shoulders(highs: List[float], lows: List[float], window: int = 30) -> Dict:
    """
    Upgrade #44 — Classical H&S pattern detection.
    When H&S at supply zone = major confluence boost.
    """
    if len(highs) < window:
        return {"hs_pattern": "NONE", "hs_note": "Insufficient data"}
    h = highs[-window:]
    n = len(h)
    if n < 5:
        return {"hs_pattern": "NONE", "hs_note": "Too few candles"}
    # Find local peaks
    peaks = [i for i in range(1, n-1) if h[i] > h[i-1] and h[i] > h[i+1]]
    if len(peaks) < 3:
        return {"hs_pattern": "NONE", "hs_note": "Insufficient peaks"}
    # Check last 3 peaks for H&S: left shoulder < head > right shoulder
    p1, p2, p3 = peaks[-3], peaks[-2], peaks[-1]
    is_hs = (h[p2] > h[p1] and h[p2] > h[p3] and
             abs(h[p1] - h[p3]) / max(h[p2], 1e-9) < 0.05)  # shoulders within 5%
    pattern = "BEARISH_HS" if is_hs else "NONE"
    return {
        "hs_pattern": pattern,
        "hs_note":    f"{'⚠️ Bearish H&S detected — neckline break = major confluence' if pattern == 'BEARISH_HS' else '✅ No H&S pattern'}",
        "hs_peaks":   [p1, p2, p3] if is_hs else [],
    }


# ── Upgrade #29 — Three-Drive Harmonic Pattern ───────────────
def detect_three_drive(highs: List[float], lows: List[float], bias: str) -> Dict:
    """
    Upgrade #41 — Three-Drive harmonic pattern (1.27x / 1.618x Fib ratios).
    Completion of third drive = high-probability reversal entry.
    """
    data = highs if bias == "BEARISH" else lows
    if len(data) < 10:
        return {"three_drive": False, "three_drive_note": "Insufficient data"}
    # Look for 3 converging drives with Fib relationships
    n = len(data)
    # Simplified: find 3 extremes in last window
    if bias == "BEARISH":
        extremes_idx = sorted(range(max(0, n-20), n), key=lambda i: data[i], reverse=True)[:3]
    else:
        extremes_idx = sorted(range(max(0, n-20), n), key=lambda i: data[i])[:3]
    if len(extremes_idx) < 3:
        return {"three_drive": False, "three_drive_note": "Insufficient extremes"}
    extremes_idx = sorted(extremes_idx)
    e1, e2, e3 = [data[i] for i in extremes_idx]
    if e1 == e2 or e2 == 0:
        return {"three_drive": False, "three_drive_note": "Invalid extremes"}
    ratio = abs(e3 - e2) / max(abs(e2 - e1), 1e-9)
    is_three_drive = 1.1 < ratio < 1.9  # approx Fib range
    return {
        "three_drive":       is_three_drive,
        "three_drive_ratio": round(ratio, 3),
        "three_drive_note":  f"{'⚠️ Three-Drive pattern: ratio=' + str(round(ratio,3)) + ' — reversal entry zone' if is_three_drive else '✅ No Three-Drive pattern'}",
    }


# ── Upgrade #30 — Market Impact Proxy (Almgren-Chriss) ───────
def compute_market_impact_proxy(price: float, atr: float, daily_volume: float, trade_size_usd: float = 1000.0) -> Dict:
    """
    Upgrade #5 — Almgren-Chriss market impact proxy.
    Estimates permanent vs temporary price impact of entry size.
    """
    if daily_volume <= 0 or price <= 0:
        return {"perm_impact_pct": 0.0, "temp_impact_pct": 0.0, "impact_note": "No volume data"}
    participation_rate = trade_size_usd / max(daily_volume * price, 1e-9)
    # Almgren-Chriss: temp impact ≈ σ × sqrt(T), perm impact ≈ γ × participation
    sigma = atr / price
    temp_impact = round(sigma * math.sqrt(participation_rate) * 100, 4)
    perm_impact = round(0.1 * participation_rate * 100, 6)  # 0.1 is typical gamma estimate
    total_impact = round(temp_impact + perm_impact, 4)
    return {
        "perm_impact_pct":  perm_impact,
        "temp_impact_pct":  temp_impact,
        "total_impact_pct": total_impact,
        "participation":    round(participation_rate * 100, 4),
        "impact_note":      f"Market impact: perm={perm_impact:.4f}% temp={temp_impact:.4f}% (participation={participation_rate*100:.3f}%)",
    }


