# ── [v8.1-P01] Ichimoku Cloud (#56) ──────────────────────────
# Research: Hosoda (1969) — Ichimoku encodes S/R, trend, momentum.
# Kumo (cloud) = dynamic S/R. Twist ahead of price = turning point signal.
def compute_ichimoku(highs: List[float], lows: List[float], closes: List[float],
                     tenkan_period: int = 9, kijun_period: int = 26,
                     senkou_b_period: int = 52) -> Dict:
    """
    [v8.1-P01] Full Ichimoku Cloud calculation.
    Tenkan-sen (9): (max_high + min_low) / 2 over 9 bars  — fast signal
    Kijun-sen (26): (max_high + min_low) / 2 over 26 bars — slow baseline
    Senkou A: (Tenkan + Kijun) / 2 — leading span A (cloud upper/lower)
    Senkou B: (max_high + min_low) / 2 over 52 bars — leading span B
    Chikou: current close shifted back 26 bars — lagging confirmation

    Signals:
      price > cloud → bullish (kumo breakout)
      price < cloud → bearish (kumo breakdown)
      price inside cloud → choppy / consolidation
      Kumo twist ahead: Senkou A crosses Senkou B → regime change incoming
      TK cross (Tenkan > Kijun) → momentum entry signal
    """
    n = len(closes)
    min_bars = max(senkou_b_period, kijun_period) + 1
    default = {
        "tenkan": 0.0, "kijun": 0.0, "senkou_a": 0.0, "senkou_b": 0.0,
        "chikou": 0.0, "cloud_top": 0.0, "cloud_bottom": 0.0,
        "price_vs_cloud": "INSIDE", "tk_cross": "NONE",
        "kumo_twist_ahead": False, "kumo_bullish": True,
        "ichi_bias": "NEUTRAL", "ichi_note": "Ichimoku: insufficient data",
    }
    if n < min_bars or len(highs) < min_bars or len(lows) < min_bars:
        return default
    try:
        def _midpoint(h_slice, l_slice):
            return (max(h_slice) + min(l_slice)) / 2.0

        # Tenkan-sen (conversion line)
        tenkan = round(_midpoint(highs[-tenkan_period:], lows[-tenkan_period:]), 8)
        # Kijun-sen (base line)
        kijun  = round(_midpoint(highs[-kijun_period:], lows[-kijun_period:]), 8)
        # Senkou A (leading span A, projected 26 bars forward)
        senkou_a = round((tenkan + kijun) / 2.0, 8)
        # Senkou B (leading span B, 52-bar midpoint)
        senkou_b = round(_midpoint(highs[-senkou_b_period:], lows[-senkou_b_period:]), 8)
        # Chikou (lagging span — current close)
        chikou = round(closes[-1], 8)
        # Cloud boundaries
        cloud_top    = max(senkou_a, senkou_b)
        cloud_bottom = min(senkou_a, senkou_b)
        price = closes[-1]

        # Price vs cloud
        if price > cloud_top:
            price_vs_cloud = "ABOVE_CLOUD"    # bullish
        elif price < cloud_bottom:
            price_vs_cloud = "BELOW_CLOUD"    # bearish
        else:
            price_vs_cloud = "INSIDE_CLOUD"   # consolidation

        # TK Cross — Tenkan vs Kijun momentum signal
        # Compute previous tenkan/kijun for cross detection
        prev_tenkan = _midpoint(highs[-tenkan_period-1:-1], lows[-tenkan_period-1:-1]) if n > tenkan_period + 1 else tenkan
        prev_kijun  = _midpoint(highs[-kijun_period-1:-1],  lows[-kijun_period-1:-1])  if n > kijun_period + 1  else kijun
        bullish_tk_cross = (prev_tenkan <= prev_kijun) and (tenkan > kijun)
        bearish_tk_cross = (prev_tenkan >= prev_kijun) and (tenkan < kijun)
        tk_cross = "BULLISH_TK" if bullish_tk_cross else "BEARISH_TK" if bearish_tk_cross else "NONE"

        # Kumo twist ahead — future cloud direction
        # If current Senkou A > Senkou B → bullish cloud. A < B → bearish cloud.
        kumo_bullish      = senkou_a > senkou_b
        # Compute prior Senkou A/B to detect twist (regime change)
        if n >= senkou_b_period + kijun_period:
            prev_tenkan_26 = _midpoint(highs[-tenkan_period-kijun_period:-kijun_period],
                                       lows[-tenkan_period-kijun_period:-kijun_period])
            prev_kijun_26  = _midpoint(highs[-kijun_period*2:-kijun_period],
                                       lows[-kijun_period*2:-kijun_period])
            prev_senkou_a  = (prev_tenkan_26 + prev_kijun_26) / 2.0
            prev_senkou_b  = _midpoint(highs[-senkou_b_period-kijun_period:-kijun_period],
                                       lows[-senkou_b_period-kijun_period:-kijun_period])
            prev_kumo_bull = prev_senkou_a > prev_senkou_b
            kumo_twist_ahead = (kumo_bullish != prev_kumo_bull)
        else:
            kumo_twist_ahead = False

        # Overall Ichimoku bias
        bull_points = sum([
            price_vs_cloud == "ABOVE_CLOUD",
            tk_cross == "BULLISH_TK",
            tenkan > kijun,
            kumo_bullish,
        ])
        if bull_points >= 3:
            ichi_bias = "BULLISH"
        elif bull_points <= 1:
            ichi_bias = "BEARISH"
        else:
            ichi_bias = "NEUTRAL"

        return {
            "tenkan":            round(tenkan, 8),
            "kijun":             round(kijun, 8),
            "senkou_a":          round(senkou_a, 8),
            "senkou_b":          round(senkou_b, 8),
            "chikou":            round(chikou, 8),
            "cloud_top":         round(cloud_top, 8),
            "cloud_bottom":      round(cloud_bottom, 8),
            "price_vs_cloud":    price_vs_cloud,
            "tk_cross":          tk_cross,
            "kumo_twist_ahead":  kumo_twist_ahead,
            "kumo_bullish":      kumo_bullish,
            "ichi_bias":         ichi_bias,
            "ichi_note": (
                f"Ichimoku: {ichi_bias} | {price_vs_cloud} | TK={tk_cross} | "
                f"Kumo={'🟢 BULLISH' if kumo_bullish else '🔴 BEARISH'}"
                f"{' | ⚡ KUMO TWIST AHEAD' if kumo_twist_ahead else ''}"
            ),
        }
    except Exception as e:
        return {**default, "ichi_note": f"Ichimoku error: {e}"}


# ── [v8.1-P02] Kalman Filter Hedge Ratio (#39) ───────────────
# Research: Kalman (1960) — optimal sequential estimation.
# Applied to pairs trading: dynamic hedge ratio outperforms static OLS.
# Used for SMT divergence pair (BTC/ETH or asset/BTC).
_KALMAN_STATE: Dict[str, Dict] = {}   # symbol_pair → {beta, P, Q, R}

def compute_kalman_hedge_ratio(
    price_x: float,
    price_y: float,
    pair_key: str = "DEFAULT",
    Q: float = 1e-5,    # process noise — how fast beta can drift
    R: float = 1e-3,    # observation noise — price measurement noise
) -> Dict:
    """
    [v8.1-P02] Kalman Filter dynamic hedge ratio for pairs (e.g. BTC/ETH).
    State: beta (hedge ratio) — how many units of Y hedge one unit of X.
    Update equations:
      P_pred  = P + Q                         (prediction step)
      K       = P_pred * x / (x^2 * P_pred + R)  (Kalman gain)
      beta    = beta + K * (y - beta * x)     (state update)
      P       = (1 - K * x) * P_pred          (covariance update)

    Returns:
      kalman_beta    : current dynamic hedge ratio
      kalman_spread  : current spread (y - beta * x)
      spread_z       : z-score of spread (if history available)
      mean_revert    : True if spread is extreme (|z| > 2.0)
    """
    state = _KALMAN_STATE.get(pair_key, {"beta": 1.0, "P": 1.0, "spread_history": []})
    beta  = state["beta"]
    P     = state["P"]
    spread_history = state.get("spread_history", [])

    if price_x <= 0 or price_y <= 0:
        return {
            "kalman_beta": beta, "kalman_spread": 0.0,
            "spread_z": 0.0, "mean_revert": False,
            "kalman_note": "Kalman: zero price input",
        }
    try:
        x = price_x
        y = price_y

        # Prediction step
        P_pred = P + Q

        # Kalman gain
        denom  = x * x * P_pred + R
        K      = (P_pred * x) / max(denom, 1e-12)

        # Update step
        innovation = y - beta * x
        beta       = beta + K * innovation
        P          = (1.0 - K * x) * P_pred

        # Update spread history (capped at 100 samples)
        spread = y - beta * x
        spread_history.append(spread)
        if len(spread_history) > 100:
            spread_history = spread_history[-100:]

        # Z-score of spread
        if len(spread_history) >= 10:
            mu_s  = sum(spread_history) / len(spread_history)
            std_s = math.sqrt(sum((s - mu_s)**2 for s in spread_history) / max(len(spread_history)-1, 1)) or 1e-9
            spread_z = round((spread - mu_s) / std_s, 3)
        else:
            spread_z = 0.0

        mean_revert = abs(spread_z) > 2.0

        # Persist state
        _KALMAN_STATE[pair_key] = {"beta": beta, "P": P, "spread_history": spread_history}

        return {
            "kalman_beta":    round(beta, 6),
            "kalman_spread":  round(spread, 6),
            "kalman_gain":    round(K, 6),
            "spread_z":       spread_z,
            "mean_revert":    mean_revert,
            "kalman_note": (
                f"Kalman β={beta:.4f} spread={spread:.4f} Z={spread_z:.2f} "
                f"{'⚠️ MEAN REVERT SIGNAL' if mean_revert else '✅ Pair tracking'}"
            ),
        }
    except Exception as e:
        return {
            "kalman_beta": 1.0, "kalman_spread": 0.0,
            "spread_z": 0.0, "mean_revert": False,
            "kalman_note": f"Kalman error: {e}",
        }


# ── [v8.1-P03] Fear & Greed Index (#41) ─────────────────────
# Research: alternative.me/fng/ — composite crypto sentiment index.
# Extreme Fear (<20) → contrarian buy. Extreme Greed (>80) → contrarian sell.
_FEAR_GREED_CACHE: Dict = {"value": None, "label": None, "ts": 0.0}
_FEAR_GREED_TTL   = 3600.0   # 1-hour TTL — index updates once daily

async def fetch_fear_greed_index(session: aiohttp.ClientSession) -> Dict:
    """
    [v8.1-P03] Fetch Crypto Fear & Greed Index from alternative.me.
    Returns value (0-100), label, and contrarian signal.
    Cached 1 hour — index only updates once per day.

    Signals:
      0–24   → Extreme Fear   → contrarian BULLISH (oversold crowd)
      25–44  → Fear           → mildly BULLISH
      45–55  → Neutral        → no bias
      56–75  → Greed          → mildly BEARISH
      76–100 → Extreme Greed  → contrarian BEARISH (overbought crowd)
    """
    now = time.time()
    if _FEAR_GREED_CACHE["value"] is not None and (now - _FEAR_GREED_CACHE["ts"]) < _FEAR_GREED_TTL:
        cached = _FEAR_GREED_CACHE
        return {
            "fg_value":   cached["value"],
            "fg_label":   cached["label"],
            "fg_signal":  cached["signal"],
            "fg_conf_mod": cached["conf_mod"],
            "fg_note":    cached["note"],
            "fg_source":  "CACHE",
        }
    url = "https://api.alternative.me/fng/?limit=1&format=json"
    try:
        async with session.get(url, timeout=aiohttp.ClientTimeout(total=5)) as r:
            if r.status == 200:
                raw  = await r.json(content_type=None)
                data = raw.get("data", [{}])[0]
                val  = int(data.get("value", 50))
                lbl  = data.get("value_classification", "Neutral")

                if val <= 24:
                    signal, conf_mod = "EXTREME_FEAR",   1.08   # contrarian bull
                    note = f"😱 F&G={val} EXTREME FEAR — contrarian BULLISH signal"
                elif val <= 44:
                    signal, conf_mod = "FEAR",           1.04
                    note = f"😟 F&G={val} FEAR — mild bullish contrarian"
                elif val <= 55:
                    signal, conf_mod = "NEUTRAL",        1.0
                    note = f"😐 F&G={val} NEUTRAL — no sentiment bias"
                elif val <= 75:
                    signal, conf_mod = "GREED",          0.96
                    note = f"😏 F&G={val} GREED — mild bearish contrarian"
                else:
                    signal, conf_mod = "EXTREME_GREED",  0.90   # contrarian bear
                    note = f"🤑 F&G={val} EXTREME GREED — contrarian BEARISH signal"

                _FEAR_GREED_CACHE.update({
                    "value": val, "label": lbl, "signal": signal,
                    "conf_mod": conf_mod, "note": note, "ts": now,
                })
                return {
                    "fg_value": val, "fg_label": lbl, "fg_signal": signal,
                    "fg_conf_mod": conf_mod, "fg_note": note, "fg_source": "LIVE",
                }
    except Exception as e:
        log.debug(f"[FG] Fear & Greed fetch failed: {e}")
    # Fallback: neutral
    return {
        "fg_value": 50, "fg_label": "Neutral", "fg_signal": "NEUTRAL",
        "fg_conf_mod": 1.0, "fg_note": "F&G: API unavailable — neutral assumed",
        "fg_source": "FALLBACK",
    }


# ── [v8.1-P04] Deribit Options P/C Ratio (#11) ──────────────
# Research: Easley, O'Hara & Srinivas (1998) — options flow contains
# directional information. P/C > 1.5 = bearish hedging; < 0.6 = bullish.
_DERIBIT_PC_CACHE: Dict[str, Tuple] = {}   # symbol → (pc_ratio, ts)
_DERIBIT_PC_TTL   = 300.0   # 5-min TTL
_DERIBIT_PC_MAX   = 50      # max unique symbols (BTC/ETH/SOL etc — small set)

async def fetch_deribit_pc_ratio(session: aiohttp.ClientSession, symbol: str = "BTC") -> Dict:
    """
    [v8.1-P04] Fetch Put/Call open interest ratio from Deribit public API.
    Deribit endpoint: /api/v2/public/get_book_summary_by_currency
    Uses open interest of all active puts vs calls for the currency.

    P/C > 1.5  → Extreme put buying → bearish hedging → contrarian BULLISH
    P/C 1.0–1.5→ Elevated puts → mild bearish
    P/C 0.6–1.0→ Normal range → neutral
    P/C < 0.6  → Extreme call buying → speculative greed → contrarian BEARISH
    """
    base = symbol.upper().replace("USDT", "").replace("PERP", "")
    # Only meaningful for BTC and ETH on Deribit
    if base not in ("BTC", "ETH"):
        return {
            "pc_ratio": 1.0, "pc_signal": "NEUTRAL", "pc_conf_mod": 1.0,
            "pc_note": f"P/C ratio: {base} not available on Deribit — NEUTRAL",
            "pc_source": "N/A",
        }
    key = base
    cached = _DERIBIT_PC_CACHE.get(key)
    if cached and (time.time() - cached[1]) < _DERIBIT_PC_TTL:
        return cached[0]

    url = (f"https://www.deribit.com/api/v2/public/get_book_summary_by_currency"
           f"?currency={base}&kind=option")
    try:
        async with session.get(url, timeout=aiohttp.ClientTimeout(total=6)) as r:
            if r.status == 200:
                raw     = await r.json(content_type=None)
                result  = raw.get("result", [])
                put_oi  = 0.0
                call_oi = 0.0
                for contract in result:
                    inst = contract.get("instrument_name", "")
                    oi   = float(contract.get("open_interest", 0) or 0)
                    if "-P" in inst:
                        put_oi  += oi
                    elif "-C" in inst:
                        call_oi += oi

                if call_oi <= 0:
                    raise ValueError("Zero call OI")

                pc_ratio = round(put_oi / call_oi, 4)

                if pc_ratio > 1.5:
                    signal, conf_mod = "EXTREME_PUTS",  1.06   # heavy hedging = contrarian bull
                    note = f"📉 P/C={pc_ratio:.2f} EXTREME PUTS — institutional hedging, contrarian BULLISH"
                elif pc_ratio > 1.0:
                    signal, conf_mod = "ELEVATED_PUTS", 1.02
                    note = f"📊 P/C={pc_ratio:.2f} ELEVATED PUTS — mild bearish sentiment"
                elif pc_ratio > 0.6:
                    signal, conf_mod = "NEUTRAL",       1.0
                    note = f"📊 P/C={pc_ratio:.2f} NEUTRAL — balanced options flow"
                else:
                    signal, conf_mod = "EXTREME_CALLS", 0.94   # call frenzy = contrarian bear
                    note = f"📈 P/C={pc_ratio:.2f} EXTREME CALLS — speculative frenzy, contrarian BEARISH"

                out = {
                    "pc_ratio": pc_ratio, "pc_signal": signal,
                    "pc_conf_mod": conf_mod, "pc_note": note,
                    "pc_put_oi": round(put_oi, 2), "pc_call_oi": round(call_oi, 2),
                    "pc_source": "DERIBIT_LIVE",
                }
                _dpc_now = time.time()
                if len(_DERIBIT_PC_CACHE) >= _DERIBIT_PC_MAX:
                    expired_dk = [k for k, v in _DERIBIT_PC_CACHE.items() if (_dpc_now - v[1]) >= _DERIBIT_PC_TTL]
                    for k in expired_dk:
                        del _DERIBIT_PC_CACHE[k]
                    if len(_DERIBIT_PC_CACHE) >= _DERIBIT_PC_MAX:
                        oldest_dk = sorted(_DERIBIT_PC_CACHE, key=lambda k: _DERIBIT_PC_CACHE[k][1])
                        for k in oldest_dk[:len(_DERIBIT_PC_CACHE) - _DERIBIT_PC_MAX // 2]:
                            del _DERIBIT_PC_CACHE[k]
                _DERIBIT_PC_CACHE[key] = (out, _dpc_now)
                return out
    except Exception as e:
        log.debug(f"[PC_RATIO] Deribit P/C fetch failed for {base}: {e}")
    return {
        "pc_ratio": 1.0, "pc_signal": "NEUTRAL", "pc_conf_mod": 1.0,
        "pc_note": "P/C ratio: Deribit unavailable — neutral assumed",
        "pc_source": "FALLBACK",
    }


# ── [v8.1-P05] Short Squeeze Probability (#26) ───────────────
# Research: Asquith et al. (2005) — heavily shorted assets prone to squeezes.
# Crypto equivalent: extreme negative funding + rising OI + price holding up.
def compute_short_squeeze_probability(
    funding_rate: float,
    funding_zscore: float,
    oi_roc: float,
    price_change_pct: float,
    cvd_slope: float,
) -> Dict:
    """
    [v8.1-P05] Short Squeeze Probability Score (0–100).
    Conditions for squeeze setup:
      1. Funding rate NEGATIVE (shorts paying) or strongly negative Z
      2. OI ROC rising (new shorts being added into move)
      3. Price NOT falling (shorts caught in trapped position)
      4. CVD slope positive (underlying buy flow despite negative funding)
      5. Funding Z < -1.5 (crowded shorts — validated by z-score history)

    Score ≥ 70 = HIGH SQUEEZE RISK
    Score 40–69 = MODERATE SQUEEZE WATCH
    Score < 40 = LOW / NEUTRAL
    """
    score = 0
    triggers = []

    # Signal 1: Negative funding (shorts paying)
    if funding_rate < -0.0001:
        score += 25
        triggers.append(f"Neg funding={funding_rate:.5f}")
    elif funding_rate < 0:
        score += 12
        triggers.append(f"Slightly neg funding={funding_rate:.5f}")

    # Signal 2: Crowded shorts by Z-score
    if funding_zscore < -1.5:
        score += 20
        triggers.append(f"Z={funding_zscore:.2f} CROWDED_SHORT")
    elif funding_zscore < -1.0:
        score += 10
        triggers.append(f"Z={funding_zscore:.2f} ELEVATED_SHORT")

    # Signal 3: OI rising (new short positions building)
    if oi_roc > 3.0:
        score += 20
        triggers.append(f"OI ROC +{oi_roc:.1f}% (new shorts)")
    elif oi_roc > 1.0:
        score += 10
        triggers.append(f"OI ROC +{oi_roc:.1f}%")

    # Signal 4: Price NOT falling (shorts not getting paid)
    if price_change_pct > 0:
        score += 20
        triggers.append(f"Price +{price_change_pct:.2f}% (shorts trapped)")
    elif price_change_pct > -0.5:
        score += 10
        triggers.append(f"Price flat (squeeze building)")

    # Signal 5: CVD slope positive (covert buy flow)
    if cvd_slope > 0:
        score += 15
        triggers.append("CVD slope+ (hidden buy pressure)")

    score = min(100, score)
    if score >= 70:
        level, conf_mod = "HIGH",     1.08   # squeeze likely — boost bull confidence
    elif score >= 40:
        level, conf_mod = "MODERATE", 1.03
    else:
        level, conf_mod = "LOW",      1.0

    return {
        "squeeze_prob":     score,
        "squeeze_level":    level,
        "squeeze_conf_mod": conf_mod,
        "squeeze_triggers": triggers,
        "squeeze_note": (
            f"Squeeze prob={score}/100 [{level}]"
            f"{' — ⚠️ SHORT SQUEEZE SETUP: ' + ', '.join(triggers[:2]) if score >= 40 else ' — ✅ No squeeze signal'}"
        ),
    }


# ── [v8.1-P06] Disposition Effect Score (#52) ────────────────
# Research: Shefrin & Statman (1985) — investors sell winners early,
# hold losers long. Flip side: winner continuation more persistent.
# Crypto application: winners in last 30 bars should continue trending
# because natural profit-taking is delayed by loss-aversion anchoring.
def compute_disposition_effect_score(
    closes: List[float],
    lookback: int = 30,
) -> Dict:
    """
    [v8.1-P06] Disposition Effect Score.
    Measures unrealised gain/loss distribution in the recent window.
    High proportion of bars in profit (above entry proxy) → delayed sell
    pressure → continuation bias.

    Method:
      - Entry proxy = VWAP of the lookback window (cost basis estimate)
      - Bars above VWAP = holders in profit (prone to early exit = overhang)
      - Bars below VWAP = holders at loss (prone to hold = less selling)
      - Disposition ratio = profit_bars / total_bars
      - Ratio > 0.65: many holders in profit → overhead supply risk
      - Ratio < 0.35: most holders at loss → loss-aversion hold → support
    """
    n = min(lookback, len(closes))
    if n < 5:
        return {
            "disp_ratio": 0.5, "disp_signal": "NEUTRAL",
            "disp_conf_mod": 1.0, "disp_note": "Disposition: insufficient data",
        }
    window = closes[-n:]
    vwap_proxy = sum(window) / n   # simple mean as cost-basis proxy
    profit_bars = sum(1 for c in window if c > vwap_proxy)
    disp_ratio  = round(profit_bars / n, 4)

    if disp_ratio > 0.70:
        signal, conf_mod = "OVERHEAD_SUPPLY", 0.94   # crowded profits = selling overhang
        note = f"Disp={disp_ratio:.2f} → OVERHEAD SUPPLY — {profit_bars}/{n} bars in profit, sell pressure building"
    elif disp_ratio > 0.55:
        signal, conf_mod = "MILD_SUPPLY", 0.97
        note = f"Disp={disp_ratio:.2f} → mild supply — moderate profit-taking risk"
    elif disp_ratio > 0.40:
        signal, conf_mod = "NEUTRAL", 1.0
        note = f"Disp={disp_ratio:.2f} → NEUTRAL — balanced profit/loss"
    elif disp_ratio > 0.25:
        signal, conf_mod = "LOSS_AVERSION_HOLD", 1.04  # losers holding = less supply
        note = f"Disp={disp_ratio:.2f} → LOSS AVERSION HOLD — {n-profit_bars}/{n} bars at loss, holding bias → continuation support"
    else:
        signal, conf_mod = "DEEP_UNDERWATER", 1.06
        note = f"Disp={disp_ratio:.2f} → DEEPLY UNDERWATER — loss-aversion maximum, capitulation risk, but support if held"

    return {
        "disp_ratio":    disp_ratio,
        "disp_signal":   signal,
        "disp_conf_mod": conf_mod,
        "profit_bars":   profit_bars,
        "total_bars":    n,
        "vwap_proxy":    round(vwap_proxy, 8),
        "disp_note":     note,
    }


# ── [v8.1-P07] Token Velocity (#65) ─────────────────────────
# Research: INET (2018) — high token transfer velocity precedes price moves.
# Abnormal velocity spikes can precede pump-and-dump patterns.
# Proxy: 24h volume / market cap (turnover ratio) as velocity estimate.
def compute_token_velocity(
    price: float,
    volume_24h: float,
    circulating_supply: float,
    symbol: str = "BTC",
) -> Dict:
    """
    [v8.1-P07] Token Velocity = daily_volume / market_cap.
    High velocity (>0.10 = 10%/day turnover) = active trading, potential pump.
    Very high velocity (>0.25) = wash trading risk or pump-and-dump signal.
    Low velocity (<0.01) = illiquid / accumulation / dormant.

    Uses _CIRCULATING_SUPPLY dict for per-symbol supply accuracy.
    """
    base = symbol.upper().replace("USDT", "").replace("PERP", "").replace("BUSD", "")
    supply_override = _CIRCULATING_SUPPLY.get(base, circulating_supply)
    if supply_override <= 0 or price <= 0:
        return {
            "token_velocity": 0.0, "velocity_signal": "NEUTRAL",
            "velocity_note": "Token velocity: insufficient data",
        }
    market_cap = price * supply_override
    if market_cap <= 0:
        return {
            "token_velocity": 0.0, "velocity_signal": "NEUTRAL",
            "velocity_note": "Token velocity: zero market cap",
        }
    velocity = round(volume_24h / market_cap, 6)

    if velocity > 0.25:
        signal = "VERY_HIGH"
        note   = f"⚠️ Token velocity={velocity:.4f} VERY HIGH — wash trading or pump risk"
    elif velocity > 0.10:
        signal = "HIGH"
        note   = f"⚡ Token velocity={velocity:.4f} HIGH — active turnover, momentum confirmed"
    elif velocity > 0.03:
        signal = "NORMAL"
        note   = f"✅ Token velocity={velocity:.4f} NORMAL — healthy trading activity"
    elif velocity > 0.005:
        signal = "LOW"
        note   = f"📉 Token velocity={velocity:.4f} LOW — thin trading, liquidity caution"
    else:
        signal = "DORMANT"
        note   = f"😴 Token velocity={velocity:.4f} DORMANT — accumulation or illiquid"

    # Confidence modifier: very high velocity (pump) or dormant both reduce conf
    conf_mod = (0.92 if signal == "VERY_HIGH" else
                1.05 if signal == "HIGH" else
                1.0  if signal == "NORMAL" else
                0.97 if signal == "LOW" else
                0.93)

    return {
        "token_velocity":    velocity,
        "velocity_signal":   signal,
        "velocity_conf_mod": conf_mod,
        "velocity_note":     note,
        "market_cap_proxy":  round(market_cap, 2),
    }


# ── [v8.1-P08] stETH Peg Deviation (#76) ────────────────────
# Research: LSD peg deviations > 0.3% precede sharp ETH price moves.
# stETH/ETH ratio from Curve pool price is the signal.
_STETH_PEG_CACHE: Dict = {"ratio": None, "ts": 0.0}
_STETH_PEG_TTL   = 300.0   # 5-min TTL

async def fetch_steth_peg_deviation(session: aiohttp.ClientSession) -> Dict:
    """
    [v8.1-P08] Fetch stETH/ETH peg ratio from Binance (stETH/ETH pair).
    If unavailable, falls back to CoinGecko price comparison.

    Peg deviation interpretation:
      stETH/ETH > 1.003  → premium (unusual, ignore)
      stETH/ETH 0.997–1.003 → on peg → neutral
      stETH/ETH 0.990–0.997 → mild depeg → caution on ETH
      stETH/ETH < 0.990     → severe depeg → risk-off ETH signal
    """
    now = time.time()
    if _STETH_PEG_CACHE["ratio"] is not None and (now - _STETH_PEG_CACHE["ts"]) < _STETH_PEG_TTL:
        c = _STETH_PEG_CACHE
        return {"steth_ratio": c["ratio"], "steth_signal": c["signal"],
                "steth_note": c["note"], "steth_source": "CACHE"}

    ratio = None
    # Attempt 1: Binance STETHETH price
    try:
        url = "https://api.binance.com/api/v3/ticker/price?symbol=STETHETH"
        async with session.get(url, timeout=aiohttp.ClientTimeout(total=4)) as r:
            if r.status == 200:
                data  = await r.json(content_type=None)
                ratio = float(data.get("price", 0) or 0)
    except Exception as e:
        log.debug(f"[STETH] Binance fetch failed: {e}")

    # Attempt 2: CoinGecko simple price for steth vs eth
    if not ratio:
        try:
            url = ("https://api.coingecko.com/api/v3/simple/price"
                   "?ids=staked-ether,ethereum&vs_currencies=usd")
            async with session.get(url, timeout=aiohttp.ClientTimeout(total=5)) as r:
                if r.status == 200:
                    data    = await r.json(content_type=None)
                    steth_p = float(data.get("staked-ether", {}).get("usd", 0) or 0)
                    eth_p   = float(data.get("ethereum",     {}).get("usd", 1) or 1)
                    if eth_p > 0 and steth_p > 0:
                        ratio = round(steth_p / eth_p, 6)
        except Exception as e:
            log.debug(f"[STETH] CoinGecko fetch failed: {e}")

    if not ratio:
        return {
            "steth_ratio": 1.0, "steth_signal": "NEUTRAL",
            "steth_note": "stETH peg: data unavailable — neutral assumed",
            "steth_source": "FALLBACK",
        }

    deviation = round(1.0 - ratio, 6)   # positive = discount

    if ratio < 0.990:
        signal, conf_mod = "SEVERE_DEPEG", 0.85
        note = f"🚨 stETH/ETH={ratio:.4f} SEVERE DEPEG ({deviation*100:.2f}% discount) — ETH RISK-OFF"
    elif ratio < 0.997:
        signal, conf_mod = "MILD_DEPEG",   0.94
        note = f"⚠️ stETH/ETH={ratio:.4f} MILD DEPEG ({deviation*100:.2f}% discount) — ETH caution"
    elif ratio > 1.003:
        signal, conf_mod = "PREMIUM",      0.98   # unusual premium
        note = f"📈 stETH/ETH={ratio:.4f} PREMIUM — unusual, monitor for arb unwind"
    else:
        signal, conf_mod = "ON_PEG",       1.0
        note = f"✅ stETH/ETH={ratio:.4f} ON PEG — ETH LSD ecosystem stable"

    _STETH_PEG_CACHE.update({"ratio": ratio, "signal": signal, "note": note, "ts": now})
    return {
        "steth_ratio":    ratio,
        "steth_deviation": deviation,
        "steth_signal":   signal,
        "steth_conf_mod": conf_mod,
        "steth_note":     note,
        "steth_source":   "LIVE",
    }


# ── [v8.1-P09] Polymarket Crypto Probability (#67) ───────────
# Research: Wolfers & Zitzewitz (2004) — prediction markets aggregate
# information efficiently. Polymarket crypto market probabilities are
# well-calibrated and useful as exogenous event probability inputs.
_POLYMARKET_CACHE: Dict = {"markets": [], "ts": 0.0}
_POLYMARKET_TTL   = 600.0   # 10-min TTL

async def fetch_polymarket_crypto_prob(session: aiohttp.ClientSession,
                                        symbol: str = "BTC") -> Dict:
    """
    [v8.1-P09] Fetch top crypto-related Polymarket prediction market probabilities.
    Uses Polymarket Gamma API (public, no auth required).
    Filters for active markets mentioning the asset (BTC/ETH/crypto).

    Returns:
      poly_markets: list of {title, yes_price, slug} — top 3 relevant
      poly_bull_prob: highest YES probability for bullish outcome
      poly_bear_prob: highest YES probability for bearish outcome
      poly_signal: BULLISH / BEARISH / NEUTRAL
    """
    now = time.time()
    base = symbol.upper().replace("USDT","").replace("PERP","")
    if (now - _POLYMARKET_CACHE["ts"]) < _POLYMARKET_TTL and _POLYMARKET_CACHE["markets"]:
        cached = _POLYMARKET_CACHE
        return _build_polymarket_result(cached["markets"], base)

    url = ("https://gamma-api.polymarket.com/markets"
           "?active=true&closed=false&tag_id=8&limit=20")  # tag_id=8 = crypto
    try:
        async with session.get(url, timeout=aiohttp.ClientTimeout(total=6)) as r:
            if r.status == 200:
                raw = await r.json(content_type=None)
                markets = []
                for m in (raw if isinstance(raw, list) else raw.get("markets", [])):
                    title     = m.get("question", "") or m.get("title", "")
                    yes_price = float(m.get("outcomePrices", [0.5])[0] if
                                      isinstance(m.get("outcomePrices"), list) else 0.5)
                    slug      = m.get("slug", "")
                    markets.append({"title": title, "yes_price": yes_price, "slug": slug})
                _POLYMARKET_CACHE.update({"markets": markets, "ts": now})
                return _build_polymarket_result(markets, base)
    except Exception as e:
        log.debug(f"[POLYMARKET] Fetch failed: {e}")
    return {
        "poly_markets": [], "poly_bull_prob": 0.5, "poly_bear_prob": 0.5,
        "poly_signal": "NEUTRAL", "poly_conf_mod": 1.0,
        "poly_note": "Polymarket: unavailable — neutral assumed",
        "poly_source": "FALLBACK",
    }

def _build_polymarket_result(markets: list, base: str) -> Dict:
    """Build Polymarket result dict from cached/live market list."""
    # Filter markets relevant to this asset or general crypto
    keywords = [base.lower(), "crypto", "bitcoin", "ethereum", "btc", "eth"]
    relevant = [m for m in markets
                if any(kw in m.get("title","").lower() for kw in keywords)]
    relevant = relevant[:5]   # cap at 5

    bull_probs = [m["yes_price"] for m in relevant
                  if any(w in m.get("title","").lower()
                         for w in ["above", "reach", "hit", "over", "higher", "bull"])]
    bear_probs = [m["yes_price"] for m in relevant
                  if any(w in m.get("title","").lower()
                         for w in ["below", "fall", "drop", "under", "lower", "bear"])]

    poly_bull = round(max(bull_probs) if bull_probs else 0.5, 4)
    poly_bear = round(max(bear_probs) if bear_probs else 0.5, 4)

    if poly_bull > 0.65:
        signal, conf_mod = "BULLISH",  1.04
    elif poly_bear > 0.65:
        signal, conf_mod = "BEARISH",  0.96
    else:
        signal, conf_mod = "NEUTRAL",  1.0

    note = (f"Polymarket: {len(relevant)} {base} markets found | "
            f"Bull={poly_bull:.1%} Bear={poly_bear:.1%} → {signal}")

    return {
        "poly_markets":   relevant,
        "poly_bull_prob": poly_bull,
        "poly_bear_prob": poly_bear,
        "poly_signal":    signal,
        "poly_conf_mod":  conf_mod,
        "poly_note":      note,
        "poly_source":    "LIVE",
    }


# ── [v8.1-P10] ARIMA(1,0,1) Mean Equation + GARCH(1,1) (#44) ─
# Research: Engle & Granger (1987) ARIMA mean + GARCH variance hybrid.
# ARIMA-GARCH captures both autocorrelation in returns AND volatility clustering.
# This wraps the existing compute_garch_variance() with an AR(1) mean equation.
def compute_arima_garch_forecast(
    closes:    List[float],
    symbol:    str  = "DEFAULT",
    ar_order:  int  = 1,   # AR(1) mean equation
    ma_order:  int  = 1,   # MA(1) mean equation
    omega:     float = 1e-6,
    alpha:     float = 0.10,
    beta:      float = 0.85,
    horizon:   int  = 1,   # forecast bars ahead
) -> Dict:
    """
    [v8.1-P10] ARIMA(1,0,1)-GARCH(1,1) hybrid forecast.
    Step 1: AR(1) mean equation — mu_t = phi1 * r_{t-1} + theta1 * e_{t-1}
    Step 2: GARCH(1,1) variance equation on residuals from step 1
    Step 3: 1-step-ahead point forecast + confidence interval

    Returns:
      arima_return_forecast  : predicted next-bar log return
      arima_price_forecast   : implied next-bar price level
      arima_ci_upper         : forecast + 1.96 * garch_vol (95% CI upper)
      arima_ci_lower         : forecast - 1.96 * garch_vol (95% CI lower)
      arima_direction        : BULLISH / BEARISH / NEUTRAL
      arima_confidence       : forecast confidence (higher vol = lower conf)
    """
    min_bars = max(ar_order + ma_order + 5, 30)
    default = {
        "arima_return_forecast": 0.0, "arima_price_forecast": closes[-1] if closes else 0.0,
        "arima_ci_upper": 0.0, "arima_ci_lower": 0.0,
        "arima_direction": "NEUTRAL", "arima_confidence": 0.5,
        "arima_garch_vol": 0.15, "arima_note": "ARIMA-GARCH: insufficient data",
    }
    if len(closes) < min_bars:
        return default
    try:
        # Step 1: Compute log returns
        returns = [
            math.log(closes[i] / closes[i-1])
            for i in range(1, len(closes))
            if closes[i-1] > 0 and closes[i] > 0
        ]
        if len(returns) < min_bars:
            return default

        n   = len(returns)
        mu  = sum(returns) / n

        # AR(1) coefficient — OLS estimate: phi1 = cov(r_t, r_{t-1}) / var(r_{t-1})
        pairs = [(returns[i], returns[i-1]) for i in range(1, n)]
        mean_y = sum(p[0] for p in pairs) / len(pairs)
        mean_x = sum(p[1] for p in pairs) / len(pairs)
        cov_xy = sum((p[0]-mean_y)*(p[1]-mean_x) for p in pairs) / len(pairs)
        var_x  = sum((p[1]-mean_x)**2 for p in pairs) / len(pairs)
        phi1   = cov_xy / max(var_x, 1e-12)
        phi1   = max(-0.99, min(0.99, phi1))   # stationarity constraint

        # MA(1) residuals — one pass
        residuals = [0.0]
        for i in range(1, n):
            predicted  = mu + phi1 * returns[i-1]
            residuals.append(returns[i] - predicted)
        theta1 = 0.0
        if len(residuals) > 2:
            pairs_ma   = [(residuals[i], residuals[i-1]) for i in range(2, len(residuals))]
            cov_ma     = sum(p[0]*p[1] for p in pairs_ma) / max(len(pairs_ma), 1)
            var_ma     = sum(p[1]**2 for p in pairs_ma) / max(len(pairs_ma), 1)
            theta1     = cov_ma / max(var_ma, 1e-12)
            theta1     = max(-0.99, min(0.99, theta1))   # invertibility constraint

        # Step 2: 1-step-ahead ARIMA mean forecast
        last_return    = returns[-1]
        last_residual  = residuals[-1] if residuals else 0.0
        forecast_return = mu + phi1 * last_return + theta1 * last_residual

        # Step 3: GARCH(1,1) variance on ARIMA residuals (reuse existing GARCH engine)
        garch_data = compute_garch_variance(closes, symbol, omega, alpha, beta)
        garch_vol  = garch_data.get("garch_vol", 15.0) / 100.0   # annualised → daily proxy
        daily_vol  = garch_vol / math.sqrt(252)   # convert annual → daily

        # 95% confidence interval
        ci_half     = 1.96 * daily_vol
        price_now   = closes[-1]
        price_fcast = round(price_now * math.exp(forecast_return), 8)
        ci_upper    = round(price_now * math.exp(forecast_return + ci_half), 8)
        ci_lower    = round(price_now * math.exp(forecast_return - ci_half), 8)

        # Direction and confidence
        if forecast_return > daily_vol * 0.3:
            direction = "BULLISH"
        elif forecast_return < -daily_vol * 0.3:
            direction = "BEARISH"
        else:
            direction = "NEUTRAL"

        # Forecast confidence: lower when GARCH vol is high (wider CI = less certainty)
        confidence = round(max(0.0, min(1.0, 1.0 - min(daily_vol * 5, 0.8))), 4)

        return {
            "arima_return_forecast": round(forecast_return, 6),
            "arima_price_forecast":  price_fcast,
            "arima_ci_upper":        ci_upper,
            "arima_ci_lower":        ci_lower,
            "arima_direction":       direction,
            "arima_confidence":      confidence,
            "arima_phi1":            round(phi1, 4),
            "arima_theta1":          round(theta1, 4),
            "arima_garch_vol":       round(daily_vol * 100, 4),
            "arima_note": (
                f"ARIMA(1,0,1)-GARCH: {direction} | forecast={forecast_return*100:+.4f}% | "
                f"CI=[{ci_lower:.4f},{ci_upper:.4f}] | conf={confidence:.2f}"
            ),
        }
    except Exception as e:
        return {**default, "arima_note": f"ARIMA-GARCH error: {e}"}


