# ── [v8.2-P15] Google Trends Proxy — CoinGecko Trending (#18) ─
# Research: Da, Engelberg & Gao (2011) — abnormal search volume
# predicts price increases followed by reversals. Proxy: CoinGecko
# trending endpoint captures real-time retail attention spikes.
_TRENDING_CACHE: Dict = {"coins": [], "ts": 0.0}
_TRENDING_TTL   = 600.0   # 10-min TTL

async def fetch_google_trends_proxy(
    session: aiohttp.ClientSession, symbol: str = "BTC"
) -> Dict:
    """
    [v8.2-P15] Retail attention signal via CoinGecko trending endpoint.
    CoinGecko /trending returns top-7 coins by search volume in last 24h.
    If the asset is in top-7 trending → abnormal retail attention spike.

    Signal logic (Da et al. 2011):
      In trending top-7 → retail FOMO active → short-term pump likely,
      followed by mean-reversion (contrarian signal at TP targets).
      Score = position in trending list (1=top → highest attention).
    """
    now  = time.time()
    base = symbol.upper().replace("USDT","").replace("PERP","")
    if (now - _TRENDING_CACHE["ts"]) < _TRENDING_TTL and _TRENDING_CACHE["coins"]:
        coins = _TRENDING_CACHE["coins"]
    else:
        try:
            url = "https://api.coingecko.com/api/v3/search/trending"
            async with session.get(url, timeout=aiohttp.ClientTimeout(total=5)) as r:
                if r.status == 200:
                    raw   = await r.json(content_type=None)
                    coins = [
                        c.get("item", {}).get("symbol","").upper()
                        for c in raw.get("coins", [])
                    ]
                    _TRENDING_CACHE.update({"coins": coins, "ts": now})
                else:
                    coins = []
        except Exception as e:
            log.debug(f"[TRENDS] CoinGecko trending failed: {e}")
            coins = []

    if not coins:
        return {
            "trends_rank": 0, "trends_trending": False, "trends_signal": "NEUTRAL",
            "trends_conf_mod": 1.0, "trends_note": "Trends: data unavailable — neutral",
            "trends_source": "FALLBACK",
        }

    try:
        rank = coins.index(base) + 1   # 1-indexed; 0 = not found
        trending = True
    except ValueError:
        rank     = 0
        trending = False

    if trending and rank <= 3:
        signal, conf_mod = "HOT_TRENDING", 1.06   # top-3 → strong retail FOMO
        note = f"🔥 Trends rank=#{rank}/7 — TOP TRENDING, retail FOMO active"
    elif trending:
        signal, conf_mod = "TRENDING",     1.03
        note = f"📈 Trends rank=#{rank}/7 — trending, retail attention elevated"
    else:
        signal, conf_mod = "NEUTRAL",      1.0
        note = f"✅ {base} not in trending top-7 — normal retail attention"

    return {
        "trends_rank":     rank,
        "trends_trending": trending,
        "trends_signal":   signal,
        "trends_conf_mod": conf_mod,
        "trends_note":     note,
        "trends_coins":    coins,
        "trends_source":   "COINGECKO_LIVE",
    }


# ── [v8.2-P16] DCA Position Builder (#20) ────────────────────
# Research: Statman (1995) — DCA reduces sequence-of-returns risk.
# Splits entry zone into N tranches. Each tranche has its own
# price, size, and priority. Tier-1 at zone bottom, Tier-N at top.
def compute_dca_position_plan(
    entry_low:        float,
    entry_high:       float,
    bias:             str,
    account_risk_pct: float = 0.01,    # 1% account risk total
    account_size_usd: float = 10000.0,
    num_tranches:     int   = 3,
    sl_price:         float = 0.0,
) -> Dict:
    """
    [v8.2-P16] DCA Position Builder — split entry into N tranches.
    Tranche sizing: largest at zone edge (best price), smaller toward midpoint.
    Geometric sizing: tranche_i = total_risk * weight_i / sum(weights)
    Weight scheme: [0.50, 0.30, 0.20] for 3 tranches (bottom-heavy).

    Returns tranche levels, sizes, and cumulative position plan.
    """
    if entry_low <= 0 or entry_high <= entry_low or num_tranches < 1:
        return {
            "dca_tranches": [], "dca_avg_entry": 0.0, "dca_total_risk_usd": 0.0,
            "dca_note": "DCA: invalid entry zone parameters",
        }
    n = min(num_tranches, 5)
    zone_range = entry_high - entry_low

    # Tranche price levels — evenly spaced across zone
    # Bullish: start from bottom (best price) → top
    # Bearish: start from top (best price) → bottom
    if bias == "BULLISH":
        prices = [round(entry_low + (zone_range * i / max(n - 1, 1)), 8)
                  for i in range(n)]
    else:
        prices = [round(entry_high - (zone_range * i / max(n - 1, 1)), 8)
                  for i in range(n)]

    # Weight scheme: heaviest at best price
    raw_weights = [1.0 / (i + 1) for i in range(n)]
    total_w     = sum(raw_weights)
    weights     = [round(w / total_w, 4) for w in raw_weights]

    total_risk_usd = account_size_usd * account_risk_pct

    tranches = []
    for i in range(n):
        risk_i      = round(total_risk_usd * weights[i], 2)
        # Position size in USD: risk / (entry - SL) * entry  (if SL known)
        if sl_price > 0 and prices[i] > 0:
            risk_per_unit = abs(prices[i] - sl_price)
            size_usd      = round(risk_i / max(risk_per_unit / prices[i], 0.001), 2)
        else:
            size_usd = round(risk_i * 10, 2)   # 10:1 leverage proxy if no SL
        tranches.append({
            "tranche":    i + 1,
            "price":      prices[i],
            "weight":     weights[i],
            "risk_usd":   risk_i,
            "size_usd":   size_usd,
            "label":      f"T{i+1} @{prices[i]:.4f} ({weights[i]*100:.0f}%)",
        })

    avg_entry = round(sum(t["price"] * t["weight"] for t in tranches), 8)
    return {
        "dca_tranches":      tranches,
        "dca_avg_entry":     avg_entry,
        "dca_total_risk_usd": round(total_risk_usd, 2),
        "dca_num_tranches":  n,
        "dca_note": (
            f"DCA {n}-tranche plan: avg entry={avg_entry:.4f} | "
            f"total risk ${total_risk_usd:.2f} | "
            + " | ".join(t["label"] for t in tranches)
        ),
    }


# ── [v8.2-P17] Twitter/X NLP Sentiment Proxy (#21) ───────────
# Research: Bollen, Mao & Zeng (2011) — social sentiment predicts
# 1-day crypto returns. Proxy: CryptoCompare social stats API
# (free public tier) returns social volume + sentiment scores.
_SOCIAL_CACHE: Dict[str, Tuple] = {}   # symbol → (result, ts)
_SOCIAL_TTL   = 300.0   # 5-min TTL
_SOCIAL_MAX   = 150     # max unique symbols cached

async def fetch_social_sentiment_nlp(
    session: aiohttp.ClientSession, symbol: str = "BTC"
) -> Dict:
    """
    [v8.2-P17] Social sentiment NLP via CryptoCompare social stats.
    Endpoint: /data/social/coin/latest — returns social volume,
    Reddit posts, Twitter posts, sentiment scores.

    Sentiment score interpretation (0–100):
      > 70 → BULLISH sentiment consensus
      30–70 → NEUTRAL
      < 30 → BEARISH sentiment consensus

    Social volume spike (>2× 30d average) = retail attention surge.
    """
    base  = symbol.upper().replace("USDT","").replace("PERP","")
    key   = base
    cached = _SOCIAL_CACHE.get(key)
    if cached and (time.time() - cached[1]) < _SOCIAL_TTL:
        return cached[0]

    # CryptoCompare coin ID map (top assets)
    coin_ids = {
        "BTC": "1182", "ETH": "7605", "BNB": "204788", "SOL": "5033763",
        "XRP": "5031358", "ADA": "321992", "AVAX": "328074", "DOT": "412355",
        "LINK": "382943", "MATIC": "21794",
    }
    coin_id = coin_ids.get(base)

    if not coin_id:
        return {
            "social_score": 50.0, "social_signal": "NEUTRAL",
            "social_volume": 0.0, "social_conf_mod": 1.0,
            "social_note": f"Social: {base} not in social index — neutral",
            "social_source": "N/A",
        }

    url = f"https://www.cryptocompare.com/api/data/socialstats/?id={coin_id}"
    try:
        async with session.get(url, timeout=aiohttp.ClientTimeout(total=6)) as r:
            if r.status == 200:
                raw  = await r.json(content_type=None)
                data = raw.get("Data", {})
                # Reddit activity
                reddit = data.get("Reddit", {})
                reddit_posts   = float(reddit.get("posts_per_day", 0) or 0)
                reddit_comments= float(reddit.get("comments_per_day", 0) or 0)
                reddit_subs    = float(reddit.get("subscribers", 0) or 0)
                # Twitter activity
                twitter = data.get("Twitter", {})
                twitter_follow = float(twitter.get("followers", 0) or 0)
                twitter_status = float(twitter.get("statuses", 0) or 0)
                # Compose sentiment score (0-100)
                # Normalize activity signals into score
                activity_score = min(100.0,
                    (reddit_posts / max(reddit_posts + 1, 1)) * 30 +
                    (reddit_comments / max(reddit_comments + 100, 1)) * 30 +
                    (min(twitter_follow / 1e6, 1.0)) * 20 +
                    (min(twitter_status / 1e5, 1.0)) * 20
                )
                social_volume = reddit_posts + reddit_comments

                if activity_score > 65:
                    signal, conf_mod = "BULLISH_SENTIMENT",  1.04
                    note = f"📣 Social score={activity_score:.0f} HIGH — bullish sentiment consensus"
                elif activity_score > 40:
                    signal, conf_mod = "NEUTRAL",            1.0
                    note = f"💬 Social score={activity_score:.0f} NEUTRAL"
                else:
                    signal, conf_mod = "BEARISH_SENTIMENT",  0.97
                    note = f"😶 Social score={activity_score:.0f} LOW — bearish/silent sentiment"

                out = {
                    "social_score":    round(activity_score, 2),
                    "social_signal":   signal,
                    "social_volume":   social_volume,
                    "social_conf_mod": conf_mod,
                    "reddit_posts":    reddit_posts,
                    "twitter_followers": twitter_follow,
                    "social_note":     note,
                    "social_source":   "CRYPTOCOMPARE_LIVE",
                }
                _social_now = time.time()
                if len(_SOCIAL_CACHE) >= _SOCIAL_MAX:
                    expired_sk = [k for k, v in _SOCIAL_CACHE.items() if (_social_now - v[1]) >= _SOCIAL_TTL]
                    for k in expired_sk:
                        del _SOCIAL_CACHE[k]
                    if len(_SOCIAL_CACHE) >= _SOCIAL_MAX:
                        oldest_sk = sorted(_SOCIAL_CACHE, key=lambda k: _SOCIAL_CACHE[k][1])
                        for k in oldest_sk[:len(_SOCIAL_CACHE) - _SOCIAL_MAX // 2]:
                            del _SOCIAL_CACHE[k]
                _SOCIAL_CACHE[key] = (out, _social_now)
                return out
    except Exception as e:
        log.debug(f"[SOCIAL] CryptoCompare social fetch failed for {base}: {e}")

    return {
        "social_score": 50.0, "social_signal": "NEUTRAL",
        "social_volume": 0.0, "social_conf_mod": 1.0,
        "social_note": "Social NLP: API unavailable — neutral assumed",
        "social_source": "FALLBACK",
    }


# ── [v8.2-P18] IV Term Structure from GARCH (#23) ────────────
# Research: When short-dated IV > long-dated (backwardation),
# near-term risk is elevated. Proxy from GARCH short vs long vol.
def compute_iv_term_structure(
    closes:   List[float],
    symbol:   str = "DEFAULT",
    short_win: int = 10,
    long_win:  int = 60,
) -> Dict:
    """
    [v8.2-P18] IV Term Structure proxy via GARCH vol on different windows.
    Short-window GARCH vol vs long-window GARCH vol.
    If short_vol > long_vol × 1.2 → term structure INVERTED (near-term risk)
    If short_vol < long_vol × 0.8 → term structure NORMAL (low near-term risk)

    Research: vol surface backwardation precedes drawdowns >10% (VIX analogue).
    """
    if len(closes) < long_win + 5:
        return {
            "iv_short_vol": 0.15, "iv_long_vol": 0.15, "iv_ratio": 1.0,
            "iv_structure": "NORMAL", "iv_inverted": False,
            "iv_conf_mod": 1.0, "iv_note": "IV Term Structure: insufficient data",
        }
    try:
        short_garch = compute_garch_variance(closes[-short_win*3:], f"{symbol}_short")
        long_garch  = compute_garch_variance(closes,                f"{symbol}_long")
        sv  = short_garch.get("garch_vol", 15.0)   # annualised %
        lv  = long_garch.get("garch_vol",  15.0)
        ratio = round(sv / max(lv, 0.1), 4)

        if ratio > 1.4:
            structure, inverted, conf_mod = "SEVERELY_INVERTED", True,  0.88
            note = f"🚨 IV term: SEVERELY INVERTED ratio={ratio:.2f} — near-term risk EXTREME"
        elif ratio > 1.2:
            structure, inverted, conf_mod = "INVERTED",          True,  0.93
            note = f"⚠️ IV term: INVERTED ratio={ratio:.2f} — elevated near-term risk"
        elif ratio < 0.8:
            structure, inverted, conf_mod = "STEEP_NORMAL",      False, 1.04
            note = f"✅ IV term: STEEP NORMAL ratio={ratio:.2f} — calm near-term"
        else:
            structure, inverted, conf_mod = "NORMAL",            False, 1.0
            note = f"IV term: NORMAL ratio={ratio:.2f} — balanced vol structure"

        return {
            "iv_short_vol":  round(sv, 4),
            "iv_long_vol":   round(lv, 4),
            "iv_ratio":      ratio,
            "iv_structure":  structure,
            "iv_inverted":   inverted,
            "iv_conf_mod":   conf_mod,
            "iv_note":       note,
        }
    except Exception as e:
        return {
            "iv_short_vol": 0.15, "iv_long_vol": 0.15, "iv_ratio": 1.0,
            "iv_structure": "NORMAL", "iv_inverted": False,
            "iv_conf_mod": 1.0, "iv_note": f"IV term error: {e}",
        }


# ── [v8.2-P19] Fractal Market Hypothesis (#29) ───────────────
# Research: Peters (1994) — markets stable when multiple horizons active.
# Crises: long-horizon participants exit, only short-horizon remain.
class FractalMarketHypothesis:
    """
    [v8.2-P19] Fractal Market Hypothesis implementation.
    Tracks participation across 4 time horizons (scalp/intra/swing/position).
    Stability score = how many horizons are actively contributing liquidity.
    Low stability (< 2 horizons) → fragile market → reduce position size.
    """
    _HORIZON_WINDOWS = {
        "scalp":    5,
        "intraday": 20,
        "swing":    60,
        "position": 200,
    }

    def __init__(self):
        self._horizon_scores: Dict[str, float] = {h: 1.0 for h in self._HORIZON_WINDOWS}

    def evaluate(
        self,
        closes:   List[float],
        volumes:  List[float],
        atrs:     List[float],
    ) -> Dict:
        n = len(closes)
        active_horizons = []
        scores = {}
        for horizon, window in self._HORIZON_WINDOWS.items():
            if n < window + 2:
                scores[horizon] = 0.0
                continue
            sub_c   = closes[-window:]
            sub_v   = volumes[-window:] if len(volumes) >= window else []
            sub_atr = atrs[-window:]    if len(atrs)    >= window else []
            # Participation proxy: trend strength × volume consistency
            price_change = abs(sub_c[-1] - sub_c[0]) / max(sub_c[0], 1e-9)
            avg_atr  = (sum(sub_atr) / len(sub_atr)) if sub_atr else 1.0
            cur_atr  = sub_atr[-1] if sub_atr else avg_atr
            vol_cons = 1.0  # default
            if sub_v and len(sub_v) >= 5:
                avg_v   = sum(sub_v) / len(sub_v)
                nonzero = sum(1 for v in sub_v if v > avg_v * 0.3)
                vol_cons = nonzero / len(sub_v)
            participation = min(1.0, price_change / max(avg_atr / max(sub_c[0], 1e-9), 0.001)) * vol_cons
            scores[horizon] = round(participation, 4)
            if participation > 0.3:
                active_horizons.append(horizon)

        self._horizon_scores = scores
        stability = len(active_horizons)
        fmh_stable = stability >= 2
        # Stability → sizing modifier
        if stability >= 4:
            conf_mod, regime = 1.06, "FULL_PARTICIPATION"
        elif stability == 3:
            conf_mod, regime = 1.02, "BROAD_PARTICIPATION"
        elif stability == 2:
            conf_mod, regime = 1.0,  "LIMITED_PARTICIPATION"
        elif stability == 1:
            conf_mod, regime = 0.90, "FRAGILE_MARKET"
        else:
            conf_mod, regime = 0.82, "CRISIS_RISK"

        return {
            "fmh_active_horizons": active_horizons,
            "fmh_stability":       stability,
            "fmh_stable":          fmh_stable,
            "fmh_regime":          regime,
            "fmh_conf_mod":        conf_mod,
            "fmh_scores":          scores,
            "fmh_note": (
                f"FMH: {stability}/4 horizons active → {regime} "
                f"({'✅ Stable' if fmh_stable else '⚠️ Fragile'})"
            ),
        }

_FMH = FractalMarketHypothesis()


# ── [v8.2-P20] Attention-Weighted Ensemble / Transformer (#30) ─
# Research: Huang et al. (2019) — attention mechanisms outperform
# LSTMs by capturing non-local temporal dependencies.
# Implementation: scaled dot-product attention over signal feature vectors.
def compute_attention_ensemble(
    signal_scores: Dict[str, float],
    bias:          str,
) -> Dict:
    """
    [v8.2-P20] Attention-weighted signal ensemble using scaled dot-product.
    Each signal is a key-value pair. Query = current bias direction.
    Attention weight = softmax(Q·K / sqrt(d)) applied to signal values.

    This IS the attention mechanism — a single-head attention layer
    over the full signal score vector, in pure Python.

    Returns:
      attn_score       : attention-weighted consensus (0-100)
      attn_weights     : per-signal attention weight
      attn_signal      : STRONG_BULL / BULL / NEUTRAL / BEAR / STRONG_BEAR
      attn_diversity   : variance of attention weights (high = focused attention)
    """
    if not signal_scores:
        return {
            "attn_score": 50.0, "attn_signal": "NEUTRAL",
            "attn_weights": {}, "attn_diversity": 0.0,
            "attn_note": "Attention: no signal scores provided",
        }
    # Query vector: bias direction encoded as scalar
    # Bullish query = 1.0, Bearish = -1.0
    query = 1.0 if bias == "BULLISH" else -1.0

    # Keys = signal alignment scores (normalised to -1..+1 range)
    # Values = raw signal scores (0..100)
    keys   = []
    values = []
    names  = []
    for name, score in signal_scores.items():
        # Normalise score to -1..+1 alignment with direction
        v  = max(0.0, min(100.0, float(score)))
        k  = (v - 50.0) / 50.0   # -1 (full bear) to +1 (full bull)
        keys.append(k)
        values.append(v)
        names.append(name)

    if not keys:
        return {
            "attn_score": 50.0, "attn_signal": "NEUTRAL",
            "attn_weights": {}, "attn_diversity": 0.0,
            "attn_note": "Attention: empty signal set",
        }

    d   = max(len(keys), 1)
    # Scaled dot-product: attention_logit_i = (Q * K_i) / sqrt(d)
    logits = [(query * k) / math.sqrt(d) for k in keys]

    # Softmax over logits
    max_l  = max(logits)
    exp_l  = [math.exp(l - max_l) for l in logits]
    sum_e  = max(sum(exp_l), 1e-9)
    attn_w = [round(e / sum_e, 6) for e in exp_l]

    # Attention-weighted score
    weighted_score = round(sum(attn_w[i] * values[i] for i in range(d)), 4)

    # Diversity: entropy of attention weights (high = spread attention)
    entropy = -sum(w * math.log(max(w, 1e-9)) for w in attn_w)
    max_ent = math.log(d) if d > 1 else 1.0
    diversity = round(entropy / max(max_ent, 1e-9), 4)

    # Signal label
    if weighted_score >= 75:
        signal = "STRONG_BULL"
    elif weighted_score >= 60:
        signal = "BULL"
    elif weighted_score <= 25:
        signal = "STRONG_BEAR"
    elif weighted_score <= 40:
        signal = "BEAR"
    else:
        signal = "NEUTRAL"

    return {
        "attn_score":     weighted_score,
        "attn_signal":    signal,
        "attn_weights":   {names[i]: attn_w[i] for i in range(d)},
        "attn_diversity": diversity,
        "attn_note": (
            f"Attn ensemble: {signal} score={weighted_score:.1f} | "
            f"diversity={diversity:.3f} | "
            f"top signal: {names[attn_w.index(max(attn_w))]}"
        ),
    }


# ── [v8.2-P21] Round Number Attraction (#33) ─────────────────
# Research: Donaldson & Kim (1993) — disproportionate order clustering
# at round-number price levels. Effect is statistically significant
# and extremely strong in crypto (BTC $100K, $50K etc.).
def compute_round_number_attraction(price: float, atr: float) -> Dict:
    """
    [v8.2-P21] Round number attraction and repulsion model.
    Identifies nearest psychologically significant price levels.
    Levels: powers of 10, halves, quarters, and crypto-specific round numbers.

    Magnetic pull: if price within 0.5×ATR of round level = MAGNETIC zone.
    Repulsion: if price just broke through round level = momentum confirmation.
    """
    if price <= 0 or atr <= 0:
        return {
            "rn_nearest": 0.0, "rn_distance_atr": 99.0,
            "rn_magnetic": False, "rn_broken": False,
            "rn_note": "Round number: invalid price/ATR",
        }
    # Generate round number levels dynamically based on price magnitude
    magnitude = 10 ** math.floor(math.log10(price))
    candidates = set()
    for mult in [0.1, 0.25, 0.5, 0.75, 1.0, 1.25, 1.5, 2.0, 2.5, 5.0,
                 10.0, 25.0, 50.0, 100.0, 250.0, 500.0, 1000.0]:
        level = round(magnitude * mult, 8)
        if price * 0.5 < level < price * 2.0:
            candidates.add(level)
    # Also add nearest ×10, ×100, ×1000 round numbers
    for exp in range(-2, 7):
        for base_mult in [1, 2, 5]:
            level = round(base_mult * (10 ** exp), 8)
            if price * 0.5 < level < price * 2.0:
                candidates.add(level)

    if not candidates:
        return {
            "rn_nearest": 0.0, "rn_distance_atr": 99.0,
            "rn_magnetic": False, "rn_broken": False,
            "rn_levels": [], "rn_note": "No round levels in range",
        }

    # Find nearest level above and below
    levels_sorted = sorted(candidates)
    below = [l for l in levels_sorted if l <= price]
    above = [l for l in levels_sorted if l >  price]

    nearest_below = below[-1] if below else None
    nearest_above = above[0]  if above else None

    # Closest of the two
    if nearest_below and nearest_above:
        nearest = (nearest_below if abs(price - nearest_below) <= abs(price - nearest_above)
                   else nearest_above)
    elif nearest_below:
        nearest = nearest_below
    else:
        nearest = nearest_above

    distance = abs(price - nearest)
    dist_atr = round(distance / max(atr, 1e-9), 4)

    magnetic = dist_atr < 0.5    # within half ATR = magnetic zone
    broken   = dist_atr < 0.1   # just broke through = momentum signal

    # Levels of significance: distance category
    levels = [{"price": l, "dist_atr": round(abs(price-l)/max(atr,1e-9),3)}
              for l in sorted(candidates, key=lambda x: abs(x-price))[:5]]

    return {
        "rn_nearest":     round(nearest, 8),
        "rn_distance_pct": round(distance / price * 100, 4),
        "rn_distance_atr": dist_atr,
        "rn_magnetic":    magnetic,
        "rn_broken":      broken,
        "rn_levels":      levels,
        "rn_note": (
            f"Round number: nearest={nearest:.4f} dist={dist_atr:.2f}×ATR "
            f"{'🧲 MAGNETIC ZONE' if magnetic else '✅ Clear of round levels'}"
            f"{' — MOMENTUM BREAK' if broken else ''}"
        ),
    }


# ── [v8.2-P22] Crypto Fama-French 3-Factor (#38) ─────────────
# Research: Fama & French (1993) — 3-factor model (market, size, value).
# Crypto adaptation: Market = BTC beta, Size = market cap rank,
# Value = NVT ratio (low NVT = cheap relative to usage).
def compute_crypto_fama_french(
    btc_correlation: float,
    btc_beta:        float,
    market_cap_rank: int,
    nvt_ratio:       float,
    momentum_30d:    float,
) -> Dict:
    """
    [v8.2-P22] Crypto 3-Factor (+ Momentum) Model.

    MKT factor (market beta):
      beta > 1.2 → high BTC beta — amplified BTC moves
      beta < 0.8 → low BTC beta — partially decoupled
    SMB factor (size):
      rank <= 5  → mega-cap (BTC/ETH/BNB/SOL/XRP) — lower volatility premium
      rank 6-20  → large-cap — size premium active
      rank > 20  → small-cap — highest size premium (higher risk/reward)
    HML factor (value via NVT):
      NVT < 30   → undervalued (cheap relative to network usage) → value buy
      NVT > 65   → overvalued → value short
    MOM factor (30d momentum):
      > +10%     → positive momentum → continuation
      < -10%     → negative momentum → mean-reversion risk

    Expected alpha = weighted sum of factor exposures.
    """
    mkt_score = 0.0
    smb_score = 0.0
    hml_score = 0.0
    mom_score = 0.0
    notes     = []

    # MKT — BTC correlation × beta
    effective_beta = round(btc_correlation * btc_beta, 4)
    if effective_beta > 1.3:
        mkt_score = -5.0   # high beta in downtrend = amplified losses
        notes.append(f"MKT β={effective_beta:.2f} HIGH (amplified)")
    elif effective_beta > 1.0:
        mkt_score = 2.0
        notes.append(f"MKT β={effective_beta:.2f} above market")
    elif effective_beta > 0.7:
        mkt_score = 5.0    # moderate beta = healthy exposure
        notes.append(f"MKT β={effective_beta:.2f} NORMAL")
    else:
        mkt_score = 3.0    # low beta = decoupled / own story
        notes.append(f"MKT β={effective_beta:.2f} LOW (decoupled)")

    # SMB — Size factor
    if market_cap_rank <= 5:
        smb_score = 3.0
        notes.append(f"SMB rank=#{market_cap_rank} mega-cap")
    elif market_cap_rank <= 20:
        smb_score = 5.0
        notes.append(f"SMB rank=#{market_cap_rank} large-cap premium")
    elif market_cap_rank <= 100:
        smb_score = 7.0
        notes.append(f"SMB rank=#{market_cap_rank} mid-cap premium")
    else:
        smb_score = 4.0    # micro-cap = high risk, discount for illiquidity
        notes.append(f"SMB rank=#{market_cap_rank} micro-cap (illiq penalty)")

    # HML — Value via NVT
    if nvt_ratio > 0:
        if nvt_ratio < 30:
            hml_score = 8.0
            notes.append(f"HML NVT={nvt_ratio:.0f} UNDERVALUED")
        elif nvt_ratio < 65:
            hml_score = 4.0
            notes.append(f"HML NVT={nvt_ratio:.0f} FAIR VALUE")
        else:
            hml_score = -3.0
            notes.append(f"HML NVT={nvt_ratio:.0f} OVERVALUED")

    # MOM — 30-day momentum
    if momentum_30d > 15:
        mom_score = 8.0
        notes.append(f"MOM +{momentum_30d:.1f}% strong")
    elif momentum_30d > 5:
        mom_score = 5.0
        notes.append(f"MOM +{momentum_30d:.1f}% positive")
    elif momentum_30d > -5:
        mom_score = 2.0
        notes.append("MOM flat")
    elif momentum_30d > -15:
        mom_score = -2.0
        notes.append(f"MOM {momentum_30d:.1f}% negative")
    else:
        mom_score = -5.0
        notes.append(f"MOM {momentum_30d:.1f}% STRONG NEGATIVE")

    # Weighted alpha score (0-100 normalised)
    raw = mkt_score * 0.25 + smb_score * 0.20 + hml_score * 0.30 + mom_score * 0.25
    alpha_score = round(max(0.0, min(100.0, 50.0 + raw * 3)), 2)
    ff_signal   = ("BULLISH" if alpha_score > 60 else
                   "BEARISH" if alpha_score < 40 else "NEUTRAL")
    conf_mod    = (1.05 if alpha_score > 65 else
                   0.95 if alpha_score < 35 else 1.0)

    return {
        "ff_alpha_score":   alpha_score,
        "ff_signal":        ff_signal,
        "ff_conf_mod":      conf_mod,
        "ff_mkt":           round(mkt_score, 2),
        "ff_smb":           round(smb_score, 2),
        "ff_hml":           round(hml_score, 2),
        "ff_mom":           round(mom_score, 2),
        "ff_beta":          effective_beta,
        "ff_note": (
            f"FF 4-factor: {ff_signal} score={alpha_score:.0f} | "
            + " | ".join(notes[:3])
        ),
    }


# ── [v8.2-P23] Heston Stochastic Volatility Proxy (#43) ──────
# Research: Heston (1993) — vol follows mean-reverting process
# correlated with price. Captures vol smile / skew effects.
# dv = κ(θ-v)dt + ξ√v·dW_v,  corr(dW_S, dW_v) = ρ
_HESTON_STATE: Dict[str, Dict] = {}   # symbol → {v: float, history: list}

def compute_heston_vol_proxy(
    closes:   List[float],
    symbol:   str   = "DEFAULT",
    kappa:    float = 2.0,    # mean-reversion speed
    theta:    float = 0.04,   # long-run variance
    xi:       float = 0.30,   # vol-of-vol
    rho:      float = -0.70,  # price-vol correlation (negative = leverage effect)
    dt:       float = 1/252,  # daily time step
) -> Dict:
    """
    [v8.2-P23] Heston model proxy — discretised Euler-Maruyama step.
    Estimates current instantaneous variance v_t and computes:
      - Implied vol smile skew (from rho)
      - Vol-of-vol clustering (from xi and v history)
      - Mean-reversion pull direction

    Returns forward vol forecast and skew direction.
    """
    if len(closes) < 20:
        return {
            "heston_v":        theta, "heston_vol_pct":   math.sqrt(theta)*100,
            "heston_skew":     "NEUTRAL", "heston_mr_pull": "NEUTRAL",
            "heston_note":     "Heston: insufficient data",
        }
    try:
        returns = [math.log(closes[i]/closes[i-1])
                   for i in range(1, len(closes)) if closes[i-1] > 0]
        if len(returns) < 5:
            raise ValueError("Too few returns")

        # Initialize or retrieve state
        state = _HESTON_STATE.get(symbol, {"v": theta, "history": []})
        v     = state["v"]
        v_history = state.get("history", [])

        # Simulate Heston variance path over recent returns
        # Discretised: v_{t+1} = v_t + kappa*(theta-v_t)*dt + xi*sqrt(max(v_t,0))*e*sqrt(dt)
        # Use realized variance as innovation proxy (skip Monte Carlo noise)
        for r in returns[-30:]:
            realized_shock = r * r   # realized variance proxy
            # Mean reversion + shock contribution
            dv = kappa * (theta - v) * dt
            v  = max(1e-8, v + dv + xi * math.sqrt(max(v, 1e-8)) * realized_shock)
            v_history.append(v)
        if len(v_history) > 100:
            v_history = v_history[-100:]

        # Current vol
        heston_vol = round(math.sqrt(max(v, 1e-8)) * math.sqrt(252) * 100, 4)

        # Skew direction from rho (price-vol correlation)
        # rho < 0 → neg correlation → down moves increase vol (left skew = bearish risk)
        # Price recently falling → vol rose → confirms negative rho → left-skew active
        recent_ret = sum(returns[-5:]) if len(returns) >= 5 else 0.0
        if rho < -0.3 and recent_ret < -0.01:
            skew = "LEFT_SKEW"    # down moves amplify vol → bearish risk premium
        elif rho > 0.3 and recent_ret > 0.01:
            skew = "RIGHT_SKEW"   # up moves amplify vol (unusual)
        else:
            skew = "NEUTRAL"

        # Mean-reversion pull
        if v > theta * 1.5:
            mr_pull = "REVERTING_DOWN"   # above long-run variance → vol will fall
        elif v < theta * 0.5:
            mr_pull = "REVERTING_UP"     # below long-run variance → vol will rise
        else:
            mr_pull = "AT_LONGRUN"

        # Persist state
        _HESTON_STATE[symbol] = {"v": v, "history": v_history}

        return {
            "heston_v":        round(v, 8),
            "heston_vol_pct":  heston_vol,
            "heston_theta_pct": round(math.sqrt(theta) * math.sqrt(252) * 100, 4),
            "heston_skew":     skew,
            "heston_mr_pull":  mr_pull,
            "heston_rho":      rho,
            "heston_note": (
                f"Heston: v={heston_vol:.1f}% ann | skew={skew} | "
                f"MR={mr_pull} | rho={rho}"
            ),
        }
    except Exception as e:
        return {
            "heston_v":       theta, "heston_vol_pct": math.sqrt(theta)*100,
            "heston_skew":    "NEUTRAL", "heston_mr_pull": "NEUTRAL",
            "heston_note":    f"Heston error: {e}",
        }


# ── [v8.2-P24] Linear SVM Signal (#47) ───────────────────────
# Research: Cao & Tay (2001) — SVMs outperform NNs on financial
# classification with limited data. RBF kernel optimal.
# Implementation: pure-Python SGD-trained linear SVM (primal form).
_SVM_STATE: Dict[str, Dict] = {}   # symbol → {w: list, b: float, n: int}

def compute_svm_signal(
    feature_vec: Dict[str, float],
    label:       int = 0,    # +1=bull, -1=bear, 0=update only
    symbol:      str = "DEFAULT",
    lr:          float = 0.01,
    C:           float = 1.0,   # regularisation strength
    update:      bool  = True,  # whether to update weights with this sample
) -> Dict:
    """
    [v8.2-P24] Online SGD Linear SVM (Pegasos algorithm, Shalev-Shwartz 2007).
    Decision function: f(x) = w·x + b
    f > 0.1  → BULLISH class
    f < -0.1 → BEARISH class
    else     → NEUTRAL

    Features are normalised to zero mean, unit variance using running stats.
    SGD update: w = (1-lr)*w + C*lr*y*x  if y*f(x) < 1 (support vector)
    """
    keys = sorted(feature_vec.keys())
    if not keys:
        return {
            "svm_score": 0.0, "svm_signal": "NEUTRAL",
            "svm_note": "SVM: no features", "svm_n_updates": 0,
        }

    state = _SVM_STATE.get(symbol, {
        "w":    [0.0] * len(keys),
        "b":    0.0,
        "n":    0,
        "feat_mean": [0.0] * len(keys),
        "feat_var":  [1.0] * len(keys),
    })

    # Align feature dimension (new keys may appear)
    if len(state["w"]) != len(keys):
        state["w"]         = [0.0] * len(keys)
        state["b"]         = 0.0
        state["feat_mean"] = [0.0] * len(keys)
        state["feat_var"]  = [1.0] * len(keys)

    x_raw = [float(feature_vec.get(k, 0.0)) for k in keys]

    # Online normalisation: running mean and variance
    n = state["n"] + 1
    for i in range(len(keys)):
        old_mean = state["feat_mean"][i]
        state["feat_mean"][i] += (x_raw[i] - old_mean) / n
        state["feat_var"][i]  = (state["feat_var"][i] * (n-1)
                                 + (x_raw[i] - old_mean) * (x_raw[i] - state["feat_mean"][i])) / n
        state["feat_var"][i]  = max(state["feat_var"][i], 1e-8)
    state["n"] = n

    # Normalise input
    x_norm = [(x_raw[i] - state["feat_mean"][i]) / math.sqrt(state["feat_var"][i])
              for i in range(len(keys))]

    # Decision function: f = w·x + b
    f = sum(state["w"][i] * x_norm[i] for i in range(len(keys))) + state["b"]

    # SGD update (Pegasos) if label provided
    if update and label in (1, -1):
        if label * f < 1.0:   # support vector — update weights
            for i in range(len(keys)):
                state["w"][i] = (1 - lr) * state["w"][i] + C * lr * label * x_norm[i]
            state["b"] += C * lr * label * 0.1
        else:                  # non-support vector — only L2 decay
            state["w"] = [(1 - lr) * wi for wi in state["w"]]

    _SVM_STATE[symbol] = state

    # Signal from decision function
    f_norm = round(max(-1.0, min(1.0, f / max(1.0, abs(f) + 0.1))), 4)
    if f > 0.3:
        signal, conf_mod = "BULLISH", 1.03
    elif f < -0.3:
        signal, conf_mod = "BEARISH", 0.97
    else:
        signal, conf_mod = "NEUTRAL", 1.0

    return {
        "svm_score":    round(f, 4),
        "svm_score_norm": f_norm,
        "svm_signal":   signal,
        "svm_conf_mod": conf_mod,
        "svm_n_updates": state["n"],
        "svm_note": (
            f"SVM: f={f:.3f} → {signal} | n_samples={state['n']} | "
            f"{'✅ Converging' if state['n'] > 50 else '⏳ Warming up'}"
        ),
    }


# ── [v8.2-P25] Adaptive Market Hypothesis (#57) ──────────────
# Research: Lo (2004) — markets evolve. Strategy edges wax/wane
# as participants adapt. Rolling win-rate tracks adaptive edge.
class AdaptiveMarketHypothesis:
    """
    [v8.2-P25] Adaptive Market Hypothesis — rolling strategy performance tracker.
    Tracks last N signal outcomes. When recent win-rate deviates significantly
    from long-run rate, edge is either expanding (early discovery) or
    decaying (crowded/arbitraged away).
    """
    def __init__(self, window: int = 50):
        self._outcomes:    deque = deque(maxlen=window)
        self._long_window: deque = deque(maxlen=200)
        self._window = window

    def record_outcome(self, win: bool) -> None:
        """Record a completed signal outcome (True=win, False=loss)."""
        self._outcomes.append(1 if win else 0)
        self._long_window.append(1 if win else 0)

    def evaluate(self) -> Dict:
        n_recent = len(self._outcomes)
        n_long   = len(self._long_window)
        if n_recent < 5:
            return {
                "amh_win_rate":   0.55, "amh_edge_state": "WARMING_UP",
                "amh_conf_mod":   1.0,  "amh_n_samples":  n_recent,
                "amh_note": f"AMH: warming up ({n_recent}/50 samples)",
            }
        recent_wr = sum(self._outcomes) / n_recent
        long_wr   = sum(self._long_window) / max(n_long, 1)

        # Edge state: is current win-rate above/below long-run?
        delta = recent_wr - long_wr
        if delta > 0.10 and recent_wr > 0.58:
            state, conf_mod = "EDGE_EXPANDING",  1.06   # alpha growing
        elif delta > 0.05:
            state, conf_mod = "EDGE_IMPROVING",  1.03
        elif delta < -0.10 and recent_wr < 0.48:
            state, conf_mod = "EDGE_DECAYING",   0.88   # alpha arbitraged away
        elif delta < -0.05:
            state, conf_mod = "EDGE_WEAKENING",  0.94
        elif recent_wr >= 0.55:
            state, conf_mod = "EDGE_STABLE",     1.0
        else:
            state, conf_mod = "EDGE_AT_NOISE",   0.95   # near 50/50

        return {
            "amh_win_rate":    round(recent_wr, 4),
            "amh_long_wr":     round(long_wr, 4),
            "amh_delta":       round(delta, 4),
            "amh_edge_state":  state,
            "amh_conf_mod":    conf_mod,
            "amh_n_samples":   n_recent,
            "amh_note": (
                f"AMH: {state} | recent_WR={recent_wr:.1%} | "
                f"long_WR={long_wr:.1%} | Δ={delta:+.1%} | n={n_recent}"
            ),
        }

_AMH = AdaptiveMarketHypothesis(window=50)


# ── [v8.2-P26] TDA Persistence Proxy (#68) ───────────────────
# Research: Gidea & Katz (2018) — persistent homology detects
# topological changes preceding market crashes.
# Implementation: 0-dimensional persistence (connected components)
# via Vietoris-Rips complex on 1D price series — pure Python.
def compute_tda_persistence_proxy(
    closes: List[float],
    window: int = 30,
) -> Dict:
    """
    [v8.2-P26] Topological Data Analysis — 0-dimensional persistence proxy.
    Method: Vietoris-Rips complex on pairwise |price_i - price_j| distances.
    Tracks birth/death of connected components as filtration radius grows.

    Persistence = death_radius - birth_radius = life span of a component.
    High persistence barcodes = significant topological feature (trend).
    Low total persistence = noisy, fragmented price structure (crash risk).

    0-dim persistence (H0): tracks connected components.
    The most persistent component = dominant price trend lifetime.
    """
    n = min(window, len(closes))
    if n < 5:
        return {
            "tda_persistence": 0.0, "tda_signal": "NEUTRAL",
            "tda_betti0": 0, "tda_note": "TDA: insufficient data",
        }
    pts = closes[-n:]
    # Normalise to [0,1] range for stable distance computation
    pmin, pmax = min(pts), max(pts)
    prange = max(pmax - pmin, 1e-9)
    norm_pts = [(p - pmin) / prange for p in pts]

    # Pairwise distances (1D: |p_i - p_j|)
    dists = []
    for i in range(n):
        for j in range(i+1, n):
            dists.append(abs(norm_pts[i] - norm_pts[j]))

    # Sort filtration radii
    dists_sorted = sorted(set(round(d, 6) for d in dists))

    # Union-Find for 0-dimensional persistence
    parent = list(range(n))
    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x
    def union(x, y):
        px, py = find(x), find(y)
        if px != py:
            parent[px] = py
            return True
        return False

    n_components = n
    births  = {i: 0.0 for i in range(n)}
    deaths  = {}
    barcodes = []

    for r in dists_sorted[:200]:   # cap at 200 filtration steps
        for i in range(n):
            for j in range(i+1, n):
                if abs(norm_pts[i] - norm_pts[j]) <= r:
                    if union(i, j):
                        # Component j merges into i → j dies at radius r
                        younger = j
                        deaths[younger] = r
                        pers = r - births.get(younger, 0.0)
                        barcodes.append(pers)
                        n_components -= 1
        if n_components <= 1:
            break

    # Persistence statistics
    if not barcodes:
        total_pers = 0.0
        max_pers   = 0.0
        mean_pers  = 0.0
    else:
        total_pers = round(sum(barcodes), 6)
        max_pers   = round(max(barcodes), 6)
        mean_pers  = round(sum(barcodes) / len(barcodes), 6)

    # High persistence = strong trend topology
    # Low persistence = fragmented / noisy = crash risk signal
    if max_pers > 0.60:
        signal, conf_mod = "STRONG_TOPOLOGY",   1.04   # dominant trend persists
    elif max_pers > 0.35:
        signal, conf_mod = "MODERATE_TOPOLOGY", 1.0
    elif max_pers > 0.15:
        signal, conf_mod = "WEAK_TOPOLOGY",     0.95
    else:
        signal, conf_mod = "FRAGMENTED",        0.88   # crash risk elevated

    return {
        "tda_persistence":  total_pers,
        "tda_max_pers":     max_pers,
        "tda_mean_pers":    mean_pers,
        "tda_betti0":       n_components,
        "tda_n_barcodes":   len(barcodes),
        "tda_signal":       signal,
        "tda_conf_mod":     conf_mod,
        "tda_note": (
            f"TDA H0: {signal} | max_pers={max_pers:.3f} | "
            f"n_barcodes={len(barcodes)} | "
            f"{'⚠️ Fragmented topology — crash risk' if signal == 'FRAGMENTED' else '✅ Stable topology'}"
        ),
    }


# ── [v8.2-P27] Macro Nowcast via FRED / On-Chain (#72) ───────
# Research: Fed Atlanta GDPNow — alt data nowcasts outperform
# consensus economists. Crypto proxy: FRED M2 money supply growth
# (public API) correlates with BTC price appreciation.
_MACRO_NOWCAST_CACHE: Dict = {"m2_growth": None, "ts": 0.0}
_MACRO_NOWCAST_TTL  = 86400.0   # 24-hour TTL — macro data changes slowly

async def fetch_macro_nowcast(session: aiohttp.ClientSession) -> Dict:
    """
    [v8.2-P27] Macro nowcast via FRED public API (M2 money supply).
    FRED series M2SL — monthly M2 in USD billions (public, no auth).
    M2 YoY growth > 5% → liquidity expansion → crypto bullish macro
    M2 YoY growth < 0% → liquidity contraction → crypto bearish macro

    Fallback: CoinGecko global market cap YoY growth as M2 proxy.
    """
    now = time.time()
    if (_MACRO_NOWCAST_CACHE["m2_growth"] is not None and
            (now - _MACRO_NOWCAST_CACHE["ts"]) < _MACRO_NOWCAST_TTL):
        c = _MACRO_NOWCAST_CACHE
        return {
            "m2_growth_pct": c["m2_growth"], "m2_regime": c["regime"],
            "m2_conf_mod":   c["conf_mod"],  "m2_note":   c["note"],
            "m2_source":     "CACHE",
        }

    m2_growth = None

    # Attempt 1: FRED public API (no auth key needed for this endpoint)
    try:
        url = ("https://fred.stlouisfed.org/graph/fredgraph.csv"
               "?id=M2SL&vintage_date=" +
               datetime.datetime.utcnow().strftime("%Y-%m-%d"))
        async with session.get(url, timeout=aiohttp.ClientTimeout(total=8)) as r:
            if r.status == 200:
                text = await r.text()
                lines = [l.strip() for l in text.strip().splitlines()
                         if l.strip() and not l.startswith("DATE")]
                if len(lines) >= 13:
                    # Parse last 13 rows (current + 12 months ago)
                    def parse_val(line):
                        parts = line.split(",")
                        return float(parts[1]) if len(parts) >= 2 and parts[1].strip() else None
                    current_m2  = parse_val(lines[-1])
                    year_ago_m2 = parse_val(lines[-13])
                    if current_m2 and year_ago_m2 and year_ago_m2 > 0:
                        m2_growth = round((current_m2 - year_ago_m2) / year_ago_m2 * 100, 4)
    except Exception as e:
        log.debug(f"[NOWCAST] FRED M2 fetch failed: {e}")

    # Attempt 2: CoinGecko global market cap as liquidity proxy
    if m2_growth is None:
        try:
            url = "https://api.coingecko.com/api/v3/global"
            async with session.get(url, timeout=aiohttp.ClientTimeout(total=5)) as r:
                if r.status == 200:
                    raw  = await r.json(content_type=None)
                    data = raw.get("data", {})
                    mkt_cap_change = float(
                        data.get("market_cap_change_percentage_24h_usd", 0) or 0
                    )
                    # Annualise 24h change as M2 proxy (rough)
                    m2_growth = round(mkt_cap_change * 365 / 12, 4)
        except Exception as e:
            log.debug(f"[NOWCAST] CoinGecko global failed: {e}")

    if m2_growth is None:
        m2_growth = 3.0   # neutral assumption if both sources fail

    if m2_growth > 8.0:
        regime, conf_mod = "EXPANDING_FAST",    1.08
        note = f"📈 M2 growth={m2_growth:.1f}% — FAST EXPANSION → strong crypto tailwind"
    elif m2_growth > 3.0:
        regime, conf_mod = "EXPANDING",         1.04
        note = f"📈 M2 growth={m2_growth:.1f}% — expanding → crypto bullish macro"
    elif m2_growth > 0.0:
        regime, conf_mod = "SLOW_GROWTH",       1.0
        note = f"➡️ M2 growth={m2_growth:.1f}% — slow growth → neutral macro"
    elif m2_growth > -3.0:
        regime, conf_mod = "CONTRACTING",       0.94
        note = f"📉 M2 growth={m2_growth:.1f}% — contracting → crypto headwind"
    else:
        regime, conf_mod = "HARD_CONTRACTION",  0.88
        note = f"📉 M2 growth={m2_growth:.1f}% — HARD CONTRACTION → risk-off macro"

    _MACRO_NOWCAST_CACHE.update({
        "m2_growth": m2_growth, "regime": regime,
        "conf_mod": conf_mod, "note": note, "ts": now,
    })
    return {
        "m2_growth_pct": m2_growth, "m2_regime": regime,
        "m2_conf_mod":   conf_mod,  "m2_note":   note,
        "m2_source":     "LIVE",
    }


# ── [v8.2-P28] Elliott Wave function alias fix (#83) ─────────
# The validated function is compute_elliott_wave_position().
# Alias detect_five_wave_elliott ensures both names resolve correctly.
detect_five_wave_elliott = compute_elliott_wave_position


# ══════════════════════════════════════════════════════════════
# ██ v8.3 — LIQUIDITY-AWARE LEVELS ENGINE (MOP P29)
#    Research: ICT methodology + #1 OFI + #6 LOB + #8 ICT + #15 Funding
#    Makes entry legs, TP, and SL directly aware of:
#      - Liquidation cluster zones (10x/20x/50x heatmap)
#      - EQH/EQL stop clusters (internal & external liquidity)
#      - Post-sweep entry validation (no pre-sweep entries)
#      - Round number magnetic zones (psychological S/R)
#      - PDH/PDL/PWH/PWL daily/weekly liq pool snapping
# ══════════════════════════════════════════════════════════════

def compute_liquidity_aware_levels(
    price:             float,
    bias:              str,
    entry_low:         float,
    entry_high:        float,
    inv_sl:            float,
    sl2:               float,
    sl3:               float,
    tp1:               float,
    tp2:               float,
    tp3:               float,
    leg1_entry:        float,
    leg2_entry:        float,
    leg3_entry:        float,
    invalidation_level: float,
    liq_inst:          Dict,
    upg_liq_heat:      Dict,
    bsl_ssl_data:      Dict,
    weekly_daily_liq:  Dict,
    atr_htf:           float,
    atr_15m:           float,
    funding_rate:      float = 0.0,
    funding_zscore:    float = 0.0,
    sweep_confirmed:   bool  = False,
    fvg_low:           float = 0.0,
    fvg_high:          float = 0.0,
) -> Dict:
    """
    [v8.3-P29] Liquidity-Aware Levels Engine.

    PRINCIPLE 1 — SL must be BEYOND liq clusters, not at them.
    Market makers hunt stop clusters before reversing. If SL sits
    at a known 10x/20x liquidation level, it will be hit. SL must
    be placed past those levels so the setup survives the hunt.

    PRINCIPLE 2 — Entry must be POST-SWEEP.
    Entering before liquidity is swept = entering before the catalyst.
    If no sweep confirmed, shift leg1 deeper into the PD array (OTE zone).

    PRINCIPLE 3 — TP must target actual liq pools.
    TP1 = nearest EQL/EQH (internal stop cluster, short-term target).
    TP2 = PDH/PDL (daily stop cluster, medium-term target).
    TP3 = PWH/PWL / BSL/SSL (session/weekly external liquidity, full target).

    PRINCIPLE 4 — Avoid SL placement at round number magnetic zones.
    Round numbers attract orders. SL at round number = SL hunt magnet.
    Push SL just past the round number level.

    Returns refined entry/SL/TP dict with all adjustments applied.
    """
    snap_log = []   # audit trail of every snapping decision
    atol     = atr_htf * 0.15   # absolute tolerance for "near" detection

    # ── Deep-copy working variables (never mutate originals in-place)
    _el   = float(entry_low)
    _eh   = float(entry_high)
    _sl1  = float(inv_sl)
    _sl2  = float(sl2)
    _sl3  = float(sl3)
    _tp1  = float(tp1)
    _tp2  = float(tp2)
    _tp3  = float(tp3)
    _l1   = float(leg1_entry)
    _l2   = float(leg2_entry)
    _l3   = float(leg3_entry)
    _inv  = float(invalidation_level)

    # ──────────────────────────────────────────────────────
    # STEP 1 — SL LIQUIDATION CLUSTER AVOIDANCE
    # If SL is within 0.25×ATR of a known liq cluster →
    # push it just past the cluster so stop-hunts don't hit SL.
    # ──────────────────────────────────────────────────────
    liq_longs  = upg_liq_heat.get("liq_long_levels",  {})   # {"10x": price, "20x": price, "50x": price}
    liq_shorts = upg_liq_heat.get("liq_short_levels", {})

    # For BULLISH: SL is below price → danger zones are long liquidation levels
    # For BEARISH: SL is above price → danger zones are short liquidation levels
    hunt_levels = []
    if bias == "BULLISH":
        hunt_levels = [float(v) for v in liq_longs.values()  if 0 < float(v) < price]
    else:
        hunt_levels = [float(v) for v in liq_shorts.values() if float(v) > price > 0]

    for hunt_lv in hunt_levels:
        dist = abs(_sl1 - hunt_lv)
        if dist < atr_htf * 0.30:   # SL within 0.30×ATR of a liq cluster
            if bias == "BULLISH":
                # Push SL below the liq cluster (past the hunt zone)
                new_sl = round(hunt_lv - atr_htf * 0.25, 8)
                if new_sl < _sl1:
                    _sl1 = new_sl
                    snap_log.append(f"SL1 pushed to {new_sl:.4f} (past {hunt_lv:.4f} liq cluster)")
            else:
                # Push SL above the liq cluster
                new_sl = round(hunt_lv + atr_htf * 0.25, 8)
                if new_sl > _sl1:
                    _sl1 = new_sl
                    snap_log.append(f"SL1 pushed to {new_sl:.4f} (past {hunt_lv:.4f} liq cluster)")
    # Propagate SL tiers: SL2/SL3 must still be past SL1
    if bias == "BULLISH":
        _sl2 = min(_sl2, _sl1 - atr_htf * 0.20)
        _sl3 = min(_sl3, _sl2 - atr_htf * 0.20)
    else:
        _sl2 = max(_sl2, _sl1 + atr_htf * 0.20)
        _sl3 = max(_sl3, _sl2 + atr_htf * 0.20)

    # ──────────────────────────────────────────────────────
    # STEP 2 — SL ROUND NUMBER AVOIDANCE
    # If SL is within 0.15×ATR of a round number, price will
    # be drawn to that level → stop-hunt risk → push SL past it.
    # ──────────────────────────────────────────────────────
    if _sl1 > 0:
        magnitude = 10 ** math.floor(math.log10(max(_sl1, 1e-9)))
        for mult in [0.5, 1.0, 2.0, 5.0, 10.0, 50.0, 100.0]:
            rn = round(magnitude * mult, 8)
            if abs(_sl1 - rn) < atr_htf * 0.15:
                if bias == "BULLISH":
                    _sl1 = round(rn - atr_htf * 0.12, 8)
                    snap_log.append(f"SL1 moved to {_sl1:.4f} (past round number {rn:.4f})")
                else:
                    _sl1 = round(rn + atr_htf * 0.12, 8)
                    snap_log.append(f"SL1 moved to {_sl1:.4f} (past round number {rn:.4f})")
                break

    # ──────────────────────────────────────────────────────
    # STEP 3 — TP1 SNAP TO NEAREST EQL/EQH (internal liquidity)
    # Equal highs above price (bullish) / equal lows below price
    # (bearish) are the first destination price targets.
    # These are confirmed stop clusters → price is drawn to them.
    # ──────────────────────────────────────────────────────
    lq_zones = liq_inst.get("lq_zones", [])
    if lq_zones and price > 0:
        if bias == "BULLISH":
            # EQH above price = stop clusters for shorts = TP1 magnet
            eqh_above = [z["price"] for z in lq_zones
                         if z.get("type") == "EQH" and z["price"] > price * 1.002]
            if eqh_above:
                nearest_eqh = min(eqh_above)   # closest EQH above
                # Only snap if it's between current TP1 and TP2 range (meaningful target)
                if _tp1 * 0.95 < nearest_eqh < _tp2 * 1.05:
                    _tp1 = round(nearest_eqh, 8)
                    snap_log.append(f"TP1 snapped to EQH={nearest_eqh:.4f} (stop cluster magnet)")
        else:
            # EQL below price = stop clusters for longs = TP1 magnet
            eql_below = [z["price"] for z in lq_zones
                         if z.get("type") == "EQL" and z["price"] < price * 0.998]
            if eql_below:
                nearest_eql = max(eql_below)   # closest EQL below
                if _tp2 * 0.95 < nearest_eql < _tp1 * 1.05:
                    _tp1 = round(nearest_eql, 8)
                    snap_log.append(f"TP1 snapped to EQL={nearest_eql:.4f} (stop cluster magnet)")

    # ──────────────────────────────────────────────────────
    # STEP 4 — TP2 SNAP TO PDH/PDL (daily stop cluster)
    # PDH (previous day high) = where daily short stops cluster.
    # PDL (previous day low)  = where daily long stops cluster.
    # These are ICT's most reliable medium-term TP targets.
    # ──────────────────────────────────────────────────────
    pdh = float(weekly_daily_liq.get("pdh") or 0)
    pdl = float(weekly_daily_liq.get("pdl") or 0)

    if bias == "BULLISH" and pdh > price * 1.001:
        # PDH is above price and in a plausible TP2 range
        if _tp1 < pdh < _tp3 * 1.1:
            _tp2 = round(pdh, 8)
            snap_log.append(f"TP2 snapped to PDH={pdh:.4f} (daily short stop cluster)")
    elif bias == "BEARISH" and 0 < pdl < price * 0.999:
        if _tp3 * 0.9 < pdl < _tp1:
            _tp2 = round(pdl, 8)
            snap_log.append(f"TP2 snapped to PDL={pdl:.4f} (daily long stop cluster)")

    # ──────────────────────────────────────────────────────
    # STEP 5 — TP3 SNAP TO PWH/PWL OR BSL/SSL (external liq)
    # Weekly highs/lows hold the largest stop clusters.
    # BSL (buy-side liq) / SSL (sell-side liq) are the ultimate targets.
    # ──────────────────────────────────────────────────────
    pwh = float(weekly_daily_liq.get("pwh") or 0)
    pwl = float(weekly_daily_liq.get("pwl") or 0)
    bsl = float(bsl_ssl_data.get("bsl_level") or 0)
    ssl = float(bsl_ssl_data.get("ssl_level") or 0)

    if bias == "BULLISH":
        # Candidates: PWH and BSL (both external buy-side liquidity)
        candidates = [c for c in [pwh, bsl] if c > max(price, _tp2) * 1.001]
        if candidates:
            best_ext = min(candidates)   # nearest external liq above
            if best_ext > _tp2 + atr_htf * 0.3:
                _tp3 = round(best_ext, 8)
                snap_log.append(f"TP3 snapped to external liq={best_ext:.4f} (PWH/BSL target)")
    else:
        candidates = [c for c in [pwl, ssl] if 0 < c < min(price, _tp2) * 0.999]
        if candidates:
            best_ext = max(candidates)   # nearest external liq below
            if best_ext < _tp2 - atr_htf * 0.3:
                _tp3 = round(best_ext, 8)
                snap_log.append(f"TP3 snapped to external liq={best_ext:.4f} (PWL/SSL target)")

    # ──────────────────────────────────────────────────────
    # STEP 6 — ENTRY POST-SWEEP VALIDATION
    # ICT rule: enter AFTER liquidity is swept, not before.
    # If no sweep confirmed → shift leg1 deeper into PD array
    # (OTE 61.8-79% zone) to reduce adverse selection risk.
    # ──────────────────────────────────────────────────────
    entry_sweep_valid = sweep_confirmed
    leg1_shift_note   = ""
    if not sweep_confirmed:
        # No sweep yet — tighten leg1 toward the 61.8% OTE zone
        zone_range = abs(_eh - _el)
        if bias == "BULLISH":
            # Shift leg1 to 61.8% of entry zone (closer to zone bottom)
            ote_target = _el + zone_range * 0.382   # 38.2% from bottom = OTE
            _l1 = round(min(_l1, ote_target), 8)
            leg1_shift_note = f"Leg1 shifted to OTE={_l1:.4f} (no sweep — pre-entry caution)"
        else:
            ote_target = _eh - zone_range * 0.382
            _l1 = round(max(_l1, ote_target), 8)
            leg1_shift_note = f"Leg1 shifted to OTE={_l1:.4f} (no sweep — pre-entry caution)"
        snap_log.append(leg1_shift_note)

    # ──────────────────────────────────────────────────────
    # STEP 7 — LEG SPACING VALIDATION
    # After all snapping: verify legs are in correct order and spaced.
    # Legs must be in price-priority order and at least 0.1×ATR apart.
    # ──────────────────────────────────────────────────────
    min_leg_gap = atr_15m * 0.15
    if bias == "BULLISH":
        # Leg1 < Leg2 < Leg3 (ascending, leg1 = best entry = lowest)
        _l2 = max(_l2, _l1 + min_leg_gap)
        _l3 = max(_l3, _l2 + min_leg_gap)
        _l1 = min(_l1, _eh - min_leg_gap * 2)   # leg1 must be below entry_high
    else:
        # Leg1 > Leg2 > Leg3 (descending, leg1 = best entry = highest)
        _l2 = min(_l2, _l1 - min_leg_gap)
        _l3 = min(_l3, _l2 - min_leg_gap)
        _l1 = max(_l1, _el + min_leg_gap * 2)   # leg1 must be above entry_low

    # ──────────────────────────────────────────────────────
    # STEP 8 — TP ORDERING VALIDATION
    # After all snapping: ensure TP1 < TP2 < TP3 (bull)
    # or TP1 > TP2 > TP3 (bear) with minimum ATR separation.
    # ──────────────────────────────────────────────────────
    min_tp_gap = atr_htf * 0.25
    if bias == "BULLISH":
        _tp1 = max(_tp1, price + atr_htf * 0.3)
        _tp2 = max(_tp2, _tp1 + min_tp_gap)
        _tp3 = max(_tp3, _tp2 + min_tp_gap)
    else:
        _tp1 = min(_tp1, price - atr_htf * 0.3)
        _tp2 = min(_tp2, _tp1 - min_tp_gap)
        _tp3 = min(_tp3, _tp2 - min_tp_gap)

    # ──────────────────────────────────────────────────────
    # STEP 9 — INVALIDATION LEVEL: push past nearest liq cluster
    # Invalidation = setup death level. Must be beyond any known
    # liq hunt zone so the setup isn't killed by a standard sweep.
    # ──────────────────────────────────────────────────────
    if bias == "BULLISH" and hunt_levels:
        deepest_hunt = min(hunt_levels)
        if _inv > deepest_hunt - atr_htf * 0.10:
            _inv = round(deepest_hunt - atr_htf * 0.20, 8)
            snap_log.append(f"Invalidation pushed to {_inv:.4f} (past {deepest_hunt:.4f} liq hunt zone)")
    elif bias == "BEARISH" and hunt_levels:
        highest_hunt = max(hunt_levels)
        if _inv < highest_hunt + atr_htf * 0.10:
            _inv = round(highest_hunt + atr_htf * 0.20, 8)
            snap_log.append(f"Invalidation pushed to {_inv:.4f} (past {highest_hunt:.4f} liq hunt zone)")

    # ──────────────────────────────────────────────────────
    # STEP 10 — CROWDED POSITION SL BUFFER
    # If funding Z shows crowded positioning in our direction
    # → SL must have extra buffer (crowd exit = sudden slippage)
    # ──────────────────────────────────────────────────────
    if abs(funding_zscore) > 1.5:
        extra_buf = atr_htf * 0.10   # 10% extra ATR buffer for slippage
        if bias == "BULLISH":
            _sl1 = round(_sl1 - extra_buf, 8)
            _sl2 = round(_sl2 - extra_buf, 8)
        else:
            _sl1 = round(_sl1 + extra_buf, 8)
            _sl2 = round(_sl2 + extra_buf, 8)
        snap_log.append(f"SL widened by {extra_buf:.4f} (funding Z={funding_zscore:.2f} crowd exit buffer)")

    # ──────────────────────────────────────────────────────
    # FINAL — recompute RR from adjusted levels
    # ──────────────────────────────────────────────────────
    _entry_mid_liq = (_el + _eh) / 2
    _risk_liq      = abs(_entry_mid_liq - _sl1)
    _rr1  = round(abs(_tp1 - _entry_mid_liq) / max(_risk_liq, 1e-9), 2)
    _rr2  = round(abs(_tp2 - _entry_mid_liq) / max(_risk_liq, 1e-9), 2)
    _rr3  = round(abs(_tp3 - _entry_mid_liq) / max(_risk_liq, 1e-9), 2)
    _rr_min_pass = _rr3 >= 1.5   # minimum viable RR after liq adjustments

    return {
        # Refined levels
        "liq_entry_low":    round(_el,   8),
        "liq_entry_high":   round(_eh,   8),
        "liq_sl1":          round(_sl1,  8),
        "liq_sl2":          round(_sl2,  8),
        "liq_sl3":          round(_sl3,  8),
        "liq_tp1":          round(_tp1,  8),
        "liq_tp2":          round(_tp2,  8),
        "liq_tp3":          round(_tp3,  8),
        "liq_leg1":         round(_l1,   8),
        "liq_leg2":         round(_l2,   8),
        "liq_leg3":         round(_l3,   8),
        "liq_invalidation": round(_inv,  8),
        # RR after liq-aware adjustments
        "liq_rr1":          _rr1,
        "liq_rr2":          _rr2,
        "liq_rr3":          _rr3,
        "liq_rr_pass":      _rr_min_pass,
        # Audit
        "entry_sweep_valid": entry_sweep_valid,
        "liq_snaps":         snap_log,
        "liq_note": (
            f"LIQ-AWARE: {len(snap_log)} adjustments | "
            f"RR1={_rr1} RR2={_rr2} RR3={_rr3} | "
            f"{'✅ RR OK' if _rr_min_pass else '⚠️ RR LOW after liq adjustments'} | "
            f"Sweep={'✅' if entry_sweep_valid else '⚠️ PENDING'}"
        ),
    }

def _has_volume_data(ca_volumes: List[float], lookback: int = 20, idx: int = -1) -> bool:
    """BUG #1 — Check volume data availability."""
    if idx < 0:
        window = ca_volumes[-lookback:]
    else:
        window = ca_volumes[max(0, idx - lookback):idx]
    if not window:
        return False
    non_zero = sum(1 for v in window if v > 1e-6)
    return non_zero >= len(window) * 0.5


def compute_displacement_v2_robust(
    ca_opens: List[float], ca_highs: List[float], ca_lows: List[float],
    ca_closes: List[float], ca_volumes: List[float], atrs: List[float],
    ma: Dict, idx: int,
) -> Tuple[float, bool]:
    """BUG #1 FIX — Robust displacement score handles missing volume."""
    if idx < 21 or atrs[idx] <= 0:
        return 0.0, False
    atr  = atrs[idx]
    body = abs(ca_closes[idx] - ca_opens[idx])
    rng  = ca_highs[idx] - ca_lows[idx]
    if rng == 0:
        return 0.0, False
    imbalance     = body / rng
    trend_str_val = ma.get("trend_score", 0.0)
    vol_available = _has_volume_data(ca_volumes, lookback=20, idx=idx)
    if vol_available:
        vol_window = ca_volumes[max(0, idx - 20):idx]
        mean_v = sum(vol_window) / len(vol_window)
        var_v  = sum((v - mean_v)**2 for v in vol_window) / len(vol_window)
        std_v  = math.sqrt(var_v) if var_v > 0 else 1.0
        vol_z  = (ca_volumes[idx] - mean_v) / max(std_v, 1e-9)
        score = (0.30*(body/atr) + 0.20*(rng/atr) + 0.20*max(0.0,vol_z)
                 + 0.15*imbalance + 0.15*abs(trend_str_val))
    else:
        score = (0.40*(body/atr) + 0.28*(rng/atr)
                 + 0.17*imbalance + 0.15*abs(trend_str_val))
    return round(score, 4), vol_available


def robust_displacement_gate(ca, atrs: List[float], ma: Dict, bias: str, existing_disp_v2: Dict) -> Dict:
    """BUG #1 FIX + FEATURE #3 — Drop-in replacement for disp_v2."""
    if existing_disp_v2.get("valid"):
        vol_ok = _has_volume_data(ca.volumes)
        return {**existing_disp_v2, "volume_confirmed": vol_ok, "vol_fallback": False, "robust_checked": True}
    best_score = 0.0; best_idx = ca.n - 1; best_vol_avail = False
    for i in range(max(21, ca.n - 20), ca.n):
        sc, vol_avail = compute_displacement_v2_robust(
            ca.opens, ca.highs, ca.lows, ca.closes, ca.volumes, atrs, ma, i)
        if sc > best_score:
            bull_dir = ca.closes[i] > ca.opens[i] and bias == "BULLISH"
            bear_dir = ca.closes[i] < ca.opens[i] and bias == "BEARISH"
            if bull_dir or bear_dir:
                best_score = sc; best_idx = i; best_vol_avail = vol_avail
    atr  = atrs[best_idx] if atrs[best_idx] > 0 else 1e-9
    rng  = ca.highs[best_idx] - ca.lows[best_idx]
    body = abs(ca.closes[best_idx] - ca.opens[best_idx])
    robust_passes = best_score >= 1.8
    if robust_passes:
        log_patch.info(f"[BUG#1] Gate 5 rescued by robust displacement. Score={best_score:.3f}")
    return {
        "score": best_score, "valid": robust_passes,
        "atr_mult": round(rng/atr, 2),
        "body_pct": int(body/rng*100) if rng > 0 else 0,
        "threshold": 1.8,
        "volume_confirmed": best_vol_avail,
        "vol_fallback": robust_passes and not best_vol_avail,
        "robust_checked": True,
    }


_TF_EXPECTED_CANDLES = {"1m": 100, "5m": 100, "15m": 100, "1h": 100, "4h": 100, "1d": 100, "1w": 100}
_TF_MINUTES          = {
    "1m": 1, "3m": 3, "5m": 5, "15m": 15, "30m": 30,
    "1h": 60, "2h": 120, "3h": 180, "4h": 240,
    "1d": 1440, "1w": 10080, "1M": 43200,
}


def validate_timeframes(ohlcv_htf: list, ohlcv_ltf: list, best_tf: str,
                         actual_htf: str = "4h", actual_ltf: str = "1h") -> Dict:
    """
    ICT TF Alignment Validator — checks:
    1. Candle count sufficiency (>= 50% of expected)
    2. HTF is genuinely higher than LTF (minutes comparison)
    3. LTF is the ICT-correct entry TF for this HTF
    4. TF pair forms a valid 3-TF combo or golden-ratio pair

    FIX-MTF-04: removed the always-True tf_consistent check
    (it was: best_tf == actual_htf, but actual_htf IS best_tf → always True).

    MTF-50: expanded ltf_aligned to accept any exec_tf from the 50-combo registry,
    not just the strict TF_ALIGNMENT golden-ratio pair.
    """
    issues = []
    htf_count = len(ohlcv_htf)
    ltf_count = len(ohlcv_ltf)

    if htf_count < _TF_EXPECTED_CANDLES.get(actual_htf, 100) * 0.5:
        issues.append(f"HTF ({actual_htf}) only {htf_count} candles — min {int(_TF_EXPECTED_CANDLES.get(actual_htf,100)*0.5)} needed")
    if ltf_count < _TF_EXPECTED_CANDLES.get(actual_ltf, 100) * 0.5:
        issues.append(f"LTF ({actual_ltf}) only {ltf_count} candles — min {int(_TF_EXPECTED_CANDLES.get(actual_ltf,100)*0.5)} needed")

    htf_mins = _TF_MINUTES.get(actual_htf, 0)
    ltf_mins = _TF_MINUTES.get(actual_ltf, 0)

    # FIX: check HTF is genuinely higher than LTF in minutes
    tf_order_valid = (htf_mins > 0 and ltf_mins > 0 and htf_mins > ltf_mins)
    if not tf_order_valid and htf_mins > 0 and ltf_mins > 0:
        issues.append(f"TF_ORDER_INVALID: HTF {actual_htf}({htf_mins}m) not > LTF {actual_ltf}({ltf_mins}m)")

    if htf_count < 20:
        issues.append(f"HTF ({actual_htf}) candles below minimum 20 for analysis")
    if ltf_count < 20:
        issues.append(f"LTF ({actual_ltf}) candles below minimum 20 for analysis")

    # ICT TF Alignment: verify actual_ltf is the correct ICT entry TF for this HTF
    # MTF-50: also accept any exec_tf from the MTF_COMBOS registry for this bias TF
    expected_ltf = TF_ALIGNMENT.get(actual_htf)
    _valid_exec_tfs = {c["exec"] for c in MTF_COMBOS if c["bias"] == actual_htf}
    _valid_exec_tfs.add(TF_ALIGNMENT.get(actual_htf, "15m"))   # always include golden-ratio default
    ltf_aligned = (expected_ltf is None) or (actual_ltf in _valid_exec_tfs) or (actual_ltf == expected_ltf)
    if not ltf_aligned:
        issues.append(
            f"TF_PAIR_MISALIGNED: HTF={actual_htf} — exec TF={actual_ltf} not in 50-combo registry for this bias"
        )

    # Valid pair check — HTF→LTF must match the ICT alignment map OR the 50-combo registry
    combo_valid = (actual_ltf in _valid_exec_tfs)

    consistent   = len(issues) == 0
    corrected_tf = actual_htf if not tf_order_valid else best_tf
    return {
        "consistent":      consistent,
        "tf_order_valid":  tf_order_valid,
        "corrected_tf":    corrected_tf,
        "actual_htf":      actual_htf,
        "actual_ltf":      actual_ltf,
        "best_tf":         best_tf,
        "htf_candles":     htf_count,
        "ltf_candles":     ltf_count,
        "ltf_aligned":     ltf_aligned,
        "expected_ltf":    expected_ltf,
        "combo_valid":     combo_valid,
        "valid_exec_tfs":  sorted(_valid_exec_tfs),
        "issues":          issues,
        "reason":          " | ".join(issues) if issues else "TF_CONSISTENT",
        "tf_note":         (
            f"✅ TF OK: {actual_htf}({htf_count}c) → {actual_ltf}({ltf_count}c)"
            if consistent else
            f"⚠️ TF Issues: {' | '.join(issues)}"
        ),
    }


async def fetch_onchain_context(base: str = "BTC") -> Dict:
    """FEATURE #2 — Fetch Fear & Greed + BTC dominance + total mcap."""
    cache_key = f"onchain:{base}"
    now = time.time()
    cached = _ONCHAIN_CACHE.get(cache_key)
    if cached and (now - cached["ts"]) < _ONCHAIN_CACHE_TTL:
        return cached["data"]
    result = {
        "fear_greed_index": None, "fear_greed_label": "UNKNOWN",
        "btc_dominance_pct": None, "total_mcap_usd": None,
        "total_mcap_label": "UNKNOWN",
        "mvrv_note":  "MVRV: not available (requires paid API)",
        "nvt_note":   "NVT: not available (requires paid API)",
        "onchain_bias_mod": 1.0, "onchain_note": "", "available": False,
    }
    try:
        async with aiohttp.ClientSession() as session:
            fg_url = "https://api.alternative.me/fng/?limit=1"
            try:
                async with session.get(fg_url, timeout=aiohttp.ClientTimeout(total=5)) as resp:
                    if resp.status == 200:
                        fg_raw  = await resp.json(content_type=None)
                        fg_data = fg_raw.get("data", [{}])[0]
                        result["fear_greed_index"] = int(fg_data.get("value", 50))
                        result["fear_greed_label"] = fg_data.get("value_classification", "Neutral")
            except Exception as e:
                log_patch.debug(f"[ONCHAIN] F&G fetch failed: {e}")
            cg_url = "https://api.coingecko.com/api/v3/global"
            try:
                async with session.get(cg_url, timeout=aiohttp.ClientTimeout(total=6)) as resp:
                    if resp.status == 200:
                        cg_data = (await resp.json(content_type=None)).get("data", {})
                        btc_dom = (cg_data.get("market_cap_percentage") or {}).get("btc")
                        total_mc = (cg_data.get("total_market_cap") or {}).get("usd")
                        if btc_dom is not None:
                            result["btc_dominance_pct"] = round(float(btc_dom), 2)
                        if total_mc is not None:
                            result["total_mcap_usd"]   = round(float(total_mc) / 1e12, 3)
                            result["total_mcap_label"] = f"${result['total_mcap_usd']:.2f}T"
            except Exception as e:
                log_patch.debug(f"[ONCHAIN] CoinGecko fetch failed: {e}")
    except Exception as e:
        log_patch.debug(f"[ONCHAIN] Session error: {e}")
    # Build bias modifier
    notes = []; bias_mod = 1.0
    fg_val = result["fear_greed_index"]
    if fg_val is not None:
        if fg_val <= 20:
            notes.append(f"🩸 Extreme Fear ({fg_val}) — capitulation zone")
            bias_mod *= 1.05
        elif fg_val <= 40:
            notes.append(f"😨 Fear ({fg_val}) — LONG bias slightly favoured")
            bias_mod *= 1.02
        elif fg_val >= 80:
            notes.append(f"🤑 Extreme Greed ({fg_val}) — euphoria, SHORT strengthened")
            bias_mod *= 0.92
        elif fg_val >= 65:
            notes.append(f"😏 Greed ({fg_val}) — caution on new LONGs")
            bias_mod *= 0.97
        else:
            notes.append(f"😐 Neutral sentiment ({fg_val})")
    btc_dom = result["btc_dominance_pct"]
    if btc_dom is not None:
        if btc_dom >= 60:
            notes.append(f"🔵 BTC Dom HIGH ({btc_dom}%) — risk-off, alts under pressure")
        elif btc_dom <= 45:
            notes.append(f"🟢 BTC Dom LOW ({btc_dom}%) — altseason conditions")
        else:
            notes.append(f"⚪ BTC Dom neutral ({btc_dom}%)")
    mcap = result["total_mcap_usd"]
    if mcap is not None:
        notes.append(f"{'💹' if mcap >= 3.0 else '📊' if mcap >= 1.5 else '📉'} Total MCap ${mcap:.2f}T")
    result["onchain_bias_mod"] = round(bias_mod, 4)
    result["onchain_note"]     = " | ".join(notes) if notes else "On-chain data unavailable"
    result["available"]        = fg_val is not None or btc_dom is not None
    result["fetched_at_utc"]   = time.strftime("%Y-%m-%d %H:%M UTC", time.gmtime(now))
    # Evict expired keys before storing to prevent unbounded growth
    if len(_ONCHAIN_CACHE) >= _ONCHAIN_CACHE_MAX:
        expired = [k for k, v in _ONCHAIN_CACHE.items() if (now - v["ts"]) >= _ONCHAIN_CACHE_TTL]
        for k in expired:
            del _ONCHAIN_CACHE[k]
        # If still over cap, evict oldest by timestamp
        if len(_ONCHAIN_CACHE) >= _ONCHAIN_CACHE_MAX:
            oldest = sorted(_ONCHAIN_CACHE, key=lambda k: _ONCHAIN_CACHE[k]["ts"])
            for k in oldest[:len(_ONCHAIN_CACHE) - _ONCHAIN_CACHE_MAX // 2]:
                del _ONCHAIN_CACHE[k]
    _ONCHAIN_CACHE[cache_key]  = {"ts": now, "data": result}
    return result


def apply_onchain_to_confidence(conf_total: float, onchain: Dict, bias: str) -> Tuple[float, str]:
    """FEATURE #2 — Apply on-chain bias modifier to confidence score."""
    if not onchain.get("available"):
        return conf_total, "On-chain data unavailable — confidence unchanged"
    fg_val   = onchain.get("fear_greed_index")
    adjusted = conf_total; note = ""
    if fg_val is not None:
        if fg_val <= 25 and bias == "BULLISH":
            adjusted = round(min(100.0, conf_total * 1.04), 1)
            note = f"On-chain boost: Extreme Fear ({fg_val}) + BULLISH = +4% conf"
        elif fg_val >= 75 and bias == "BEARISH":
            adjusted = round(min(100.0, conf_total * 1.04), 1)
            note = f"On-chain boost: Extreme Greed ({fg_val}) + BEARISH = +4% conf"
        elif fg_val >= 75 and bias == "BULLISH":
            adjusted = round(conf_total * 0.93, 1)
            note = f"On-chain penalty: Extreme Greed ({fg_val}) + BULLISH = -7% conf"
        elif fg_val <= 25 and bias == "BEARISH":
            adjusted = round(conf_total * 0.93, 1)
            note = f"On-chain penalty: Extreme Fear ({fg_val}) + BEARISH = -7% conf"
        else:
            note = f"On-chain neutral (F&G={fg_val}) — no adjustment"
    return adjusted, note


_DEPTH_LEVELS_PCT = [0.001, 0.005, 0.010, 0.020, 0.050]


def compute_enhanced_liquidity_metrics(ob_bids: list, ob_asks: list, mid_price: float, symbol: str = "") -> Dict:
    """FEATURE #4 — Enhanced liquidity metrics from live order book."""
    if not ob_bids or not ob_asks or mid_price <= 0:
        return {"depth_levels": {}, "imbalance_by_level": {}, "liquidity_cliff": None,
                "large_order_flag": False, "liq_depth_score": 50,
                "liq_depth_note": "Enhanced liquidity: no OB data", "available": False}
    try:
        bids = [(float(b[0]), float(b[1])) for b in ob_bids if len(b) >= 2]
        asks = [(float(a[0]), float(a[1])) for a in ob_asks if len(a) >= 2]
    except (ValueError, TypeError):
        return {"depth_levels": {}, "imbalance_by_level": {}, "liquidity_cliff": None,
                "large_order_flag": False, "liq_depth_score": 50,
                "liq_depth_note": "Enhanced liquidity: parse error", "available": False}
    depth_levels = {}; imbalance_by_level = {}
    for pct in _DEPTH_LEVELS_PCT:
        lk = f"{pct*100:.1f}%"
        bid_d = sum(p*q for p, q in bids if p >= mid_price*(1-pct))
        ask_d = sum(p*q for p, q in asks if p <= mid_price*(1+pct))
        depth_levels[lk] = {"bid_usd": round(bid_d,2), "ask_usd": round(ask_d,2), "total_usd": round(bid_d+ask_d,2)}
        tot = bid_d + ask_d
        imbalance_by_level[lk] = round(bid_d/tot, 4) if tot > 0 else 0.5
    # Cliff detection
    liquidity_cliff = None
    level_keys = [f"{p*100:.1f}%" for p in _DEPTH_LEVELS_PCT]
    for i in range(len(level_keys) - 1):
        curr = depth_levels[level_keys[i]]["total_usd"]
        nxt  = depth_levels[level_keys[i+1]]["total_usd"]
        if curr > 0 and nxt < curr * 0.40:
            liquidity_cliff = {"at_level": level_keys[i+1], "drop_pct": round((1-nxt/curr)*100,1),
                               "cliff_note": f"⚠️ Cliff at {level_keys[i+1]}: drops {round((1-nxt/curr)*100,1)}%"}
            break
    # Large order detection
    ref_d = (depth_levels.get("1.0%") or {}).get("total_usd", 0)
    large_order_flag = False; large_order_side = None
    if ref_d > 0:
        for p, q in bids:
            if p >= mid_price*0.99 and p*q > ref_d*0.05:
                large_order_flag = True; large_order_side = "BID"; break
        if not large_order_flag:
            for p, q in asks:
                if p <= mid_price*1.01 and p*q > ref_d*0.05:
                    large_order_flag = True; large_order_side = "ASK"; break
    # Score
    tight_d = (depth_levels.get("0.1%") or {}).get("total_usd", 0)
    score = (30 if tight_d >= 5e6 else 20 if tight_d >= 1e6 else 10 if tight_d >= 1e5 else 0)
    imb05 = imbalance_by_level.get("0.5%", 0.5)
    score += max(0, 30 - abs(imb05-0.5)*100)
    if liquidity_cliff is None: score += 20
    if not large_order_flag:    score += 20
    liq_depth_score = round(min(100, max(0, score)))
    depth_grade = "DEEP" if liq_depth_score >= 70 else "ADEQUATE" if liq_depth_score >= 45 else "THIN"
    cliff_note  = liquidity_cliff["cliff_note"] if liquidity_cliff else "No liquidity cliff"
    large_note  = f"⚠️ Large {large_order_side} wall" if large_order_flag else "No dominant walls"
    return {
        "depth_levels": depth_levels, "imbalance_by_level": imbalance_by_level,
        "liquidity_cliff": liquidity_cliff, "large_order_flag": large_order_flag,
        "large_order_side": large_order_side, "liq_depth_score": liq_depth_score,
        "liq_depth_grade": depth_grade,
        "liq_depth_note": f"OB Depth [{depth_grade}] Score={liq_depth_score}/100 | {cliff_note} | {large_note}",
        "available": True,
    }


async def fetch_enhanced_liquidity(base: str, session=None) -> Dict:
    """FEATURE #4 — Fetch live Binance OB for enhanced liquidity metrics."""
    sym = f"{base}USDT"; ob_data = None
    _close = session is None
    if session is None:
        session = aiohttp.ClientSession()
    try:
        try:
            async with session.get(f"https://fapi.binance.com/fapi/v1/depth?symbol={sym}&limit=50",
                                   timeout=aiohttp.ClientTimeout(total=5)) as resp:
                if resp.status == 200:
                    ob_data = await resp.json(content_type=None)
        except Exception as _ob_err:
            log.debug(f"[LIQUIDITY] OB fetch error ({sym}): {_ob_err}")
        if not ob_data:
            try:
                async with session.get(f"https://api.binance.com/api/v3/depth?symbol={sym}&limit=50",
                                       timeout=aiohttp.ClientTimeout(total=5)) as resp:
                    if resp.status == 200:
                        ob_data = await resp.json(content_type=None)
            except Exception as _e:
                log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
    finally:
        if _close:
            await session.close()
    if not ob_data:
        return {"depth_levels": {}, "liq_depth_score": 50, "liq_depth_grade": "UNKNOWN",
                "liq_depth_note": "Enhanced liquidity: Binance unavailable", "available": False}
    bids = ob_data.get("bids", []); asks = ob_data.get("asks", [])
    try:
        best_bid  = float(bids[0][0]) if bids else 0.0
        best_ask  = float(asks[0][0]) if asks else 0.0
        mid_price = (best_bid + best_ask) / 2 if best_bid and best_ask else 0.0
    except (IndexError, ValueError):
        mid_price = 0.0
    return compute_enhanced_liquidity_metrics(bids, asks, mid_price, sym)


def detect_data_gaps(ohlcv: list, tf: str) -> Dict:
    """
    Fix #36 — Detect missing candles in OHLCV series.
    If consecutive candles share the same OHLCV values it means the exchange
    returned a fill-forward stub (gap masquerading as data).
    Returns: gap_count, gap_pct, data_quality.
    """
    if len(ohlcv) < 3:
        return {"gap_count": 0, "gap_pct": 0.0, "data_quality": "UNKNOWN"}
    gap_count = 0
    for i in range(1, len(ohlcv)):
        prev, curr = ohlcv[i-1], ohlcv[i]
        # Same open/high/low/close = fill-forward = gap
        if (len(prev) >= 4 and len(curr) >= 4 and
                prev[0] == curr[0] and prev[1] == curr[1] and
                prev[2] == curr[2] and prev[3] == curr[3]):
            gap_count += 1
    gap_pct = round(gap_count / max(len(ohlcv) - 1, 1) * 100, 2)
    quality = "GOOD" if gap_pct < 2 else "DEGRADED" if gap_pct < 10 else "BAD"
    if quality != "GOOD":
        log.warning(f"[DATA GAP] {tf}: {gap_count} gaps ({gap_pct:.1f}%) — data quality {quality}")
    return {"gap_count": gap_count, "gap_pct": gap_pct, "data_quality": quality,
            "note": f"Data gaps [{quality}]: {gap_count} fill-forward candles ({gap_pct:.1f}%)"}


def compute_volume_confirmation(ohlcv: list, bias: str, period: int = 20, lookback: int = 5) -> Dict:
    """BUG #3 FIX — Volume Confirmation for ICT Decision Engine output."""
    if len(ohlcv) < period + lookback:
        return {"confirmed": False, "vol_ratio": 0.0, "above_avg_count": 0,
                "avg_volume": 0.0, "vol_note": "Insufficient data"}
    baseline = ohlcv[-(period+lookback):-lookback]
    vols     = [float(c[4]) if len(c) > 4 and c[4] is not None else 0.0 for c in baseline]
    avg_vol  = sum(vols) / max(len(vols), 1)
    if avg_vol <= 0:
        return {"confirmed": False, "vol_ratio": 0.0, "above_avg_count": 0,
                "avg_volume": 0.0, "vol_note": "Volume data unavailable (all zeros)"}
    recent = ohlcv[-lookback:]
    above_avg_count = 0; last_vol_ratio = 0.0
    for i, c in enumerate(recent):
        candle_vol = float(c[4]) if len(c) > 4 and c[4] is not None else 0.0
        in_dir = ((bias == "BULLISH" and float(c[3]) > float(c[0])) or
                  (bias == "BEARISH" and float(c[3]) < float(c[0])))
        if in_dir and candle_vol > 0:
            vr = candle_vol / avg_vol
            if vr >= 1.2: above_avg_count += 1
            if i == len(recent) - 1: last_vol_ratio = round(vr, 3)
    confirmed = above_avg_count >= 2 and last_vol_ratio >= 1.0
    return {
        "confirmed":       confirmed, "vol_ratio": last_vol_ratio,
        "above_avg_count": above_avg_count, "avg_volume": round(avg_vol, 2),
        "vol_note":        (f"✅ Volume confirmed: {above_avg_count}/5 bars above avg (last={last_vol_ratio:.2f}x)"
                            if confirmed else
                            f"⚠️ Volume weak: {above_avg_count}/5 bars above avg (last={last_vol_ratio:.2f}x)"),
    }


async def run_all_patch_features(
    base: str, ca_htf, atrs_htf: List[float], ma_stack: Dict, bias: str,
    ohlcv_htf: list, ohlcv_ltf: list, best_tf: str, disp_v2: Dict,
    conf_total: float, ob_bids: list, ob_asks: list, price: float,
) -> Dict:
    """Single entry point running all patch + onchain features concurrently."""
    onchain_task = asyncio.create_task(fetch_onchain_context(base))
    liq_task     = asyncio.create_task(fetch_enhanced_liquidity(base))
    disp_robust  = robust_displacement_gate(ca_htf, atrs_htf, ma_stack, bias, disp_v2)
    tf_valid     = validate_timeframes(ohlcv_htf, ohlcv_ltf, best_tf)
    vol_confirm  = compute_volume_confirmation(ohlcv_htf, bias)
    onchain      = await onchain_task
    enhanced_liq = await liq_task
    conf_after_onchain, onchain_conf_note = apply_onchain_to_confidence(conf_total, onchain, bias)
    if ob_bids and ob_asks and price > 0:
        enhanced_liq_local = compute_enhanced_liquidity_metrics(ob_bids, ob_asks, price)
        if not enhanced_liq.get("available"):
            enhanced_liq = enhanced_liq_local
    return {
        "disp_v2_robust":      disp_robust,
        "tf_valid":            tf_valid,
        "corrected_tf":        tf_valid["corrected_tf"],
        "volume_confirmation": vol_confirm,
        "onchain":             onchain,
        "conf_after_onchain":  conf_after_onchain,
        "onchain_conf_note":   onchain_conf_note,
        "enhanced_liq":        enhanced_liq,
    }

# ══════════════════════════════════════════════════════════════
# Q0 — MACRO LIQUIDITY MODEL (M2 · DXY · Rates → Risk-On Score)
# ══════════════════════════════════════════════════════════════

class MacroLiquidityModel:
    """
    Simplified macro risk-on / risk-off scoring.
    In a full production system this would pull live M2, DXY, Fed Funds rate.
    Here we proxy using BTC dominance trend + DXY-equivalent (USD pair strength).
    Risk-On Score 0–100: >60 = risk-on (favour longs), <40 = risk-off (favour shorts).
    """
    def __init__(self):
        self.risk_on_score: float = 50.0
        self.dxy_proxy:     float = 0.0
        self.m2_trend:      str   = "NEUTRAL"
        self.regime:        str   = "NEUTRAL"

    def update(self, btc_change_pct: float, eth_change_pct: float) -> None:
        """
        Proxy: BTC + ETH both rising → risk-on.
        BTC/ETH both falling → risk-off.
        """
        avg_chg = (btc_change_pct + eth_change_pct) / 2
        # Map change to risk-on score
        self.risk_on_score = max(0.0, min(100.0, 50.0 + avg_chg * 5.0))
        self.m2_trend = "EXPANDING" if self.risk_on_score > 60 else "CONTRACTING" if self.risk_on_score < 40 else "NEUTRAL"
        self.regime   = "RISK_ON" if self.risk_on_score > 60 else "RISK_OFF" if self.risk_on_score < 40 else "NEUTRAL"

    def get_score(self) -> Dict:
        return {
            "risk_on_score": round(self.risk_on_score, 1),
            "m2_trend":      self.m2_trend,
            "dxy_proxy":     round(self.dxy_proxy, 4),
            "macro_regime":  self.regime,
            "bias_modifier": 1.1 if self.regime == "RISK_ON" else 0.9 if self.regime == "RISK_OFF" else 1.0,
        }

# Global macro model instance
_MACRO_MODEL = MacroLiquidityModel()

