# ── TIER 1 #1: PO3 / AMD Phase Engine ─────────────────────────
def detect_po3_phase(session: str, ohlcv_ltf: list, atr: float) -> Dict:
    """
    Power of Three (PO3) — Accumulation → Manipulation → Distribution.
    Every institutional day structured in 3 acts:
      Accumulation  : Asia session — consolidation range forms
      Manipulation  : London open  — sweep above/below Asia range (stop hunt)
      Distribution  : NY session   — actual directional delivery
    Returns current phase + manipulation direction guess + entry gate.
    """
    if not ohlcv_ltf or len(ohlcv_ltf) < 10:
        return {"po3_phase": "UNKNOWN", "po3_gate": True, "po3_note": "Insufficient data",
                "manipulation_direction": "UNKNOWN", "asia_high": 0.0, "asia_low": 0.0}
    try:
        closes = [c[3] for c in ohlcv_ltf if len(c) >= 4]
        highs  = [c[1] for c in ohlcv_ltf if len(c) >= 4]
        lows   = [c[2] for c in ohlcv_ltf if len(c) >= 4]
        # Approximate Asia session as first 8 candles of last 24h for 15m data (~2hrs)
        n = len(closes)
        asia_slice = max(0, n - 96), max(8, n - 88)     # Asia window in last 24h
        asia_hi = max(highs[asia_slice[0]:asia_slice[1]]) if asia_slice[1] > asia_slice[0] else highs[-1]
        asia_lo = min(lows[asia_slice[0]:asia_slice[1]])  if asia_slice[1] > asia_slice[0] else lows[-1]
        asia_range = asia_hi - asia_lo
        current_price = closes[-1]
        # Phase detection by session
        if session in ("ASIA", "OFF_HOURS"):
            phase = "ACCUMULATION"
            po3_gate = True   # entries allowed — building range
            manip_dir = "UNKNOWN"
        elif session in ("LONDON",):
            # Check if price swept Asia high or low (manipulation sweep)
            swept_high = current_price > asia_hi + atr * 0.3
            swept_low  = current_price < asia_lo - atr * 0.3
            if swept_high:
                phase = "MANIPULATION_UP"
                manip_dir = "BULLISH_SWEEP"   # swept high → distribution will go DOWN
                po3_gate = False              # block bullish entries during upward manipulation
            elif swept_low:
                phase = "MANIPULATION_DOWN"
                manip_dir = "BEARISH_SWEEP"   # swept low → distribution will go UP
                po3_gate = False              # block bearish entries during downward manipulation
            else:
                phase = "ACCUMULATION"
                manip_dir = "PENDING"
                po3_gate = True
        elif session in ("NEW_YORK", "NY_AM", "NY_PM", "OVERLAP"):
            phase = "DISTRIBUTION"
            po3_gate = True   # highest probability entries in NY
            manip_dir = "COMPLETE"
        else:
            phase = "UNKNOWN"
            po3_gate = True
            manip_dir = "UNKNOWN"
        amd_note = (
            f"PO3: {phase} | Asia={asia_lo:.4g}–{asia_hi:.4g} "
            f"range={asia_range:.4g} | Manip={manip_dir}"
        )
        return {
            "po3_phase":            phase,
            "po3_gate":             po3_gate,
            "po3_note":             amd_note,
            "manipulation_direction": manip_dir,
            "asia_high":            round(asia_hi, 8),
            "asia_low":             round(asia_lo, 8),
            "asia_range":           round(asia_range, 8),
        }
    except Exception as e:
        return {"po3_phase": "UNKNOWN", "po3_gate": True, "po3_note": f"PO3 error: {e}",
                "manipulation_direction": "UNKNOWN", "asia_high": 0.0, "asia_low": 0.0}


# ── TIER 1 #2: MMXM Market Maker Model (5-Phase) ───────────────
def detect_mmxm_phase(ohlcv_htf: list, bias: str, bos_data: Dict,
                       liq_inst: Dict, fvg_low: float, fvg_high: float) -> Dict:
    """
    MMXM Market Maker Buy/Sell Model — 5 phases:
      Phase 1: Original Consolidation  (accumulation range)
      Phase 2: Price Run / Liquidity Raid (sweep ERL)
      Phase 3: Smart Money Reversal / CISD (MSS confirmation)
      Phase 4: Accumulation into PD Array (OB/FVG retest)
      Phase 5: Distribution / Delivery to IRL target
    Entry: Phase 4 (retest of PD array after MSS)
    Avoid: Phase 2 (price running, chasing) & Phase 5 (near completion)
    """
    if not ohlcv_htf or len(ohlcv_htf) < 20:
        return {"mmxm_phase": "UNKNOWN", "mmxm_gate": True,
                "mmxm_note": "Insufficient data", "mmxm_phase_num": 0}
    try:
        closes = [c[3] for c in ohlcv_htf if len(c) >= 4]
        highs  = [c[1] for c in ohlcv_htf if len(c) >= 4]
        lows   = [c[2] for c in ohlcv_htf if len(c) >= 4]
        n = len(closes)
        # Detect consolidation: low ATR over last 10 bars
        recent_range = [highs[i] - lows[i] for i in range(max(0,n-10), n)]
        avg_range = sum(recent_range) / max(len(recent_range), 1)
        total_range = [highs[i] - lows[i] for i in range(max(0,n-50), n)]
        avg_total_range = sum(total_range) / max(len(total_range), 1)
        in_consolidation = avg_range < avg_total_range * 0.6
        # BOS present = structural break = Phase 3
        bos_present = bos_data.get("structure_valid", False)
        # Liquidity swept = Phase 2 raid complete
        liq_swept   = liq_inst.get("sweep_confirmed", False)
        # Price near FVG = Phase 4 retest
        price = closes[-1]
        near_fvg = (fvg_low <= price <= fvg_high) if fvg_high > fvg_low > 0 else False
        # Phase determination
        if in_consolidation and not liq_swept:
            phase_num, phase = 1, "ORIGINAL_CONSOLIDATION"
            mmxm_gate = False   # wait for the model to develop
        elif liq_swept and not bos_present:
            phase_num, phase = 2, "LIQUIDITY_RAID"
            mmxm_gate = False   # DO NOT chase the run
        elif liq_swept and bos_present and not near_fvg:
            phase_num, phase = 3, "SMART_MONEY_REVERSAL"
            mmxm_gate = True    # MSS confirmed — wait for retest entry
        elif bos_present and near_fvg:
            phase_num, phase = 4, "PD_ARRAY_RETEST"
            mmxm_gate = True    # OPTIMAL ENTRY PHASE
        elif bos_present and not near_fvg:
            phase_num, phase = 5, "DISTRIBUTION_DELIVERY"
            mmxm_gate = False   # too late — near completion
        else:
            phase_num, phase = 0, "UNKNOWN"
            mmxm_gate = True
        opt = "✅ OPTIMAL ENTRY" if phase_num == 4 else (
              "⚠️ WAIT" if phase_num in (1, 3) else
              "❌ AVOID" if phase_num in (2, 5) else "—")
        return {
            "mmxm_phase":     phase,
            "mmxm_phase_num": phase_num,
            "mmxm_gate":      mmxm_gate,
            "mmxm_optimal":   phase_num == 4,
            "mmxm_note":      f"MMXM Phase {phase_num}: {phase} — {opt}",
        }
    except Exception as e:
        return {"mmxm_phase": "UNKNOWN", "mmxm_gate": True,
                "mmxm_note": f"MMXM error: {e}", "mmxm_phase_num": 0}


# ── TIER 1 #3: IPDA Data Ranges (20 / 40 / 60 day) ─────────────
def compute_ipda_ranges(ohlcv_daily: list, price: float) -> Dict:
    """
    InterBank Price Delivery Algorithm (IPDA) dealing ranges.
    ICT: institutions deliver price in 20/40/60 candle windows.
    The range boundaries define IRL/ERL targets for TPs.
    """
    if not ohlcv_daily or len(ohlcv_daily) < 10:
        return {"ipda_20h": None, "ipda_40h": None, "ipda_60h": None,
                "ipda_note": "Insufficient daily data", "ipda_draw": "UNKNOWN",
                "ipda_tp_target": 0.0}
    try:
        highs  = [c[1] for c in ohlcv_daily if len(c) >= 4]
        lows   = [c[2] for c in ohlcv_daily if len(c) >= 4]
        closes = [c[3] for c in ohlcv_daily if len(c) >= 4]
        def _ipda_window(n):
            n = min(n, len(highs))
            hi = max(highs[-n:])
            lo = min(lows[-n:])
            mid = (hi + lo) / 2
            return {"high": round(hi,8), "low": round(lo,8), "mid": round(mid,8),
                    "range": round(hi-lo,8)}
        ipda_20 = _ipda_window(20)
        ipda_40 = _ipda_window(40)
        ipda_60 = _ipda_window(60)
        # Determine draw direction — price below midpoint → draw to high (BSL), above → draw to low (SSL)
        mid_60 = ipda_60["mid"]
        if price < mid_60:
            draw = "BULLISH_DRAW_TO_BSL"
            tp_target = ipda_20["high"]
        else:
            draw = "BEARISH_DRAW_TO_SSL"
            tp_target = ipda_20["low"]
        # Find current range position (% from low of 20-day range)
        r20 = ipda_20["range"]
        pos_pct = round((price - ipda_20["low"]) / max(r20, 1e-9) * 100, 1) if r20 > 0 else 50.0
        note = (f"IPDA 20d H={ipda_20['high']:.4g} L={ipda_20['low']:.4g} "
                f"| Pos={pos_pct:.1f}% | Draw={draw}")
        return {
            "ipda_20":        ipda_20,
            "ipda_40":        ipda_40,
            "ipda_60":        ipda_60,
            "ipda_draw":      draw,
            "ipda_tp_target": round(tp_target, 8),
            "ipda_pos_pct":   pos_pct,
            "ipda_note":      note,
        }
    except Exception as e:
        return {"ipda_20": None, "ipda_40": None, "ipda_60": None,
                "ipda_draw": "UNKNOWN", "ipda_tp_target": 0.0,
                "ipda_note": f"IPDA error: {e}", "ipda_pos_pct": 50.0}


# ── TIER 1 #4: SMT Divergence (BTC/ETH cross-pair) ─────────────
_SMT_PRICE_CACHE: Dict[str, Tuple[float, float]] = {}   # symbol → (price, ts)
_SMT_CACHE_TTL  = 30.0  # seconds

async def fetch_smt_pair_price(session_http: aiohttp.ClientSession, symbol: str) -> float:
    """Fetch correlated pair price for SMT divergence (BTC↔ETH, SOL↔ETH, etc.)."""
    now = time.time()
    cached = _SMT_PRICE_CACHE.get(symbol)
    if cached and (now - cached[1]) < _SMT_CACHE_TTL:
        return cached[0]
    try:
        url = f"https://api.binance.com/api/v3/ticker/price?symbol={symbol}USDT"
        async with session_http.get(url, timeout=aiohttp.ClientTimeout(total=4)) as r:
            if r.status == 200:
                d = await r.json(content_type=None)
                p = float(d.get("price", 0))
                _SMT_PRICE_CACHE[symbol] = (p, now)
                return p
    except Exception as _e:
        log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
    return 0.0

def compute_smt_divergence(base: str, base_price: float,
                            pair_price: float, bias: str,
                            ohlcv_htf: list, atr: float) -> Dict:
    """
    SMT Divergence — Smart Money Technique.
    BTC new high + ETH fails to confirm → institutional distribution.
    BTC new low  + ETH fails to confirm → institutional accumulation (divergence = reversal).
    When SMT fires AGAINST bias → reduce confidence 20%.
    When SMT confirms bias → small confidence boost.
    """
    # Map correlated pairs
    SMT_PAIRS = {
        "BTC": "ETH", "ETH": "BTC",
        "SOL": "ETH", "BNB": "ETH",
        "AVAX": "SOL", "MATIC": "ETH",
        "LINK": "ETH", "ADA": "ETH",
    }
    pair = SMT_PAIRS.get(base.upper(), "ETH")
    if pair_price <= 0 or base_price <= 0 or not ohlcv_htf or len(ohlcv_htf) < 10:
        return {"smt_divergence": False, "smt_dir": "NONE", "smt_note": "No pair data",
                "smt_conf_mod": 1.0, "smt_pair": pair}
    try:
        closes_base = [c[3] for c in ohlcv_htf if len(c) >= 4]
        n = len(closes_base)
        # Look at last 5 swings for divergence
        window = min(20, n)
        recent_high_base = max(closes_base[-window:])
        recent_low_base  = min(closes_base[-window:])
        prev_high_base   = max(closes_base[-(window*2):-window]) if n >= window*2 else recent_high_base
        prev_low_base    = min(closes_base[-(window*2):-window]) if n >= window*2 else recent_low_base
        # Pair directional change estimated from current vs cached previous
        # For the pair we use a simple 2% swing threshold heuristic
        base_higher_high = recent_high_base > prev_high_base * 1.002
        base_lower_low   = recent_low_base  < prev_low_base  * 0.998
        # Approximate pair confirmation: if pair price moved in same direction
        # (We don't have pair OHLCV — use price vs atr as proxy)
        pair_confirms_up  = pair_price > base_price * 0.95   # rough alignment check
        pair_confirms_dn  = pair_price < base_price * 1.05
        smt_bearish = base_higher_high and not pair_confirms_up   # base new high, pair fails
        smt_bullish = base_lower_low   and not pair_confirms_dn   # base new low, pair fails
        if smt_bearish and bias == "BULLISH":
            divergence = True
            smt_dir = "BEARISH_SMT"
            conf_mod = 0.80   # −20% confidence — institutional distribution signal
            note = f"⚠️ SMT BEARISH: {base} new HH but {pair} not confirming → trap"
        elif smt_bullish and bias == "BEARISH":
            divergence = True
            smt_dir = "BULLISH_SMT"
            conf_mod = 0.80
            note = f"⚠️ SMT BULLISH: {base} new LL but {pair} not confirming → trap"
        elif (smt_bearish and bias == "BEARISH") or (smt_bullish and bias == "BULLISH"):
            divergence = False
            smt_dir = "CONFIRMING"
            conf_mod = 1.05   # +5% confirmation
            note = f"✅ SMT CONFIRMING: {base}/{pair} aligned with {bias}"
        else:
            divergence = False
            smt_dir = "NONE"
            conf_mod = 1.0
            note = f"SMT: No significant divergence ({base}/{pair})"
        return {
            "smt_divergence": divergence,
            "smt_dir":        smt_dir,
            "smt_conf_mod":   conf_mod,
            "smt_pair":       pair,
            "smt_note":       note,
        }
    except Exception as e:
        return {"smt_divergence": False, "smt_dir": "NONE", "smt_note": f"SMT error: {e}",
                "smt_conf_mod": 1.0, "smt_pair": "ETH"}


# ── TIER 1 #5: CISD (Change in State of Delivery) ──────────────
def detect_cisd(ohlcv_ltf: list, bias: str, liq_zone_swept: float,
                liq_zone_target: float, atr_ltf: float) -> Dict:
    """
    CISD — Change in State of Delivery.
    After liquidity sweep: the candle that swept the level must CLOSE
    back inside the prior range. This closes the delivery state change,
    confirming the sweep was institutional manipulation, not a real breakout.
    Required as LTF entry confirmation (upgrades RTCW Gate).
    """
    if not ohlcv_ltf or len(ohlcv_ltf) < 4 or liq_zone_swept <= 0:
        return {"cisd_confirmed": False, "cisd_note": "No sweep data for CISD",
                "cisd_candle_idx": -1, "cisd_gate": False}
    try:
        n = len(ohlcv_ltf)
        # Look at last 5 candles for the CISD pattern
        for i in range(max(0, n-5), n):
            c = ohlcv_ltf[i]
            if len(c) < 4:
                continue
            o, h, l, cl = float(c[0]), float(c[1]), float(c[2]), float(c[3])
            if bias == "BULLISH":
                # Swept low → close must come back above the swept level
                wick_swept_low = l < liq_zone_swept - atr_ltf * 0.1
                close_recovered = cl > liq_zone_swept + atr_ltf * 0.05
                if wick_swept_low and close_recovered:
                    return {
                        "cisd_confirmed": True,
                        "cisd_candle_idx": i,
                        "cisd_gate": True,
                        "cisd_note": f"✅ CISD BULLISH: Wick swept {liq_zone_swept:.4g}, close recovered above",
                    }
            else:  # BEARISH
                wick_swept_high = h > liq_zone_swept + atr_ltf * 0.1
                close_recovered = cl < liq_zone_swept - atr_ltf * 0.05
                if wick_swept_high and close_recovered:
                    return {
                        "cisd_confirmed": True,
                        "cisd_candle_idx": i,
                        "cisd_gate": True,
                        "cisd_note": f"✅ CISD BEARISH: Wick swept {liq_zone_swept:.4g}, close recovered below",
                    }
        return {
            "cisd_confirmed": False,
            "cisd_candle_idx": -1,
            "cisd_gate": False,
            "cisd_note": "⏳ CISD pending — no close-back-inside confirmation yet",
        }
    except Exception as e:
        return {"cisd_confirmed": False, "cisd_gate": False,
                "cisd_note": f"CISD error: {e}", "cisd_candle_idx": -1}


# ── TIER 1 #6: IRL vs ERL Classification + TP Routing ──────────
def classify_irl_erl_and_route_tps(
    bias: str, price: float,
    fvg_low: float, fvg_high: float,
    ob_low: float, ob_high: float,
    pdh: float, pdl: float,
    pwh: float, pwl: float,
    eqh: float, eql: float,
    ipda_tp: float, atr_htf: float,
) -> Dict:
    """
    IRL vs ERL TP Routing — ICT doctrine:
      TP1 = nearest IRL (FVG CE or OB midpoint — inside current range)
      TP2 = nearest ERL within range (PDH/PDL)
      TP3 = higher-TF liquidity draw (EQH/EQL, PWH/PWL, IPDA boundary)
    Replaces RR-multiple TP calculation with actual institutional magnets.
    """
    fvg_ce  = (fvg_low + fvg_high) / 2 if fvg_high > fvg_low > 0 else 0.0
    ob_mid  = (ob_low + ob_high) / 2   if ob_high > ob_low > 0 else 0.0
    try:
        if bias == "BULLISH":
            # IRL targets above price
            irl_candidates = [v for v in [fvg_ce, ob_mid] if v > price + atr_htf * 0.1]
            erl_near = [v for v in [pdh, pwh] if v > price + atr_htf * 0.5]
            erl_far  = [v for v in [eqh, ipda_tp, pwh] if v > price + atr_htf * 1.0]
            irl_tp1  = min(irl_candidates) if irl_candidates else round(price + atr_htf * 1.0, 8)
            erl_tp2  = min(erl_near)       if erl_near       else round(price + atr_htf * 2.0, 8)
            erl_tp3  = min(erl_far)        if erl_far        else round(price + atr_htf * 3.0, 8)
            # Ensure ascending order
            erl_tp2 = max(erl_tp2, irl_tp1 + atr_htf * 0.5)
            erl_tp3 = max(erl_tp3, erl_tp2 + atr_htf * 0.5)
        else:  # BEARISH
            irl_candidates = [v for v in [fvg_ce, ob_mid] if v < price - atr_htf * 0.1]
            erl_near = [v for v in [pdl, pwl] if v < price - atr_htf * 0.5]
            erl_far  = [v for v in [eql, ipda_tp, pwl] if v < price - atr_htf * 1.0]
            irl_tp1  = max(irl_candidates) if irl_candidates else round(price - atr_htf * 1.0, 8)
            erl_tp2  = max(erl_near)       if erl_near       else round(price - atr_htf * 2.0, 8)
            erl_tp3  = max(erl_far)        if erl_far        else round(price - atr_htf * 3.0, 8)
            erl_tp2 = min(erl_tp2, irl_tp1 - atr_htf * 0.5)
            erl_tp3 = min(erl_tp3, erl_tp2 - atr_htf * 0.5)
        return {
            "irl_tp1":    round(irl_tp1, 8),
            "erl_tp2":    round(erl_tp2, 8),
            "erl_tp3":    round(erl_tp3, 8),
            "irl_label":  "FVG CE" if (fvg_ce and fvg_ce == irl_tp1) else "OB Mid",
            "erl2_label": "PDH" if erl_tp2 == pdh else ("PDL" if erl_tp2 == pdl else "ERL"),
            "erl3_label": "EQH/PWH" if bias == "BULLISH" else "EQL/PWL",
            "irl_erl_note": f"TP1=IRL({irl_tp1:.4g}) TP2=ERL({erl_tp2:.4g}) TP3=HTF-ERL({erl_tp3:.4g})",
        }
    except Exception as e:
        return {"irl_tp1": 0.0, "erl_tp2": 0.0, "erl_tp3": 0.0,
                "irl_label": "—", "erl2_label": "—", "erl3_label": "—",
                "irl_erl_note": f"IRL/ERL error: {e}"}


# ── TIER 2 #7: Midnight/True Day Open Reference ─────────────────
def compute_midnight_open(ohlcv_1h: list, price: float) -> Dict:
    """
    True Day Open — price at 00:00 UTC (ICT Midnight Open).
    Premium/Discount context relative to current intraday day.
    Short entries only when price above True Open; longs when below.
    """
    if not ohlcv_1h or len(ohlcv_1h) < 2:
        return {"midnight_open": price, "midnight_premium": False,
                "midnight_note": "No 1H data for midnight open"}
    try:
        now_utc_hour = datetime.datetime.utcnow().hour
        # The midnight open = open of the candle 'now_utc_hour' candles ago in 1H data
        offset = min(now_utc_hour, len(ohlcv_1h) - 1)
        mo_candle = ohlcv_1h[-(offset + 1)]
        mo_price = float(mo_candle[0]) if len(mo_candle) >= 1 else price
        premium = price > mo_price
        dist_pct = round((price - mo_price) / max(mo_price, 1e-9) * 100, 3)
        return {
            "midnight_open":    round(mo_price, 8),
            "midnight_premium": premium,
            "midnight_discount": not premium,
            "midnight_dist_pct": dist_pct,
            "midnight_note": (
                f"True Day Open: {mo_price:.4g} | Price {'PREMIUM' if premium else 'DISCOUNT'} "
                f"({dist_pct:+.3f}%)"
            ),
        }
    except Exception as e:
        return {"midnight_open": price, "midnight_premium": False,
                "midnight_note": f"Midnight open error: {e}"}


# ── TIER 2 #8: Asian Session Range (ASR) ───────────────────────
def detect_asian_session_range(ohlcv_1h: list, price: float) -> Dict:
    """
    Asian Session Range (ASR) — 20:00–00:00 EST / 00:00–04:00 UTC.
    London sweep = manipulate above/below ASR.
    ICT: identify sweep direction, trade in OPPOSITE direction after sweep.
    """
    if not ohlcv_1h or len(ohlcv_1h) < 5:
        return {"asr_high": 0.0, "asr_low": 0.0, "asr_swept": False,
                "asr_note": "No 1H data", "asr_sweep_dir": "NONE"}
    try:
        # Asia session in UTC: hours 0–5 → look at last 5 1H candles before current session
        now_h = datetime.datetime.utcnow().hour
        # QA FIX: old slice `ohlcv_1h[-(asia_end):-(asia_start)]` produced 1-candle
        # range when asia_start==0, silently giving a degenerate ASR.
        # New approach: always take the last 6 candles that fall in the Asia UTC window (0-5h).
        # Since we don't have per-candle timestamps, we use a robust offset:
        # look back (now_h + 1) candles to skip today's non-Asia candles, then grab 6.
        lookback_start = max(6, min(len(ohlcv_1h) - 1, now_h + 6))
        lookback_end   = max(0, lookback_start - 6)
        if lookback_end == 0:
            asia_candles = ohlcv_1h[-lookback_start:]
        else:
            asia_candles = ohlcv_1h[-lookback_start:-lookback_end]
        if not asia_candles or len(asia_candles) < 2:
            asia_candles = ohlcv_1h[-6:]
        asr_high = max(float(c[1]) for c in asia_candles if len(c) >= 4)
        asr_low  = min(float(c[2]) for c in asia_candles if len(c) >= 4)
        asr_mid  = (asr_high + asr_low) / 2
        # Check if current price swept the ASR
        swept_high = price > asr_high * 1.001
        swept_low  = price < asr_low  * 0.999
        asr_swept  = swept_high or swept_low
        sweep_dir  = "BULLISH_SWEEP" if swept_high else ("BEARISH_SWEEP" if swept_low else "NONE")
        # After sweep of ASR high → expect reversal DOWN (distribution)
        # After sweep of ASR low → expect reversal UP (accumulation)
        expected_dir = "BEARISH" if swept_high else ("BULLISH" if swept_low else "NEUTRAL")
        return {
            "asr_high":       round(asr_high, 8),
            "asr_low":        round(asr_low,  8),
            "asr_mid":        round(asr_mid,  8),
            "asr_swept":      asr_swept,
            "asr_sweep_dir":  sweep_dir,
            "asr_expected_dir": expected_dir,
            "asr_note": (
                f"ASR: H={asr_high:.4g} L={asr_low:.4g} | "
                f"{'⚠️ SWEPT ' + sweep_dir + ' → expect ' + expected_dir if asr_swept else '○ Range intact'}"
            ),
        }
    except Exception as e:
        return {"asr_high": 0.0, "asr_low": 0.0, "asr_swept": False,
                "asr_note": f"ASR error: {e}", "asr_sweep_dir": "NONE"}


# ══════════════════════════════════════════════════════════════════════
# THESIS P1 — ICT TIME MACRO WINDOWS (8 precision 20-min windows)
# Research: ForexFactory 2025 + ICT inner circle documentation
# These are the algorithmic windows where price seeks liquidity or
# reprices FVGs. Different from kill zones (1h blocks) — these are
# 20-minute precision windows validated by ICT source material.
# All times in US/Eastern (NY). DST-aware conversion applied at runtime.
# ══════════════════════════════════════════════════════════════════════
ICT_MACRO_WINDOWS = {
    "LONDON_1":   {"start_est": (2,  33), "end_est": (3,  0),  "label": "London Macro 1   02:33–03:00 EST"},
    "LONDON_2":   {"start_est": (4,   3), "end_est": (4, 30),  "label": "London Macro 2   04:03–04:30 EST"},
    "NY_AM_1":    {"start_est": (8,  50), "end_est": (9, 10),  "label": "NY AM Macro 1    08:50–09:10 EST"},
    "NY_AM_2":    {"start_est": (9,  50), "end_est": (10, 10), "label": "NY AM Macro 2    09:50–10:10 EST"},
    "NY_AM_3":    {"start_est": (10, 50), "end_est": (11, 10), "label": "NY AM Macro 3    10:50–11:10 EST"},
    "NY_LUNCH":   {"start_est": (11, 50), "end_est": (12, 10), "label": "NY Lunch Macro   11:50–12:10 EST"},
    "NY_PM":      {"start_est": (13, 10), "end_est": (13, 40), "label": "NY PM Macro      13:10–13:40 EST"},
    "NY_CLOSE":   {"start_est": (15, 15), "end_est": (15, 45), "label": "NY Close Macro   15:15–15:45 EST"},
}

def get_macro_window_status() -> Dict:
    """
    Return current active ICT Macro window (if any), next upcoming, and alignment with kill zones.
    All ICT Macro times are in US/Eastern. DST-aware conversion (EDT=UTC-4, EST=UTC-5).
    QA FIX: was hardcoded UTC-5 — off by 1 hour March–November (EDT period).
    """
    now_utc  = datetime.datetime.utcnow()
    now_mins = now_utc.hour * 60 + now_utc.minute
    # DST-aware: use _utc_mins_to_ny_mins instead of hardcoded -300
    est_mins = _utc_mins_to_ny_mins(now_mins)

    active = None
    next_macro = None
    mins_to_next = 9999

    for name, mw in ICT_MACRO_WINDOWS.items():
        sh, sm = mw["start_est"]
        eh, em = mw["end_est"]
        start_est = sh * 60 + sm
        end_est   = eh * 60 + em
        if start_est <= est_mins <= end_est:
            active = {"name": name, "label": mw["label"],
                      "mins_remaining": end_est - est_mins}
        elif start_est > est_mins:
            diff = start_est - est_mins
            if diff < mins_to_next:
                mins_to_next = diff
                next_macro = {"name": name, "label": mw["label"],
                              "mins_until": diff}

    return {
        "macro_active":    active is not None,
        "active_macro":    active,
        "next_macro":      next_macro,
        "macro_note": (
            f"🎯 MACRO ACTIVE: {active['label']}  ({active['mins_remaining']}m left)"
            if active else
            (f"⏳ Next macro: {next_macro['label']}  (in {next_macro['mins_until']}m)"
             if next_macro else "○ No macros today — check tomorrow")
        ),
    }


# ══════════════════════════════════════════════════════════════════════
# THESIS P2.1 — JUDAS SWING DETECTION
# Research: ebc.com ICT May 2025 + ICT source material
# Judas Swing = false breakout of PDH/PDL in first trading hour,
# before the true direction is revealed. London and NY opens most common.
# Institutions accumulate positions during the false move,
# then reverse hard into the actual delivery direction.
# ══════════════════════════════════════════════════════════════════════
def detect_judas_swing(ohlcv_1h: list, price: float, bias: str,
                        pdh: float, pdl: float, atr: float) -> Dict:
    """
    Detect a Judas Swing in the first-hour candle of a session.
    A Judas Swing is confirmed when:
      - Price extends beyond PDH (bearish Judas) or PDL (bullish Judas)
      - But then CLOSES back inside the PDH/PDL level within 1–2 candles
      - The swing magnitude > 0.3×ATR (genuine inducement, not noise)
    Returns detection status, direction, and confluence with current bias.
    """
    if not ohlcv_1h or len(ohlcv_1h) < 3 or pdh <= 0 or pdl <= 0:
        return {"judas_detected": False, "judas_dir": "NONE",
                "judas_conf_bias": False,
                "judas_note": "Insufficient data for Judas Swing detection"}
    try:
        # Use last 3 candles (current session opening range)
        recent = ohlcv_1h[-3:]
        judas_bear = False   # false break above PDH → real move is DOWN
        judas_bull = False   # false break below PDL → real move is UP
        judas_mag  = 0.0

        for i, c in enumerate(recent):
            o, h, l, cl = float(c[0]), float(c[1]), float(c[2]), float(c[3])
            # Bearish Judas: wick above PDH but close below PDH
            if h > pdh * 1.001 and cl < pdh and (h - pdh) >= atr * 0.3:
                judas_bear = True
                judas_mag  = round(h - pdh, 8)
            # Bullish Judas: wick below PDL but close above PDL
            if l < pdl * 0.999 and cl > pdl and (pdl - l) >= atr * 0.3:
                judas_bull = True
                judas_mag  = round(pdl - l, 8)

        judas_dir = ("BEARISH_JUDAS" if judas_bear else
                     "BULLISH_JUDAS" if judas_bull else "NONE")
        detected  = judas_bear or judas_bull

        # Confluence: Judas bear confirms SHORT bias; Judas bull confirms LONG bias
        conf_bias = (
            (judas_bear and bias == "BEARISH") or
            (judas_bull and bias == "BULLISH")
        )
        return {
            "judas_detected":  detected,
            "judas_dir":       judas_dir,
            "judas_magnitude": judas_mag,
            "judas_conf_bias": conf_bias,
            "judas_note": (
                f"{'✅' if conf_bias else '⚠️'}  Judas Swing {judas_dir}: mag={judas_mag:.4g}  "
                f"{'Confirms bias' if conf_bias else 'No confluence'}"
                if detected else
                "○ No Judas Swing detected this session"
            ),
        }
    except Exception as e:
        return {"judas_detected": False, "judas_dir": "NONE",
                "judas_conf_bias": False, "judas_note": f"Judas error: {e}"}


# ══════════════════════════════════════════════════════════════════════
# THESIS P2.2 — IPDA QUARTERLY SHIFT SIGNAL
# Research: IPDA source + ICT quarterly theory (Traders With Edge 2025)
# When price CONSUMES the 60-day range high/low (reaches ERL),
# it signals an IPDA quarterly shift — price will rotate to the
# OPPOSITE side for the next 20–60 day delivery cycle.
# This is the HTF directional rotation signal.
# ══════════════════════════════════════════════════════════════════════
def compute_ipda_quarterly_shift(ipda_data: Dict, price: float, atr_htf: float) -> Dict:
    """
    Detect IPDA quarterly shift: price has consumed 60-day ERL and is rotating.
    Returns shift direction, confidence, and TP target for the new cycle.
    """
    try:
        # Use 'or {}' to handle both missing key AND key present with None value
        ipda_60 = ipda_data.get("ipda_60") or {}
        ipda_20 = ipda_data.get("ipda_20") or {}
        if not ipda_60 or not isinstance(ipda_60, dict):
            return {"quarterly_shift": False, "shift_dir": "NONE",
                    "shift_note": "No IPDA 60-day data"}

        hi_60 = float(ipda_60.get("high", 0))
        lo_60 = float(ipda_60.get("low", 0))
        hi_20 = float(ipda_20.get("high", 0)) if ipda_20 else 0
        lo_20 = float(ipda_20.get("low",  0)) if ipda_20 else 0
        if hi_60 <= 0 or lo_60 <= 0:
            return {"quarterly_shift": False, "shift_dir": "NONE",
                    "shift_note": "IPDA 60d levels unavailable"}

        # Shift threshold: price within 0.5×ATR of 60d extreme = ERL consumed
        shift_threshold = atr_htf * 0.5
        near_60_high = abs(price - hi_60) <= shift_threshold
        near_60_low  = abs(price - lo_60) <= shift_threshold

        if near_60_high:
            # Consumed 60d BSL → now rotating BEARISH to 60d low (SSL draw)
            shift_dir  = "BEARISH_ROTATION"
            shift_tp   = lo_20 if lo_20 > 0 else lo_60
            confidence = "HIGH" if abs(price - hi_60) <= atr_htf * 0.2 else "MODERATE"
        elif near_60_low:
            # Consumed 60d SSL → now rotating BULLISH to 60d high (BSL draw)
            shift_dir  = "BULLISH_ROTATION"
            shift_tp   = hi_20 if hi_20 > 0 else hi_60
            confidence = "HIGH" if abs(price - lo_60) <= atr_htf * 0.2 else "MODERATE"
        else:
            return {
                "quarterly_shift": False, "shift_dir": "NONE", "shift_tp": 0.0,
                "quarterly_shift_confidence": "NONE",
                "shift_note": (
                    f"○ IPDA: {((price-lo_60)/(hi_60-lo_60)*100):.1f}% through 60d range — "
                    f"no shift yet (ERL H={hi_60:.4g} L={lo_60:.4g})"
                ),
            }

        return {
            "quarterly_shift":             True,
            "shift_dir":                   shift_dir,
            "shift_tp":                    round(shift_tp, 8),
            "quarterly_shift_confidence":  confidence,
            "shift_note": (
                f"🔄 IPDA QUARTERLY SHIFT: {shift_dir}  [{confidence}]  "
                f"ERL consumed at {'60d HIGH' if near_60_high else '60d LOW'}  "
                f"→ TP target: {shift_tp:.4g}"
            ),
        }
    except Exception as e:
        return {"quarterly_shift": False, "shift_dir": "NONE",
                "shift_note": f"Quarterly shift error: {e}"}


# ══════════════════════════════════════════════════════════════════════
# THESIS P2.3 — UNIVERSAL CE (Consequent Encroachment) COMPUTATION
# Research: ICT inner circle canonical definition (innercircletrader.net)
# CE = 50% midpoint of ANY PD array: FVG, OB, BB, NWOG, NDOG, Void.
# Currently only computed for FVGs. This extends it to all arrays.
# ══════════════════════════════════════════════════════════════════════
def compute_universal_ce(
    ob_low: float, ob_high: float,
    fvg_low: float, fvg_high: float,
    breaker_block: Optional[Dict],
    nwog_low: float, nwog_high: float,
    ndog_low: float, ndog_high: float,
    lv_data: Optional[Dict],
) -> Dict:
    """
    Compute CE (50% midpoint) for every active PD array.
    ICT: CE is the primary magnetic level within any imbalance zone.
    Price is expected to fill to CE before reversing in high-probability setups.
    """
    def _ce(lo, hi):
        if lo > 0 and hi > 0 and hi > lo:
            return round((lo + hi) / 2, 8)
        return None

    ob_ce  = _ce(ob_low,   ob_high)
    fvg_ce = _ce(fvg_low,  fvg_high)

    bb_low  = float(breaker_block.get("bb_low",  0)) if isinstance(breaker_block, dict) else 0.0
    bb_high = float(breaker_block.get("bb_high", 0)) if isinstance(breaker_block, dict) else 0.0
    bb_ce   = _ce(bb_low, bb_high)

    nwog_ce = _ce(nwog_low, nwog_high)
    ndog_ce = _ce(ndog_low, ndog_high)

    lv_top = float((lv_data.get("lv_nearest") or {}).get("top",    0)) if isinstance(lv_data, dict) else 0.0
    lv_bot = float((lv_data.get("lv_nearest") or {}).get("bottom", 0)) if isinstance(lv_data, dict) else 0.0
    lv_ce  = _ce(lv_bot, lv_top)

    ces = {k: v for k, v in {
        "ob_ce": ob_ce, "fvg_ce": fvg_ce, "bb_ce": bb_ce,
        "nwog_ce": nwog_ce, "ndog_ce": ndog_ce, "lv_ce": lv_ce
    }.items() if v is not None}

    note_parts = [f"{k.upper().replace('_CE','')} CE={v:.4g}" for k, v in ces.items()]
    return {
        **ces,
        "all_ce_levels": list(ces.values()),
        "ce_note": "CE Levels: " + "  |  ".join(note_parts) if note_parts else "No CE levels computed",
    }


# ══════════════════════════════════════════════════════════════════════
# THESIS P3.1 — CENTRAL BANK DEALER RANGE (CBDR)
# Research: ICT ICT methodology + institutional research 2025
# CBDR = 2:00–5:00 PM EST (London close overlap / NY PM session).
# Defines the institutional "dealing range" — the range from which
# price departs during Asian session and returns to during London/NY.
# When price is INSIDE CBDR during Asia → no breakout, consolidation.
# When price BREAKS CBDR → directional delivery is beginning.
# ══════════════════════════════════════════════════════════════════════
def compute_cbdr(ohlcv_1h: list, price: float, atr: float) -> Dict:
    """
    Central Bank Dealer Range (CBDR): 2:00–5:00 PM EST / 19:00–22:00 UTC.
    Uses the last occurrence of this 3-hour window in 1H data.
    """
    if not ohlcv_1h or len(ohlcv_1h) < 5:
        return {"cbdr_high": 0.0, "cbdr_low": 0.0, "cbdr_active": False,
                "cbdr_break": "NONE", "cbdr_note": "Insufficient 1H data for CBDR"}
    try:
        now_h = datetime.datetime.utcnow().hour
        # CBDR in UTC: 19:00–22:00
        cbdr_utc_start, cbdr_utc_end = 19, 22
        # Find candles from the CBDR window — look back up to 30 candles
        cbdr_candles = []
        for c in reversed(ohlcv_1h[-30:]):
            # We don't have timestamps per candle, so approximate:
            # The last 3–6 candles typically represent the 3h CBDR block
            if len(cbdr_candles) < 3:
                cbdr_candles.append(c)
        if not cbdr_candles:
            cbdr_candles = ohlcv_1h[-3:]

        cbdr_high = max(float(c[1]) for c in cbdr_candles if len(c) >= 4)
        cbdr_low  = min(float(c[2]) for c in cbdr_candles if len(c) >= 4)
        cbdr_mid  = (cbdr_high + cbdr_low) / 2
        cbdr_ce   = round(cbdr_mid, 8)
        cbdr_rng  = cbdr_high - cbdr_low

        # Price position relative to CBDR
        inside_cbdr = cbdr_low <= price <= cbdr_high
        broke_high  = price > cbdr_high + atr * 0.2
        broke_low   = price < cbdr_low  - atr * 0.2

        if broke_high:
            cbdr_break = "BULLISH_BREAK"
            note_dir   = "→ BULLISH delivery expected"
        elif broke_low:
            cbdr_break = "BEARISH_BREAK"
            note_dir   = "→ BEARISH delivery expected"
        elif inside_cbdr:
            cbdr_break = "INSIDE"
            note_dir   = "→ Consolidation / no breakout"
        else:
            cbdr_break = "NONE"
            note_dir   = "→ Awaiting range formation"

        return {
            "cbdr_high":   round(cbdr_high, 8),
            "cbdr_low":    round(cbdr_low,  8),
            "cbdr_mid":    round(cbdr_mid,  8),
            "cbdr_ce":     cbdr_ce,
            "cbdr_range":  round(cbdr_rng,  8),
            "cbdr_break":  cbdr_break,
            "cbdr_active": inside_cbdr,
            "cbdr_note": (
                f"CBDR: H={cbdr_high:.4g} L={cbdr_low:.4g}  "
                f"CE={cbdr_ce:.4g}  [{cbdr_break}]  {note_dir}"
            ),
        }
    except Exception as e:
        return {"cbdr_high": 0.0, "cbdr_low": 0.0, "cbdr_active": False,
                "cbdr_break": "NONE", "cbdr_note": f"CBDR error: {e}"}


# ══════════════════════════════════════════════════════════════════════
# THESIS P3.2 — IMPLIED FVG (Hidden Imbalance / Body-Wick Overlap)
# Research: advanced ICT curriculum 2025
# Implied FVG occurs when a large displacement candle has wicks that
# OVERLAP the bodies of adjacent candles — no visual three-candle gap
# exists, but a HIDDEN imbalance is present at the CE zone of the move.
# Distinct from standard FVG (three-candle gap) and IFVG (blown FVG).
# The CE of the implied FVG is the precision entry/rejection level.
# ══════════════════════════════════════════════════════════════════════
def detect_implied_fvg(ohlcv: list, bias: str, atr: float) -> Dict:
    """
    Detect an Implied FVG (hidden imbalance) in recent candles.
    Criteria:
    - Large displacement candle: body > 1.5×ATR
    - Wicks overlap adjacent candle bodies (no clean gap = implied imbalance)
    - CE of the displacement candle body = precision entry
    """
    if len(ohlcv) < 4 or atr <= 0:
        return {"implied_fvg": False, "ifvg_ce": 0.0, "ifvg_note": "Insufficient data"}
    try:
        # Scan last 10 candles for large displacement candles
        for i in range(max(1, len(ohlcv) - 10), len(ohlcv) - 1):
            o, h, l, c = float(ohlcv[i][0]), float(ohlcv[i][1]), float(ohlcv[i][2]), float(ohlcv[i][3])
            body    = abs(c - o)
            candle_range = h - l

            # Must be a displacement candle (body > 1.5×ATR)
            if body < atr * 1.5:
                continue

            is_bull_disp = c > o and bias == "BULLISH"
            is_bear_disp = c < o and bias == "BEARISH"

            if not (is_bull_disp or is_bear_disp):
                continue

            # Check wick overlap with previous candle body
            prev = ohlcv[i - 1]
            prev_o, prev_c = float(prev[0]), float(prev[3])
            prev_body_top = max(prev_o, prev_c)
            prev_body_bot = min(prev_o, prev_c)

            if is_bull_disp:
                # Lower wick should overlap previous candle body
                wick_overlap = l <= prev_body_top and l >= prev_body_bot
            else:
                # Upper wick should overlap previous candle body
                wick_overlap = h >= prev_body_bot and h <= prev_body_top

            if wick_overlap:
                # CE of the displacement body = hidden precision level
                body_top = max(o, c)
                body_bot = min(o, c)
                ifvg_ce  = round((body_top + body_bot) / 2, 8)
                return {
                    "implied_fvg":  True,
                    "ifvg_ce":      ifvg_ce,
                    "ifvg_top":     round(body_top, 8),
                    "ifvg_bot":     round(body_bot, 8),
                    "ifvg_bias":    "BULLISH" if is_bull_disp else "BEARISH",
                    "ifvg_note": (
                        f"✅ Implied FVG: body {body_bot:.4g}–{body_top:.4g}  "
                        f"CE={ifvg_ce:.4g}  (hidden imbalance — wick/body overlap)"
                    ),
                }

        return {"implied_fvg": False, "ifvg_ce": 0.0,
                "ifvg_note": "○ No Implied FVG detected in recent candles"}
    except Exception as e:
        return {"implied_fvg": False, "ifvg_ce": 0.0, "ifvg_note": f"IFVG error: {e}"}


# ══════════════════════════════════════════════════════════════════════
# THESIS P3.3 — ICT QUARTERLY THEORY (Fractal AMD Structure)
# Research: ICT Quarterly Theory Mar 2025 + Traders With Edge
# AMD = Accumulation → Manipulation → Distribution (fractal at all TFs).
# The quarterly theory assigns AMD phases to YEARLY, MONTHLY, WEEKLY,
# DAILY, and SESSION levels. Each period's Q1 = Accumulation, etc.
# True Opens: Jan 1 (yearly), 1st of month, Monday open, day open.
# ══════════════════════════════════════════════════════════════════════
def compute_quarterly_theory_context(ohlcv_daily: list, price: float) -> Dict:
    """
    Determine ICT Quarterly Theory phase context:
    - Which yearly quarter we're in (Q1/Q2/Q3/Q4)
    - Which monthly AMD phase (first 3rd, second 3rd, final 3rd of month)
    - Which weekly phase (Mon=Accum, Tue/Wed=Manip, Thu/Fri=Distrib)
    - True Open references (monthly open, weekly open)
    - Price position in AMD context
    """
    try:
        now = datetime.datetime.utcnow()
        month = now.month
        day   = now.day
        weekday = now.weekday()   # 0=Mon, 6=Sun

        # ── YEARLY QUARTER
        yearly_q = ((month - 1) // 3) + 1
        yearly_phase = {1: "ACCUMULATION (Q1 Jan–Mar)",
                        2: "MANIPULATION (Q2 Apr–Jun)",
                        3: "DISTRIBUTION  (Q3 Jul–Sep)",
                        4: "REBALANCE     (Q4 Oct–Dec)"}[yearly_q]

        # ── MONTHLY AMD PHASE (3-part split)
        if day <= 10:
            monthly_phase = "ACCUMULATION"
            monthly_note  = f"Day {day}/~30 — Early month: consolidation / accumulation"
        elif day <= 20:
            monthly_phase = "MANIPULATION"
            monthly_note  = f"Day {day}/~30 — Mid month: manipulation / stop hunt expected"
        else:
            monthly_phase = "DISTRIBUTION"
            monthly_note  = f"Day {day}/~30 — Late month: distribution / directional delivery"

        # ── WEEKLY AMD PHASE
        weekly_phase_map = {
            0: ("ACCUMULATION", "Monday — institutions accumulate positions"),
            1: ("MANIPULATION", "Tuesday — most common Judas Swing day"),
            2: ("MANIPULATION", "Wednesday — mid-week manipulation / reversal"),
            3: ("DISTRIBUTION", "Thursday — directional delivery begins"),
            4: ("DISTRIBUTION", "Friday — end of week profit taking / NWOG setup"),
            5: ("WEEKEND",      "Saturday — no institutional activity"),
            6: ("WEEKEND",      "Sunday — gap risk / NWOG formation"),
        }
        weekly_phase, weekly_note = weekly_phase_map.get(weekday, ("UNKNOWN", "Unknown"))

        # ── TRUE OPEN references from daily OHLCV
        monthly_open = float(ohlcv_daily[-day][0]) if ohlcv_daily and len(ohlcv_daily) >= day else 0.0
        weekly_open  = float(ohlcv_daily[-min(weekday+1, len(ohlcv_daily))][0]) if ohlcv_daily else 0.0

        # ── Price position relative to monthly true open
        price_above_monthly_open = price > monthly_open if monthly_open > 0 else None
        price_above_weekly_open  = price > weekly_open  if weekly_open  > 0 else None

        return {
            "yearly_q":              f"Q{yearly_q}",
            "yearly_phase":          yearly_phase,
            "monthly_phase":         monthly_phase,
            "monthly_note":          monthly_note,
            "weekly_phase":          weekly_phase,
            "weekly_note":           weekly_note,
            "monthly_true_open":     round(monthly_open, 8),
            "weekly_true_open":      round(weekly_open,  8),
            "price_above_monthly":   price_above_monthly_open,
            "price_above_weekly":    price_above_weekly_open,
            "qt_note": (
                f"QT: Yearly {yearly_phase[:2].strip()} Q{yearly_q}  |  "
                f"Monthly: {monthly_phase}  |  Weekly: {weekly_phase}  "
                f"({weekly_note})"
            ),
        }
    except Exception as e:
        return {
            "yearly_q": "?", "yearly_phase": "UNKNOWN",
            "monthly_phase": "UNKNOWN", "weekly_phase": "UNKNOWN",
            "qt_note": f"QT error: {e}",
        }


# ── TIER 2 #9: BSL/SSL Precise Level Computation ───────────────
def compute_bsl_ssl_levels(ohlcv_htf: list, price: float, atr: float) -> Dict:
    """
    Buy Side Liquidity (BSL) = Equal highs / swing highs above price (stop hunt target).
    Sell Side Liquidity (SSL) = Equal lows / swing lows below price (stop hunt target).
    Computes precise levels, distance, and primary draw direction.
    """
    if not ohlcv_htf or len(ohlcv_htf) < 10:
        return {"bsl_level": 0.0, "ssl_level": 0.0, "primary_draw": "BSL",
                "bsl_ssl_note": "Insufficient data"}
    try:
        highs  = [float(c[1]) for c in ohlcv_htf if len(c) >= 4]
        lows   = [float(c[2]) for c in ohlcv_htf if len(c) >= 4]
        n = len(highs)
        # Find swing highs (local maxima) and swing lows (local minima) in last 50 candles
        window = min(50, n)
        swing_highs_lvl, swing_lows_lvl = [], []
        for i in range(2, window - 2):
            idx = n - window + i
            if highs[idx] > highs[idx-1] and highs[idx] > highs[idx+1]:
                swing_highs_lvl.append(highs[idx])
            if lows[idx] < lows[idx-1] and lows[idx] < lows[idx+1]:
                swing_lows_lvl.append(lows[idx])
        # Find Equal Highs (within 0.15% of each other) — BSL cluster
        def _find_eq_cluster(levels, tol=0.0015):
            if len(levels) < 2:
                return max(levels) if levels else 0.0
            levels_s = sorted(levels, reverse=True)
            clusters = []
            for l in levels_s:
                found = False
                for cl in clusters:
                    if abs(l - cl[0]) / max(cl[0], 1e-9) < tol:
                        cl.append(l); found = True; break
                if not found:
                    clusters.append([l])
            best = max(clusters, key=len) if clusters else [levels_s[0]]
            return round(sum(best) / len(best), 8)
        bsl_lvls_above = [h for h in swing_highs_lvl if h > price + atr * 0.3]
        ssl_lvls_below = [l for l in swing_lows_lvl  if l < price - atr * 0.3]
        bsl_level = _find_eq_cluster(bsl_lvls_above) if bsl_lvls_above else round(max(highs[-20:]), 8)
        ssl_level = _find_eq_cluster(ssl_lvls_below) if ssl_lvls_below else round(min(lows[-20:]),  8)
        dist_to_bsl = abs(price - bsl_level) if bsl_level > 0 else float("inf")
        dist_to_ssl = abs(price - ssl_level) if ssl_level > 0 else float("inf")
        primary_draw = "BSL" if dist_to_bsl < dist_to_ssl else "SSL"
        return {
            "bsl_level":    bsl_level,
            "ssl_level":    ssl_level,
            "dist_to_bsl":  round(dist_to_bsl, 8),
            "dist_to_ssl":  round(dist_to_ssl, 8),
            "primary_draw": primary_draw,
            "bsl_ssl_note": (
                f"BSL={bsl_level:.4g} SSL={ssl_level:.4g} "
                f"| Primary draw → {primary_draw}"
            ),
        }
    except Exception as e:
        return {"bsl_level": 0.0, "ssl_level": 0.0, "primary_draw": "BSL",
                "bsl_ssl_note": f"BSL/SSL error: {e}"}


# ── TIER 2 #11: Turtle Soup Pattern Detection ───────────────────
def detect_turtle_soup(ohlcv_htf: list, bias: str, atr: float) -> Dict:
    """
    Turtle Soup — price makes new N-bar high/low (triggers retail breakout buyers/sellers),
    then reverses hard within 2 candles, trapping them.
    Entry: against breakout. SL: above/below the new extreme. TP: prior range midpoint.
    Lookback: 20 bars. Reversal: close back inside within 2 candles.
    """
    if not ohlcv_htf or len(ohlcv_htf) < 25:
        return {"turtle_soup": False, "ts_note": "Insufficient data", "ts_gate": False}
    try:
        highs  = [float(c[1]) for c in ohlcv_htf if len(c) >= 4]
        lows   = [float(c[2]) for c in ohlcv_htf if len(c) >= 4]
        closes = [float(c[3]) for c in ohlcv_htf if len(c) >= 4]
        n = len(closes)
        lookback = 20
        recent_high = max(highs[-(lookback+2):-2])
        recent_low  = min(lows[-(lookback+2):-2])
        # Check last 2 candles for: spike beyond, then close back inside
        for i in [-2, -1]:
            h_i = highs[i];  l_i = lows[i];  c_i = closes[i]
            # Bullish Turtle Soup: spike below recent_low, close ABOVE recent_low
            if bias == "BULLISH":
                if l_i < recent_low - atr * 0.1 and c_i > recent_low:
                    return {
                        "turtle_soup":   True,
                        "ts_direction":  "BULLISH",
                        "ts_level":      round(recent_low, 8),
                        "ts_gate":       True,
                        "ts_note": f"✅ Turtle Soup BULLISH: spike to {l_i:.4g} below {recent_low:.4g}, close recovered",
                    }
            # Bearish Turtle Soup: spike above recent_high, close BELOW recent_high
            elif bias == "BEARISH":
                if h_i > recent_high + atr * 0.1 and c_i < recent_high:
                    return {
                        "turtle_soup":   True,
                        "ts_direction":  "BEARISH",
                        "ts_level":      round(recent_high, 8),
                        "ts_gate":       True,
                        "ts_note": f"✅ Turtle Soup BEARISH: spike to {h_i:.4g} above {recent_high:.4g}, close recovered",
                    }
        return {"turtle_soup": False, "ts_note": "No turtle soup pattern detected", "ts_gate": False}
    except Exception as e:
        return {"turtle_soup": False, "ts_note": f"Turtle soup error: {e}", "ts_gate": False}


# ── TIER 2 #12: Mitigation Block Tracking ──────────────────────
_OB_MITIGATION_MEMORY: Dict[str, List[Dict]] = {}   # symbol → list of OB records

def track_ob_mitigation(symbol: str, ob_low: float, ob_high: float,
                         price: float, bias: str) -> Dict:
    """
    Track whether each detected OB has been mitigated (price traded through it).
    Unmitigated OB = fresh (strong). Mitigated OB = weakened (breaker candidate).
    Stores per-symbol OB history to detect repeating entries into dead zones.
    """
    if symbol not in _OB_MITIGATION_MEMORY:
        _OB_MITIGATION_MEMORY[symbol] = []
    records = _OB_MITIGATION_MEMORY[symbol]
    # Check if this OB level already mitigated
    ob_key = f"{round(ob_low,4)}_{round(ob_high,4)}"
    for rec in records:
        if rec["key"] == ob_key:
            if rec["mitigated"]:
                return {
                    "ob_fresh":     False,
                    "ob_mitigated": True,
                    "ob_mit_note":  f"⚠️ OB MITIGATED: {ob_low:.4g}–{ob_high:.4g} already touched — weaker setup",
                    "ob_touch_count": rec.get("touches", 1),
                }
            else:
                # Check if current price now touching/inside OB
                inside = ob_low <= price <= ob_high
                if inside:
                    rec["mitigated"] = True
                    rec["touches"] = rec.get("touches", 0) + 1
                return {
                    "ob_fresh":     True,
                    "ob_mitigated": False,
                    "ob_mit_note":  f"✅ OB FRESH: {ob_low:.4g}–{ob_high:.4g} unmitigated",
                    "ob_touch_count": rec.get("touches", 0),
                }
    # New OB — register it
    records.append({"key": ob_key, "low": ob_low, "high": ob_high,
                    "bias": bias, "mitigated": False, "touches": 0})
    # Evict old records (keep last 10 per symbol)
    if len(records) > 10:
        _OB_MITIGATION_MEMORY[symbol] = records[-10:]
    return {
        "ob_fresh":     True,
        "ob_mitigated": False,
        "ob_mit_note":  f"✅ OB NEW: {ob_low:.4g}–{ob_high:.4g} registered (fresh)",
        "ob_touch_count": 0,
    }


# ── TIER 3 #18: RSI Classic + Hidden Divergence ─────────────────
def compute_rsi_divergence(ohlcv_htf: list, bias: str, lookback: int = 14) -> Dict:
    """
    RSI Classic Divergence: price new high + RSI lower high = distribution (bearish).
    RSI Hidden  Divergence: price higher low + RSI lower low = continuation (bullish).
    Classic fires against trend (reversal warning). Hidden fires with trend (confirmation).
    """
    if not ohlcv_htf or len(ohlcv_htf) < lookback * 2 + 5:
        return {"rsi_div_classic": False, "rsi_div_hidden": False,
                "rsi_div_note": "Insufficient data", "rsi_div_conf_mod": 1.0}
    try:
        closes = [float(c[3]) for c in ohlcv_htf if len(c) >= 4]
        n = len(closes)
        # Compute RSI for last 2*lookback candles
        def _rsi(cl, period=14):
            if len(cl) < period + 1:
                return 50.0
            gains, losses = [], []
            for i in range(1, len(cl)):
                d = cl[i] - cl[i-1]
                gains.append(max(d, 0)); losses.append(max(-d, 0))
            ag = sum(gains[-period:]) / period
            al = sum(losses[-period:]) / period
            if al == 0:
                return 100.0
            rs = ag / al
            return round(100 - 100 / (1 + rs), 2)
        window = min(lookback * 3, n)
        half   = window // 2
        rsi_recent = _rsi(closes[-half:],   period=lookback)
        rsi_prior  = _rsi(closes[-window:-half], period=lookback)
        price_recent_high = max(closes[-half:])
        price_prior_high  = max(closes[-window:-half])
        price_recent_low  = min(closes[-half:])
        price_prior_low   = min(closes[-window:-half])
        # Classic Bearish: price higher high + RSI lower high → distribution
        classic_bearish = (price_recent_high > price_prior_high * 1.002) and (rsi_recent < rsi_prior - 2)
        # Classic Bullish: price lower low + RSI higher low → accumulation
        classic_bullish = (price_recent_low < price_prior_low * 0.998) and (rsi_recent > rsi_prior + 2)
        # Hidden Bullish: price higher low + RSI lower low → continuation bullish
        hidden_bullish  = (price_recent_low > price_prior_low * 1.002) and (rsi_recent < rsi_prior - 2)
        # Hidden Bearish: price lower high + RSI higher high → continuation bearish
        hidden_bearish  = (price_recent_high < price_prior_high * 0.998) and (rsi_recent > rsi_prior + 2)
        # Apply to bias
        if bias == "BULLISH":
            if classic_bearish:
                conf_mod = 0.85; note = f"⚠️ RSI Classic BEARISH div — price HH, RSI {rsi_prior:.1f}→{rsi_recent:.1f} ↓"
            elif hidden_bullish:
                conf_mod = 1.05; note = f"✅ RSI Hidden BULLISH div — continuation confirmed"
            else:
                conf_mod = 1.0;  note = f"RSI: No significant divergence (RSI {rsi_recent:.1f})"
        else:
            if classic_bullish:
                conf_mod = 0.85; note = f"⚠️ RSI Classic BULLISH div — price LL, RSI {rsi_prior:.1f}→{rsi_recent:.1f} ↑"
            elif hidden_bearish:
                conf_mod = 1.05; note = f"✅ RSI Hidden BEARISH div — continuation confirmed"
            else:
                conf_mod = 1.0;  note = f"RSI: No significant divergence (RSI {rsi_recent:.1f})"
        return {
            "rsi_div_classic":  classic_bearish or classic_bullish,
            "rsi_div_hidden":   hidden_bullish  or hidden_bearish,
            "rsi_div_bearish":  classic_bearish,
            "rsi_div_bullish":  classic_bullish,
            "rsi_div_conf_mod": conf_mod,
            "rsi_recent":       rsi_recent,
            "rsi_prior":        rsi_prior,
            "rsi_div_note":     note,
        }
    except Exception as e:
        return {"rsi_div_classic": False, "rsi_div_hidden": False,
                "rsi_div_note": f"RSI div error: {e}", "rsi_div_conf_mod": 1.0}


# ── TIER 3 #19: VSA (Volume Spread Analysis) ────────────────────
def compute_vsa(ohlcv_htf: list, bias: str) -> Dict:
    """
    Volume Spread Analysis — 3 key signals:
      No-Supply Bar:   Low volume + narrow spread + close near top (bullish)
      Absorption:      High volume + narrow spread (smart money absorbing supply)
      Stopping Volume: Ultra-high volume + close reversal (reversal confirmation)
    """
    if not ohlcv_htf or len(ohlcv_htf) < 20:
        return {"vsa_signal": "NONE", "vsa_note": "Insufficient data", "vsa_conf_mod": 1.0}
    try:
        window = min(20, len(ohlcv_htf))
        recent = ohlcv_htf[-window:]
        vols   = [float(c[4]) if len(c) > 4 else 0.0 for c in recent]
        ranges = [float(c[1]) - float(c[2]) for c in recent if len(c) >= 4]
        closes = [float(c[3]) for c in recent if len(c) >= 4]
        opens  = [float(c[0]) for c in recent if len(c) >= 4]
        if not vols or sum(vols) == 0:
            return {"vsa_signal": "NO_VOLUME_DATA", "vsa_note": "No volume data",
                    "vsa_conf_mod": 1.0}
        avg_vol   = sum(vols) / len(vols)
        avg_range = sum(ranges) / max(len(ranges), 1)
        # Last candle
        last_vol   = vols[-1]
        last_range = ranges[-1] if ranges else 0
        last_close = closes[-1] if closes else 0
        last_open  = opens[-1]  if opens  else 0
        last_body  = abs(last_close - last_open)
        # VSA signals
        low_vol   = last_vol   < avg_vol   * 0.5
        high_vol  = last_vol   > avg_vol   * 1.8
        narrow_sp = last_range < avg_range * 0.6
        wide_sp   = last_range > avg_range * 1.4
        # Close position in range
        if last_range > 0:
            close_pos = (last_close - (last_close - last_range/2)) / last_range
        else:
            close_pos = 0.5
        up_close  = last_close > last_open
        dn_close  = last_close < last_open
        # No-Supply (bullish): low vol + narrow spread + up close
        if bias == "BULLISH" and low_vol and narrow_sp and up_close:
            signal, conf_mod = "NO_SUPPLY", 1.08
            note = "✅ VSA No-Supply: low vol pullback → bulls in control"
        # No-Demand (bearish): low vol + narrow spread + down close
        elif bias == "BEARISH" and low_vol and narrow_sp and dn_close:
            signal, conf_mod = "NO_DEMAND", 1.08
            note = "✅ VSA No-Demand: low vol rally → bears in control"
        # Absorption: high vol + narrow spread (institutions absorbing)
        elif high_vol and narrow_sp:
            signal, conf_mod = "ABSORPTION", 1.05
            note = "✅ VSA Absorption: high vol + narrow spread → smart money absorbing"
        # Stopping Volume (bullish reversal): high vol + down candle but narrow range
        elif bias == "BULLISH" and high_vol and dn_close and not wide_sp:
            signal, conf_mod = "STOPPING_VOL_BULL", 1.06
            note = "✅ VSA Stopping Volume: bearish candle absorbed → bullish reversal"
        elif bias == "BEARISH" and high_vol and up_close and not wide_sp:
            signal, conf_mod = "STOPPING_VOL_BEAR", 1.06
            note = "✅ VSA Stopping Volume: bullish candle absorbed → bearish reversal"
        # Effort without result: high vol but price closes unchanged
        elif high_vol and last_body < avg_range * 0.3:
            signal, conf_mod = "EFFORT_NO_RESULT", 0.92
            note = "⚠️ VSA Effort without result: high vol but no directional close"
        else:
            signal, conf_mod = "NORMAL", 1.0
            note = f"VSA: Normal conditions (vol={last_vol:.0f} avg={avg_vol:.0f})"
        return {
            "vsa_signal":   signal,
            "vsa_conf_mod": conf_mod,
            "vsa_note":     note,
            "vsa_last_vol": round(last_vol, 2),
            "vsa_avg_vol":  round(avg_vol, 2),
        }
    except Exception as e:
        return {"vsa_signal": "NONE", "vsa_note": f"VSA error: {e}", "vsa_conf_mod": 1.0}


# ── TIER 3 #22: StochRSI for LTF Entry Timing ──────────────────
def compute_stoch_rsi(ohlcv_ltf: list, period: int = 14, smooth_k: int = 3) -> Dict:
    """
    Stochastic RSI — normalizes RSI over a lookback for overbought/oversold on LTF.
    %K < 20 + oversold = bullish entry zone. %K > 80 + overbought = bearish entry zone.
    Used for RTCW sub-scoring and LTF entry precision timing.
    """
    if not ohlcv_ltf or len(ohlcv_ltf) < period * 2 + smooth_k + 2:
        return {"stoch_rsi_k": 50.0, "stoch_rsi_d": 50.0,
                "stoch_oversold": False, "stoch_overbought": False,
                "stoch_note": "Insufficient LTF data"}
    try:
        closes = [float(c[3]) for c in ohlcv_ltf if len(c) >= 4]
        n = len(closes)
        # Compute RSI series for last (period * 2 + smooth_k) candles
        rsi_series = []
        window_needed = period * 2 + smooth_k
        for end in range(n - window_needed, n):
            sub = closes[max(0, end - period - 1):end + 1]
            if len(sub) < period + 1:
                rsi_series.append(50.0)
                continue
            gains, losses = [], []
            for i in range(1, len(sub)):
                d = sub[i] - sub[i-1]
                gains.append(max(d, 0)); losses.append(max(-d, 0))
            ag = sum(gains[-period:]) / period
            al = sum(losses[-period:]) / period
            rs = ag / max(al, 1e-9)
            rsi_series.append(100 - 100 / (1 + rs))
        if len(rsi_series) < period + smooth_k:
            return {"stoch_rsi_k": 50.0, "stoch_rsi_d": 50.0,
                    "stoch_oversold": False, "stoch_overbought": False,
                    "stoch_note": "RSI series too short"}
        # StochRSI %K = (RSI - lowest RSI) / (highest RSI - lowest RSI) over period
        stoch_k_series = []
        for i in range(period, len(rsi_series)):
            sub_rsi = rsi_series[i - period:i + 1]
            lo_rsi = min(sub_rsi); hi_rsi = max(sub_rsi)
            rng = hi_rsi - lo_rsi
            k = (rsi_series[i] - lo_rsi) / max(rng, 1e-9) * 100 if rng > 0 else 50.0
            stoch_k_series.append(round(k, 2))
        # %D = 3-period SMA of %K
        if len(stoch_k_series) >= smooth_k:
            stoch_k = stoch_k_series[-1]
            stoch_d = round(sum(stoch_k_series[-smooth_k:]) / smooth_k, 2)
        else:
            stoch_k, stoch_d = 50.0, 50.0
        oversold   = stoch_k < 20
        overbought = stoch_k > 80
        note = (f"StochRSI %K={stoch_k:.1f} %D={stoch_d:.1f} — "
                f"{'🟢 OVERSOLD — buy zone' if oversold else '🔴 OVERBOUGHT — sell zone' if overbought else '🟡 Neutral'}")
        return {
            "stoch_rsi_k":      stoch_k,
            "stoch_rsi_d":      stoch_d,
            "stoch_oversold":   oversold,
            "stoch_overbought": overbought,
            "stoch_note":       note,
        }
    except Exception as e:
        return {"stoch_rsi_k": 50.0, "stoch_rsi_d": 50.0,
                "stoch_oversold": False, "stoch_overbought": False,
                "stoch_note": f"StochRSI error: {e}"}


# ── TIER 3 #24: Composite Candle Anatomy Score ─────────────────
def compute_candle_anatomy_score(ohlcv_ltf: list, bias: str) -> Dict:
    """
    Institutional entry candle anatomy — 3 criteria:
      1. Wick ≥ 50% total range on correct side (rejection wick)
      2. Close in top/bottom 30% of candle range (for long/short)
      3. Body ≥ 50% total range (conviction close)
    Score: 0–3. 2+ = valid institutional entry candle.
    """
    if not ohlcv_ltf or len(ohlcv_ltf) < 2:
        return {"candle_anatomy_score": 0, "candle_anatomy_valid": False,
                "candle_anatomy_note": "No LTF data"}
    try:
        last = ohlcv_ltf[-1]
        if len(last) < 4:
            return {"candle_anatomy_score": 0, "candle_anatomy_valid": False,
                    "candle_anatomy_note": "Bad candle data"}
        o, h, l, c = float(last[0]), float(last[1]), float(last[2]), float(last[3])
        total_range = h - l
        if total_range <= 0:
            return {"candle_anatomy_score": 0, "candle_anatomy_valid": False,
                    "candle_anatomy_note": "Zero-range candle"}
        body = abs(c - o)
        upper_wick = h - max(o, c)
        lower_wick = min(o, c) - l
        close_pos  = (c - l) / total_range   # 0 = at low, 1 = at high
        score = 0
        details = []
        if bias == "BULLISH":
            # Criterion 1: Lower wick >= 50% range (rejection of lows)
            if lower_wick >= total_range * 0.5:
                score += 1; details.append("✅ Lower wick ≥50%")
            else:
                details.append(f"❌ Lower wick {lower_wick/total_range*100:.0f}%<50%")
            # Criterion 2: Close in top 30% of range
            if close_pos >= 0.70:
                score += 1; details.append("✅ Close top 30%")
            else:
                details.append(f"❌ Close at {close_pos*100:.0f}% (need ≥70%)")
            # Criterion 3: Body >= 50% total range
            if body >= total_range * 0.50:
                score += 1; details.append("✅ Body ≥50% range")
            else:
                details.append(f"❌ Body {body/total_range*100:.0f}%<50%")
        else:  # BEARISH
            if upper_wick >= total_range * 0.5:
                score += 1; details.append("✅ Upper wick ≥50%")
            else:
                details.append(f"❌ Upper wick {upper_wick/total_range*100:.0f}%<50%")
            if close_pos <= 0.30:
                score += 1; details.append("✅ Close bottom 30%")
            else:
                details.append(f"❌ Close at {close_pos*100:.0f}% (need ≤30%)")
            if body >= total_range * 0.50:
                score += 1; details.append("✅ Body ≥50% range")
            else:
                details.append(f"❌ Body {body/total_range*100:.0f}%<50%")
        valid = score >= 2
        return {
            "candle_anatomy_score":   score,
            "candle_anatomy_valid":   valid,
            "candle_anatomy_note":    f"Candle anatomy {score}/3: {' | '.join(details)}",
            "candle_anatomy_details": details,
        }
    except Exception as e:
        return {"candle_anatomy_score": 0, "candle_anatomy_valid": False,
                "candle_anatomy_note": f"Candle anatomy error: {e}"}


# ── TIER 4 #25: Liquidity Void Detection ────────────────────────
def detect_liquidity_void(ohlcv_htf: list, price: float, atr: float, bias: str) -> Dict:
    """
    Liquidity Void (LV) — region of fast price movement, minimal bids/asks.
    Price moves > 2× ATR in a single candle with no overlap with prior candle.
    Gravitation: price always returns to fill LVs (TP magnet).
    Distinct from FVG (FVG = 3-candle gap; LV = single-candle void).
    """
    if not ohlcv_htf or len(ohlcv_htf) < 5:
        return {"lv_detected": False, "lv_levels": [], "lv_note": "Insufficient data"}
    try:
        lv_levels = []
        for i in range(1, min(30, len(ohlcv_htf))):
            idx = len(ohlcv_htf) - i
            if idx < 1:
                break
            c_curr = ohlcv_htf[idx]
            c_prev = ohlcv_htf[idx - 1]
            if len(c_curr) < 4 or len(c_prev) < 4:
                continue
            lo_curr, hi_curr = float(c_curr[2]), float(c_curr[1])
            lo_prev, hi_prev = float(c_prev[2]), float(c_prev[1])
            # Bullish void: current low > prior high (no overlap, fast up-move)
            if lo_curr > hi_prev and (lo_curr - hi_prev) > atr * 0.3:
                lv_levels.append({
                    "type": "BULLISH_VOID",
                    "top": round(lo_curr, 8),
                    "bottom": round(hi_prev, 8),
                    "size": round(lo_curr - hi_prev, 8),
                })
            # Bearish void: current high < prior low (no overlap, fast dn-move)
            elif hi_curr < lo_prev and (lo_prev - hi_curr) > atr * 0.3:
                lv_levels.append({
                    "type": "BEARISH_VOID",
                    "top": round(lo_prev, 8),
                    "bottom": round(hi_curr, 8),
                    "size": round(lo_prev - hi_curr, 8),
                })
        # Filter to voids near price (within 5× ATR)
        nearby_lv = [lv for lv in lv_levels
                     if abs(price - (lv["top"] + lv["bottom"]) / 2) < atr * 5]
        detected = len(nearby_lv) > 0
        nearest = nearby_lv[0] if nearby_lv else None
        return {
            "lv_detected":  detected,
            "lv_levels":    nearby_lv[:3],
            "lv_nearest":   nearest,
            "lv_count":     len(nearby_lv),
            "lv_note": (
                f"LV: {len(nearby_lv)} void(s) near price "
                f"| Nearest: {nearest['type']} {nearest['bottom']:.4g}–{nearest['top']:.4g}"
                if nearby_lv else "LV: No liquidity voids detected near price"
            ),
        }
    except Exception as e:
        return {"lv_detected": False, "lv_levels": [], "lv_note": f"LV error: {e}"}


# ── TIER 4 #21: Unicorn Model Detection ─────────────────────────
def detect_unicorn_model(ohlcv_htf: list, bias: str, bos_data: Dict,
                          ob_low: float, ob_high: float,
                          fvg_low: float, fvg_high: float, atr: float) -> Dict:
    """
    Unicorn Model — ICT highest-probability entry:
      1. Liquidity sweep (BSL/SSL swept)
      2. BOS/MSS confirms (structure breaks in new direction)
      3. Breaker Block forms (mitigated OB flips)
      4. FVG from manipulation leg = entry zone (Unicorn FVG)
    When all 4 conditions present → Unicorn model active → S-tier setup.
    """
    if not ohlcv_htf or len(ohlcv_htf) < 10:
        return {"unicorn_active": False, "unicorn_note": "Insufficient data",
                "unicorn_conf_bonus": 0}
    try:
        sweep_confirmed = bos_data.get("swept_price", 0) > 0 or bos_data.get("sweep_confirmed", False)
        bos_valid       = bos_data.get("structure_valid", False)
        fvg_valid       = fvg_high > fvg_low > 0
        ob_valid        = ob_high > ob_low > 0
        # Price retracing into FVG after BOS = Unicorn entry zone
        closes = [float(c[3]) for c in ohlcv_htf if len(c) >= 4]
        price = closes[-1] if closes else 0
        if bias == "BULLISH":
            in_fvg = fvg_low <= price <= fvg_high if fvg_valid else False
            above_ob = price > ob_low if ob_valid else False
        else:
            in_fvg = fvg_low <= price <= fvg_high if fvg_valid else False
            below_ob = price < ob_high if ob_valid else False
        conditions_met = sum([sweep_confirmed, bos_valid, fvg_valid, in_fvg])
        active = conditions_met >= 3
        conf_bonus = 8 if conditions_met == 4 else (4 if conditions_met == 3 else 0)
        return {
            "unicorn_active":      active,
            "unicorn_conditions":  conditions_met,
            "unicorn_conf_bonus":  conf_bonus,
            "unicorn_note": (
                f"{'🦄 UNICORN ACTIVE (' + str(conditions_met) + '/4 conditions)' if active else '○ Unicorn: ' + str(conditions_met) + '/4 conditions'}"
            ),
        }
    except Exception as e:
        return {"unicorn_active": False, "unicorn_note": f"Unicorn error: {e}",
                "unicorn_conf_bonus": 0}


# ── TIER 4 #27: On-Chain vs Price Divergence ────────────────────
def compute_onchain_price_divergence(onchain: Dict, bias: str,
                                      change_pct: float) -> Dict:
    """
    Divergence between on-chain sentiment and price action direction.
    Rising F&G + falling price = bullish divergence (accumulation).
    Falling F&G + rising price = bearish divergence (distribution).
    """
    if not onchain or not onchain.get("available"):
        return {"onchain_price_div": False, "onchain_div_note": "No on-chain data",
                "onchain_div_conf_mod": 1.0}
    try:
        fg = onchain.get("fear_greed_index", 50) or 50
        price_up   = change_pct > 1.0
        price_down = change_pct < -1.0
        # Bearish divergence: price rising but sentiment declining (euphoria → distribution)
        bearish_div = price_up and fg > 75 and bias == "BULLISH"
        # Bullish divergence: price falling but sentiment low (fear → accumulation)
        bullish_div = price_down and fg < 25 and bias == "BEARISH"
        if bearish_div:
            mod  = 0.90
            note = f"⚠️ On-chain divergence: price ↑ but F&G={fg} euphoric → distribution risk"
        elif bullish_div:
            mod  = 0.90
            note = f"⚠️ On-chain divergence: price ↓ but F&G={fg} extreme fear → capitulation risk"
        else:
            mod  = 1.0
            note = f"✅ On-chain/price aligned (F&G={fg})"
        return {
            "onchain_price_div":      bearish_div or bullish_div,
            "onchain_div_conf_mod":   mod,
            "onchain_div_note":       note,
        }
    except Exception as e:
        return {"onchain_price_div": False, "onchain_div_note": f"OC div error: {e}",
                "onchain_div_conf_mod": 1.0}


# ── TIER 3 #23: Funding Rate Threshold Gate ─────────────────────
def compute_funding_gate(funding_rate: float, bias: str) -> Dict:
    """
    Funding rate extreme thresholds as gate modifiers:
    > +0.10%: extreme longs → reduce bullish conf (crowded trade, squeeze risk)
    < -0.05%: extreme shorts → high-probability squeeze if BULLISH setup
    +0.03%–+0.10%: elevated → slight headwind for longs
    """
    try:
        fr = float(funding_rate or 0)
        if fr > 0.10:
            mod  = 0.82
            note = f"⚠️ Funding EXTREME LONG ({fr:.4f}%) — crowded longs, squeeze risk for LONGS"
            gate = bias == "BEARISH"   # favors shorts
        elif fr < -0.05:
            mod  = 0.82 if bias == "BEARISH" else 1.10
            note = (f"{'⚠️ Funding EXTREME SHORT' if bias == 'BEARISH' else '✅ Funding squeeze setup'} "
                    f"({fr:.4f}%) — short squeeze risk")
            gate = bias == "BULLISH"
        elif fr > 0.03:
            mod  = 0.93
            note = f"⚠️ Funding elevated ({fr:.4f}%) — mild headwind for longs"
            gate = True
        elif fr < -0.01:
            mod  = 1.03
            note = f"✅ Funding negative ({fr:.4f}%) — slight squeeze potential for longs"
            gate = True
        else:
            mod  = 1.0
            note = f"✅ Funding neutral ({fr:.4f}%)"
            gate = True
        return {
            "funding_gate_pass": gate,
            "funding_conf_mod":  mod,
            "funding_gate_note": note,
        }
    except Exception as e:
        return {"funding_gate_pass": True, "funding_conf_mod": 1.0,
                "funding_gate_note": f"Funding gate error: {e}"}


# ── TIER 2 #13: NWOG / NDOG Gap TP Magnet Scoring ──────────────
def score_nwog_ndog_as_tp(weekly_daily_liq: Dict, bias: str,
                            price: float, tp1: float, tp2: float, tp3: float,
                            atr: float) -> Dict:
    """
    NWOG (New Week Opening Gap) and NDOG (New Day Opening Gap):
    ICT: price ALWAYS fills these gaps. Use as TP magnets.
    If unfilled gap exists between price and TP2/TP3 → upgrade that TP to the gap level.
    """
    if not weekly_daily_liq:
        return {"nwog_tp_upgrade": False, "ndog_tp_upgrade": False,
                "gap_tp_note": "No weekly/daily liquidity data"}
    try:
        nwog_lo = weekly_daily_liq.get("nwog_low",  0) or 0
        nwog_hi = weekly_daily_liq.get("nwog_high", 0) or 0
        ndog_lo = weekly_daily_liq.get("ndog_low",  0) or 0
        ndog_hi = weekly_daily_liq.get("ndog_high", 0) or 0
        nwog_mid = (nwog_lo + nwog_hi) / 2 if nwog_hi > nwog_lo > 0 else 0
        ndog_mid = (ndog_lo + ndog_hi) / 2 if ndog_hi > ndog_lo > 0 else 0
        notes = []
        nwog_upg = ndog_upg = False
        new_tp2, new_tp3 = tp2, tp3
        if bias == "BULLISH":
            if ndog_mid > price + atr * 0.3 and ndog_mid < tp2:
                new_tp2  = round(ndog_mid, 8); ndog_upg = True
                notes.append(f"NDOG TP2 magnet: {ndog_mid:.4g}")
            if nwog_mid > price + atr * 0.5 and nwog_mid > new_tp2:
                new_tp3  = round(nwog_mid, 8); nwog_upg = True
                notes.append(f"NWOG TP3 magnet: {nwog_mid:.4g}")
        else:
            if ndog_mid > 0 and ndog_mid < price - atr * 0.3 and ndog_mid > tp2:
                new_tp2  = round(ndog_mid, 8); ndog_upg = True
                notes.append(f"NDOG TP2 magnet: {ndog_mid:.4g}")
            if nwog_mid > 0 and nwog_mid < price - atr * 0.5 and nwog_mid < new_tp2:
                new_tp3  = round(nwog_mid, 8); nwog_upg = True
                notes.append(f"NWOG TP3 magnet: {nwog_mid:.4g}")
        return {
            "nwog_tp_upgrade": nwog_upg,
            "ndog_tp_upgrade": ndog_upg,
            "tp2_gap_upgraded": new_tp2,
            "tp3_gap_upgraded": new_tp3,
            "gap_tp_note": ("✅ Gap TPs: " + " | ".join(notes)) if notes else "○ No gap magnets in range",
        }
    except Exception as e:
        return {"nwog_tp_upgrade": False, "ndog_tp_upgrade": False,
                "tp2_gap_upgraded": tp2, "tp3_gap_upgraded": tp3,
                "gap_tp_note": f"Gap TP error: {e}"}


# ── TIER 3 #16: Gate 8 Sequential Narrative Chain ───────────────
def check_narrative_sequence(liq_swept: bool, structure_valid: bool,
                              displacement_valid: bool, bos_data: Dict,
                              ohlcv_htf: list) -> Dict:
    """
    ICT Narrative Chain — must be SEQUENTIAL:
    Step 1: Liquidity swept    (prerequisite — must happen FIRST)
    Step 2: Structure broken   (BOS/CHOCH after sweep)
    Step 3: Displacement into PD array (after BOS)
    If sweep occurred but BOS came before sweep → low-quality chain.
    Returns narrative quality score (0–3) and sequential gate.
    """
    steps_met = 0
    chain_notes = []
    # Step 1
    if liq_swept:
        steps_met += 1; chain_notes.append("✅ S1: Liquidity swept")
    else:
        chain_notes.append("❌ S1: No sweep confirmed")
    # Step 2
    if structure_valid and liq_swept:
        steps_met += 1; chain_notes.append("✅ S2: BOS after sweep")
    elif structure_valid:
        chain_notes.append("⚠️ S2: BOS but no prior sweep (lower quality)")
    else:
        chain_notes.append("❌ S2: No structure break")
    # Step 3
    if displacement_valid and structure_valid:
        steps_met += 1; chain_notes.append("✅ S3: Displacement into PD array")
    elif displacement_valid:
        chain_notes.append("⚠️ S3: Displacement but no BOS")
    else:
        chain_notes.append("❌ S3: No displacement")
    # Sequential gate: all 3 in order = full pass; 2 = partial; 1 or fewer = fail
    seq_gate  = steps_met >= 2
    seq_score = steps_met   # 0–3
    quality   = "FULL" if steps_met == 3 else ("PARTIAL" if steps_met == 2 else "WEAK")
    return {
        "narrative_seq_gate":  seq_gate,
        "narrative_seq_score": seq_score,
        "narrative_quality":   quality,
        "narrative_chain_note": f"Narrative chain {quality} ({steps_met}/3): {' → '.join(chain_notes)}",
    }


