# ─────────────────────────────────────────────────────────────
# LAYER 8 — AI ALPHA STACK
# Meta-labeling · Directional model · Ensemble consensus
# ─────────────────────────────────────────────────────────────

class AIAlphaStack:
    """
    Layer 8 — Explicit AI Architecture (not vague 'AI').

    Components:
    1. Feature Encoder       — latent representation of features
    2. Meta-Labeling         — binary: bet on this ICT signal?
    3. Directional Model     — P(Long win), P(Short win), P(No trade)
    4. RL Execution Policy   — limit/market/wait/size decision
    5. Confidence Calibration — Platt scaling proxy
    6. Ensemble Consensus    — weighted vote across all models
    """

    def feature_encoder(self, feature_vec: Dict[str, float]) -> Dict[str, float]:
        """
        Simulate deep embedding: compress features to latent representation.
        In production: transformer encoder. Here: weighted PCA-style combination.
        """
        vals = list(feature_vec.values())
        if not vals:
            return {"latent_1": 0.0, "latent_2": 0.0, "latent_3": 0.0}
        mean_v = sum(vals) / len(vals)
        # Latent dims = weighted sums of feature groups
        ict_keys = ["bos_bullish", "choch_flag", "fvg_size", "ob_size", "displacement", "liq_swept", "pd_score"]
        micro_keys = ["spread_pct", "bid_ratio", "ob_imbalance", "tick_imbalance"]
        macro_keys = ["macro_score", "dxy_roc", "funding_rate", "hmm_trending"]

        def group_mean(keys):
            vals_ = [feature_vec.get(k, 0.0) for k in keys]
            return sum(vals_) / max(len(vals_), 1)

        return {
            "latent_ict":   round(group_mean(ict_keys), 4),
            "latent_micro": round(group_mean(micro_keys), 4),
            "latent_macro": round(group_mean(macro_keys), 4),
        }

    def meta_labeler(
        self,
        gate_pass: List[bool],
        conf: float,
        hmm_state: str,
        disp_score: float,
    ) -> Dict:
        """
        Binary: Should we bet on this ICT signal?
        Reduces false positives by rejecting low-quality setups.
        """
        gates_ok  = sum(gate_pass) >= 8
        conf_ok   = conf >= 55
        hmm_ok    = hmm_state != "CHOPPY"
        disp_ok   = disp_score >= 1.2

        conditions_met = sum([gates_ok, conf_ok, hmm_ok, disp_ok])
        bet = conditions_met >= 3   # at least 3 of 4 conditions

        return {
            "meta_label_bet": bet,
            "meta_conditions": conditions_met,
            "meta_reason": "BET" if bet else "NO_BET",
        }

    def directional_model(
        self,
        win_prob: float,
        bias: str,
        macro_regime: str,
        dxy_kill: bool,
    ) -> Dict:
        """
        Probabilistic output: P(Long win), P(Short win), P(No trade).
        Minimum P=0.55 to proceed.
        """
        p_base = max(0.01, min(0.99, win_prob / 100.0))

        # Macro adjustment
        if macro_regime == "RISK_ON"  and bias == "BULLISH": p_base = min(0.99, p_base * 1.1)
        if macro_regime == "RISK_OFF" and bias == "BEARISH": p_base = min(0.99, p_base * 1.05)
        if dxy_kill and bias == "BULLISH":                   p_base *= 0.6

        p_long  = p_base  if bias == "BULLISH" else 1 - p_base
        p_short = 1 - p_long
        p_no    = max(0.0, 1.0 - max(p_long, p_short) - 0.05)

        proceed = max(p_long, p_short) >= 0.55

        return {
            "p_long":   round(p_long,  4),
            "p_short":  round(p_short, 4),
            "p_notrade": round(p_no,   4),
            "ai_dir_proceed": proceed,
            "ai_dir_note": f"P({bias[:4]})={max(p_long,p_short)*100:.1f}%",
        }

    def rl_execution_policy(
        self,
        chase_distance_pct: float,
        latency_ms: float,
        wss_size_mod: float,
    ) -> Dict:
        """
        PPO/SAC proxy: decide execution type.
        State: OB position, latency, slippage.
        Action: limit/market/wait/half-size.
        """
        if chase_distance_pct > 0.5:
            action = "MARKET"     # too far — accept market fill
        elif latency_ms > 50:
            action = "HALF_SIZE"  # high latency — reduce size
        elif wss_size_mod < 1.0:
            action = "HALF_SIZE"  # WSS degraded — reduce size
        else:
            action = "LIMIT"      # standard post-only limit

        return {
            "rl_action":       action,
            "rl_size_mod":     0.5 if action == "HALF_SIZE" else 1.0,
            "rl_order_type":   action,
        }

    def confidence_calibration(self, raw_prob: float) -> float:
        """
        Platt scaling proxy — calibrate overconfident model outputs.
        Maps raw probability through sigmoid to calibrated probability.
        """
        # Platt: calibrated = 1 / (1 + exp(-(A*f + B))) where A≈1, B≈0 is simplified
        calibrated = 1.0 / (1.0 + math.exp(-(raw_prob - 0.5) * 4))
        return round(calibrated, 4)

    def ensemble_consensus(
        self,
        hmm_pass:    bool,
        meta_bet:    bool,
        dir_proceed: bool,
        rl_action:   str,
    ) -> Dict:
        """
        [G8] Weighted vote: HMM + Meta-labeler + Directional + RL.
        Diversity-weighted: correlated models count as less than 1 vote each.
        Research (Lopez de Prado AFML): Jaccard feature overlap > 0.5 = double-counting.
        """
        votes = {
            "hmm":   1.0 if hmm_pass    else 0.0,
            "meta":  1.0 if meta_bet    else 0.0,
            "dir":   1.0 if dir_proceed else 0.0,
            "rl":    1.0 if rl_action in ("LIMIT", "MARKET") else 0.0,
        }

        # [G8] Feature set per model — measure independence via Jaccard similarity
        _model_features = {
            "hmm":  {"atr_pct", "adx", "slope"},
            "meta": {"gate_pass", "conf", "disp_score", "hmm_state"},
            "dir":  {"win_prob", "macro_regime", "dxy_kill", "bias"},
            "rl":   {"chase_pct", "latency_ms", "wss_mod", "epsilon"},
        }
        models = list(_model_features.keys())
        jaccard_sum = 0.0
        pair_count  = 0
        for i in range(len(models)):
            for j in range(i + 1, len(models)):
                a = _model_features[models[i]]
                b = _model_features[models[j]]
                inter = len(a & b)
                union = len(a | b)
                jaccard_sum += inter / max(union, 1)
                pair_count  += 1
        mean_jaccard   = jaccard_sum / max(pair_count, 1)
        diversity_score = round(1.0 - mean_jaccard, 4)   # 1.0 = fully independent

        # Penalize correlated ensemble: low diversity → consensus carries less weight
        # Formula: adj_consensus = raw × (0.70 + 0.30 × diversity)
        total_votes = sum(votes.values())
        max_votes   = len(votes)
        raw_consensus = total_votes / max_votes
        adj_consensus = raw_consensus * (0.70 + 0.30 * diversity_score)
        adj_consensus = round(min(1.0, adj_consensus), 4)

        if adj_consensus >= 0.95:   tier = "UNANIMOUS"
        elif adj_consensus >= 0.75: tier = "HIGH_CONF"
        elif adj_consensus >= 0.50: tier = "MODERATE"
        else:                       tier = "LOW_CONF"

        diversity_label = "HIGH" if diversity_score > 0.7 else "MED" if diversity_score > 0.4 else "LOW-CORRELATED"

        return {
            "ensemble_consensus":  adj_consensus,
            "raw_consensus":       round(raw_consensus, 4),
            "diversity_score":     diversity_score,
            "diversity_label":     diversity_label,
            "mean_jaccard":        round(mean_jaccard, 4),
            "ensemble_tier":       tier,
            "votes":               votes,
            "ensemble_pass":       adj_consensus >= 0.5,
            "ensemble_note": (
                f"AI Ensemble: {tier} ({total_votes:.0f}/{max_votes} votes) "
                f"| Diversity={diversity_score:.2f} [{diversity_label}]"
            ),
        }

    def run_full_stack(
        self,
        feature_vec: Dict[str, float],
        gate_pass: List[bool],
        conf: float,
        hmm_state: str,
        hmm_pass: bool,
        disp_score: float,
        win_prob: float,
        bias: str,
        macro_regime: str,
        dxy_kill: bool,
        chase_pct: float = 0.0,
        latency_ms: float = 20.0,
        wss_mod: float = 1.0,
    ) -> Dict:
        """Run all Layer 8 AI models and return consolidated output."""
        encoded  = self.feature_encoder(feature_vec)
        meta     = self.meta_labeler(gate_pass, conf, hmm_state, disp_score)
        dir_out  = self.directional_model(win_prob, bias, macro_regime, dxy_kill)
        rl_out   = self.rl_execution_policy(chase_pct, latency_ms, wss_mod)
        cal_prob = self.confidence_calibration(win_prob / 100.0)
        ensemble = self.ensemble_consensus(
            hmm_pass, meta["meta_label_bet"],
            dir_out["ai_dir_proceed"], rl_out["rl_action"]
        )
        return {
            "encoded_features": encoded,
            "meta_label":       meta,
            "directional":      dir_out,
            "rl_policy":        rl_out,
            "calibrated_prob":  cal_prob,
            "ensemble":         ensemble,
            "ai_stack_pass":    ensemble["ensemble_pass"] and meta["meta_label_bet"],
            "ai_score":         round(ensemble["ensemble_consensus"] * 100, 1),
        }

_AI_STACK = AIAlphaStack()


# ─────────────────────────────────────────────────────────────
# LAYER 10 — DRIFT DETECTION + ALPHA HALF-LIFE ENGINE
# PSI · Concept drift alarms · Edge decay · Auto-decommission
# ─────────────────────────────────────────────────────────────

class DriftDetectionEngine:
    """
    Layer 10 — Is the edge still alive?
    PSI > 0.2 = significant drift → trigger retrain.
    Winrate decay slope > 0.5%/week = warning.
    Alpha half-life: ICT OB ~90d, Macro ~180d, Microstructure ~14d.
    """
    PSI_DRIFT_THRESHOLD  = 0.20
    WINRATE_DECAY_WARN   = -0.005   # -0.5%/week slope
    WINRATE_DECAY_HALT   = -0.010   # -1.0%/week slope
    EXPECTANCY_FLOOR     = 0.0      # below 0 = kill signal

    # Alpha half-life in days per signal type
    ALPHA_HALF_LIFE = {
        "ICT_OB":         90,
        "ICT_FVG":        60,
        "MACRO":         180,
        "MICROSTRUCTURE": 14,
        "MOMENTUM":       30,
        "DEFAULT":        45,
    }

    def __init__(self):
        self._win_history:   List[float] = []   # rolling win/loss (1/0)
        self._psi_baseline:  Dict        = {}   # feature distribution baseline
        self._signal_ages:   Dict[str, float] = {}   # signal_type → creation timestamp
        self._decommissioned: List[str]  = []
        self._retrain_queued: bool       = False

    def update_win_history(self, win: bool) -> None:
        self._win_history.append(1.0 if win else 0.0)
        if len(self._win_history) > 200:
            self._win_history.pop(0)

    def compute_psi(self, feature_vec: Dict[str, float]) -> float:
        """
        Population Stability Index proxy.
        Compares current feature distribution to baseline.
        PSI = sum[(actual% - expected%) × ln(actual%/expected%)]
        Here: simplified deviation score.
        """
        if not self._psi_baseline:
            self._psi_baseline = {k: v for k, v in feature_vec.items()}
            return 0.0

        total_dev = 0.0
        count     = 0
        for k, current in feature_vec.items():
            baseline = self._psi_baseline.get(k, current)
            if abs(baseline) > 1e-9:
                dev = abs(current - baseline) / max(abs(baseline), 1e-9)
                total_dev += dev
                count += 1

        psi_proxy = total_dev / max(count, 1)
        return round(min(1.0, psi_proxy), 4)

    def detect_concept_drift(self) -> Dict:
        """ADWIN / Page-Hinkley proxy on rolling win rate."""
        if len(self._win_history) < 20:
            return {"drift_detected": False, "halt_trading": False, "winrate": 0.5, "winrate_slope": 0.0, "slope": 0.0, "action": "OK"}

        recent_20  = self._win_history[-20:]
        earlier_20 = self._win_history[-40:-20] if len(self._win_history) >= 40 else self._win_history[:20]

        wr_recent  = sum(recent_20)  / len(recent_20)
        wr_earlier = sum(earlier_20) / max(len(earlier_20), 1)
        slope      = wr_recent - wr_earlier   # positive = improving

        drift = slope < self.WINRATE_DECAY_WARN
        halt  = slope < self.WINRATE_DECAY_HALT

        return {
            "drift_detected": drift,
            "halt_trading":   halt,
            "winrate":        round(wr_recent,  4),
            "winrate_slope":  round(slope, 4),
            "action":         "HALT_TRADING" if halt else "WARN_DECAY" if drift else "OK",
        }

    def alpha_half_life(self, signal_type: str = "DEFAULT") -> Dict:
        """
        Compute remaining edge weight based on signal age.
        Weight decays exponentially: w(t) = exp(-t / half_life)
        """
        half_life_days = self.ALPHA_HALF_LIFE.get(signal_type, self.ALPHA_HALF_LIFE["DEFAULT"])
        age_days = (time.time() - self._signal_ages.get(signal_type, time.time())) / 86400.0
        weight   = math.exp(-age_days / max(half_life_days, 1))

        if weight < 0.05:
            if signal_type not in self._decommissioned:
                self._decommissioned.append(signal_type)
                log.info(f"[L10 DRIFT] Signal '{signal_type}' auto-decommissioned (weight={weight:.3f})")

        return {
            "signal_type":   signal_type,
            "age_days":      round(age_days, 1),
            "half_life_days": half_life_days,
            "weight":        round(weight, 4),
            "decommissioned": signal_type in self._decommissioned,
        }

    def get_full_report(self, feature_vec: Dict[str, float]) -> Dict:
        psi        = self.compute_psi(feature_vec)
        drift      = self.detect_concept_drift()
        hl_ict     = self.alpha_half_life("ICT_OB")
        retrain    = psi > self.PSI_DRIFT_THRESHOLD or drift["halt_trading"]
        if retrain and not self._retrain_queued:
            self._retrain_queued = True
            log.warning(f"[L10 DRIFT] Model retrain queued — PSI={psi:.3f}, drift={drift['drift_detected']}")
        return {
            "psi":              psi,
            "psi_alert":        psi > self.PSI_DRIFT_THRESHOLD,
            "concept_drift":    drift,
            "ict_ob_halflife":  hl_ict,
            "retrain_queued":   self._retrain_queued,
            "edge_alive":       not drift["halt_trading"] and psi < self.PSI_DRIFT_THRESHOLD,
        }

_DRIFT_ENGINE = DriftDetectionEngine()


# ─────────────────────────────────────────────────────────────
# LAYER 11 — PORTFOLIO INTELLIGENCE BRAIN
# Covariance · Risk parity · Exposure netting · Tail hedge
# ─────────────────────────────────────────────────────────────

class PortfolioIntelligenceBrain:
    """
    Layer 11 — Where Funds Are Born.
    Trades are downstream of portfolio math — not the other way around.
    Tracks position correlations, netting, risk parity allocation.
    """
    MAX_CLUSTER_EXPOSURE = 0.06   # max 6% per correlated cluster
    MAX_CORRELATED_TRADES = 2     # fix #19 — max simultaneous trades in same correlation cluster
    TAIL_HEDGE_ALLOC     = 0.03   # 3% to tail hedges

    def __init__(self):
        self._open_positions: Dict[str, Dict] = {}   # symbol → {size, direction, entry}
        self._correlation_clusters = {
            "BTC_cluster":  ["BTC", "ETH", "SOL", "AVAX"],
            "ALT_cluster":  ["XRP", "ADA", "DOT", "MATIC"],
            "DEFI_cluster": ["UNI", "LINK", "AAVE", "MKR"],
        }

    def add_position(self, symbol: str, direction: str, size_pct: float) -> None:
        self._open_positions[symbol] = {
            "direction": direction,
            "size_pct":  size_pct,
            "time":      time.time(),
        }

    def correlation_penalty(self, symbol: str) -> float:
        """
        ρ penalty: if multiple positions exist in same cluster → reduce size.
        Returns correlation penalty 0.0–0.5.
        """
        base_symbol = symbol.replace("USDT", "").replace("BUSD", "")
        in_cluster  = False
        cluster_exposure = 0.0

        for cluster, members in self._correlation_clusters.items():
            if base_symbol in members:
                in_cluster = True
                # Sum existing exposure in cluster and count open positions
                cluster_trade_count = 0
                for sym, pos in self._open_positions.items():
                    sym_base = sym.replace("USDT", "")
                    if sym_base in members:
                        cluster_exposure += pos.get("size_pct", 0.01)
                        cluster_trade_count += 1
                # Fix #19 — hard block if already at max correlated trades
                if cluster_trade_count >= self.MAX_CORRELATED_TRADES:
                    return 0.5   # 50% penalty = effectively block new position
                break

        if not in_cluster:
            return 0.0

        if cluster_exposure > self.MAX_CLUSTER_EXPOSURE:
            penalty = min(0.5, (cluster_exposure - self.MAX_CLUSTER_EXPOSURE) * 5)
        else:
            penalty = cluster_exposure * 2   # light penalty even below cap

        return round(penalty, 4)

    def exposure_netting(self, symbol: str, new_direction: str) -> Dict:
        """
        Compute net directional exposure if new position is added.
        Long + Short in correlated pairs = partially netted.
        """
        base = symbol.replace("USDT", "")
        net_long  = 0.0
        net_short = 0.0
        for sym, pos in self._open_positions.items():
            if pos["direction"] == "BULLISH":
                net_long  += pos.get("size_pct", 0.01)
            else:
                net_short += pos.get("size_pct", 0.01)

        net_dir = net_long - net_short
        return {
            "net_directional_pct": round(net_dir * 100, 2),
            "gross_long_pct":      round(net_long * 100,  2),
            "gross_short_pct":     round(net_short * 100, 2),
            "hedged":              abs(net_dir) < 0.02,
        }

    def risk_parity_size(self, base_size_pct: float, atr_pct: float) -> float:
        """
        Risk parity: each position contributes equal risk.
        High-vol signals get smaller allocation.
        Target: each position contributes 1% portfolio risk.
        """
        target_risk  = 0.01   # 1% per trade
        vol_adj_size = target_risk / max(atr_pct / 100.0, 0.005)
        # Blend with base Kelly size
        rp_size = (base_size_pct * 0.4 + vol_adj_size * 0.6)
        return round(max(0.005, min(0.02, rp_size)), 4)

    def get_portfolio_summary(self) -> Dict:
        n_pos = len(self._open_positions)
        return {
            "open_positions":    n_pos,
            "tail_hedge_alloc":  f"{self.TAIL_HEDGE_ALLOC*100:.0f}%",
            "max_cluster_exp":   f"{self.MAX_CLUSTER_EXPOSURE*100:.0f}%",
            "portfolio_note":    "Risk parity active" if n_pos > 0 else "No open positions",
        }

_PORTFOLIO_BRAIN = PortfolioIntelligenceBrain()


# ─────────────────────────────────────────────────────────────
# LAYER 12 ADDITIONS — Risk Physics Engine Extensions
# Convex position sizing · Volatility targeting · Stress VaR
# ─────────────────────────────────────────────────────────────

def compute_convex_position_size(
    base_kelly_pct: float,
    trade_score:    float,
    max_pct:        float = 0.02,
) -> float:
    """
    Convex sizing: size grows super-linearly with edge quality.
    High-confidence trades get disproportionally larger allocation.
    Size = base × (trade_score/100)^1.5   — convex (not linear)
    """
    if trade_score <= 0:
        return base_kelly_pct
    multiplier  = (trade_score / 100.0) ** 1.5   # convex exponent
    convex_size = base_kelly_pct * (1 + multiplier)
    return round(min(max_pct, convex_size), 5)

def compute_volatility_target(
    atr_pct:        float,
    target_vol_ann: float = 0.15,    # 15% annualized portfolio vol target
    base_size_pct:  float = 0.01,
) -> Dict:
    """
    Volatility targeting: scale all positions so portfolio vol stays constant.
    realized_vol_daily = ATR_pct / 100 × sqrt(252)
    scale = target_vol / realized_vol
    """
    realized_vol_ann = (atr_pct / 100.0) * math.sqrt(252)
    scale            = target_vol_ann / max(realized_vol_ann, 0.01)
    vol_tgt_size     = round(base_size_pct * scale, 5)
    vol_tgt_size     = max(KELLY_MIN_PCT, min(KELLY_MAX_PCT, vol_tgt_size))
    return {
        "realized_vol_ann": round(realized_vol_ann, 4),
        "vol_target_ann":   target_vol_ann,
        "vol_scale_factor": round(scale, 4),
        "vol_tgt_size_pct": vol_tgt_size,
    }

def compute_stress_var(
    win_prob:    float,
    rr:          float,
    risk_pct:    float = 0.01,
    confidence:  float = 0.95,
) -> Dict:
    """
    [v7.0-U5] Historical VaR + CVaR (Expected Shortfall) at 95th/99th percentile.
    Thesis: VaR understates tail risk for crypto fat-tail distributions.
    CVaR = average loss in the worst (1-confidence) fraction of scenarios.
    This is the BIS/Basel III standard for tail-risk measurement.
    Gate uses CVaR (not VaR) as the primary limit — stricter but more accurate.
    """
    runs = 500
    outcomes = []
    for _ in range(runs):
        p = max(0.01, min(0.99, win_prob / 100.0 + random.gauss(0, 0.05)))
        if random.random() < p:
            outcomes.append(risk_pct * rr)    # win = gain
        else:
            outcomes.append(-risk_pct)         # loss

    outcomes_sorted = sorted(outcomes)
    var_idx_95  = int(runs * (1 - confidence))
    var_idx_99  = int(runs * 0.01)

    var_95  = abs(outcomes_sorted[max(0, var_idx_95)])
    var_99  = abs(outcomes_sorted[max(0, var_idx_99)])

    # CVaR = mean of all losses AT OR BEYOND the VaR threshold (Expected Shortfall)
    tail_losses = [abs(x) for x in outcomes_sorted[:max(1, var_idx_95)] if x < 0]
    cvar_95 = (sum(tail_losses) / len(tail_losses)) if tail_losses else var_95

    daily_var_limit  = 0.02   # 2% daily VaR cap
    daily_cvar_limit = 0.03   # 3% daily CVaR cap (tail loss budget)
    var_ok  = var_95  < daily_var_limit
    cvar_ok = cvar_95 < daily_cvar_limit
    both_ok = var_ok and cvar_ok

    return {
        "var_95":      round(var_95,   4),
        "var_99":      round(var_99,   4),
        "cvar_95":     round(cvar_95,  4),
        "var_ok":      both_ok,   # gate uses both_ok so L13 checks CVaR
        "var_only_ok": var_ok,
        "cvar_ok":     cvar_ok,
        "var_note": (
            f"VaR(95%)={var_95*100:.2f}% {'✅' if var_ok else '⚠️ >2%'}  "
            f"CVaR(95%)={cvar_95*100:.2f}% {'✅' if cvar_ok else '⚠️ >3% EXCEEDS TAIL LIMIT'}"
        ),
    }


# ─────────────────────────────────────────────────────────────
# LAYER 13 — FINAL RISK GATING (Extended with VaR + Latency)
# DD → DXY → Slippage → Grade → VaR → Latency → Ghost Order
# ─────────────────────────────────────────────────────────────

def run_final_risk_gate(
    dd_status:        Dict,
    dxy_status:       Dict,
    slip_data:        Dict,
    trade_score_data: Dict,
    var_data:         Dict,
    wss_status:       Dict,
    bias:             str,
) -> Dict:
    """
    Layer 13 — Sequential hard-stop risk gates.
    All must PASS before execution proceeds.
    """
    gates = []
    reasons = []

    # Gate A: Drawdown Governor
    if dd_status.get("kill_switch", False):
        gates.append(False)
        reasons.append(f"DD_KILL: {dd_status.get('drawdown_pct', 0):.1f}% > 25%")
    else:
        gates.append(True)

    # Gate B: DXY Kill Switch
    if dxy_status.get("kill_longs", False) and bias == "BULLISH":
        gates.append(False)
        reasons.append(f"DXY_KILL: dxy_roc={dxy_status.get('dxy_roc', 0):.4f}%/hr")
    else:
        gates.append(True)

    # Gate C: Slippage
    if not slip_data.get("acceptable", True):
        gates.append(False)
        reasons.append(f"SLIP_WARN: est={slip_data.get('estimated_slip_pct', 0)*100:.3f}%")
    else:
        gates.append(True)

    # Gate D: VaR Limit
    if not var_data.get("var_ok", True):
        gates.append(False)
        reasons.append(f"VAR_HALT: VaR(95%)={var_data.get('var_95', 0)*100:.2f}%")
    else:
        gates.append(True)

    # Gate E: Trade Grade
    grade = trade_score_data.get("combined_grade", "F")
    if grade == "F":
        gates.append(False)
        reasons.append(f"GRADE_F: combined_grade={grade}")
    else:
        gates.append(True)

    # Gate F: WSS Latency Guard
    hb_lag = wss_status.get("heartbeat_lag", 0)
    if hb_lag > 120:   # 2 min without heartbeat = degraded
        gates.append(False)
        reasons.append(f"LATENCY_GUARD: lag={hb_lag:.0f}s")
    else:
        gates.append(True)

    # [G7] Gate G: DD Duration Soft Block — chronic edge failure detection
    # Depth-only DD can miss a strategy sitting at 14% DD for 60 bars (chronic edge failure).
    dd_dur = dd_status.get("dd_duration_bars", 0)
    if dd_dur >= DrawdownGovernor.DD_DURATION_BLOCK:
        gates.append(False)
        reasons.append(f"DD_DURATION_BLOCK: {dd_dur} bars > {DrawdownGovernor.DD_DURATION_BLOCK} — chronic edge failure")
    else:
        gates.append(True)

    all_pass = all(gates)
    return {
        "l13_all_pass":   all_pass,
        "l13_gates":      gates,
        "l13_reasons":    reasons,
        "l13_gate_names": ["DD_GOV", "DXY_KILL", "SLIPPAGE", "VAR_LIMIT", "GRADE", "LATENCY", "DD_DURATION"],
        "l13_note":       "✅ ALL RISK GATES PASSED" if all_pass else
                          f"❌ BLOCKED: {' | '.join(reasons)}",
        "size_mod_l13":   dd_status.get("size_multiplier", 1.0) * (
                              wss_status.get("size_modifier", 1.0)
                              if isinstance(wss_status, dict) else 1.0
                          ),
    }


# ─────────────────────────────────────────────────────────────
# LAYER 14 ADDITIONS — Execution Intelligence
# TWAP · Smart Order Routing · Adversarial fill avoidance
# ─────────────────────────────────────────────────────────────

def compute_smart_order_routing(
    ex_scored: List[Dict],
    bias: str,
) -> Dict:
    """
    Layer 14 — Route order to venue with best fill probability.
    Not just best-price but best OB depth + spread combination.
    """
    if not ex_scored:
        return {"best_venue": "UNKNOWN", "routing_score": 0}

    # Score: spread penalty + depth bonus
    def fill_score(ex: Dict) -> float:
        spread  = ex.get("spread_pct", 0.1)   # lower = better
        vol     = ex.get("vol_24h", 1.0)       # higher = better
        liq     = ex.get("score", 50)          # existing score
        return liq * 0.4 + (1 - min(1.0, spread * 10)) * 30 + min(30, vol / 1e6 * 10)

    scored  = sorted(ex_scored, key=fill_score, reverse=True)
    best    = scored[0] if scored else ex_scored[0]
    return {
        "best_venue":    best.get("name", "UNKNOWN"),
        "routing_score": round(fill_score(best), 2),
        "sor_note":      f"SOR → {best.get('name','?')} (fill score: {fill_score(best):.1f})",
    }

def compute_twap_schedule(
    total_size_usd: float,
    n_slices: int = 4,
    interval_secs: int = 30,
) -> Dict:
    """
    Layer 14 — TWAP execution schedule.
    Time-Weighted Average Price slicing for large orders.
    """
    slice_size = total_size_usd / max(n_slices, 1)
    schedule   = [
        {
            "slice": i + 1,
            "delay_secs": i * interval_secs,
            "size_usd": round(slice_size, 2),
        }
        for i in range(n_slices)
    ]
    return {
        "twap_slices":     n_slices,
        "slice_size_usd":  round(slice_size, 2),
        "total_duration":  n_slices * interval_secs,
        "schedule":        schedule,
        "twap_note":       f"TWAP: {n_slices} slices × {interval_secs}s intervals",
    }

def adversarial_fill_avoidance(base_delay_ms: float = 0.0) -> Dict:
    """
    Layer 14 — Anti-HFT: randomize order timing ±200ms.
    Avoid predictable order signatures.
    """
    jitter_ms = random.uniform(-200, 200)
    final_delay = max(0, base_delay_ms + jitter_ms)
    return {
        "jitter_ms":    round(jitter_ms, 1),
        "final_delay":  round(final_delay, 1),
        "afa_note":     f"Order jitter: {jitter_ms:+.0f}ms (anti-HFT)",
    }


