# ─────────────────────────────────────────────────────────────
# LAYER 19 — PERFORMANCE ATTRIBUTION + CAPITAL SCALING SIM
# SHAP attribution · Edge decomposition · Scaling Sharpe decay
# ─────────────────────────────────────────────────────────────

class PerformanceAttributionEngine:
    """
    Layer 19 — Investor Trust Layer.
    SHAP-style attribution: which features drove this trade?
    Explainable AI: every trade has a human-readable reason string.
    """

    def shap_attribution(
        self,
        gate_pass:   List[bool],
        conf:        float,
        timing_score: float,
        macro_score: float,
        ai_score:    float,
    ) -> Dict:
        """
        SHAP-style: decompose trade decision into feature contributions.
        In production: actual SHAP values from trained model.
        Here: rule-based attribution mirroring scoring weights.
        """
        total = max(conf + timing_score + macro_score + ai_score + sum(gate_pass) * 3, 1)

        attribution = {
            "ICT_Gates":    round(sum(gate_pass) * 3 / total * 100, 1),
            "Confluence":   round(conf / total * 100, 1),
            "Timing":       round(timing_score / total * 100, 1),
            "Macro":        round(macro_score / total * 100, 1),
            "AI_Ensemble":  round(ai_score / total * 100, 1),
        }
        top_driver = max(attribution, key=attribution.get)

        return {
            "attribution":  attribution,
            "top_driver":   top_driver,
            "human_reason": (
                f"Primary edge: {top_driver} ({attribution[top_driver]:.0f}% contribution). "
                f"Gates {sum(gate_pass)}/10 passed. Conf={conf:.0f}. Timing={timing_score:.0f}."
            ),
        }

    def capital_scaling_sim(self, current_aum: float) -> Dict:
        """
        Simulate Sharpe decay as AUM grows.
        Sharpe(AUM) = S₀ × (1 − k × log10(AUM))
        Capacity limit: AUM where Sharpe < 1.0
        """
        S0 = 2.5    # baseline Sharpe
        k  = 0.15   # decay coefficient

        def sharpe_at(aum):
            return max(0, S0 * (1 - k * math.log10(max(aum, 1000))))

        tiers = [
            ("Solo Quant",         1_000_000),
            ("Small Prop Desk",   25_000_000),
            ("Institutional",    250_000_000),
        ]

        scaling_table = [
            {
                "tier": name,
                "aum":  f"${aum/1e6:.0f}M",
                "est_sharpe": round(sharpe_at(aum), 2),
                "viable": sharpe_at(aum) >= 1.0,
            }
            for name, aum in tiers
        ]

        current_sharpe = round(sharpe_at(current_aum), 2)
        return {
            "current_aum":       f"${current_aum:,.0f}",
            "current_sharpe":    current_sharpe,
            "scaling_table":     scaling_table,
            "capacity_note":     f"Strategy viable at {current_aum/1e6:.1f}M AUM (Sharpe={current_sharpe})",
        }

    def edge_decomposition(self, trade_data: Dict) -> str:
        """
        Generate human-readable edge decomposition string for investor reports.
        """
        bias     = trade_data.get("bias", "BULLISH")
        score    = (trade_data.get("trade_score_data") or {}).get("trade_score", 0)
        win_prob = trade_data.get("win_prob", 60)
        session  = trade_data.get("session", "LONDON")
        return (
            f"Edge: {bias} ICT signal. Score={score}/100. "
            f"Win_P={win_prob}%. Session={session}. "
            f"Structure + Timing + Macro triple-confirmed."
        )

_PERF_ATTR = PerformanceAttributionEngine()

