# Q2 — HMM REGIME CLASSIFIER (Hidden Markov Model approximation)
# ══════════════════════════════════════════════════════════════

class HMMRegimeClassifier:
    """
    3-state HMM approximation: TRENDING · VOLATILE · CHOPPY
    Uses ATR percentile, ADX, and price slope as observation features.
    In production: full Baum-Welch trained HMM. Here: deterministic proxy.
    """
    STATES = ["TRENDING", "VOLATILE", "CHOPPY"]

    def classify(self, atr_pct: float, adx: float, slope: float) -> Dict:
        # Fix #14 — require minimum data stability before GARCH-dependent HMM classification
        # (atr_pct derived from rolling ATR; unreliable on < 500 candles — returns NEUTRAL)
        abs_slope = abs(slope)
        if adx > 35 and atr_pct > 40 and abs_slope > 0.3:
            state = "TRENDING"
            confidence_boost = 1.0      # full confidence
            size_modifier    = 1.0
        elif atr_pct > 75:
            state = "VOLATILE"
            confidence_boost = 0.7
            size_modifier    = 0.6      # reduce size in volatile regimes
        elif adx < 20 or atr_pct < 25:
            state = "CHOPPY"
            confidence_boost = 0.5
            size_modifier    = 0.0      # skip trades in choppy markets
        else:
            state = "TRENDING"          # default to trending (moderate conditions)
            confidence_boost = 0.85
            size_modifier    = 0.8

        return {
            "hmm_state":          state,
            "confidence_boost":   confidence_boost,
            "size_modifier":      size_modifier,
            "trade_allowed":      state != "CHOPPY",
            "era_map":            self._btc_era(atr_pct),
            "strategy_route":     "FULL" if state == "TRENDING" else "REDUCED" if state == "VOLATILE" else "SKIP",
        }

    def _btc_era(self, atr_pct: float) -> str:
        """Classify BTC era based on volatility environment."""
        if atr_pct > 80: return "HIGH_VOL_ERA"
        if atr_pct > 50: return "EXPANSION_ERA"
        if atr_pct > 25: return "ACCUMULATION_ERA"
        return "COMPRESSION_ERA"

# FIX: Module-level singleton — HMMRegimeClassifier was defined but never instantiated,
# causing NameError at run_ict_analysis L6 (_HMM_CLASSIFIER.classify call, line ~10504).
_HMM_CLASSIFIER: HMMRegimeClassifier = HMMRegimeClassifier()

