# ══════════════════════════════════════════════════════════════
# Q7 — CAPITAL ALLOCATION ENGINE (Kelly · Quarter Kelly · Vol Target)
# ══════════════════════════════════════════════════════════════

def compute_kelly_position_size(
    win_prob:       float,      # 0–1
    rr:             float,      # risk:reward ratio (e.g. 2.5)
    account_balance: float = 10000.0,
    portfolio_modifier: float = 1.0,
    correlation_penalty: float = 0.0,  # ρ — reduces size when correlated positions exist
) -> Dict:
    """
    Kelly Fraction:  f* = (p * b - q) / b   where b=RR, p=win_prob, q=1-p
    Quarter Kelly:   f_q = f* / 2  (standard conservative institutional approach)
    Size = BaseRisk × ScoreMultiplier × PortfolioModifier × (1 − ρ)
    Capped at KELLY_MIN_PCT – KELLY_MAX_PCT of account balance.
    """
    p = max(0.01, min(0.99, win_prob))
    q = 1.0 - p
    b = max(0.1, rr)

    kelly_full    = (p * b - q) / b
    kelly_quarter = kelly_full * KELLY_FRACTION   # half-kelly by default
    kelly_capped  = max(KELLY_MIN_PCT, min(KELLY_MAX_PCT, kelly_quarter))

    # Apply portfolio modifier and correlation penalty
    final_fraction = kelly_capped * portfolio_modifier * (1.0 - correlation_penalty)
    final_fraction = max(KELLY_MIN_PCT, min(KELLY_MAX_PCT, final_fraction))

    dollar_risk   = account_balance * final_fraction

    return {
        "kelly_full":         round(kelly_full,    6),
        "kelly_quarter":      round(kelly_quarter, 6),
        "kelly_capped":       round(kelly_capped,  6),
        "final_fraction_pct": round(final_fraction * 100, 3),
        "dollar_risk":        round(dollar_risk,   2),
        "account_balance":    account_balance,
        "corr_penalty":       round(correlation_penalty, 4),
    }

# ══════════════════════════════════════════════════════════════
# Q8 — PORTFOLIO RISK ENGINE (Drawdown Governor · Kill Switch)
# ══════════════════════════════════════════════════════════════

class DrawdownGovernor:
    """
    Tracks rolling peak equity and current drawdown.
    [G7] Also tracks time-in-drawdown duration (bars) — depth alone misses chronic edge failure.
    PASS    < 12%  — trade normally
    MARGINAL 15–22% — reduce size by 50%
    FAIL    > 25%  — kill switch fired, no new trades
    DD_DURATION > 20 bars — progressive size reduction warning
    DD_DURATION > 40 bars — alert + 40% size reduction
    DD_DURATION > 60 bars — soft L13 block
    """
    DD_DURATION_WARN  = 20   # bars at > 8% DD → reduce size 20%
    DD_DURATION_ALERT = 40   # bars at > 8% DD → reduce size 40% + L18 alert
    DD_DURATION_BLOCK = 60   # bars at > 8% DD → L13 soft block

    def __init__(self, initial_equity: float = 10000.0):
        self.peak_equity      = initial_equity
        self.current_equity   = initial_equity
        self._trade_history:  List[Dict] = []
        self.dd_duration_bars: int = 0        # [G7] consecutive bars in DD > 8%

    def update(self, pnl_pct: float) -> None:
        self.current_equity *= (1.0 + pnl_pct)
        if self.current_equity > self.peak_equity:
            self.peak_equity      = self.current_equity
            self.dd_duration_bars = 0     # [G7] reset on new equity peak
        elif self.current_drawdown() > 0.08:
            self.dd_duration_bars += 1    # [G7] increment while in significant DD

    def current_drawdown(self) -> float:
        if self.peak_equity == 0:
            return 0.0
        return (self.peak_equity - self.current_equity) / self.peak_equity

    def get_status(self) -> Dict:
        dd  = self.current_drawdown()
        dur = self.dd_duration_bars

        if dd < DD_PASS_THRESHOLD:
            status     = "PASS"
            size_mult  = 1.0
            kill       = False
        elif dd < DD_MARGINAL_LOW:
            status     = "PASS"
            size_mult  = 0.75
            kill       = False
        elif dd < DD_MARGINAL_HIGH:
            status     = "MARGINAL"
            size_mult  = 0.50
            kill       = False
        elif dd < DD_FAIL_THRESHOLD:
            status     = "MARGINAL"
            size_mult  = 0.25
            kill       = False
        else:
            status     = "FAIL"
            size_mult  = 0.0
            kill       = True

        # [G7] Duration modifier — applies on top of depth-based size_mult
        if dur >= self.DD_DURATION_BLOCK:
            dur_status = "CHRONIC_EDGE_FAILURE"
            size_mult  = min(size_mult, 0.30)   # hard cap at 30%
        elif dur >= self.DD_DURATION_ALERT:
            dur_status = "PROLONGED_DD_ALERT"
            size_mult  = min(size_mult, 0.60)   # cap at 60%
        elif dur >= self.DD_DURATION_WARN:
            dur_status = "EXTENDED_DD_WARN"
            size_mult  = min(size_mult, 0.80)   # cap at 80%
        else:
            dur_status = "NORMAL"

        return {
            "drawdown_pct":   round(dd * 100, 2),
            "status":         status,
            "size_multiplier": size_mult,
            "kill_switch":    kill,
            "peak_equity":    round(self.peak_equity, 2),
            "current_equity": round(self.current_equity, 2),
            # [G7] Duration fields
            "dd_duration_bars":   dur,
            "dd_duration_status": dur_status,
            "dd_duration_note":   (
                f"⚠️ DD {dur} bars — {dur_status}" if dur >= self.DD_DURATION_WARN
                else f"✅ DD duration OK ({dur} bars)"
            ),
        }

_DD_GOVERNOR = DrawdownGovernor()

# ══════════════════════════════════════════════════════════════
# Q9 — SLIPPAGE MODEL (ATR-factor · FOMC · Liquidity)
# ══════════════════════════════════════════════════════════════

def compute_prop_slippage(
    atr_pct: float,
    session: str,
    is_news_window: bool,
    spread_pct: float,
) -> Dict:
    """
    Slippage = base_slip × ATR_factor × session_factor
    FOMC:     ATR × 3.5×
    Low Liq:  ATR × 2.5×
    Normal:   ATR × 1.0×
    """
    base_slip = spread_pct / 2.0   # half spread as base estimate

    if is_news_window:
        atr_factor = 3.5
        reason = "FOMC/NEWS_WINDOW"
    elif session in ("OFF_SESSION", "WEEKEND", "ASIA"):
        atr_factor = 2.5
        reason = "LOW_LIQUIDITY_SESSION"
    elif atr_pct > 80:
        atr_factor = 2.0
        reason = "HIGH_VOLATILITY"
    else:
        atr_factor = 1.0
        reason = "NORMAL"

    estimated_slip_pct = round(base_slip * atr_factor, 4)
    return {
        "estimated_slip_pct": estimated_slip_pct,
        "atr_factor":         atr_factor,
        "reason":             reason,
        "acceptable":         estimated_slip_pct < 0.15,  # >0.15% slippage = caution
    }

# ══════════════════════════════════════════════════════════════
# NEWS FILTER — [G4] Calendar-driven precision blackout
# Primary: Forex Factory JSON API (event date + exact UTC time)
# Fallback: hardcoded UTC windows (original behavior preserved)
# Blackout window: T-5min to T+30min per ICT standard
# ══════════════════════════════════════════════════════════════

_CALENDAR_CACHE: Dict = {"events": [], "ts": 0.0, "ttl": 21600.0}   # 6-hour TTL
_HIGH_IMPACT_CURRENCIES = {"USD", "GBP", "EUR", "JPY", "CNY"}       # BTC-moving currencies

async def fetch_economic_calendar() -> list:
    """
    [G4] Fetch this-week high-impact events from Forex Factory public API.
    Caches for 6 hours — no per-signal latency impact.
    Returns list of {title, date, time, impact, currency, utc_minutes}.
    """
    now = time.time()
    if _CALENDAR_CACHE["ts"] and (now - _CALENDAR_CACHE["ts"]) < _CALENDAR_CACHE["ttl"]:
        return _CALENDAR_CACHE["events"]

    url = "https://nfs.faireconomy.media/ff_calendar_thisweek.json"
    try:
        async with aiohttp.ClientSession() as sess:
            async with sess.get(url, timeout=aiohttp.ClientTimeout(total=6)) as r:
                if r.status == 200:
                    raw = await r.json(content_type=None)
                    events = []
                    for ev in raw:
                        if ev.get("impact", "").lower() != "high":
                            continue
                        currency = (ev.get("currency") or "").upper()
                        if currency not in _HIGH_IMPACT_CURRENCIES:
                            continue
                        # Parse event time to UTC minutes-of-day
                        ev_time_str = ev.get("date", "") + " " + ev.get("time", "")
                        utc_mins = None
                        try:
                            # FF format: "2026-03-15" + "12:30am" or "All Day"
                            t_str = ev.get("time", "").strip().lower()
                            if "all day" not in t_str and t_str:
                                import re as _re
                                m = _re.match(r"(\d{1,2}):(\d{2})(am|pm)", t_str)
                                if m:
                                    hh, mm, ampm = int(m.group(1)), int(m.group(2)), m.group(3)
                                    if ampm == "pm" and hh != 12: hh += 12
                                    if ampm == "am" and hh == 12: hh = 0
                                    # FF times are US/Eastern — convert to UTC (approx UTC+5 for EST)
                                    utc_offset = 5  # rough average; good enough for blackout windows
                                    utc_h = (hh + utc_offset) % 24
                                    utc_mins = utc_h * 60 + mm
                        except Exception as _e:
                            log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
                        events.append({
                            "title":     ev.get("title", "High Impact Event"),
                            "currency":  currency,
                            "date":      ev.get("date", ""),
                            "time_str":  ev.get("time", ""),
                            "utc_mins":  utc_mins,
                        })
                    _CALENDAR_CACHE["events"] = events
                    _CALENDAR_CACHE["ts"]     = now
                    log.info(f"[G4 CALENDAR] Loaded {len(events)} high-impact events for this week")
                    return events
    except Exception as e:
        log.debug(f"[G4 CALENDAR] Fetch failed ({e}); using fallback UTC windows")
    # Return cached (possibly stale) on failure
    return _CALENDAR_CACHE.get("events", [])

def is_news_blackout() -> Dict:
    """
    [G4] Check current UTC time against calendar events first, then fallback to
    hardcoded windows. Returns in_blackout, event_name, minutes_to_event,
    blackout_type ('CALENDAR' | 'FALLBACK').

    Blackout window: T-5min to T+30min per ICT standard (tight, precise).
    """
    now  = datetime.datetime.utcnow()
    mins = now.hour * 60 + now.minute
    today_str = now.strftime("%Y-%m-%d")

    # ── Calendar-driven check (precise) ──────────────────────
    events = _CALENDAR_CACHE.get("events", [])
    for ev in events:
        if ev.get("date", "") != today_str:
            continue
        utc_mins = ev.get("utc_mins")
        if utc_mins is None:
            continue
        # Blackout: T-5 to T+30 (35-minute window centered T+12.5)
        start_bl = utc_mins - 5
        end_bl   = utc_mins + 30
        if start_bl <= mins <= end_bl:
            mins_to_event = utc_mins - mins  # negative = event passed
            return {
                "in_blackout":     True,
                "window":          f"{ev['title']} ({ev['currency']}) @ {ev['time_str']} UTC+5",
                "reason":          f"NEWS_BLACKOUT_CALENDAR ({ev['title']})",
                "event_name":      ev["title"],
                "minutes_to_event": mins_to_event,
                "blackout_type":   "CALENDAR",
            }

    # ── Fallback: hardcoded UTC windows ───────────────────────
    in_blackout = False
    window_name = None
    for (sh, sm, eh, em) in NEWS_BLACKOUT_UTC_HOURS:
        start = sh * 60 + sm
        end   = eh * 60 + em
        if start <= mins <= end:
            in_blackout = True
            window_name = f"{sh:02d}:{sm:02d}–{eh:02d}:{em:02d} UTC"
            break

    return {
        "in_blackout":     in_blackout,
        "window":          window_name,
        "reason":          f"NEWS_BLACKOUT ({window_name})" if in_blackout else "CLEAR",
        "event_name":      window_name or "",
        "minutes_to_event": 0,
        "blackout_type":   "FALLBACK" if in_blackout else "CLEAR",
    }

# ══════════════════════════════════════════════════════════════
# FREQUENCY CONTROL — Max 3 signals per day per user
# ══════════════════════════════════════════════════════════════

def check_frequency_limit(user_id: str) -> Dict:
    """
    Track signal count per user per UTC day. Max 3 signals/day.
    Uses in-memory dict (resets on bot restart — acceptable for prop-grade daily limit).
    """
    now = time.time()
    # Keep only today's timestamps (within last 24h rolling window)
    _DAILY_TRADE_LOG[user_id] = [t for t in _DAILY_TRADE_LOG[user_id] if now - t < 86400]
    count     = len(_DAILY_TRADE_LOG[user_id])
    remaining = max(0, MAX_DAILY_TRADES - count)
    allowed   = count < MAX_DAILY_TRADES

    return {
        "allowed":    allowed,
        "count":      count,
        "remaining":  remaining,
        "max":        MAX_DAILY_TRADES,
        "reason":     "FREQ_OK" if allowed else f"DAILY_LIMIT_REACHED ({count}/{MAX_DAILY_TRADES})",
    }

def record_signal(user_id: str) -> None:
    """Record a signal dispatch for frequency tracking."""
    _DAILY_TRADE_LOG[user_id].append(time.time())

# ══════════════════════════════════════════════════════════════
# Q11 — SELF-LEARNING RL FEEDBACK LOOP
# ══════════════════════════════════════════════════════════════

class RLFeedbackLoop:
    """
    Online RL: State → Action → Reward cycle.
    State:   (regime, vol_rank, drawdown, edge_score)
    Action:  (weight_adjust, size_adjust, disable_strategy, rotate_bias)
    Reward:  Sharpe of recent returns (rolling 20 trades)
    Weekly meta-model retrain · Monthly feature recalibration
    Strategy decay detection via rolling Sharpe degradation.
    [F11] SQLite persistence — RL state survives bot restarts.
    """
    _DB_PATH = "rl_state.db"
    # FIX #3 — SQLite is not async-safe. Multiple concurrent writes cause
    # "database is locked" errors. Serialize all DB access with a threading lock.
    _db_lock = __import__("threading").Lock()

    def __init__(self):
        self._reward_history: List[float] = []
        self._state_history:  List[Dict]  = []
        self._weight_adjustments: Dict    = {
            "regime_weight": 1.0,
            "liq_weight":    1.0,
            "disp_weight":   1.0,
            "session_weight": 1.0,
        }
        self._last_retrain: float = time.time()
        self._strategy_active: bool = True
        self._total_updates: int = 0
        # [v7.0] Epsilon-greedy decay schedule
        self._epsilon:       float = 1.0
        self._epsilon_start: float = 1.0
        self._epsilon_decay: float = 0.995
        self._epsilon_floor: float = 0.05
        # [G6] Adaptive Kelly — live win rate computed from RL trade history
        self.kelly_live_pct:   float = KELLY_MAX_PCT   # starts at cap; recalibrates every 20 trades
        self._rr_history:      List[float] = []        # track recent final_rr values
        # [G9] OOS Genetic holdout — track overfit detection
        self._overfit_count:   int  = 0    # consecutive overfit cycles
        self._is_frozen:       bool = False  # freeze weights if 3 consecutive overfits
        self._prev_weights:    Dict = {}   # weights snapshot before last evolution (for revert)
        # [F11] Load persisted state on startup
        self._init_db()
        self._load_state()

    def _init_db(self):
        """[F11] Create SQLite table if it doesn't exist. FIX #3: lock-protected."""
        with self._db_lock:
            try:
                con = sqlite3.connect(self._DB_PATH)
                con.execute("PRAGMA journal_mode=WAL")
                con.execute("""
                    CREATE TABLE IF NOT EXISTS rl_trades (
                        id        INTEGER PRIMARY KEY AUTOINCREMENT,
                        ts        REAL,
                        symbol    TEXT,
                        reward    REAL,
                        sharpe    REAL,
                        weights   TEXT
                    )
                """)
                con.execute("""
                    CREATE TABLE IF NOT EXISTS rl_meta (
                        key   TEXT PRIMARY KEY,
                        value TEXT
                    )
                """)
                con.commit()
                con.close()
            except Exception as e:
                log.warning(f"[F11 RL DB] Init error: {e}")

    def _recalculate_kelly(self) -> None:
        """
        [G6] Adaptive Kelly: recompute live win rate from last 50 RL trade rewards.
        Blend 60% live + 40% initial cap for stability.
        Research (Frontiers 2020): rolling Kelly outperforms static Kelly.
        """
        if len(self._reward_history) < 10:
            return
        recent = self._reward_history[-50:]
        rl_wr  = sum(1 for r in recent if r > 0) / len(recent)
        avg_rr = sum(self._rr_history[-20:]) / max(len(self._rr_history[-20:]), 1) if self._rr_history else 2.2
        # Full Kelly from live data
        q = 1.0 - rl_wr
        kelly_full = max(0.0, (rl_wr * avg_rr - q) / max(avg_rr, 0.1))
        kelly_q    = kelly_full * KELLY_FRACTION
        kelly_live = max(KELLY_MIN_PCT, min(KELLY_MAX_PCT, kelly_q))
        # Blend with static cap for stability — prevent whiplash on short streaks
        self.kelly_live_pct = round(0.60 * kelly_live + 0.40 * KELLY_MAX_PCT, 5)
        log.info(f"[G6 KELLY] Live recalc: wr={rl_wr:.2f} rr={avg_rr:.2f} → kelly_live={self.kelly_live_pct*100:.3f}%")

    def _compute_oos_fitness(self) -> Tuple[float, float, float]:
        """
        [G9] Split reward_history 70/30 in-sample / OOS.
        Returns (is_sharpe, oos_sharpe, generalization_score).
        """
        n = len(self._reward_history)
        if n < 10:
            return 0.0, 0.0, 1.0
        split = int(n * 0.70)
        is_rewards  = self._reward_history[:split]
        oos_rewards = self._reward_history[split:]
        if len(oos_rewards) < 5:
            return 0.0, 0.0, 1.0
        def _sharpe(r: List[float]) -> float:
            if not r: return 0.0
            mu  = sum(r) / len(r)
            var = sum((x - mu)**2 for x in r) / max(len(r) - 1, 1)
            std = math.sqrt(var) if var > 0 else 1e-9
            return (mu / std) * math.sqrt(252)
        is_s   = _sharpe(is_rewards)
        oos_s  = _sharpe(oos_rewards)
        gen_s  = oos_s / max(abs(is_s), 0.01)   # generalization ratio
        return round(is_s, 4), round(oos_s, 4), round(gen_s, 4)

    def update(self, trade_pnl: float, state: Dict, symbol: str = "UNKNOWN",
               final_rr: float = 2.2) -> Dict:
        """Process a completed trade and update weights. [F11] Persists to SQLite."""
        self._reward_history.append(trade_pnl)
        self._state_history.append(state)
        self._total_updates += 1
        if final_rr > 0:
            self._rr_history.append(final_rr)
            if len(self._rr_history) > 50:
                self._rr_history.pop(0)

        # [v7.0] Anneal epsilon toward floor after each update
        self._epsilon = max(
            self._epsilon_floor,
            self._epsilon_start * (self._epsilon_decay ** self._total_updates)
        )

        # Keep last 100 observations
        if len(self._reward_history) > 100:
            self._reward_history.pop(0)
            self._state_history.pop(0)

        # [G6] Adaptive Kelly recalculation every 20 trades
        if self._total_updates % 20 == 0:
            self._recalculate_kelly()

        action = self._compute_action()
        reward = self._compute_sharpe()
        self._apply_action(action, reward)

        # [F11] Persist to SQLite so state survives restarts
        self._persist_trade(trade_pnl, symbol)

        return {
            "action":         action,
            "reward":         round(reward, 4),
            "sharpe":         round(reward, 4),
            "n_trades":       self._total_updates,
            "epsilon":        round(self._epsilon, 4),
            "kelly_live_pct": round(self.kelly_live_pct * 100, 3),  # [G6]
            "is_frozen":      self._is_frozen,                       # [G9]
        }

    def _compute_sharpe(self) -> float:
        """Rolling Sharpe of last 20 returns."""
        recent = self._reward_history[-20:] if len(self._reward_history) >= 5 else self._reward_history
        if not recent:
            return 0.0
        mean_r = sum(recent) / len(recent)
        var_r  = sum((r - mean_r) ** 2 for r in recent) / max(len(recent) - 1, 1)
        std_r  = math.sqrt(var_r) if var_r > 0 else 1e-9
        return (mean_r / std_r) * math.sqrt(252)

    def _compute_action(self) -> str:
        """Determine action based on recent performance."""
        sharpe = self._compute_sharpe()
        if sharpe < -0.5:
            return "DISABLE_ROTATE"
        elif sharpe < 0.5:
            return "REDUCE_SIZE"
        elif sharpe > 2.0:
            return "MAINTAIN"
        else:
            return "WEIGHT_ADJUST"

    def _apply_action(self, action: str, reward: float) -> None:
        """
        [G9] Apply RL action with OOS validation — revert weights if overfit detected.
        Overfit: generalization_score < 0.5 (OOS Sharpe < 50% of IS Sharpe).
        Freeze after 3 consecutive overfit cycles.
        """
        if self._is_frozen:
            return   # frozen — no weight evolution until enough new OOS data accumulates

        # [G9] OOS check before any weight change
        is_s, oos_s, gen_s = self._compute_oos_fitness()
        overfit = len(self._reward_history) >= 15 and gen_s < 0.5

        if overfit:
            self._overfit_count += 1
            log.warning(f"[G9 OOS] Overfit detected: IS={is_s:.2f} OOS={oos_s:.2f} gen={gen_s:.2f} "
                        f"(count={self._overfit_count})")
            # Revert to previous weights snapshot if available
            if self._prev_weights:
                self._weight_adjustments.update(self._prev_weights)
                log.info("[G9 OOS] Reverted to pre-evolution weights")
            if self._overfit_count >= 3:
                self._is_frozen = True
                log.warning("[G9 OOS] FROZEN — weight evolution halted after 3 overfit cycles")
            return
        else:
            self._overfit_count = 0   # reset on clean cycle

        # Snapshot current weights before evolution (for potential revert)
        self._prev_weights = dict(self._weight_adjustments)

        lr = 0.05  # learning rate
        if action == "REDUCE_SIZE":
            for k in self._weight_adjustments:
                self._weight_adjustments[k] = max(0.5, self._weight_adjustments[k] - lr)
        elif action == "MAINTAIN" or reward > 1.0:
            for k in self._weight_adjustments:
                self._weight_adjustments[k] = min(1.5, self._weight_adjustments[k] + lr * 0.5)
        elif action == "DISABLE_ROTATE":
            self._strategy_active = False

    def get_status(self) -> Dict:
        sharpe = self._compute_sharpe()
        is_s, oos_s, gen_s = self._compute_oos_fitness()
        weeks_since = (time.time() - self._last_retrain) / (7 * 86400)
        return {
            "strategy_active":    self._strategy_active,
            "rolling_sharpe":     round(sharpe, 4),
            "total_updates":      self._total_updates,
            "weight_adjustments": {k: round(v, 4) for k, v in self._weight_adjustments.items()},
            "retrain_due":        weeks_since >= 1.0,
            "weeks_since_retrain": round(weeks_since, 2),
            "last_action":        self._compute_action(),
            "epsilon":            round(self._epsilon, 4),
            # [G6] Adaptive Kelly
            "kelly_live_pct":     round(self.kelly_live_pct * 100, 3),
            # [G9] OOS integrity
            "is_sharpe":          is_s,
            "oos_sharpe":         oos_s,
            "generalization":     gen_s,
            "overfit_detected":   gen_s < 0.5 and len(self._reward_history) >= 15,
            "is_frozen":          self._is_frozen,
            "overfit_count":      self._overfit_count,
        }

    def record_trade_outcome(
        self,
        realized_pnl: float,
        outcome:      str,
        symbol:       str = "UNKNOWN",
    ) -> None:
        """
        [C05/I01] Called by TradeLifecycleTracker when a trade closes.
        Computes multi-objective reward and feeds it to the RL loop.

        Multi-objective reward formula:
          R = w1*norm_pnl - w2*dd_penalty - w3*overtrading - w4*sharpe_delta_penalty
        where sharpe_delta_penalty penalises a drop in rolling Sharpe.
        """
        w1, w2, w3, w4 = 0.40, 0.25, 0.10, 0.25

        # Normalise PnL to [-1, 1] range
        norm_pnl = max(-1.0, min(1.0, realized_pnl * 10.0))

        # DD penalty from current equity drawdown
        dd_now = 0.0
        try:
            dd_now = _REWARD_SHAPER.shape_reward(0.0, abs(min(0.0, realized_pnl)), 0)
        except Exception as _e:
            log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")

        # Overtrading penalty (daily trade count)
        n_today = len([
            t for t in list(self._reward_history)[-20:]
            if t != 0.0   # proxy — each reward entry is 1 trade
        ])
        overtrading_penalty = max(0.0, n_today - 3) * 0.05

        # Sharpe delta: penalise if rolling Sharpe deteriorated
        prev_sharpe = self._compute_sharpe()
        self._reward_history.append(realized_pnl)
        if len(self._reward_history) > 100:
            self._reward_history.pop(0)
        new_sharpe  = self._compute_sharpe()
        sharpe_drop = max(0.0, prev_sharpe - new_sharpe)   # only penalise drops

        reward = (
            w1 * norm_pnl
            - w2 * abs(dd_now)
            - w3 * overtrading_penalty
            - w4 * sharpe_drop
        )
        reward = round(max(-1.0, min(1.0, reward)), 6)

        log.info(
            f"[I01 RL REWARD] {symbol} {outcome} pnl={realized_pnl:+.4f} "
            f"→ R={reward:+.4f} (norm_pnl={norm_pnl:.3f} "
            f"dd={dd_now:.3f} overtrading={overtrading_penalty:.3f} "
            f"sharpe_drop={sharpe_drop:.3f})"
        )
        _write_structured_log("rl_reward", {
            "symbol":  symbol, "outcome": outcome,
            "pnl":     realized_pnl, "reward": reward,
            "sharpe":  round(new_sharpe, 4),
        })
        self._total_updates += 1

        """[F11] Create SQLite table if it doesn't exist. FIX #3: lock-protected."""
        with self._db_lock:
            try:
                con = sqlite3.connect(self._DB_PATH)
                con.execute("PRAGMA journal_mode=WAL")   # fix #5 — WAL prevents write-lock on concurrent async access
                con.execute("""
                    CREATE TABLE IF NOT EXISTS rl_trades (
                        id        INTEGER PRIMARY KEY AUTOINCREMENT,
                        ts        REAL,
                        symbol    TEXT,
                        reward    REAL,
                        sharpe    REAL,
                        weights   TEXT
                    )
                """)
                con.execute("""
                    CREATE TABLE IF NOT EXISTS rl_meta (
                        key   TEXT PRIMARY KEY,
                        value TEXT
                    )
                """)
                con.commit()
                con.close()
            except Exception as e:
                log.warning(f"[F11 RL DB] Init error: {e}")

    def _load_state(self):
        """[F11] Load last 100 rewards and weights from SQLite on startup. FIX #3: lock-protected."""
        with self._db_lock:
            try:
                con = sqlite3.connect(self._DB_PATH)
                rows = con.execute(
                    "SELECT reward FROM rl_trades ORDER BY ts DESC LIMIT 100"
                ).fetchall()
                self._reward_history = [r[0] for r in reversed(rows)]
                row = con.execute(
                    "SELECT value FROM rl_meta WHERE key='total_updates'"
                ).fetchone()
                if row:
                    self._total_updates = int(row[0])
                row = con.execute(
                    "SELECT value FROM rl_meta WHERE key='weights'"
                ).fetchone()
                if row:
                    loaded = json.loads(row[0])
                    self._weight_adjustments.update(loaded)
                con.close()
                if self._reward_history:
                    log.info(f"[F11 RL DB] Loaded {len(self._reward_history)} trades from persistent state.")
            except Exception as e:
                log.warning(f"[F11 RL DB] Load error (starting fresh): {e}")

    def _persist_trade(self, reward: float, symbol: str = "UNKNOWN"):
        """[F11] Persist a single trade reward to SQLite. FIX #3: lock-protected."""
        with self._db_lock:
            try:
                con = sqlite3.connect(self._DB_PATH)
                con.execute(
                    "INSERT INTO rl_trades (ts, symbol, reward, sharpe, weights) VALUES (?,?,?,?,?)",
                    (time.time(), symbol, reward, self._compute_sharpe(),
                     json.dumps(self._weight_adjustments))
                )
                con.execute(
                    "INSERT OR REPLACE INTO rl_meta (key, value) VALUES ('total_updates', ?)",
                    (str(self._total_updates),)
                )
                con.execute(
                    "INSERT OR REPLACE INTO rl_meta (key, value) VALUES ('weights', ?)",
                    (json.dumps(self._weight_adjustments),)
                )
                con.commit()
                con.close()
            except Exception as e:
                log.warning(f"[F11 RL DB] Persist error: {e}")


    def trigger_weekly_retrain(self) -> None:
        """Reset retrain timer and recalibrate weights toward neutral."""
        self._last_retrain = time.time()
        for k in self._weight_adjustments:
            # Drift weights toward 1.0 (neutral) — monthly recalibration effect
            self._weight_adjustments[k] = self._weight_adjustments[k] * 0.9 + 1.0 * 0.1

_RL_LOOP = RLFeedbackLoop()

# ══════════════════════════════════════════════════════════════
# [C05] TRADE LIFECYCLE TRACKER
# Monitors every emitted signal through its full lifecycle:
#   PENDING → TRIGGERED → ACTIVE → CLOSED (WIN/LOSS/EXPIRED)
# Persists to SQLite alongside RL state.
# On close, realized P&L is fed directly to the RL reward function.
# ──────────────────────────────────────────────────────────────
# [C06] PAPER MODE P&L ENGINE
# When HumanOverrideDashboard.paper_mode == True:
#   - Signals are NOT forwarded to users
#   - Hypothetical fills are tracked against live price updates
#   - P&L is logged to SQLite and fed to RL exactly as live trades
#   - Running paper equity curve is maintained
# ══════════════════════════════════════════════════════════════

class TradeLifecycleTracker:
    """
    [C05/C06] Tracks emitted signals from entry zone through SL/TP outcome.

    Each trade record:
      symbol, bias, entry_low, entry_high, sl, tp1, tp2, tp3,
      status, paper_mode, open_ts, close_ts, realized_pnl,
      close_reason (TP1/TP2/TP3/SL/EXPIRED)

    SQLite table: lifecycle_trades
    Max open trades tracked simultaneously: 50 (memory cap)
    Expiry: 48 h with no fill → EXPIRED (prevents stale ghost trades)
    """

    _DB_PATH         = "rl_state.db"
    _db_lock         = __import__("threading").Lock()
    _MAX_OPEN        = 50
    _EXPIRY_HOURS    = 48

    def __init__(self) -> None:
        self._open_trades: Dict[str, Dict] = {}   # trade_id → record
        self._init_db()

    # ── SQLite schema ─────────────────────────────────────────
    def _init_db(self) -> None:
        try:
            with self._db_lock:
                con = sqlite3.connect(self._DB_PATH)
                con.execute("""
                    CREATE TABLE IF NOT EXISTS lifecycle_trades (
                        trade_id     TEXT PRIMARY KEY,
                        symbol       TEXT,
                        bias         TEXT,
                        entry_low    REAL,
                        entry_high   REAL,
                        sl           REAL,
                        tp1          REAL,
                        tp2          REAL,
                        tp3          REAL,
                        status       TEXT,
                        paper_mode   INTEGER,
                        open_ts      REAL,
                        close_ts     REAL,
                        realized_pnl REAL,
                        close_reason TEXT
                    )
                """)
                con.execute("""
                    CREATE TABLE IF NOT EXISTS paper_equity (
                        ts        REAL PRIMARY KEY,
                        equity    REAL,
                        trade_id  TEXT,
                        pnl       REAL,
                        symbol    TEXT
                    )
                """)
                con.commit()
                con.close()
        except Exception as e:
            log.warning(f"[C05 LIFECYCLE] DB init failed: {e}")

    # ── Register a new signal ─────────────────────────────────
    def open_trade(
        self,
        symbol:     str,
        bias:       str,
        entry_low:  float,
        entry_high: float,
        sl:         float,
        tp1:        float,
        tp2:        float,
        tp3:        float,
        paper_mode: bool = False,
    ) -> str:
        """Register a new pending trade. Returns trade_id."""
        # Enforce open trade cap
        if len(self._open_trades) >= self._MAX_OPEN:
            oldest = min(self._open_trades, key=lambda k: self._open_trades[k]["open_ts"])
            self._expire_trade(oldest)

        trade_id = f"{symbol}_{bias}_{int(time.time()*1000)}"
        record = {
            "trade_id":    trade_id,
            "symbol":      symbol,
            "bias":        bias,
            "entry_low":   entry_low,
            "entry_high":  entry_high,
            "sl":          sl,
            "tp1":         tp1,
            "tp2":         tp2,
            "tp3":         tp3,
            "status":      "PENDING",
            "paper_mode":  paper_mode,
            "open_ts":     time.time(),
            "close_ts":    None,
            "realized_pnl": None,
            "close_reason": None,
        }
        self._open_trades[trade_id] = record
        self._persist(record)
        log.info(f"[C05 LIFECYCLE] OPEN  {trade_id} | paper={paper_mode}")
        return trade_id

    # ── Update open trades against current price ──────────────
    def update_prices(self, symbol: str, current_price: float, paper_mode: bool) -> None:
        """
        [C05/C06] Called on each RTCW cycle or analysis completion.
        Checks all open trades for this symbol against current_price.
        Closes trades that have hit SL or TP.
        Expires stale trades older than _EXPIRY_HOURS.
        """
        now = time.time()
        to_close: List[Tuple[str, str, float]] = []   # (trade_id, reason, pnl)

        for tid, rec in list(self._open_trades.items()):
            if rec["symbol"] != symbol:
                continue

            # ── Expiry check ──────────────────────────────────
            age_h = (now - rec["open_ts"]) / 3600.0
            if age_h > self._EXPIRY_HOURS:
                to_close.append((tid, "EXPIRED", 0.0))
                continue

            el, eh = rec["entry_low"], rec["entry_high"]
            sl     = rec["sl"]
            tp1, tp2, tp3 = rec["tp1"], rec["tp2"], rec["tp3"]
            entry_mid = (el + eh) / 2.0
            risk_dist = abs(entry_mid - sl) if abs(entry_mid - sl) > 1e-12 else 1.0

            # ── PENDING → TRIGGERED when price enters entry zone ─
            if rec["status"] == "PENDING":
                if el <= current_price <= eh:
                    self._open_trades[tid]["status"] = "TRIGGERED"
                    rec["status"] = "TRIGGERED"

            # ── Check SL/TP once triggered ─────────────────────
            if rec["status"] in ("TRIGGERED", "ACTIVE"):
                if rec["bias"] == "BULLISH":
                    if current_price <= sl:
                        raw_pnl = -(abs(entry_mid - sl) / entry_mid)
                        to_close.append((tid, "SL", round(raw_pnl, 6)))
                    elif current_price >= tp3:
                        raw_pnl = abs(tp3 - entry_mid) / entry_mid
                        to_close.append((tid, "TP3", round(raw_pnl, 6)))
                    elif current_price >= tp2:
                        raw_pnl = abs(tp2 - entry_mid) / entry_mid
                        to_close.append((tid, "TP2", round(raw_pnl, 6)))
                    elif current_price >= tp1:
                        raw_pnl = abs(tp1 - entry_mid) / entry_mid
                        to_close.append((tid, "TP1", round(raw_pnl, 6)))
                else:   # BEARISH
                    if current_price >= sl:
                        raw_pnl = -(abs(sl - entry_mid) / entry_mid)
                        to_close.append((tid, "SL", round(raw_pnl, 6)))
                    elif current_price <= tp3:
                        raw_pnl = abs(entry_mid - tp3) / entry_mid
                        to_close.append((tid, "TP3", round(raw_pnl, 6)))
                    elif current_price <= tp2:
                        raw_pnl = abs(entry_mid - tp2) / entry_mid
                        to_close.append((tid, "TP2", round(raw_pnl, 6)))
                    elif current_price <= tp1:
                        raw_pnl = abs(entry_mid - tp1) / entry_mid
                        to_close.append((tid, "TP1", round(raw_pnl, 6)))

        for tid, reason, pnl in to_close:
            self._close_trade(tid, reason, pnl, current_price, paper_mode)

    # ── Close a trade ─────────────────────────────────────────
    def _close_trade(
        self,
        trade_id:     str,
        close_reason: str,
        realized_pnl: float,
        current_price: float,
        paper_mode:   bool,
    ) -> None:
        rec = self._open_trades.pop(trade_id, None)
        if rec is None:
            return
        rec["status"]       = "CLOSED"
        rec["close_ts"]     = time.time()
        rec["realized_pnl"] = realized_pnl
        rec["close_reason"] = close_reason
        self._persist(rec)

        outcome = "WIN" if realized_pnl > 0 else ("LOSS" if realized_pnl < 0 else "FLAT")
        log.info(
            f"[C05 LIFECYCLE] CLOSE {trade_id} | {close_reason} | "
            f"pnl={realized_pnl:+.4f} | {outcome} | paper={paper_mode}"
        )
        _write_structured_log("trade_closed", {
            "trade_id":    trade_id,
            "close_reason": close_reason,
            "realized_pnl": realized_pnl,
            "outcome":     outcome,
            "paper_mode":  paper_mode,
        })

        # [C06] Paper equity curve update
        if paper_mode:
            self._update_paper_equity(trade_id, realized_pnl, rec["symbol"])

        # Feed realized outcome to RL reward loop
        try:
            _RL_LOOP.record_trade_outcome(
                realized_pnl=realized_pnl,
                outcome=outcome,
                symbol=rec["symbol"],
            )
        except Exception as e:
            log.debug(f"[C05] RL feed failed: {e}")

    def _expire_trade(self, trade_id: str) -> None:
        self._close_trade(trade_id, "EXPIRED", 0.0, 0.0, False)

    # ── [C06] Paper equity curve ──────────────────────────────
    def _update_paper_equity(self, trade_id: str, pnl: float, symbol: str) -> None:
        """[C06] Append realized paper trade P&L to equity curve in SQLite."""
        try:
            with self._db_lock:
                con = sqlite3.connect(self._DB_PATH)
                # Compute running equity from last row
                row = con.execute(
                    "SELECT equity FROM paper_equity ORDER BY ts DESC LIMIT 1"
                ).fetchone()
                prev_equity = row[0] if row else 1.0
                new_equity  = round(prev_equity * (1.0 + pnl), 6)
                con.execute(
                    "INSERT OR REPLACE INTO paper_equity (ts, equity, trade_id, pnl, symbol) "
                    "VALUES (?, ?, ?, ?, ?)",
                    (time.time(), new_equity, trade_id, pnl, symbol)
                )
                con.commit()
                con.close()
                log.info(
                    f"[C06 PAPER] Equity {prev_equity:.4f} → {new_equity:.4f} "
                    f"({pnl:+.4f}) [{symbol}]"
                )
        except Exception as e:
            log.warning(f"[C06 PAPER] Equity update failed: {e}")

    def get_paper_summary(self) -> Dict:
        """[C06] Return paper trading performance summary from SQLite."""
        try:
            with self._db_lock:
                con = sqlite3.connect(self._DB_PATH)
                rows = con.execute(
                    "SELECT pnl, equity FROM paper_equity ORDER BY ts ASC"
                ).fetchall()
                con.close()
            if not rows:
                return {"paper_trades": 0, "paper_equity": 1.0,
                        "paper_pnl_pct": 0.0, "paper_sharpe": 0.0,
                        "paper_sortino": 0.0, "paper_calmar": 0.0,
                        "paper_note": "No paper trades yet"}
            pnls   = [r[0] for r in rows]
            equity = rows[-1][1]
            wins   = sum(1 for p in pnls if p > 0)
            wr     = round(wins / len(pnls), 4)
            total_pct = round((equity - 1.0) * 100, 2)
            sharpe  = compute_sortino_ratio(pnls)   # reuse Sortino helper
            sortino = compute_sortino_ratio(pnls)
            calmar  = compute_calmar_ratio(pnls)
            return {
                "paper_trades":   len(pnls),
                "paper_winrate":  wr,
                "paper_equity":   equity,
                "paper_pnl_pct":  total_pct,
                "paper_sharpe":   sharpe,
                "paper_sortino":  sortino,
                "paper_calmar":   calmar,
                "paper_note": (
                    f"Paper: {len(pnls)} trades | WR={wr*100:.1f}% | "
                    f"Equity={equity:.4f} ({total_pct:+.1f}%) | "
                    f"Sortino={sortino:.2f} Calmar={calmar:.2f}"
                ),
            }
        except Exception as e:
            return {"paper_trades": 0, "paper_equity": 1.0,
                    "paper_pnl_pct": 0.0, "paper_note": f"Paper summary error: {e}"}

    # ── SQLite persistence ────────────────────────────────────
    def _persist(self, rec: Dict) -> None:
        try:
            with self._db_lock:
                con = sqlite3.connect(self._DB_PATH)
                con.execute("""
                    INSERT OR REPLACE INTO lifecycle_trades
                    (trade_id, symbol, bias, entry_low, entry_high,
                     sl, tp1, tp2, tp3, status, paper_mode,
                     open_ts, close_ts, realized_pnl, close_reason)
                    VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
                """, (
                    rec["trade_id"], rec["symbol"], rec["bias"],
                    rec["entry_low"], rec["entry_high"],
                    rec["sl"], rec["tp1"], rec["tp2"], rec["tp3"],
                    rec["status"], int(rec["paper_mode"]),
                    rec["open_ts"], rec["close_ts"],
                    rec["realized_pnl"], rec["close_reason"],
                ))
                con.commit()
                con.close()
        except Exception as e:
            log.debug(f"[C05] Persist failed: {e}")

    def get_open_count(self) -> int:
        return len(self._open_trades)

    def get_open_trades(self) -> List[Dict]:
        return list(self._open_trades.values())


_TRADE_TRACKER = TradeLifecycleTracker()


# ══════════════════════════════════════════════════════════════
# TIMING GRADE ENGINE — Grade A timing filter
# Scores the QUALITY OF TIMING not just the structure
# Feeds into Trade Score as a new component (+15 pts max)
# ══════════════════════════════════════════════════════════════

def compute_timing_grade(
    rsi:           float,
    slope:         float,
    adx:           float,
    bias:          str,
    ltf_bias:      str,
    htf_bias:      str,
    last_candle:   list,    # [open, high, low, close]
    prev_candles:  list,    # last 5 candles [[o,h,l,c], ...]
    session:       str,
    disp_score:    float,
) -> Dict:
    """
    Timing Grade — scores how well-timed the entry is RIGHT NOW.

    Components (100 pts total):
      RSI momentum alignment   (20 pts) — RSI trending in trade direction
      Slope + ADX confirmation (15 pts) — trend has strength and direction
      LTF/HTF bias alignment   (20 pts) — lower TF confirms higher TF
      Rejection candle quality (20 pts) — last candle shows clean rejection
      Lower highs / lower lows (15 pts) — structure confirming the move
      Session timing bonus     (10 pts) — London/NY = ideal, Asia = penalty

    Grades: A(80+) B(65+) C(50+) D(35+) F(<35)
    """
    score = 0.0

    # ── 1. RSI Momentum Alignment (20 pts)
    # BEARISH: RSI < 55 and falling (not overbought bounce)
    # BULLISH: RSI > 45 and rising (not oversold dead-cat)
    if bias == "BEARISH":
        if rsi < 45:    score += 20   # strong bearish momentum
        elif rsi < 55:  score += 14   # moderate bearish
        elif rsi < 65:  score += 7    # neutral — caution
        else:           score += 0    # overbought — bad timing for short
    else:
        if rsi > 55:    score += 20
        elif rsi > 45:  score += 14
        elif rsi > 35:  score += 7
        else:           score += 0

    # ── 2. Slope + ADX (15 pts)
    # Strong trend (ADX > 25) + slope in trade direction = ideal timing
    slope_aligned = (slope < 0 and bias == "BEARISH") or (slope > 0 and bias == "BULLISH")
    if slope_aligned and adx > 25:   score += 15
    elif slope_aligned and adx > 18: score += 10
    elif slope_aligned:               score += 6
    else:                             score += 0   # slope against bias = bad timing

    # ── 3. LTF/HTF Bias Alignment (20 pts)
    # Both timeframes pointing same direction = timing is confirmed
    if ltf_bias == htf_bias == bias:  score += 20   # perfect alignment
    elif htf_bias == bias:            score += 12   # HTF agrees, LTF lagging
    elif ltf_bias == bias:            score += 6    # LTF agrees, HTF lagging
    else:                             score += 0    # both against — very bad timing

    # ── 4. Rejection Candle Quality (20 pts)
    # Last closed candle should show rejection from the zone
    if last_candle and len(last_candle) >= 4:
        o, h, l, c = last_candle[0], last_candle[1], last_candle[2], last_candle[3]
        candle_range = max(h - l, 1e-9)
        body = abs(c - o)
        body_pct = body / candle_range

        if bias == "BEARISH":
            # Bearish rejection: red candle, upper wick > 30% of range, closes in lower half
            upper_wick = h - max(o, c)
            upper_wick_pct = upper_wick / candle_range
            closed_lower_half = c < (h + l) / 2
            is_red = c < o
            if is_red and upper_wick_pct > 0.3 and closed_lower_half:
                score += 20   # textbook bearish rejection candle
            elif is_red and closed_lower_half:
                score += 13
            elif is_red:
                score += 7
            else:
                score += 0    # green candle — bad timing for short entry
        else:
            # Bullish rejection: green candle, lower wick > 30%, closes in upper half
            lower_wick = min(o, c) - l
            lower_wick_pct = lower_wick / candle_range
            closed_upper_half = c > (h + l) / 2
            is_green = c > o
            if is_green and lower_wick_pct > 0.3 and closed_upper_half:
                score += 20
            elif is_green and closed_upper_half:
                score += 13
            elif is_green:
                score += 7
            else:
                score += 0

    # ── 5. Lower Highs / Lower Lows Structure (15 pts)
    # Check last 4-5 candles for consecutive lower highs (BEARISH) or higher lows (BULLISH)
    if prev_candles and len(prev_candles) >= 3:
        highs = [c[1] for c in prev_candles[-4:]]
        lows  = [c[2] for c in prev_candles[-4:]]
        if bias == "BEARISH":
            lower_highs = all(highs[i] > highs[i+1] for i in range(len(highs)-1))
            lower_lows  = all(lows[i]  > lows[i+1]  for i in range(len(lows)-1))
            if lower_highs and lower_lows:  score += 15   # perfect lower H + lower L
            elif lower_highs:               score += 10   # lower highs only
            elif lower_lows:                score += 5    # lower lows only
        else:
            higher_lows  = all(lows[i]  < lows[i+1]  for i in range(len(lows)-1))
            higher_highs = all(highs[i] < highs[i+1] for i in range(len(highs)-1))
            if higher_highs and higher_lows: score += 15
            elif higher_lows:                score += 10
            elif higher_highs:               score += 5

    # ── 6. Session Timing Bonus (10 pts)
    # London open + NY AM = best execution windows
    # Asia = low volume, avoid
    if session in ("LONDON", "NY_AM"):     score += 10   # prime execution window
    elif session in ("NY_PM", "OVERLAP"):  score += 6    # decent
    elif session == "ASIA":               score += 2    # low volume penalty
    else:                                  score += 5    # unknown/weekend

    # Displacement bonus: strong displacement = timing confirmed
    if disp_score >= 2.0:   score = min(100.0, score + 5)
    elif disp_score >= 1.5: score = min(100.0, score + 2)

    score = round(min(100.0, max(0.0, score)), 1)

    # Grade
    if score >= 80:   timing_grade = "A"
    elif score >= 65: timing_grade = "B"
    elif score >= 50: timing_grade = "C"
    elif score >= 35: timing_grade = "D"
    else:             timing_grade = "F"

    # Emoji
    grade_icon = {"A": "🟢", "B": "🔵", "C": "🟡", "D": "🟠", "F": "🔴"}.get(timing_grade, "⚪")

    return {
        "timing_score":       score,
        "timing_grade":       timing_grade,
        "timing_icon":        grade_icon,
        "rsi_contrib":        round(min(20, score), 1),
        "session":            session,
        "ltf_htf_aligned":    ltf_bias == htf_bias == bias,
        "slope_aligned":      slope_aligned,
        "rejection_candle":   last_candle is not None,
        "timing_note":        (
            "⚡ Grade A — Perfect timing. Enter now." if timing_grade == "A" else
            "✅ Grade B — Good timing. Proceed with plan." if timing_grade == "B" else
            "⚠️ Grade C — Acceptable. Wait for LTF confirmation." if timing_grade == "C" else
            "🚫 Grade D — Poor timing. Wait for better entry candle." if timing_grade == "D" else
            "❌ Grade F — Do NOT enter. Timing is against you."
        ),
    }


# ══════════════════════════════════════════════════════════════
# Q4+Q5 — SIGNAL SCORING ENGINE (Weighting + Confluence → TRADE_SCORE 0–100)
# ══════════════════════════════════════════════════════════════

def compute_trade_score(
    gate_pass:     List[bool],
    conf_total:    float,
    disp_score:    float,
    lqi:           int,
    hmm_state:     str,
    macro_score:   float,
    of_score:      int,
    timing_score:  float = 50.0,   # NEW — timing grade contribution
) -> Dict:
    """
    TRADE_SCORE = weighted confluence of all Quant Stack outputs.
    Score 0–100. Grade: S(90+) A(75+) B(60+) C(45+) D(30+) F(<30)
    v5.0: Timing grade now feeds in as a component (+15 pts max).
    Pro-grade: ICT structure bonus + corrected HMM multipliers.
    """
    rl_weights = _RL_LOOP._weight_adjustments

    gates_passed  = sum(gate_pass)
    gate_score    = (gates_passed / 10) * 30 * rl_weights.get("regime_weight", 1.0)  # 0–30
    conf_score    = (conf_total / 100) * 25   # 0–25
    lqi_score     = (lqi / 100) * 15 * rl_weights.get("liq_weight", 1.0)             # 0–15
    disp_contrib  = min(10.0, disp_score * 5) * rl_weights.get("disp_weight", 1.0)   # 0–10
    of_contrib    = (of_score / 100) * 10     # 0–10 (orderflow)
    macro_contrib = (macro_score / 100) * 10  # 0–10 (macro regime)

    # ICT Structure Bonus: extra points when core ICT conditions are clean
    # Gates 2 (BOS), 4 (Structure), 5 (Displacement), 6 (PD Array) are the ICT heart
    ict_core_gates = [gate_pass[1], gate_pass[3], gate_pass[4], gate_pass[5]]
    ict_bonus = sum(ict_core_gates) * 1.5   # up to +6 points for clean ICT structure

    # HMM modifier — pro-grade corrected (VOLATILE was too punishing at 0.75)
    # TRENDING:  full score (market is doing what ICT expects)
    # VOLATILE:  0.85× (reduce slightly — risk is higher but setup may still be valid)
    # CHOPPY:    0.55× (significant penalty — low-probability environment)
    if hmm_state == "CHOPPY":
        hmm_mult = 0.55
    elif hmm_state == "VOLATILE":
        hmm_mult = 0.85
    else:
        hmm_mult = 1.0

    # Timing contribution: up to +15 pts — rewards Grade A timing
    timing_contrib = (timing_score / 100) * 15   # 0–15 pts

    raw_score = (gate_score + conf_score + lqi_score + disp_contrib +
                 of_contrib + macro_contrib + ict_bonus + timing_contrib) * hmm_mult
    trade_score = round(max(0.0, min(100.0, raw_score)), 1)

    if trade_score >= 90:   trade_grade = "S"
    elif trade_score >= 75: trade_grade = "A"
    elif trade_score >= 60: trade_grade = "B"
    elif trade_score >= 45: trade_grade = "C"
    elif trade_score >= 30: trade_grade = "D"
    else:                   trade_grade = "F"

    # Combined grade: structure × timing  (the real number traders should use)
    # Structure grade from trade_score, timing grade passed in via timing_score
    _str_val  = trade_score
    _tim_val  = timing_score
    combined  = round((_str_val * 0.6 + _tim_val * 0.4), 1)   # 60% structure, 40% timing
    if combined >= 82:   combined_grade = "A"
    elif combined >= 68: combined_grade = "B"
    elif combined >= 52: combined_grade = "C"
    elif combined >= 38: combined_grade = "D"
    else:                combined_grade = "F"

    return {
        "trade_score":     trade_score,
        "trade_grade":     trade_grade,
        "combined_score":  combined,
        "combined_grade":  combined_grade,
        "gate_contrib":    round(gate_score,    2),
        "conf_contrib":    round(conf_score,    2),
        "lqi_contrib":     round(lqi_score,     2),
        "disp_contrib":    round(disp_contrib,  2),
        "of_contrib":      round(of_contrib,    2),
        "macro_contrib":   round(macro_contrib, 2),
        "timing_contrib":  round(timing_contrib,2),
        "ict_bonus":       round(ict_bonus,     2),
        "hmm_mult":        hmm_mult,
    }

# ══════════════════════════════════════════════════════════════
# SECTION 1 — CANDLE DATA MODEL
# ══════════════════════════════════════════════════════════════

@dataclass
class Candle:
    timestamp: float
    open: float
    high: float
    low: float
    close: float
    volume: float

class CandleArray:
    """Numpy-style fast access using plain lists (no numpy needed, low memory)."""
    def __init__(self, ohlcv: list):
        self.opens   = [float(c[0] or 0) for c in ohlcv]
        self.highs   = [float(c[1] or 0) for c in ohlcv]
        self.lows    = [float(c[2] or 0) for c in ohlcv]
        self.closes  = [float(c[3] or 0) for c in ohlcv]
        self.volumes = [float(c[4]) if len(c) > 4 and c[4] is not None else 0.0 for c in ohlcv]
        self.n       = len(ohlcv)

    def to_candles(self) -> List[Candle]:
        return [Candle(0.0, self.opens[i], self.highs[i], self.lows[i],
                       self.closes[i], self.volumes[i]) for i in range(self.n)]

# ══════════════════════════════════════════════════════════════
# SECTION 2 — INSTITUTIONAL ATR (true range, vectorized)
# ══════════════════════════════════════════════════════════════

def compute_true_atr(ca: CandleArray, period: int = 14) -> List[float]:
    """Returns full ATR array, one value per candle (0 for first candle)."""
    n = ca.n
    trs = [0.0]
    for i in range(1, n):
        hl  = ca.highs[i] - ca.lows[i]
        hpc = abs(ca.highs[i] - ca.closes[i-1])
        lpc = abs(ca.lows[i]  - ca.closes[i-1])
        trs.append(max(hl, hpc, lpc))
    # Rolling mean ATR
    atrs = [0.0] * n
    for i in range(period, n):
        atrs[i] = sum(trs[i-period+1:i+1]) / period
    # Fill early values
    for i in range(1, period):
        atrs[i] = sum(trs[1:i+1]) / i if i > 0 else 0.0
    return atrs

# ══════════════════════════════════════════════════════════════
# SECTION 3 — MARKET STRUCTURE ENGINE (fractal BOS/CHOCH)
# ══════════════════════════════════════════════════════════════

def find_fractal_swings(ca: CandleArray, lookback: int = 2) -> Tuple[List[Tuple], List[Tuple]]:
    """Fractal swing highs/lows: high[i] > all neighbors within lookback."""
    swing_highs, swing_lows = [], []
    for i in range(lookback, ca.n - lookback):
        is_high = all(ca.highs[i] > ca.highs[j] for j in range(i-lookback, i+lookback+1) if j != i)
        is_low  = all(ca.lows[i]  < ca.lows[j]  for j in range(i-lookback, i+lookback+1) if j != i)
        if is_high:
            swing_highs.append((i, ca.highs[i]))
        if is_low:
            swing_lows.append((i, ca.lows[i]))
    return swing_highs, swing_lows

def detect_bos_choch(ca: CandleArray, atrs: List[float]) -> Dict:
    """
    Full BOS/CHOCH detection with ATR-confirmation.
    bullish_BOS: close > last_swing_high AND excess > 0.3*ATR AND body > 0.5*ATR
    bearish_BOS: close < last_swing_low  AND excess > 0.3*ATR AND body > 0.5*ATR
    CHOCH = BOS that reverses previous trend direction.
    """
    swing_highs, swing_lows = find_fractal_swings(ca)
    if not swing_highs or not swing_lows:
        return {"bias": "BULLISH", "bos_type": "BULLISH BOS", "bos_price": ca.closes[-1],
                "structure_valid": True, "choch": False, "prev_trend": "BULLISH"}

    last_sh = swing_highs[-1][1]
    last_sl = swing_lows[-1][1]
    prev_bias = "BULLISH" if len(swing_highs) >= 2 and swing_highs[-1][1] > swing_highs[-2][1] else "BEARISH"

    bos_events = []
    for i in range(max(1, ca.n - 40), ca.n):
        atr_i = atrs[i] if atrs[i] > 0 else 1e-9
        body  = abs(ca.closes[i] - ca.opens[i])
        # Bullish BOS
        if (ca.closes[i] > last_sh and
            (ca.closes[i] - last_sh) > 0.3 * atr_i and
            body > 0.5 * atr_i):
            choch = (prev_bias == "BEARISH")
            bos_events.append({"bias": "BULLISH", "bos_type": "BULLISH CHOCH" if choch else "BULLISH BOS",
                                "bos_price": last_sh, "structure_valid": True, "choch": choch,
                                "prev_trend": prev_bias})
        # Bearish BOS
        if (ca.closes[i] < last_sl and
            (last_sl - ca.closes[i]) > 0.3 * atr_i and
            body > 0.5 * atr_i):
            choch = (prev_bias == "BULLISH")
            bos_events.append({"bias": "BEARISH", "bos_type": "BEARISH CHOCH" if choch else "BEARISH BOS",
                                "bos_price": last_sl, "structure_valid": True, "choch": choch,
                                "prev_trend": prev_bias})

    if bos_events:
        return bos_events[-1]

    # Fallback to HH/HL structure
    hh = swing_highs[-1][1] > swing_highs[-2][1] if len(swing_highs) >= 2 else True
    hl = swing_lows[-1][1]  > swing_lows[-2][1]  if len(swing_lows)  >= 2 else True
    if hh and hl:
        return {"bias": "BULLISH", "bos_type": "BULLISH BOS", "bos_price": last_sh,
                "structure_valid": True, "choch": False, "prev_trend": "BEARISH"}
    else:
        return {"bias": "BEARISH", "bos_type": "BEARISH BOS", "bos_price": last_sl,
                "structure_valid": True, "choch": False, "prev_trend": "BULLISH"}

# ══════════════════════════════════════════════════════════════
# SECTION 4 — DISPLACEMENT ENGINE (volume-weighted score)
# ══════════════════════════════════════════════════════════════

def compute_displacement_score(ca: CandleArray, atrs: List[float], idx: int) -> float:
    """
    displacement_score = (body/ATR)*0.5 + (vol_ratio)*0.3 + (range/ATR)*0.2
    Institutional threshold >= 1.5
    """
    if idx < 20 or atrs[idx] <= 0:
        return 0.0
    atr   = atrs[idx]
    body  = abs(ca.closes[idx] - ca.opens[idx])
    rng   = ca.highs[idx] - ca.lows[idx]
    avg_vol = sum(ca.volumes[idx-20:idx]) / 20 if sum(ca.volumes[idx-20:idx]) > 0 else 1.0
    vol_ratio = ca.volumes[idx] / max(avg_vol, 1e-9)
    score = (body / atr) * 0.5 + vol_ratio * 0.3 + (rng / atr) * 0.2
    return round(score, 4)

def find_best_displacement(ca: CandleArray, atrs: List[float], bias: str, lookback: int = 20) -> Tuple[bool, float, int, float]:
    """Scan last N candles for displacement >= 1.5. Returns (found, atr_mult, body_pct, disp_score)."""
    for i in range(ca.n - 1, max(ca.n - lookback - 1, 0), -1):
        score = compute_displacement_score(ca, atrs, i)
        if score >= 1.5:
            atr   = atrs[i] if atrs[i] > 0 else 1e-9
            rng   = ca.highs[i] - ca.lows[i]
            body  = abs(ca.closes[i] - ca.opens[i])
            body_pct = int(body / rng * 100) if rng > 0 else 0
            atr_mult = round(rng / atr, 2)
            bull_dir = ca.closes[i] > ca.opens[i] and bias == "BULLISH"
            bear_dir = ca.closes[i] < ca.opens[i] and bias == "BEARISH"
            if bull_dir or bear_dir:
                return True, atr_mult, body_pct, score
    # No qualifying displacement — return last candle metrics
    i = ca.n - 1
    atr = atrs[i] if atrs[i] > 0 else 1e-9
    rng = ca.highs[i] - ca.lows[i]
    return False, round(rng / atr, 2), 0, compute_displacement_score(ca, atrs, i)

# ══════════════════════════════════════════════════════════════
# SECTION 5 — LIQUIDITY ENGINE (equal H/L + sweep detection)
# ══════════════════════════════════════════════════════════════

def detect_liquidity_institutional(ca: CandleArray, atrs: List[float], bias: str) -> Dict:
    """
    Equal highs: abs(high[i]-high[j]) <= 0.1 * ATR[i]
    Equal lows:  abs(low[i]-low[j])   <= 0.1 * ATR[i]
    Sweep: low[i] < eq_low AND close[i] > eq_low (bullish)
           high[i] > eq_high AND close[i] < eq_high (bearish)
    Returns dict with swept_price, target_price, sweep_confirmed, lq_zones.
    """
    atr_now = (atrs[-1] or 0.0) if (atrs[-1] or 0.0) > 0 else (ca.highs[-1] - ca.lows[-1])
    tol = 0.1 * atr_now

    # Find equal highs and lows
    eq_highs, eq_lows = [], []
    n = min(ca.n, 50)
    for i in range(ca.n - n, ca.n - 1):
        for j in range(i + 1, ca.n):
            if abs(ca.highs[i] - ca.highs[j]) <= tol:
                eq_highs.append({"price": (ca.highs[i]+ca.highs[j])/2, "type": "EQH", "idx": j})
            if abs(ca.lows[i] - ca.lows[j]) <= tol:
                eq_lows.append({"price": (ca.lows[i]+ca.lows[j])/2, "type": "EQL", "idx": j})

    # Check sweeps on last 10 candles (BTC 4H sweep resolution requires wider window)
    sweep_confirmed = False
    swept_price = min(ca.lows[-20:]) if bias == "BULLISH" else max(ca.highs[-20:])
    target_price = max(ca.highs[-20:]) if bias == "BULLISH" else min(ca.lows[-20:])

    for zone in eq_lows:
        eq_l = zone["price"]
        for i in range(max(0, ca.n - 10), ca.n):
            # [v7.0-U4] Close-confirmed sweep: close must be meaningfully ABOVE swept level
            # (not just any close > eq_l — require 0.05% clearance to eliminate wick-only noise)
            # Thesis: wick-only check produces ~40-60% false sweeps vs. close confirmation.
            close_confirm_threshold = eq_l * 1.0005   # 0.05% above swept level
            if ca.lows[i] < eq_l and ca.closes[i] > close_confirm_threshold and bias == "BULLISH":
                sweep_confirmed = True
                swept_price = eq_l
                break

    for zone in eq_highs:
        eq_h = zone["price"]
        for i in range(max(0, ca.n - 10), ca.n):
            # [v7.0-U4] Close-confirmed sweep: close must be meaningfully BELOW swept level
            close_confirm_threshold = eq_h * 0.9995   # 0.05% below swept level
            if ca.highs[i] > eq_h and ca.closes[i] < close_confirm_threshold and bias == "BEARISH":
                sweep_confirmed = True
                swept_price = eq_h
                break

    if bias == "BULLISH":
        target_price = max([z["price"] for z in eq_highs], default=max(ca.highs[-20:]))
    else:
        target_price = min([z["price"] for z in eq_lows], default=min(ca.lows[-20:]))

    all_zones = eq_highs + eq_lows
    return {
        "swept_price": swept_price,
        "target_price": target_price,
        "sweep_confirmed": sweep_confirmed,
        "lq_zones": all_zones,
        "eq_high_count": len(eq_highs),
        "eq_low_count": len(eq_lows),
    }

def compute_lqi_institutional(liq: Dict, ohlcv_len: int) -> int:
    """LQI 0-100 from institutional liquidity data."""
    score = 0
    score += min(40, (liq["eq_high_count"] + liq["eq_low_count"]) * 5)
    score += 40 if liq["sweep_confirmed"] else 0
    # Bonus for having both equal highs AND equal lows (richer liquidity pool)
    score += 20 if (liq["eq_high_count"] > 0 and liq["eq_low_count"] > 0) else 0
    return min(100, score)

# ══════════════════════════════════════════════════════════════
# SECTION 6 — FVG ENGINE (exact 3-candle pattern)
# ══════════════════════════════════════════════════════════════

def detect_fvg_institutional(ca: CandleArray, bias: str) -> Optional[Tuple[float, float]]:
    """
    Bullish FVG: low[i] > high[i-2]  → gap = high[i-2] → low[i]
    Bearish FVG: high[i] < low[i-2]  → gap = high[i] → low[i-2]
    Scans recent candles, returns most recent valid FVG or None.
    """
    fvg_zones = []
    for i in range(2, ca.n):
        if bias == "BULLISH":
            if ca.lows[i] > ca.highs[i-2]:
                fvg_zones.append((ca.highs[i-2], ca.lows[i]))
        else:
            if ca.highs[i] < ca.lows[i-2]:
                fvg_zones.append((ca.highs[i], ca.lows[i-2]))
    if fvg_zones:
        lo, hi = fvg_zones[-1]
        return min(lo, hi), max(lo, hi)
    return None

def compute_fvg_ce(fvg: Optional[Tuple[float, float]]) -> Optional[float]:
    """
    Consequent Encroachment (CE) = exact 50% midpoint of the FVG.
    ICT: price typically fills to CE before reversing — precision entry level.
    Returns the CE price or None if no FVG.
    """
    if fvg is None:
        return None
    return round((fvg[0] + fvg[1]) / 2, 8)

def compute_fvg_fill_pct(fvg: Optional[Tuple[float, float]], current_price: float, bias: str) -> float:
    """
    How much of the FVG has price already filled? 0%=untouched, 50%=at CE, 100%=fully filled.
    Bullish FVG fills from top down. Bearish FVG fills from bottom up.
    """
    if fvg is None:
        return 0.0
    lo, hi = fvg
    gap = max(hi - lo, 1e-9)
    if bias == "BULLISH":
        filled = max(0.0, hi - current_price)
    else:
        filled = max(0.0, current_price - lo)
    return round(min(100.0, filled / gap * 100), 1)

def compute_ote(swing_high: float, swing_low: float, bias: str) -> Dict:
    """
    Optimal Trade Entry (OTE) — ICT's precision Fibonacci entry zone.
    Drawn on the displacement leg (swing low → swing high for bullish, reverse for bearish).
    Key levels:
      0.5   = equilibrium (CE equivalent on the leg)
      0.618 = OTE entry (golden ratio — highest probability reversal)
      0.705 = deep OTE (secondary entry)
      0.786 = last line of defence (beyond = invalidation)
    Bullish: price pulls back INTO the 0.618–0.786 zone → buy
    Bearish: price rallies INTO the 0.618–0.786 zone → sell
    """
    leg = abs(swing_high - swing_low)
    if leg == 0:
        return {"ote_entry": None, "ote_zone_low": None, "ote_zone_high": None, "valid": False}

    if bias == "BULLISH":
        # Retracement from high back toward low
        lvl_50  = swing_high - 0.500 * leg
        lvl_618 = swing_high - 0.618 * leg
        lvl_705 = swing_high - 0.705 * leg
        lvl_786 = swing_high - 0.786 * leg
        ote_zone_high = lvl_618
        ote_zone_low  = lvl_786
        ote_entry     = lvl_618   # primary entry
    else:
        # Retracement from low back toward high
        lvl_50  = swing_low + 0.500 * leg
        lvl_618 = swing_low + 0.618 * leg
        lvl_705 = swing_low + 0.705 * leg
        lvl_786 = swing_low + 0.786 * leg
        ote_zone_low  = lvl_618
        ote_zone_high = lvl_786
        ote_entry     = lvl_618

    return {
        "ote_entry":     round(ote_entry, 8),
        "ote_zone_low":  round(min(ote_zone_low, ote_zone_high), 8),
        "ote_zone_high": round(max(ote_zone_low, ote_zone_high), 8),
        "fib_50":        round(lvl_50,  8),
        "fib_618":       round(lvl_618, 8),
        "fib_705":       round(lvl_705, 8),
        "fib_786":       round(lvl_786, 8),
        "valid":         True,
    }

def compute_bpr(bullish_fvg: Optional[Tuple], bearish_fvg: Optional[Tuple]) -> Optional[Dict]:
    """
    Balanced Price Range (BPR) = overlap zone between a bullish FVG and a bearish FVG.
    When both exist and overlap, the overlap is the highest confluence entry zone in ICT —
    institutions have left imbalance on BOTH sides, making the overlap a magnet.
    Returns {"bpr_low": float, "bpr_high": float} if overlap exists, else None.
    """
    if bullish_fvg is None or bearish_fvg is None:
        return None
    bull_lo, bull_hi = bullish_fvg
    bear_lo, bear_hi = bearish_fvg
    overlap_lo = max(bull_lo, bear_lo)
    overlap_hi = min(bull_hi, bear_hi)
    if overlap_hi > overlap_lo:
        return {"bpr_low": round(overlap_lo, 8), "bpr_high": round(overlap_hi, 8)}
    return None

