def select_mtf_combo(
    best_tf: str,
    session: str,
    asset_hint: str = "",
    prefer_style: str = "",
) -> Dict:
    """
    Select the optimal 3-layer MTF combo from the 50-combo registry.

    Priority:
      1. Bias TF must match best_tf (or be the closest higher TF)
      2. Kill zone must be compatible with current session
      3. Prefer CONFIRMED > VALID > CONDITIONAL tier
      4. If asset_hint provided, match asset_class
      5. If prefer_style provided, match style
      6. Fall back to primary combo for this best_tf

    Returns the selected combo dict (always returns a valid combo).
    """
    # Normalize best_tf to known bias levels
    _bias_map = {
        "1w": "1w", "1d": "1d", "4h": "4h", "1h": "1h",
        "2h": "2h", "3h": "3h", "15m": "15m", "1M": "1M",
    }
    bias_tf = _bias_map.get(best_tf.lower(), "4h")

    # Filter combos to those with this bias TF
    candidates = [c for c in MTF_COMBOS if c["bias"] == bias_tf]
    if not candidates:
        # Fallback: widen to adjacent TF combos
        candidates = MTF_COMBOS

    # Session-aware filter: keep combos whose kill zone supports current session
    def _kz_ok(combo_kz: str, sess: str) -> bool:
        allowed = _KZ_SESSION_MAP.get(combo_kz, set())
        return sess.upper() in allowed or "Agnostic" in combo_kz or not sess

    session_ok = [c for c in candidates if _kz_ok(c["kz"], session)]
    if session_ok:
        candidates = session_ok

    # Tier priority sort: CONFIRMED=0, VALID=1, CONDITIONAL=2
    _tier_rank = {"CONFIRMED": 0, "VALID": 1, "CONDITIONAL": 2}
    candidates.sort(key=lambda c: _tier_rank.get(c["tier"], 3))

    # Asset hint match (soft boost — move matching combos to front)
    if asset_hint:
        hint_up = asset_hint.upper()
        asset_match = [c for c in candidates if hint_up in c["asset"].upper()]
        if asset_match:
            candidates = asset_match + [c for c in candidates if c not in asset_match]

    # Style preference match (soft boost)
    if prefer_style:
        style_match = [c for c in candidates if prefer_style.lower() in c["style"].lower()]
        if style_match:
            candidates = style_match + [c for c in candidates if c not in style_match]

    selected = candidates[0] if candidates else MTF_COMBO_BY_ID.get(_MTF_PRIMARY_BY_BIAS.get(bias_tf, 16), MTF_COMBOS[15])
    return selected


def validate_mtf_combo_3layer(
    combo: Dict,
    ohlcv_by_tf: Dict[str, list],
    min_candles: int = 20,
) -> Dict:
    """
    Validate that a 3-layer MTF combo has sufficient data at all three layers.

    Returns:
        valid:       bool — all three layers have data
        bias_ok:     bool — bias_tf data present
        ref_ok:      bool — refinement_tf data present (graceful fallback)
        exec_ok:     bool — exec_tf data present (graceful fallback)
        fallback_ref:str  — refinement TF used if original ref not available
        fallback_exec:str — exec TF used if original exec not available
        issues:      list of validation warnings
        ratio_bias_ref:   float — minutes ratio between bias and ref layers
        ratio_ref_exec:   float — minutes ratio between ref and exec layers
        ratio_note:  str  — ratio validation summary
    """
    bias_tf  = combo.get("bias", "4h")
    ref_tf   = combo.get("ref",  "1h")
    exec_tf  = combo.get("exec", "15m")
    issues   = []

    # Layer data availability
    bias_data  = ohlcv_by_tf.get(bias_tf, [])
    ref_data   = ohlcv_by_tf.get(ref_tf,  [])
    exec_data  = ohlcv_by_tf.get(exec_tf, [])

    bias_ok = len(bias_data)  >= min_candles
    ref_ok  = len(ref_data)   >= min_candles
    exec_ok = len(exec_data)  >= min_candles

    # Graceful TF fallbacks for non-standard frames (2h→1h, 3h→4h, 30m→15m)
    _fallback_tf = {"2h": "1h", "3h": "4h", "30m": "15m", "3m": "5m", "5m": "1m", "1M": "1w"}
    fallback_ref  = ref_tf
    fallback_exec = exec_tf

    if not ref_ok:
        fb = _fallback_tf.get(ref_tf)
        if fb and len(ohlcv_by_tf.get(fb, [])) >= min_candles:
            fallback_ref = fb
            ref_ok = True
            issues.append(f"Refinement TF {ref_tf} unavailable — using {fb}")

    if not exec_ok:
        fb = _fallback_tf.get(exec_tf)
        if fb and len(ohlcv_by_tf.get(fb, [])) >= min_candles:
            fallback_exec = fb
            exec_ok = True
            issues.append(f"Execution TF {exec_tf} unavailable — using {fb}")

    if not bias_ok:
        issues.append(f"Bias TF {bias_tf} insufficient data ({len(bias_data)} candles)")

    # Ratio validation
    tf_mins = {
        "1m": 1, "3m": 3, "5m": 5, "15m": 15, "30m": 30,
        "1h": 60, "2h": 120, "3h": 180, "4h": 240,
        "1d": 1440, "1w": 10080, "1M": 43200,
    }
    bias_m  = tf_mins.get(bias_tf, 240)
    ref_m   = tf_mins.get(fallback_ref, 60)
    exec_m  = tf_mins.get(fallback_exec, 15)

    ratio_br = round(bias_m / max(ref_m, 1), 2)
    ratio_re = round(ref_m  / max(exec_m, 1), 2)

    # Ideal ratio: 4–6x per layer. Flag if outside 2–16x range
    def _ratio_label(r):
        if 4 <= r <= 6:   return "✅ IDEAL"
        if 2 <= r < 4:    return "⚠️ CLOSE"
        if 6 < r <= 16:   return "⚠️ WIDE"
        return "❌ OUT_OF_RANGE"

    ratio_note = (
        f"Bias→Ref: {bias_tf}→{fallback_ref} = {ratio_br}x {_ratio_label(ratio_br)} | "
        f"Ref→Exec: {fallback_ref}→{fallback_exec} = {ratio_re}x {_ratio_label(ratio_re)}"
    )

    return {
        "valid":          bias_ok and ref_ok and exec_ok,
        "bias_ok":        bias_ok,
        "ref_ok":         ref_ok,
        "exec_ok":        exec_ok,
        "fallback_ref":   fallback_ref,
        "fallback_exec":  fallback_exec,
        "ratio_bias_ref": ratio_br,
        "ratio_ref_exec": ratio_re,
        "ratio_note":     ratio_note,
        "issues":         issues,
        "combo_id":       combo.get("id", 0),
        "combo_tier":     combo.get("tier", "UNKNOWN"),
        "combo_label":    f"{bias_tf.upper()}→{fallback_ref.upper()}→{fallback_exec.upper()}",
    }
