# ══════════════════════════════════════════════════════════════════════
# DST-AWARE ICT TIME ENGINE
# QA FIX: hardcoded UTC-5 was wrong for ~7 months/year (EDT = UTC-4).
# All ICT Macro windows are in US/Eastern — must account for DST.
# US DST: 2nd Sunday of March → 1st Sunday of November.
# ══════════════════════════════════════════════════════════════════════

def _nth_sunday(year: int, month: int, n: int) -> datetime.datetime:
    """Return the nth Sunday (1-indexed) of the given year/month."""
    first_day = datetime.datetime(year, month, 1)
    first_sun = first_day + datetime.timedelta(days=(6 - first_day.weekday()) % 7)
    return first_sun + datetime.timedelta(weeks=n - 1)

def _get_ny_utc_offset_minutes() -> int:
    """
    DST-AWARE: Return US/Eastern offset from UTC in minutes.
    EDT (UTC-4) = -240  →  Mar 2nd Sunday → Nov 1st Sunday
    EST (UTC-5) = -300  →  all other times
    """
    now = datetime.datetime.utcnow()
    dst_start = _nth_sunday(now.year, 3,  2)   # 2nd Sunday of March
    dst_end   = _nth_sunday(now.year, 11, 1)   # 1st Sunday of November
    if dst_start <= now < dst_end:
        return -240   # EDT
    return -300       # EST

def _utc_mins_to_ny_mins(utc_mins: int) -> int:
    """Convert UTC minutes-of-day to US/Eastern minutes-of-day (DST-aware)."""
    return (utc_mins + _get_ny_utc_offset_minutes()) % 1440

def _ny_mins_to_utc_mins(ny_mins: int) -> int:
    """Convert NY minutes-of-day to UTC minutes-of-day (DST-aware)."""
    return (ny_mins - _get_ny_utc_offset_minutes()) % 1440

# ─────────────────────── IN-MEMORY CACHE ──────────────────────
# Prevents hammering APIs when multiple users request same symbol
_cache: dict = {}
CACHE_TTL = 60   # seconds — refresh data every 60s

def _cache_get(key: str):
    entry = _cache.get(key)
    if entry and (time.time() - entry["ts"]) < CACHE_TTL:
        return entry["data"]
    return None

def _cache_set(key: str, data):
    _cache[key] = {"ts": time.time(), "data": data}
    # FIX #8 — Evict expired entries on every write to prevent unbounded growth.
    # Without this, _cache grows indefinitely over weeks of uptime (memory leak).
    _now = time.time()
    expired = [k for k, v in _cache.items() if (_now - v["ts"]) > CACHE_TTL * 10]
    for k in expired:
        _cache.pop(k, None)

# ─────────────────────── FLASH-CRASH CIRCUIT BREAKER (fix #6) ───────────────
# If price moves > 10% in the last N closes, signal generation is halted.
FLASH_CRASH_THRESHOLD_PCT = 10.0   # % move that triggers halt

def check_flash_crash(closes: list, lookback: int = 5) -> dict:
    """
    Fix #6 — Flash-crash circuit breaker.
    If abs(close[-1] / close[-lookback] - 1) * 100 > FLASH_CRASH_THRESHOLD_PCT → halt.
    """
    if len(closes) < lookback + 1:
        return {"flash_crash": False, "price_change_pct": 0.0, "note": "Insufficient data"}
    ref   = closes[-(lookback + 1)]
    curr  = closes[-1]
    if ref <= 0:
        return {"flash_crash": False, "price_change_pct": 0.0, "note": "Invalid ref price"}
    pct   = round((curr / ref - 1) * 100, 3)
    crash = abs(pct) > FLASH_CRASH_THRESHOLD_PCT
    return {
        "flash_crash":       crash,
        "price_change_pct":  pct,
        "note": (f"⚠️ FLASH CRASH DETECTED — {pct:+.2f}% in {lookback} candles — HALT"
                 if crash else f"✅ Normal move ({pct:+.2f}%)"),
    }


# Per-host failure tracking. After _CB_FAIL_THRESHOLD consecutive
# failures the host is marked OPEN and skipped for _CB_RESET_SECS.
# Prevents a dead exchange from eating timeout budget every run.
_CB_FAIL_THRESHOLD = 3      # consecutive failures before open
_CB_RESET_SECS     = 120    # seconds before half-open retry
_circuit: dict = {}         # host → {"fails": int, "open_until": float, "half_open": bool}
# BUG-TA-03 FIX: _circuit was mutated from multiple async coroutines with no
# lock. asyncio is single-threaded but await points allow interleaving — two
# coroutines can both read state["fails"]==2, both increment to 3, both open
# the circuit. Fix: guard all circuit mutations with a shared asyncio.Lock.
# Initialized None here; created on first use (safe — module-level is sync).
_circuit_lock: asyncio.Lock = None  # type: ignore[assignment]

def _cb_host(url: str) -> str:
    """Extract host key from URL for circuit-breaker keying.
    N-TA-01 FIX: use full netloc (scheme+host+port) not url[:40] to avoid
    collisions between different URLs sharing the same first 40 characters.
    """
    try:
        from urllib.parse import urlparse
        parsed = urlparse(url)
        return parsed.netloc or url[:60]
    except Exception:
        return url[:60]

async def _cb_is_open_async(url: str) -> bool:
    """Async version: Return True if circuit OPEN. BUG-TA-06 FIX: half-open
    releases exactly ONE probe via 'half_open' sentinel — not all waiters."""
    global _circuit_lock
    if _circuit_lock is None:
        _circuit_lock = asyncio.Lock()
    host = _cb_host(url)
    async with _circuit_lock:
        state = _circuit.get(host)
        if not state:
            return False
        if state.get("open_until", 0) > time.time():
            return True          # still open — skip
        # Timer expired → transition to HALF-OPEN
        # BUG-TA-06 FIX: only one coroutine gets through (half_open flag)
        if not state.get("half_open", False):
            state["half_open"] = True   # let exactly one probe through
            state["fails"] = 0
            state["open_until"] = 0.0
            return False        # this caller is the probe
        # Another coroutine already holds the half-open slot — block it
        return True

def _cb_is_open(url: str) -> bool:
    """Sync wrapper for backward compat — safe since GIL protects dict reads."""
    host = _cb_host(url)
    state = _circuit.get(host)
    if not state:
        return False
    return state.get("open_until", 0) > time.time()

async def _cb_record_fail_async(url: str):
    """BUG-TA-03 FIX: Lock-protected failure recording."""
    global _circuit_lock
    if _circuit_lock is None:
        _circuit_lock = asyncio.Lock()
    host = _cb_host(url)
    async with _circuit_lock:
        state = _circuit.setdefault(host, {"fails": 0, "open_until": 0.0, "half_open": False})
        state["half_open"] = False   # probe failed — go back to OPEN
        state["fails"] += 1
        if state["fails"] >= _CB_FAIL_THRESHOLD:
            state["open_until"] = time.time() + _CB_RESET_SECS
            log.warning(f"[CIRCUIT] {host} OPEN — skipping for {_CB_RESET_SECS}s "
                        f"after {state['fails']} consecutive failures")

def _cb_record_fail(url: str):
    """Sync fallback — kept for any non-async callers."""
    host = _cb_host(url)
    state = _circuit.setdefault(host, {"fails": 0, "open_until": 0.0, "half_open": False})
    state["half_open"] = False
    state["fails"] += 1
    if state["fails"] >= _CB_FAIL_THRESHOLD:
        state["open_until"] = time.time() + _CB_RESET_SECS
        log.warning(f"[CIRCUIT] {host} OPEN — skipping for {_CB_RESET_SECS}s "
                    f"after {state['fails']} consecutive failures")

async def _cb_record_success_async(url: str):
    """BUG-TA-03 FIX: Lock-protected success reset."""
    global _circuit_lock
    if _circuit_lock is None:
        _circuit_lock = asyncio.Lock()
    host = _cb_host(url)
    async with _circuit_lock:
        _circuit[host] = {"fails": 0, "open_until": 0.0, "half_open": False}

def _cb_record_success(url: str):
    """Sync fallback."""
    host = _cb_host(url)
    if host in _circuit:
        _circuit[host] = {"fails": 0, "open_until": 0.0, "half_open": False}

# ─────────────────────── RATE LIMITER (#12) ────────────────────
# Token-bucket per host — max _RL_MAX_RPS requests per second.
# Prevents burst of parallel fetches from triggering exchange bans.
_RL_MAX_RPS   = 4.0         # max requests per second per host
_rl_tokens:  dict = {}      # host → float (token count)
_rl_last_ts: dict = {}      # host → float (last refill timestamp)
# BUG-TA-01 FIX: _rl_lock was initialized lazily inside _rl_acquire with no
# guard — two coroutines could both see None simultaneously and create two
# different Lock objects. Fix: use a threading.Lock as a sync sentinel for
# the one-time async Lock creation (double-checked locking pattern).
import threading as _threading
_rl_lock = None
_rl_lock_guard = _threading.Lock()

async def _rl_acquire(url: str):
    """Consume one rate-limit token for this host. Awaits if empty."""
    global _rl_lock
    # BUG-TA-01 FIX: double-checked lock ensures exactly one Lock is created
    if _rl_lock is None:
        with _rl_lock_guard:
            if _rl_lock is None:
                _rl_lock = asyncio.Lock()
    host = _cb_host(url)
    async with _rl_lock:
        now = time.monotonic()
        last = _rl_last_ts.get(host, now)
        elapsed = now - last
        # BUG-TA-04 FIX: new hosts start with 1 token (not _RL_MAX_RPS) to
        # prevent a full burst of 4 simultaneous requests on first encounter.
        # Tokens accumulate from there based on elapsed time.
        tokens = _rl_tokens.get(host, 1.0)
        tokens = min(_RL_MAX_RPS, tokens + elapsed * _RL_MAX_RPS)
        _rl_last_ts[host] = now
        if tokens >= 1.0:
            _rl_tokens[host] = tokens - 1.0
            return
        # Not enough tokens — compute wait and sleep outside lock
        wait = (1.0 - tokens) / _RL_MAX_RPS
        _rl_tokens[host] = 0.0
    await asyncio.sleep(wait)

# ── Fix #24 — WebSocket reconnect parameters
CLOCK_SKEW_WARN_SECS: float = 5.0   # fix #28 — warn if local clock drifts > 5 s from exchange time

def check_clock_sync(exchange_ts_ms: float) -> Dict:
    """
    Fix #28 — Compare local UTC time against exchange-provided timestamp.
    Skew > CLOCK_SKEW_WARN_SECS → signal_time accuracy degraded.
    """
    local_ts = time.time()
    exchange_ts = exchange_ts_ms / 1000.0
    skew = abs(local_ts - exchange_ts)
    ok = skew <= CLOCK_SKEW_WARN_SECS
    if not ok:
        log.warning(f"[CLOCK SYNC] Skew={skew:.2f}s > {CLOCK_SKEW_WARN_SECS}s — session/signal timing may be inaccurate")
    return {
        "clock_ok":      ok,
        "skew_secs":     round(skew, 3),
        "note": (f"✅ Clock synced (skew={skew:.2f}s)"
                 if ok else f"⚠️ CLOCK SKEW {skew:.1f}s — sync your system clock"),
    }




WSS_RECONNECT_MAX_ATTEMPTS:    int   = 10    # max reconnect attempts before giving up
WSS_RECONNECT_BACKOFF_FACTOR:  float = 2.0   # exponential backoff multiplier


# Retry logic: up to _FETCH_MAX_RETRIES on 429 / 5xx / timeout.
# Exponential backoff: 0.5s → 1.0s → 2.0s between retries.
_FETCH_MAX_RETRIES = 2
_FETCH_RETRY_BASE  = 0.5    # seconds, doubled each retry

async def _fetch(session: aiohttp.ClientSession, url: str, timeout: int = 6):
    """Fetch JSON from URL. Returns None on persistent error.
    Enhancements vs original:
      • Rate limiter  — token-bucket per host (#12)
      • Retry logic   — up to 2 retries on 429/5xx/timeout (#13)
      • Circuit breaker — skip known-dead hosts (#89)
    """
    if _cb_is_open(url):
        log.debug(f"[CIRCUIT OPEN] skipping {url[:60]}")
        return None

    for attempt in range(_FETCH_MAX_RETRIES + 1):
        await _rl_acquire(url)
        try:
            async with session.get(url, timeout=aiohttp.ClientTimeout(total=timeout)) as resp:
                if resp.status == 200:
                    _cb_record_success(url)
                    return await resp.json(content_type=None)
                if resp.status == 429 or resp.status >= 500:
                    # Retriable — back off then retry
                    if attempt < _FETCH_MAX_RETRIES:
                        wait = _FETCH_RETRY_BASE * (2 ** attempt)
                        log.debug(f"[RETRY {attempt+1}] HTTP {resp.status} {url[:60]} — wait {wait:.1f}s")
                        _cb_record_fail(url)
                        await asyncio.sleep(wait)
                        continue
                # Non-retriable 4xx (e.g. 404 = pair not listed)
                _cb_record_fail(url)
                return None
        except asyncio.TimeoutError:
            if attempt < _FETCH_MAX_RETRIES:
                wait = _FETCH_RETRY_BASE * (2 ** attempt)
                log.debug(f"[RETRY {attempt+1}] Timeout {url[:60]} — wait {wait:.1f}s")
                _cb_record_fail(url)
                await asyncio.sleep(wait)
            else:
                _cb_record_fail(url)
                log.debug(f"[FETCH FAIL] Timeout after {_FETCH_MAX_RETRIES} retries: {url[:60]}")
        except Exception as e:
            _cb_record_fail(url)
            log.debug(f"[FETCH ERR] {url[:60]}: {e}")
            break   # non-transient exception — do not retry
    return None

# ─────────────────────── PARSERS ──────────────────────────────
def parse_ticker(ex_cfg: dict, raw) -> Optional[Dict]:
    """Extract last, volume_usd, change_pct from raw ticker JSON.

    HARDENING (v8.2 patch): All exchanges can return null JSON values for
    optional fields (change_pct, volume_usd) on low-liquidity altcoins.
    dict.get(key, default) only fires the default when the KEY IS ABSENT —
    if the key exists with a null value, .get() returns None, and float(None)
    raises TypeError which silently drops the exchange.

    Fix: use `(d.get(key) or fallback)` for all nullable fields so null JSON
    values are treated identically to missing keys. Applied to every parser.
    Core price field (last/lastPrice) intentionally left strict — null price
    means the exchange genuinely has no data and should be dropped.
    """
    def _f(v, fallback=0.0):
        """Null-safe float: returns fallback for None/missing, raises for bad types."""
        return float(v if v is not None else fallback)

    try:
        p = ex_cfg["parse"]

        if p == "binance":
            return {"last":       float(raw["lastPrice"]),
                    "volume_usd": _f(raw.get("quoteVolume")),
                    "change_pct": _f(raw.get("priceChangePercent"))}

        if p == "okx":
            d = raw["data"][0]
            _okx_open = float(d.get("open24h") or d["last"])
            _okx_last = float(d["last"])
            _okx_chg  = (_okx_last - _okx_open) / max(_okx_open, 1e-9) * 100
            return {"last":       _okx_last,
                    "volume_usd": _f(d.get("volCcy24h")) * _okx_last,
                    "change_pct": round(_okx_chg, 4)}

        if p == "bybit":
            d = raw["result"]["list"][0]
            _last = float(d["lastPrice"])
            prev  = float(d.get("prevPrice24h") or d["lastPrice"]) or _last
            chg   = (_last - prev) / max(prev, 1e-9) * 100
            return {"last":       _last,
                    "volume_usd": _f(d.get("turnover24h")),
                    "change_pct": chg}

        if p == "kraken":
            pair = list(raw["result"].keys())[0]
            d    = raw["result"][pair]
            last  = float(d["c"][0])
            open_ = float(d["o"])
            chg   = (last - open_) / max(open_, 1e-9) * 100
            return {"last":       last,
                    "volume_usd": _f(d["v"][1]) * last,
                    "change_pct": chg}

        if p == "kucoin":
            d     = raw["data"]
            last  = float(d["last"])
            open_ = float(d.get("open") or last)
            chg   = (last - open_) / max(open_, 1e-9) * 100
            return {"last":       last,
                    "volume_usd": _f(d.get("volValue")),
                    "change_pct": chg}

        if p in ("mexc", "phemex"):
            # Altcoin-safe: MEXC/Phemex return null for nullable fields on low-volume pairs.
            # Use `or` chaining so null values fall through to the numeric fallback.
            _lp = raw.get("lastPrice") or raw.get("price") or 0
            _qv = raw.get("quoteVolume") or raw.get("volume") or 0
            _pc = raw.get("priceChangePercent") or 0
            return {"last":       float(_lp),
                    "volume_usd": float(_qv),
                    "change_pct": float(_pc)}

        if p == "bitget":
            d = raw["data"][0]
            return {"last":       float(d["lastPr"]),
                    "volume_usd": _f(d.get("quoteVolume")),
                    "change_pct": _f(d.get("change24h")) * 100}

        if p == "gateio":
            d    = raw[0]
            last = float(d["last"])
            return {"last":       last,
                    "volume_usd": _f(d.get("base_volume")) * last,
                    "change_pct": _f(d.get("change_percentage"))}

        if p == "htx":
            d     = raw["tick"]
            last  = float(d["close"])
            open_ = float(d["open"])
            chg   = (last - open_) / max(open_, 1e-9) * 100
            return {"last":       last,
                    "volume_usd": _f(d.get("amount")) * last,
                    "change_pct": chg}

        if p == "coinex":
            d     = raw["data"]["ticker"]
            last  = float(d["last"])
            open_ = float(d.get("open") or last)
            chg   = (last - open_) / max(open_, 1e-9) * 100
            return {"last":       last,
                    "volume_usd": _f(d.get("quote_volume")),
                    "change_pct": chg}

        if p == "mexc_futures":
            d = raw["data"]
            # MEXC Futures may return a list when querying all tickers
            if isinstance(d, list):
                d = d[0] if d else {}
            if not d or "lastPrice" not in d:
                return None
            last = float(d["lastPrice"])
            chg  = _f(d.get("riseFallRate")) * 100
            return {"last":       last,
                    "volume_usd": _f(d.get("amount24")),
                    "change_pct": chg}

        if p == "binance_futures":
            return {"last":       float(raw["lastPrice"]),
                    "volume_usd": _f(raw.get("quoteVolume")),
                    "change_pct": _f(raw.get("priceChangePercent"))}

        if p == "bybit_futures":
            d     = raw["result"]["list"][0]
            _last = float(d["lastPrice"])
            prev  = float(d.get("prevPrice24h") or d["lastPrice"]) or _last
            chg   = (_last - prev) / max(prev, 1e-9) * 100
            return {"last":       _last,
                    "volume_usd": _f(d.get("turnover24h")),
                    "change_pct": chg}

        if p == "gateio_futures":
            d    = raw[0]
            last = float(d["last"])
            return {"last":       last,
                    "volume_usd": _f(d.get("volume_24h_quote")),
                    "change_pct": _f(d.get("change_percentage"))}

    except Exception as e:
        log.debug(f"parse_ticker {ex_cfg['name']}: {e}")
    return None


def parse_ohlcv(ex_cfg: dict, raw) -> Optional[list]:
    """
    Returns list of (open, high, low, close, volume) candles, oldest first.
    """
    try:
        p = ex_cfg["parse"]
        candles = []
        if p == "binance" or p == "mexc":
            for c in raw:
                candles.append((float(c[1]), float(c[2]), float(c[3]), float(c[4]), float(c[5])))
        elif p == "okx":
            for c in reversed(raw["data"]):
                candles.append((float(c[1]), float(c[2]), float(c[3]), float(c[4]), float(c[5])))
        elif p == "bybit":
            for c in reversed(raw["result"]["list"]):
                candles.append((float(c[1]), float(c[2]), float(c[3]), float(c[4]), float(c[5])))
        elif p == "kraken":
            pair = list(raw["result"].keys())[0]
            for c in raw["result"][pair]:
                candles.append((float(c[1]), float(c[2]), float(c[3]), float(c[4]), float(c[6])))
        elif p == "kucoin":
            for c in reversed(raw["data"]):
                candles.append((float(c[1]), float(c[3]), float(c[4]), float(c[2]), float(c[5])))
        elif p == "bitget":
            for c in reversed(raw["data"]):
                candles.append((float(c[1]), float(c[2]), float(c[3]), float(c[4]), float(c[5])))
        elif p == "gateio":
            for c in raw:
                candles.append((float(c[1]), float(c[3]), float(c[4]), float(c[2]), float(c[5])))
        elif p == "htx":
            for c in reversed(raw["data"]):
                candles.append((float(c["open"]), float(c["high"]), float(c["low"]), float(c["close"]), float(c["amount"])))
        elif p == "coinex":
            for c in raw["data"]:
                candles.append((float(c["open"]), float(c["high"]), float(c["low"]), float(c["close"]), float(c["volume"])))
        elif p == "phemex":
            rows = (raw.get("data") or {}).get("rows", [])
            for c in rows:
                candles.append((float(c[3]), float(c[4]), float(c[5]), float(c[6]), float(c[7])))
        elif p == "mexc_futures":
            # MEXC futures kline: {time, open, close, high, low, vol, ...}
            data = raw.get("data", {})
            times   = data.get("time", [])
            opens   = data.get("open", [])
            highs   = data.get("high", [])
            lows    = data.get("low", [])
            closes  = data.get("close", [])
            vols    = data.get("vol", [])
            for i in range(len(closes)):
                candles.append((float(opens[i]), float(highs[i]), float(lows[i]), float(closes[i]), float(vols[i])))
        elif p == "binance_futures":
            # Same format as Binance spot
            for c in raw:
                candles.append((float(c[1]), float(c[2]), float(c[3]), float(c[4]), float(c[5])))
        elif p == "bybit_futures":
            # Same format as Bybit spot
            for c in reversed(raw["result"]["list"]):
                candles.append((float(c[1]), float(c[2]), float(c[3]), float(c[4]), float(c[5])))
        elif p == "gateio_futures":
            # Gate.io futures candlesticks: [t, v, c, h, l, o, ...]
            for c in raw:
                candles.append((float(c[5]), float(c[3]), float(c[4]), float(c[2]), float(c[1])))
        if candles:
            return candles
    except Exception as e:
        log.debug(f"parse_ohlcv {ex_cfg['name']}: {e}")
    return None


def parse_orderbook(ex_cfg: dict, raw) -> Optional[Dict]:
    """Returns {'bids': [[price, qty],...], 'asks': [[price, qty],...]}"""
    try:
        p = ex_cfg["parse"]
        if p in ("binance", "mexc"):
            return {"bids": [[float(b[0]), float(b[1])] for b in raw["bids"]],
                    "asks": [[float(a[0]), float(a[1])] for a in raw["asks"]]}
        if p == "okx":
            d = raw["data"][0]
            return {"bids": [[float(b[0]), float(b[1])] for b in d["bids"]],
                    "asks": [[float(a[0]), float(a[1])] for a in d["asks"]]}
        if p == "bybit":
            d = raw["result"]
            return {"bids": [[float(b[0]), float(b[1])] for b in d["b"]],
                    "asks": [[float(a[0]), float(a[1])] for a in d["a"]]}
        if p == "kraken":
            pair = list(raw["result"].keys())[0]
            d = raw["result"][pair]
            return {"bids": [[float(b[0]), float(b[1])] for b in d["bids"]],
                    "asks": [[float(a[0]), float(a[1])] for a in d["asks"]]}
        if p == "kucoin":
            d = raw["data"]
            return {"bids": [[float(b[0]), float(b[1])] for b in d["bids"]],
                    "asks": [[float(a[0]), float(a[1])] for a in d["asks"]]}
        if p == "bitget":
            d = raw["data"]
            return {"bids": [[float(b[0]), float(b[1])] for b in d["bids"]],
                    "asks": [[float(a[0]), float(a[1])] for a in d["asks"]]}
        if p == "gateio":
            return {"bids": [[float(b[0]), float(b[1])] for b in raw["bids"]],
                    "asks": [[float(a[0]), float(a[1])] for a in raw["asks"]]}
        if p == "htx":
            d = raw["tick"]
            return {"bids": [[float(b[0]), float(b[1])] for b in d["bids"]],
                    "asks": [[float(a[0]), float(a[1])] for a in d["asks"]]}
        if p == "coinex":
            d = raw["data"]
            return {"bids": [[float(b[0]), float(b[1])] for b in d["bids"]],
                    "asks": [[float(a[0]), float(a[1])] for a in d["asks"]]}
        if p == "phemex":
            d = raw.get("result", raw)
            return {"bids": [[float(b[0]), float(b[1])] for b in d.get("bids", [])],
                    "asks": [[float(a[0]), float(a[1])] for a in d.get("asks", [])]}
        if p == "mexc_futures":
            d = raw.get("data", {})
            return {"bids": [[float(b[0]), float(b[1])] for b in d.get("bids", [])],
                    "asks": [[float(a[0]), float(a[1])] for a in d.get("asks", [])]}
        if p == "binance_futures":
            return {"bids": [[float(b[0]), float(b[1])] for b in raw["bids"]],
                    "asks": [[float(a[0]), float(a[1])] for a in raw["asks"]]}
        if p == "bybit_futures":
            d = raw["result"]
            return {"bids": [[float(b[0]), float(b[1])] for b in d["b"]],
                    "asks": [[float(a[0]), float(a[1])] for a in d["a"]]}
        if p == "gateio_futures":
            return {"bids": [[float(b[0]), float(b[1])] for b in raw.get("bids", [])],
                    "asks": [[float(a[0]), float(a[1])] for a in raw.get("asks", [])]}
    except Exception as e:
        log.debug(f"parse_ob {ex_cfg['name']}: {e}")
    return None

# ─────────────────────── LIVE DATA FETCH ──────────────────────

async def fetch_exchange_data(session: aiohttp.ClientSession, ex_cfg: dict, base: str, tf: str) -> Optional[Dict]:
    """Fetch ticker + OHLCV + orderbook for one exchange. Returns None if unavailable."""
    sym = ex_cfg["symbol_fmt"].format(base=base)
    ex_tf = ex_cfg["tf_map"].get(tf, tf)

    ticker_url = ex_cfg["ticker_url"].format(symbol=sym)
    ohlcv_url  = ex_cfg["ohlcv_url"].format(symbol=sym, tf=ex_tf)
    ob_url     = ex_cfg["ob_url"].format(symbol=sym)

    if FETCH_FUNNEL_MODE:
        ticker_raw = await _fetch(session, ticker_url)
        if ticker_raw is None:
            return None
        ohlcv_raw = await _fetch(session, ohlcv_url)
    else:
        # Fire ticker and OHLCV concurrently; orderbook separately to not waste if pair missing
        ticker_raw, ohlcv_raw = await asyncio.gather(
            _fetch(session, ticker_url),
            _fetch(session, ohlcv_url),
        )

    if ticker_raw is None or ohlcv_raw is None:
        return None

    ticker = parse_ticker(ex_cfg, ticker_raw)
    ohlcv  = parse_ohlcv(ex_cfg, ohlcv_raw)

    if not ticker or not ohlcv or len(ohlcv) < 20:
        return None

    # ── Sanitise ticker: coerce all values to float, reject if price is 0 or None
    try:
        ticker["last"]       = float(ticker["last"] or 0)
        ticker["volume_usd"] = float(ticker.get("volume_usd") or 0)
        ticker["change_pct"] = float(ticker.get("change_pct") or 0)
        if ticker["last"] <= 0:
            return None
    except (TypeError, ValueError):
        return None

    # ── Sanitise ohlcv: ensure every candle field is a valid float
    clean_ohlcv = []
    for c in ohlcv:
        try:
            o, h, l, cl, v = float(c[0]), float(c[1]), float(c[2]), float(c[3]), float(c[4])
            if any(x is None or x != x for x in [o, h, l, cl]):  # NaN check
                continue
            clean_ohlcv.append((o, h, l, cl, v))
        except (TypeError, ValueError):
            continue
    if len(clean_ohlcv) < 20:
        return None
    ohlcv = clean_ohlcv

    ob_raw = await _fetch(session, ob_url)
    ob = parse_orderbook(ex_cfg, ob_raw) if ob_raw else None

    return {"ticker": ticker, "ohlcv": ohlcv, "ob": ob, "ex": ex_cfg}


async def fetch_all_exchanges(base: str, tf: str, exchange_subset: Optional[List[Dict]] = None) -> List[Dict]:
    """Fetch data from exchanges with RAM-aware funnel support."""
    targets = exchange_subset or EXCHANGES
    cache_key = _subset_cache_key(base, tf, targets)
    cached = _cache_get(cache_key)
    if cached is not None:
        return cached

    connector_limit = FETCH_FUNNEL_CONNECTOR if FETCH_FUNNEL_MODE else 20
    async with aiohttp.ClientSession(
        headers={"User-Agent": "ICT-Bot/2.0"},
        connector=aiohttp.TCPConnector(limit=connector_limit, ssl=False),
    ) as session:
        if FETCH_FUNNEL_MODE:
            live = await _run_funnel_workers(
                targets,
                lambda ex: fetch_exchange_data(session, ex, base, tf),
                label=f"fetch:{base}:{tf}",
                batch_size=EXCHANGE_FETCH_BATCH,
                timeout_s=8,
            )
        else:
            tasks = [fetch_exchange_data(session, ex, base, tf) for ex in targets]
            results = await asyncio.gather(*tasks, return_exceptions=True)
            live = [r for r in results if isinstance(r, dict) and r is not None]

    _cache_set(cache_key, live)
    return live


async def fetch_all_exchanges_with_orderflow(base: str, tf: str, exchange_subset: Optional[List[Dict]] = None) -> tuple:
    """Fetch CEX data + orderflow with RAM-aware funnel support."""
    targets = exchange_subset or EXCHANGES
    cache_key = _subset_cache_key(base, tf, targets)
    cached = _cache_get(cache_key)
    connector_limit = FETCH_FUNNEL_CONNECTOR if FETCH_FUNNEL_MODE else 30

    async with aiohttp.ClientSession(
        headers={"User-Agent": "ICT-Bot/2.0"},
        connector=aiohttp.TCPConnector(limit=connector_limit, ssl=False),
    ) as session:
        if cached is not None:
            live = cached
            try:
                if FETCH_FUNNEL_MODE:
                    await _wait_for_memory(f"orderflow:{base}", timeout_s=8)
                    of = await asyncio.wait_for(fetch_orderflow(session, base), timeout=8)
                else:
                    of = await asyncio.wait_for(fetch_orderflow(session, base), timeout=8)
            except Exception:
                of = {"available": False}
        else:
            if FETCH_FUNNEL_MODE:
                live = await _run_funnel_workers(
                    targets,
                    lambda ex: fetch_exchange_data(session, ex, base, tf),
                    label=f"fetch-of:{base}:{tf}",
                    batch_size=EXCHANGE_FETCH_BATCH,
                    timeout_s=8,
                )
                _cache_set(cache_key, live)
                await _funnel_pause(f"orderflow:{base}")
                try:
                    await _wait_for_memory(f"orderflow:{base}", timeout_s=8)
                    of = await asyncio.wait_for(fetch_orderflow(session, base), timeout=8)
                    if not isinstance(of, dict):
                        of = {"available": False}
                except Exception:
                    of = {"available": False}
            else:
                ex_tasks = [fetch_exchange_data(session, ex, base, tf) for ex in targets]
                of_task  = asyncio.ensure_future(fetch_orderflow(session, base))
                results  = await asyncio.gather(*ex_tasks, return_exceptions=True)
                try:
                    of = await asyncio.wait_for(asyncio.shield(of_task), timeout=8)
                    if not isinstance(of, dict):
                        of = {"available": False}
                except Exception:
                    of = {"available": False}
                live = [r for r in results if isinstance(r, dict) and r is not None]
                _cache_set(cache_key, live)

    return live, of

