def compute_atr(ohlcv: list, period: int = 14) -> float:
    trs = []
    for i in range(1, len(ohlcv)):
        high, low, prev_close = ohlcv[i][1], ohlcv[i][2], ohlcv[i-1][3]
        trs.append(max(high - low, abs(high - prev_close), abs(low - prev_close)))
    if not trs:
        return 0.0
    return sum(trs[-period:]) / min(len(trs), period)


def compute_rsi(closes: list, period: int = 14) -> float:
    if len(closes) < period + 1:
        return 50.0
    gains, losses = [], []
    for i in range(1, len(closes)):
        d = closes[i] - closes[i - 1]
        gains.append(max(d, 0))
        losses.append(max(-d, 0))
    avg_g = sum(gains[-period:]) / period
    avg_l = sum(losses[-period:]) / period
    if avg_l == 0:
        return 100.0
    rs = avg_g / avg_l
    return round(100 - (100 / (1 + rs)), 2)


def compute_adx(ohlcv: list, period: int = 14) -> float:
    """Simplified ADX for trend strength 0-100."""
    if len(ohlcv) < period + 1:
        return 25.0
    plus_dm, minus_dm, trs = [], [], []
    for i in range(1, len(ohlcv)):
        h, l, ph, pl = ohlcv[i][1], ohlcv[i][2], ohlcv[i-1][1], ohlcv[i-1][2]
        pc = ohlcv[i-1][3]
        up, down = h - ph, pl - l
        plus_dm.append(up if up > down and up > 0 else 0)
        minus_dm.append(down if down > up and down > 0 else 0)
        trs.append(max(h - l, abs(h - pc), abs(l - pc)))
    def smooth(vals):
        s = sum(vals[:period])
        result = [s]
        for v in vals[period:]:
            s = s - s / period + v
            result.append(s)
        return result
    str_ = smooth(trs)
    spdm = smooth(plus_dm)
    smdm = smooth(minus_dm)
    di_vals = []
    for i in range(len(str_)):
        if str_[i] == 0:
            continue
        pdi = 100 * spdm[i] / str_[i]
        mdi = 100 * smdm[i] / str_[i]
        dx  = 100 * abs(pdi - mdi) / (pdi + mdi + 1e-9)
        di_vals.append(dx)
    return round(sum(di_vals[-period:]) / max(len(di_vals[-period:]), 1), 2)


def compute_macd(closes: list, fast: int = 12, slow: int = 26, signal: int = 9) -> Dict:
    """
    MACD = EMA(fast) − EMA(slow).
    Signal line = EMA(MACD, signal_period).
    Histogram = MACD − Signal.
    Returns macd_line, signal_line, histogram, crossover bias.
    """
    if len(closes) < slow + signal:
        return {
            "macd": 0.0, "signal": 0.0, "histogram": 0.0,
            "bias": "NEUTRAL", "crossover": False,
            "macd_note": "Insufficient data for MACD",
        }
    def _ema_series(data, period):
        k = 2.0 / (period + 1)
        ema = data[0]
        series = [ema]
        for v in data[1:]:
            ema = v * k + ema * (1 - k)
            series.append(ema)
        return series

    ema_fast_s  = _ema_series(closes, fast)
    ema_slow_s  = _ema_series(closes, slow)
    # Align lengths (slow series is shorter start)
    n_min = min(len(ema_fast_s), len(ema_slow_s))
    macd_series = [ema_fast_s[i] - ema_slow_s[i] for i in range(n_min)]
    signal_series = _ema_series(macd_series, signal)
    n_sig = min(len(macd_series), len(signal_series))
    hist_series   = [macd_series[i] - signal_series[i] for i in range(n_sig)]

    macd_val   = round(macd_series[-1], 8)
    signal_val = round(signal_series[-1], 8)
    hist_val   = round(hist_series[-1], 8)

    # Bias and crossover detection
    prev_hist  = hist_series[-2] if len(hist_series) >= 2 else hist_val
    crossover  = (prev_hist < 0 and hist_val >= 0) or (prev_hist > 0 and hist_val <= 0)
    bias       = "BULLISH" if macd_val > signal_val else "BEARISH" if macd_val < signal_val else "NEUTRAL"

    return {
        "macd":       macd_val,
        "signal":     signal_val,
        "histogram":  hist_val,
        "bias":       bias,
        "crossover":  crossover,
        "macd_note":  f"MACD={macd_val:.5f} Sig={signal_val:.5f} Hist={hist_val:.5f} → {bias}{'  ⚡ CROSSOVER' if crossover else ''}",
    }


def find_swing_highs_lows(ohlcv: list, lookback: int = 5):
    """Find swing highs and lows for structure analysis."""
    highs, lows = [], []
    for i in range(lookback, len(ohlcv) - lookback):
        h = ohlcv[i][1]
        l = ohlcv[i][2]
        if all(h >= ohlcv[j][1] for j in range(i - lookback, i + lookback + 1) if j != i):
            highs.append((i, h))
        if all(l <= ohlcv[j][2] for j in range(i - lookback, i + lookback + 1) if j != i):
            lows.append((i, l))
    return highs, lows


def detect_support_resistance(prices: list, window: int = 5) -> Dict:
    """
    Rank #1/#2/#3 — Horizontal Support/Resistance + Reaction Zones.
    Pivot-based detection: local minima → supports, local maxima → resistances.
    Returns up to 5 nearest support and resistance levels to current price.
    """
    supports = []
    resistances = []
    n = len(prices)
    if n < window * 2 + 1:
        return {"supports": [], "resistances": [], "nearest_support": None,
                "nearest_resistance": None, "sr_note": "Insufficient data for S/R"}

    for i in range(window, n - window):
        low = prices[i]
        if all(low < prices[i - j] for j in range(1, window + 1)) and \
           all(low < prices[i + j] for j in range(1, window + 1)):
            supports.append(round(low, 8))

        high = prices[i]
        if all(high > prices[i - j] for j in range(1, window + 1)) and \
           all(high > prices[i + j] for j in range(1, window + 1)):
            resistances.append(round(high, 8))

    current = prices[-1]
    # Keep unique levels (deduplicate within 0.2% tolerance)
    def dedupe(levels, tol=0.002):
        result = []
        for lv in sorted(set(levels)):
            if not result or abs(lv - result[-1]) / max(result[-1], 1e-9) > tol:
                result.append(lv)
        return result

    supports     = dedupe(supports)
    resistances  = dedupe(resistances)

    # Nearest levels to current price
    supports_below    = [s for s in supports    if s < current]
    resistances_above = [r for r in resistances if r > current]
    nearest_sup  = max(supports_below,    default=None)
    nearest_res  = min(resistances_above, default=None)

    sr_note = (
        f"S/R: nearest support={round(nearest_sup, 4) if nearest_sup else 'N/A'} "
        f"| nearest resistance={round(nearest_res, 4) if nearest_res else 'N/A'} "
        f"| {len(supports)} sup + {len(resistances)} res levels found"
    )

    return {
        "supports":           supports[-5:],
        "resistances":        resistances[:5],
        "nearest_support":    nearest_sup,
        "nearest_resistance": nearest_res,
        "sr_note":            sr_note,
    }


def detect_trendline(prices: list, bias: str = "BULLISH") -> Dict:
    """
    Rank #16–25 — Diagonal Trendline Detection via linear regression.
    Ascending trendline (lows rising) = bullish support.
    Descending trendline (highs falling) = bearish resistance.
    Detects trendline break and retest.
    """
    n = len(prices)
    if n < 3:
        return {"slope": 0.0, "intercept": 0.0, "trendline_bias": "NEUTRAL",
                "trendline_break": False, "trendline_retest": False,
                "trendline_note": "Insufficient data"}

    x = list(range(n))
    y = prices
    mean_x = sum(x) / n
    mean_y = sum(y) / n
    denom  = sum((xi - mean_x) ** 2 for xi in x)
    slope  = (sum((x[i] - mean_x) * (y[i] - mean_y) for i in range(n)) / max(denom, 1e-9))
    intercept = mean_y - slope * mean_x

    # Current projected trendline value
    tl_current = slope * (n - 1) + intercept
    current_price = prices[-1]
    prev_price    = prices[-2] if n >= 2 else current_price

    # Slope as % of price for normalisation
    slope_pct = round(slope / max(abs(mean_y), 1e-9) * 100, 4)

    trendline_bias = "BULLISH" if slope > 0 else "BEARISH" if slope < 0 else "NEUTRAL"

    # Break: price crosses the trendline
    prev_tl = slope * (n - 2) + intercept
    break_up   = prev_price <= prev_tl and current_price > tl_current
    break_down = prev_price >= prev_tl and current_price < tl_current
    trendline_break = break_up or break_down

    # Retest: price came back to tl after a break (within 0.3% of tl level)
    dist_to_tl = abs(current_price - tl_current) / max(tl_current, 1e-9)
    trendline_retest = dist_to_tl < 0.003

    note = (
        f"TL slope={slope_pct:+.3f}%/bar → {trendline_bias} "
        f"{'| 🔴 BREAK' if trendline_break else ''}"
        f"{'| 🔵 RETEST' if trendline_retest else ''}"
    ).strip()

    return {
        "slope":             round(slope, 8),
        "slope_pct":         slope_pct,
        "intercept":         round(intercept, 8),
        "tl_current_value":  round(tl_current, 8),
        "trendline_bias":    trendline_bias,
        "trendline_break":   trendline_break,
        "trendline_retest":  trendline_retest,
        "trendline_note":    note,
    }


def detect_double_top(prices: list, tolerance: float = 0.02) -> Dict:
    """
    Rank #51 — Double Top pattern detection.
    Two peaks within `tolerance` of each other = distribution / reversal signal.
    """
    peaks = []
    for i in range(1, len(prices) - 1):
        if prices[i] > prices[i - 1] and prices[i] > prices[i + 1]:
            peaks.append((i, prices[i]))

    detected = False
    p1_val = p2_val = 0.0
    if len(peaks) >= 2:
        p1, p2 = peaks[-2], peaks[-1]
        if abs(p1[1] - p2[1]) / max(p1[1], 1e-9) < tolerance:
            detected = True
            p1_val, p2_val = p1[1], p2[1]

    return {
        "double_top":      detected,
        "peak1":           round(p1_val, 8),
        "peak2":           round(p2_val, 8),
        "double_top_note": f"⚠️ Double Top detected @ ~{round((p1_val+p2_val)/2, 4)} — BEARISH reversal signal" if detected else "No Double Top",
    }


def detect_double_bottom(prices: list, tolerance: float = 0.02) -> Dict:
    """
    Rank #52 — Double Bottom pattern detection.
    Two troughs within `tolerance` of each other = accumulation / reversal signal.
    """
    troughs = []
    for i in range(1, len(prices) - 1):
        if prices[i] < prices[i - 1] and prices[i] < prices[i + 1]:
            troughs.append((i, prices[i]))

    detected = False
    t1_val = t2_val = 0.0
    if len(troughs) >= 2:
        t1, t2 = troughs[-2], troughs[-1]
        if abs(t1[1] - t2[1]) / max(t1[1], 1e-9) < tolerance:
            detected = True
            t1_val, t2_val = t1[1], t2[1]

    return {
        "double_bottom":      detected,
        "trough1":            round(t1_val, 8),
        "trough2":            round(t2_val, 8),
        "double_bottom_note": f"✅ Double Bottom detected @ ~{round((t1_val+t2_val)/2, 4)} — BULLISH reversal signal" if detected else "No Double Bottom",
    }


def compute_volume_profile(prices: list, volumes: list, bins: int = 20) -> Dict:
    """
    Volume Profile — High Volume Nodes (HVN), Low Volume Nodes (LVN), POC.
    Identifies liquidity clusters: where most volume traded = strongest S/R.
    """
    if len(prices) < bins or len(volumes) < bins or not prices:
        return {"poc": 0.0, "hvn_levels": [], "lvn_levels": [], "profile": {},
                "vp_note": "Insufficient data for volume profile"}

    min_p = min(prices)
    max_p = max(prices)
    if max_p == min_p:
        return {"poc": min_p, "hvn_levels": [], "lvn_levels": [], "profile": {},
                "vp_note": "No price range for volume profile"}

    step    = (max_p - min_p) / bins
    profile = {}

    for p, v in zip(prices, volumes):
        level = min(int((p - min_p) / step), bins - 1)
        profile[level] = profile.get(level, 0) + v

    # Convert bucket index → price level
    price_profile = {
        round(min_p + k * step + step / 2, 8): round(v, 4)
        for k, v in profile.items()
    }

    # POC = price level with highest volume
    poc_price = max(price_profile, key=price_profile.get) if price_profile else 0.0
    max_vol   = max(price_profile.values(), default=1.0)
    avg_vol   = sum(price_profile.values()) / max(len(price_profile), 1)

    hvn_levels = sorted([p for p, v in price_profile.items() if v >= avg_vol * 1.5])
    lvn_levels = sorted([p for p, v in price_profile.items() if v <= avg_vol * 0.5])

    return {
        "poc":        poc_price,
        "hvn_levels": hvn_levels[:5],
        "lvn_levels": lvn_levels[:5],
        "profile":    price_profile,
        "vp_note":    f"VP POC={round(poc_price, 4)} | {len(hvn_levels)} HVN | {len(lvn_levels)} LVN — liquidity clusters mapped",
    }




