def _find_swing_points(prices: list, window: int = 3):
    """Extract local swing highs and lows with their indices."""
    highs, lows = [], []
    for i in range(window, len(prices) - window):
        if all(prices[i] >= prices[i-j] and prices[i] >= prices[i+j] for j in range(1, window+1)):
            highs.append((i, prices[i]))
        if all(prices[i] <= prices[i-j] and prices[i] <= prices[i+j] for j in range(1, window+1)):
            lows.append((i, prices[i]))
    return highs, lows


def detect_ascending_triangle(highs: list, lows: list, tolerance: float = 0.015) -> Dict:
    """
    Ascending Triangle (Bullish Continuation):
    - Flat resistance (equal highs within tolerance)
    - Rising support (higher lows)
    """
    if len(highs) < 3 or len(lows) < 3:
        return {"detected": False, "pattern": "ASCENDING_TRIANGLE", "bias": "BULLISH",
                "note": "Insufficient data", "resistance": 0.0, "support_slope": 0.0}
    recent_highs = [h[1] for h in highs[-4:]]
    recent_lows  = [l[1] for l in lows[-4:]]
    h_max = max(recent_highs); h_min = min(recent_highs)
    flat_resistance = (h_max - h_min) / h_max < tolerance if h_max > 0 else False
    rising_support  = all(recent_lows[i] > recent_lows[i-1] for i in range(1, len(recent_lows)))
    detected = flat_resistance and rising_support
    slope = (recent_lows[-1] - recent_lows[0]) / max(len(recent_lows), 1) if rising_support else 0.0
    return {
        "detected":       detected,
        "pattern":        "ASCENDING_TRIANGLE",
        "type":           "CONTINUATION",
        "bias":           "BULLISH",
        "resistance":     round(sum(recent_highs) / len(recent_highs), 8),
        "support_slope":  round(slope, 8),
        "note": ("✅ Ascending Triangle — flat resistance, rising support → bullish breakout expected"
                 if detected else "No ascending triangle"),
    }


def detect_descending_triangle(highs: list, lows: list, tolerance: float = 0.015) -> Dict:
    """
    Descending Triangle (Bearish Continuation):
    - Flat support (equal lows within tolerance)
    - Declining resistance (lower highs)
    """
    if len(highs) < 3 or len(lows) < 3:
        return {"detected": False, "pattern": "DESCENDING_TRIANGLE", "bias": "BEARISH",
                "note": "Insufficient data", "support": 0.0, "resistance_slope": 0.0}
    recent_highs = [h[1] for h in highs[-4:]]
    recent_lows  = [l[1] for l in lows[-4:]]
    l_max = max(recent_lows); l_min = min(recent_lows)
    flat_support      = (l_max - l_min) / l_max < tolerance if l_max > 0 else False
    declining_resist  = all(recent_highs[i] < recent_highs[i-1] for i in range(1, len(recent_highs)))
    detected = flat_support and declining_resist
    slope = (recent_highs[-1] - recent_highs[0]) / max(len(recent_highs), 1) if declining_resist else 0.0
    return {
        "detected":          detected,
        "pattern":           "DESCENDING_TRIANGLE",
        "type":              "CONTINUATION",
        "bias":              "BEARISH",
        "support":           round(sum(recent_lows) / len(recent_lows), 8),
        "resistance_slope":  round(slope, 8),
        "note": ("✅ Descending Triangle — flat support, lower highs → bearish breakdown expected"
                 if detected else "No descending triangle"),
    }


def detect_symmetrical_triangle(highs: list, lows: list) -> Dict:
    """
    Symmetrical Triangle (Continuation — direction of prior trend):
    - Converging trendlines: lower highs + higher lows
    """
    if len(highs) < 3 or len(lows) < 3:
        return {"detected": False, "pattern": "SYMMETRICAL_TRIANGLE",
                "note": "Insufficient data", "apex_distance": 0.0}
    recent_highs = [h[1] for h in highs[-4:]]
    recent_lows  = [l[1] for l in lows[-4:]]
    lower_highs = all(recent_highs[i] < recent_highs[i-1] for i in range(1, len(recent_highs)))
    higher_lows = all(recent_lows[i]  > recent_lows[i-1]  for i in range(1, len(recent_lows)))
    detected = lower_highs and higher_lows
    apex = (recent_highs[-1] + recent_lows[-1]) / 2 if detected else 0.0
    spread = abs(recent_highs[-1] - recent_lows[-1]) if detected else 0.0
    return {
        "detected":       detected,
        "pattern":        "SYMMETRICAL_TRIANGLE",
        "type":           "CONTINUATION",
        "bias":           "NEUTRAL",
        "apex":           round(apex, 8),
        "apex_spread":    round(spread, 8),
        "note": ("✅ Symmetrical Triangle — converging trendlines → breakout imminent (direction = prior trend)"
                 if detected else "No symmetrical triangle"),
    }


def detect_bullish_flag(prices: list, volumes: list = None, lookback: int = 40) -> Dict:
    """
    Bullish Flag (Continuation):
    - Strong upward pole (sharp rally)
    - Tight consolidation channel slightly lower (flag)
    """
    if len(prices) < lookback:
        return {"detected": False, "pattern": "BULLISH_FLAG", "note": "Insufficient data"}
    recent = prices[-lookback:]
    mid    = len(recent) // 2
    pole   = recent[:mid]
    flag   = recent[mid:]
    pole_gain  = (pole[-1] - pole[0]) / max(abs(pole[0]), 1e-9)
    flag_range = (max(flag) - min(flag)) / max(abs(max(flag)), 1e-9)
    flag_drift = (flag[-1] - flag[0]) / max(abs(flag[0]), 1e-9)
    detected = (pole_gain > 0.04 and flag_range < pole_gain * 0.5 and flag_drift < 0.01)
    return {
        "detected":   detected,
        "pattern":    "BULLISH_FLAG",
        "type":       "CONTINUATION",
        "bias":       "BULLISH",
        "pole_gain":  round(pole_gain * 100, 2),
        "flag_range": round(flag_range * 100, 2),
        "note": (f"✅ Bullish Flag — pole +{round(pole_gain*100,1)}%, tight flag → upside continuation"
                 if detected else "No bullish flag"),
    }


def detect_bearish_flag(prices: list, volumes: list = None, lookback: int = 40) -> Dict:
    """
    Bearish Flag (Continuation):
    - Strong downward pole (sharp drop)
    - Tight consolidation channel slightly higher (bear flag)
    """
    if len(prices) < lookback:
        return {"detected": False, "pattern": "BEARISH_FLAG", "note": "Insufficient data"}
    recent = prices[-lookback:]
    mid    = len(recent) // 2
    pole   = recent[:mid]
    flag   = recent[mid:]
    pole_drop  = (pole[0] - pole[-1]) / max(abs(pole[0]), 1e-9)
    flag_range = (max(flag) - min(flag)) / max(abs(max(flag)), 1e-9)
    flag_drift = (flag[-1] - flag[0]) / max(abs(flag[0]), 1e-9)
    detected = (pole_drop > 0.04 and flag_range < pole_drop * 0.5 and flag_drift > -0.01)
    return {
        "detected":   detected,
        "pattern":    "BEARISH_FLAG",
        "type":       "CONTINUATION",
        "bias":       "BEARISH",
        "pole_drop":  round(pole_drop * 100, 2),
        "flag_range": round(flag_range * 100, 2),
        "note": (f"✅ Bearish Flag — pole -{round(pole_drop*100,1)}%, tight flag → downside continuation"
                 if detected else "No bearish flag"),
    }


def detect_rising_wedge(highs: list, lows: list) -> Dict:
    """
    Rising Wedge (Bearish Reversal):
    - Both highs and lows trending up, but highs rising slower → converging
    """
    if len(highs) < 3 or len(lows) < 3:
        return {"detected": False, "pattern": "RISING_WEDGE", "note": "Insufficient data"}
    rh = [h[1] for h in highs[-4:]]
    rl = [l[1] for l in lows[-4:]]
    highs_rising = all(rh[i] > rh[i-1] for i in range(1, len(rh)))
    lows_rising  = all(rl[i] > rl[i-1] for i in range(1, len(rl)))
    if not (highs_rising and lows_rising):
        return {"detected": False, "pattern": "RISING_WEDGE", "note": "No rising wedge"}
    high_slope = (rh[-1] - rh[0]) / max(len(rh), 1)
    low_slope  = (rl[-1] - rl[0]) / max(len(rl), 1)
    converging = low_slope > high_slope  # lows rising faster than highs → converging
    detected   = highs_rising and lows_rising and converging
    return {
        "detected":    detected,
        "pattern":     "RISING_WEDGE",
        "type":        "REVERSAL",
        "bias":        "BEARISH",
        "high_slope":  round(high_slope, 8),
        "low_slope":   round(low_slope, 8),
        "note": ("✅ Rising Wedge — converging up → bearish reversal on breakdown"
                 if detected else "No rising wedge"),
    }


def detect_falling_wedge(highs: list, lows: list) -> Dict:
    """
    Falling Wedge (Bullish Reversal):
    - Both highs and lows trending down, but lows falling slower → converging
    """
    if len(highs) < 3 or len(lows) < 3:
        return {"detected": False, "pattern": "FALLING_WEDGE", "note": "Insufficient data"}
    rh = [h[1] for h in highs[-4:]]
    rl = [l[1] for l in lows[-4:]]
    highs_falling = all(rh[i] < rh[i-1] for i in range(1, len(rh)))
    lows_falling  = all(rl[i] < rl[i-1] for i in range(1, len(rl)))
    if not (highs_falling and lows_falling):
        return {"detected": False, "pattern": "FALLING_WEDGE", "note": "No falling wedge"}
    high_slope = (rh[-1] - rh[0]) / max(len(rh), 1)
    low_slope  = (rl[-1] - rl[0]) / max(len(rl), 1)
    converging = low_slope > high_slope  # lows falling slower than highs → converging
    detected   = highs_falling and lows_falling and converging
    return {
        "detected":    detected,
        "pattern":     "FALLING_WEDGE",
        "type":        "REVERSAL",
        "bias":        "BULLISH",
        "high_slope":  round(high_slope, 8),
        "low_slope":   round(low_slope, 8),
        "note": ("✅ Falling Wedge — converging down → bullish reversal on breakout"
                 if detected else "No falling wedge"),
    }


def detect_bearish_wedge(highs: list, lows: list) -> Dict:
    """
    Bearish Wedge (Continuation — in downtrend):
    Rising wedge forming during a downtrend = continuation lower.
    """
    rw = detect_rising_wedge(highs, lows)
    result = dict(rw)
    result["pattern"] = "BEARISH_WEDGE"
    result["type"]    = "CONTINUATION"
    if result["detected"]:
        result["note"] = "✅ Bearish Wedge (continuation) — rising wedge in downtrend → breakdown continues"
    return result


def detect_bullish_wedge(highs: list, lows: list) -> Dict:
    """
    Bullish Wedge (Continuation — in uptrend):
    Falling wedge forming during an uptrend = continuation higher.
    """
    fw = detect_falling_wedge(highs, lows)
    result = dict(fw)
    result["pattern"] = "BULLISH_WEDGE"
    result["type"]    = "CONTINUATION"
    if result["detected"]:
        result["note"] = "✅ Bullish Wedge (continuation) — falling wedge in uptrend → rally continues"
    return result


def detect_triple_top(prices: list, tolerance: float = 0.015, window: int = 5) -> Dict:
    """
    Triple Top (Bearish Reversal):
    - Three peaks at approximately same level
    - Two valleys between peaks (neckline)
    """
    if len(prices) < 20:
        return {"detected": False, "pattern": "TRIPLE_TOP", "note": "Insufficient data"}
    swing_highs, swing_lows = _find_swing_points(prices, window)
    if len(swing_highs) < 3 or len(swing_lows) < 2:
        return {"detected": False, "pattern": "TRIPLE_TOP", "note": "Not enough swing points"}
    h = swing_highs[-3:]
    h_vals = [x[1] for x in h]
    h_max = max(h_vals); h_min = min(h_vals)
    three_equal = (h_max - h_min) / h_max < tolerance if h_max > 0 else False
    neckline = sum(l[1] for l in swing_lows[-2:]) / 2 if len(swing_lows) >= 2 else 0.0
    detected = three_equal
    return {
        "detected":  detected,
        "pattern":   "TRIPLE_TOP",
        "type":      "REVERSAL",
        "bias":      "BEARISH",
        "resistance": round(sum(h_vals) / 3, 8),
        "neckline":  round(neckline, 8),
        "note": (f"✅ Triple Top — 3 peaks ~{round(sum(h_vals)/3, 4)} → bearish reversal below neckline {round(neckline,4)}"
                 if detected else "No triple top"),
    }


def detect_triple_bottom(prices: list, tolerance: float = 0.015, window: int = 5) -> Dict:
    """
    Triple Bottom (Bullish Reversal):
    - Three troughs at approximately same level
    - Two peaks between troughs (neckline)
    """
    if len(prices) < 20:
        return {"detected": False, "pattern": "TRIPLE_BOTTOM", "note": "Insufficient data"}
    swing_highs, swing_lows = _find_swing_points(prices, window)
    if len(swing_lows) < 3 or len(swing_highs) < 2:
        return {"detected": False, "pattern": "TRIPLE_BOTTOM", "note": "Not enough swing points"}
    l = swing_lows[-3:]
    l_vals = [x[1] for x in l]
    l_max = max(l_vals); l_min = min(l_vals)
    three_equal = (l_max - l_min) / l_max < tolerance if l_max > 0 else False
    neckline = sum(h[1] for h in swing_highs[-2:]) / 2 if len(swing_highs) >= 2 else 0.0
    detected = three_equal
    return {
        "detected":  detected,
        "pattern":   "TRIPLE_BOTTOM",
        "type":      "REVERSAL",
        "bias":      "BULLISH",
        "support":   round(sum(l_vals) / 3, 8),
        "neckline":  round(neckline, 8),
        "note": (f"✅ Triple Bottom — 3 troughs ~{round(sum(l_vals)/3, 4)} → bullish reversal above neckline {round(neckline,4)}"
                 if detected else "No triple bottom"),
    }


def detect_inverted_head_shoulders(highs: list, lows: list, window: int = 30) -> Dict:
    """
    Inverted Head & Shoulders (Bullish Reversal):
    - Left shoulder trough, lower head trough, right shoulder trough
    - Neckline connecting the peaks between troughs
    """
    if len(lows) < window:
        return {"detected": False, "pattern": "INVERTED_H&S", "note": "Insufficient data"}
    prices = lows[-window:]
    # Find 3 significant troughs
    troughs = []
    for i in range(1, len(prices) - 1):
        if prices[i] < prices[i-1] and prices[i] < prices[i+1]:
            troughs.append((i, prices[i]))
    if len(troughs) < 3:
        return {"detected": False, "pattern": "INVERTED_H&S", "note": "Not enough troughs"}
    ls, head, rs = troughs[-3], troughs[-2], troughs[-1]
    head_lower    = head[1] < ls[1] and head[1] < rs[1]
    shoulders_sim = abs(ls[1] - rs[1]) / max(abs(ls[1]), 1e-9) < 0.03
    detected = head_lower and shoulders_sim
    neckline = (ls[1] + rs[1]) / 2
    return {
        "detected":  detected,
        "pattern":   "INVERTED_H&S",
        "type":      "REVERSAL",
        "bias":      "BULLISH",
        "head":      round(head[1], 8),
        "neckline":  round(neckline, 8),
        "note": (f"✅ Inverted H&S — head at {round(head[1],4)}, neckline {round(neckline,4)} → bullish breakout"
                 if detected else "No inverted H&S"),
    }


def run_all_chart_patterns(closes: list, highs_raw: list, lows_raw: list,
                            volumes: list = None, bias: str = "BEARISH") -> Dict:
    """
    Master pattern scanner — runs all 16 patterns and returns a unified summary.
    Returns dict with each pattern result + best_pattern (highest confidence active one).
    """
    _highs_sw, _lows_sw = _find_swing_points(closes, window=3)
    _highs_hl = [(i, h) for i, h in enumerate(highs_raw)]
    _lows_hl  = [(i, l) for i, l in enumerate(lows_raw)]

    results = {
        # Continuation
        "asc_triangle":   detect_ascending_triangle(_highs_hl, _lows_hl),
        "desc_triangle":  detect_descending_triangle(_highs_hl, _lows_hl),
        "sym_triangle":   detect_symmetrical_triangle(_highs_hl, _lows_hl),
        "bull_flag":      detect_bullish_flag(closes, volumes),
        "bear_flag":      detect_bearish_flag(closes, volumes),
        "bull_wedge":     detect_bullish_wedge(_highs_sw, _lows_sw),
        "bear_wedge":     detect_bearish_wedge(_highs_sw, _lows_sw),
        # Reversal
        "double_top":     detect_double_top(closes),
        "double_bot":     detect_double_bottom(closes),
        "triple_top":     detect_triple_top(closes),
        "triple_bot":     detect_triple_bottom(closes),
        "rising_wedge":   detect_rising_wedge(_highs_sw, _lows_sw),
        "falling_wedge":  detect_falling_wedge(_highs_sw, _lows_sw),
        "hs":             detect_head_shoulders(highs_raw, lows_raw),
        "ihs":            detect_inverted_head_shoulders(highs_raw, lows_raw),
    }

    detected = [(k, v) for k, v in results.items() if v.get("detected")]
    # Bias-aligned patterns rank higher
    aligned   = [(k, v) for k, v in detected if v.get("bias") == bias]
    best_key  = aligned[0][0] if aligned else (detected[0][0] if detected else None)
    best      = results[best_key] if best_key else {"detected": False, "note": "No pattern detected"}

    return {
        "patterns":      results,
        "detected_list": [v["pattern"] for _, v in detected],
        "aligned_list":  [v["pattern"] for _, v in aligned],
        "best_pattern":  best,
        "count":         len(detected),
        "aligned_count": len(aligned),
        "summary": (
            f"{len(detected)} pattern(s) detected | "
            f"{len(aligned)} bias-aligned ({bias}) | "
            f"Best: {best.get('pattern','NONE')} — {best.get('note','')}"
        ),
    }


def detect_market_structure(ohlcv: list):
    """
    Detect BOS/CHOCH. Returns bias ('BULLISH'/'BEARISH'), bos_price, bos_type,
    structure_valid (body-close based).
    """
    closes = [c[3] for c in ohlcv]
    highs_idx, lows_idx = find_swing_highs_lows(ohlcv)

    if len(highs_idx) < 2 or len(lows_idx) < 2:
        # fallback: simple slope
        slope = closes[-1] - closes[-20] if len(closes) >= 20 else 0
        bias = "BULLISH" if slope > 0 else "BEARISH"
        return bias, closes[-1], f"{'BULLISH' if slope > 0 else 'BEARISH'} BOS", True

    last_high = highs_idx[-1][1]
    prev_high = highs_idx[-2][1] if len(highs_idx) >= 2 else last_high
    last_low  = lows_idx[-1][1]
    prev_low  = lows_idx[-2][1] if len(lows_idx) >= 2 else last_low

    # HH + HL = bullish, LH + LL = bearish
    hh = last_high > prev_high
    hl = last_low  > prev_low
    lh = last_high < prev_high
    ll = last_low  < prev_low

    if hh and hl:
        bias = "BULLISH"
        bos_price = last_high
        bos_type = "BULLISH BOS"
    elif lh and ll:
        bias = "BEARISH"
        bos_price = last_low
        bos_type = "BEARISH BOS"
    else:
        # Mixed — use latest swing
        slope = closes[-1] - closes[-10] if len(closes) >= 10 else 0
        bias = "BULLISH" if slope > 0 else "BEARISH"
        bos_price = last_high if bias == "BULLISH" else last_low
        bos_type = f"{bias} CHOCH"

    # Structure validity: close-based break (not wick-only)
    structure_valid = True
    if bias == "BULLISH":
        structure_valid = closes[-1] > bos_price * 0.998
    else:
        structure_valid = closes[-1] < bos_price * 1.002

    return bias, bos_price, bos_type, structure_valid


def detect_order_blocks(ohlcv: list, bias: str):
    """
    Find the most recent UNMITIGATED order block.
    Bullish OB (BISI — Buy Side Imbalance Sell Side Inefficiency):
        = last bearish candle before a bullish displacement.
    Bearish OB (SIBI — Sell Side Imbalance Buy Side Inefficiency):
        = last bullish candle before a bearish displacement.
    Mitigation check: price must not have traded back through the OB since formation.
    CE Invalidation (research-validated rule):
        OB is invalid when ANY candle CLOSES beyond the 50% midpoint (CE) of the OB.
        A close beyond CE = institutional re-engagement failed → OB is compromised.
    Returns (ob_low, ob_high) or None.
    """
    if len(ohlcv) < 5:
        return None
    for i in range(len(ohlcv) - 2, 2, -1):
        o, h, l, c = ohlcv[i][0], ohlcv[i][1], ohlcv[i][2], ohlcv[i][3]
        next_c = ohlcv[i + 1]
        ob_ce = (h + l) / 2   # 50% CE of this OB
        if bias == "BULLISH":
            # BISI — bearish OB candle (close < open)
            if c < o:
                # followed by a strong bullish candle
                if next_c[3] > next_c[0] and (next_c[3] - next_c[0]) > (h - l) * 0.5:
                    # CE Invalidation: any subsequent candle CLOSE below CE = OB compromised
                    ce_invalidated = any(ohlcv[j][3] < ob_ce for j in range(i + 2, len(ohlcv)))
                    if not ce_invalidated:
                        return l, h
        else:
            # SIBI — bullish OB candle (close > open)
            if c > o:
                # followed by a strong bearish candle
                if next_c[3] < next_c[0] and (next_c[0] - next_c[3]) > (h - l) * 0.5:
                    # CE Invalidation: any subsequent candle CLOSE above CE = OB compromised
                    ce_invalidated = any(ohlcv[j][3] > ob_ce for j in range(i + 2, len(ohlcv)))
                    if not ce_invalidated:
                        return l, h
    # Fallback to last significant candle range
    c = ohlcv[-3]
    return c[2], c[1]

def detect_breaker_block(ohlcv: list, bias: str) -> Optional[Dict]:
    """
    Breaker Block = a mitigated OB that price has broken through and is now retesting from the other side.
    Bullish Breaker: bearish OB that was mitigated (price closed below OB low),
                     then price reclaims above it → OB low becomes support.
    Bearish Breaker: bullish OB that was mitigated (price closed above OB high),
                     then price rejects back below it → OB high becomes resistance.
    Higher probability than fresh OBs (~75% reversal rate per Agent F data).
    Returns {"breaker_low": float, "breaker_high": float} or None.
    """
    if len(ohlcv) < 8:
        return None
    current_price = ohlcv[-1][3]
    for i in range(len(ohlcv) - 4, 2, -1):
        o, h, l, c = ohlcv[i][0], ohlcv[i][1], ohlcv[i][2], ohlcv[i][3]
        next_c = ohlcv[i + 1]
        if bias == "BULLISH":
            # Was a bearish OB candle
            if c < o and next_c[3] > next_c[0] and (next_c[3] - next_c[0]) > (h - l) * 0.5:
                # Check if it was mitigated: any close BELOW OB low after formation
                mitigated_at = None
                for j in range(i + 2, len(ohlcv)):
                    if ohlcv[j][3] < l:
                        mitigated_at = j
                        break
                if mitigated_at is None:
                    continue  # not mitigated — regular OB, not a breaker
                # Now check if price has reclaimed back above OB low (the breaker flip)
                reclaimed = any(ohlcv[k][3] > l for k in range(mitigated_at + 1, len(ohlcv)))
                if reclaimed and current_price > l:
                    return {"breaker_low": l, "breaker_high": h}
        else:
            # Was a bullish OB candle
            if c > o and next_c[3] < next_c[0] and (next_c[0] - next_c[3]) > (h - l) * 0.5:
                # Check if mitigated: any close ABOVE OB high after formation
                mitigated_at = None
                for j in range(i + 2, len(ohlcv)):
                    if ohlcv[j][3] > h:
                        mitigated_at = j
                        break
                if mitigated_at is None:
                    continue
                # Check if price has rejected back below OB high
                rejected = any(ohlcv[k][3] < h for k in range(mitigated_at + 1, len(ohlcv)))
                if rejected and current_price < h:
                    return {"breaker_low": l, "breaker_high": h}
    return None


def detect_liquidity_zones(ohlcv: list, bias: str, tolerance: float = 0.001):
    """
    Equal highs/lows = liquidity. Find clusters of highs or lows within tolerance.
    Returns (swept_zone, target_zone).
    """
    highs = [c[1] for c in ohlcv]
    lows  = [c[2] for c in ohlcv]
    price = ohlcv[-1][3]

    # Find equal highs (within tolerance band)
    eq_highs = []
    for i in range(len(highs) - 1):
        for j in range(i + 1, len(highs)):
            if abs(highs[i] - highs[j]) / highs[i] < tolerance:
                eq_highs.append((highs[i] + highs[j]) / 2)

    eq_lows = []
    for i in range(len(lows) - 1):
        for j in range(i + 1, len(lows)):
            if abs(lows[i] - lows[j]) / (lows[i] + 1e-9) < tolerance:
                eq_lows.append((lows[i] + lows[j]) / 2)

    if bias == "BULLISH":
        swept  = min(eq_lows,  default=min(lows[-20:]))   # recent equal lows (swept)
        target = max(eq_highs, default=max(highs[-20:]))  # liquidity above
    else:
        swept  = max(eq_highs, default=max(highs[-20:]))
        target = min(eq_lows,  default=min(lows[-20:]))

    return swept, target


def compute_lqi(ohlcv: list, swept: float, tolerance: float = 0.001) -> int:
    """
    Liquidity Quality Index 0-100.
    - Count of candles touching the level (persistence)
    - Whether it's been swept (price moved through)
    - Wick rejection after sweep
    """
    lows  = [c[2] for c in ohlcv]
    highs = [c[1] for c in ohlcv]
    closes = [c[3] for c in ohlcv]

    # Count touches
    touches = sum(1 for l in lows  if abs(l - swept) / (swept + 1e-9) < tolerance * 2)
    touches += sum(1 for h in highs if abs(h - swept) / (swept + 1e-9) < tolerance * 2)
    persistence_score = min(40, touches * 8)

    # Was it swept?
    price = closes[-1]
    swept_score = 30 if (price > swept * 1.002 or price < swept * 0.998) else 0

    # Wick rejection
    last = ohlcv[-1]
    body = abs(last[3] - last[0])
    wick = last[1] - last[2]
    wick_score = 30 if wick > body * 1.5 else 0

    return min(100, persistence_score + swept_score + wick_score)


def detect_displacement(ohlcv: list, atr: float, bias: str):
    """
    Gate 5: Displacement = recent candle with range >= 1.2x ATR and body >= 60%.
    Returns (passed, atr_mult, body_pct, disp_score).
    """
    for c in reversed(ohlcv[-20:]):
        rng  = c[1] - c[2]
        body = abs(c[3] - c[0])
        if atr > 0 and rng >= 1.2 * atr:
            body_pct = int(body / rng * 100) if rng > 0 else 0
            atr_mult = round(rng / atr, 2)
            # Direction match
            bull_disp = c[3] > c[0] and bias == "BULLISH"
            bear_disp = c[3] < c[0] and bias == "BEARISH"
            if body_pct >= 60 and (bull_disp or bear_disp):
                disp_score = round(min(0.99, (rng / (atr * 3))), 2)
                return True, atr_mult, body_pct, disp_score
    return False, round((ohlcv[-1][1] - ohlcv[-1][2]) / max(atr, 1e-9), 2), 0, 0.0


def get_current_session() -> str:
    """Return current trading session based on real UTC time."""
    now = datetime.datetime.utcnow()
    mins = now.hour * 60 + now.minute
    weekday = now.weekday()  # 0=Mon, 6=Sun

    if weekday >= 5:  # weekend
        return "WEEKEND"

    for name, (start, end) in SESSIONS.items():
        if start <= mins < end:
            return name

    return "OFF_SESSION"

def get_silver_bullet_status() -> Dict:
    """
    Detect if current UTC time falls within an ICT Silver Bullet window.
    Silver Bullets are the highest-probability 1-hour ICT setups:
    - London SB:  02:00–03:00 UTC
    - NY AM SB:   10:00–11:00 UTC  (most powerful — pre-NY overlap)
    - NY PM SB:   14:00–15:00 UTC
    Returns active window name and minutes remaining, or None if outside.
    """
    now  = datetime.datetime.utcnow()
    mins = now.hour * 60 + now.minute
    weekday = now.weekday()

    if weekday >= 5:
        return {"active": False, "window": None, "minutes_remaining": 0, "next_window": "Monday"}

    for name, (start, end) in SILVER_BULLET_WINDOWS.items():
        if start <= mins < end:
            return {
                "active":            True,
                "window":            name,
                "minutes_remaining": end - mins,
                "boost":             True,   # confidence bonus applies
            }

    # Find next Silver Bullet
    future = [(n, s) for n, (s, e) in SILVER_BULLET_WINDOWS.items() if s > mins]
    if future:
        next_name, next_start = min(future, key=lambda x: x[1])
        return {"active": False, "window": None, "minutes_remaining": 0,
                "next_window": next_name, "next_in_mins": next_start - mins}
    return {"active": False, "window": None, "minutes_remaining": 0, "next_window": "Tomorrow_LONDON_SB"}


def _compute_next_candle_open(exec_tf: str) -> str:
    """
    FIX-NEXT-CANDLE-TIMESTAMP: Compute the UTC open time of the NEXT exec_tf candle.
    Example: called at 11:11 PM with exec_tf='15m' → returns '23:15 UTC'
    This is the exact timestamp the trader places their limit order.
    """
    tf_mins = _TF_MINUTES.get(exec_tf.lower().replace(" ", ""), 15)
    now     = datetime.datetime.utcnow()
    # Total minutes since midnight
    total_mins  = now.hour * 60 + now.minute
    # Next boundary = ceiling to next multiple of tf_mins
    next_mins   = (total_mins // tf_mins + 1) * tf_mins
    next_hour   = (next_mins // 60) % 24
    next_minute = next_mins % 60
    next_open   = now.replace(hour=next_hour, minute=next_minute,
                               second=0, microsecond=0)
    # If next boundary crosses midnight, add a day
    if next_mins >= 1440:
        next_open += datetime.timedelta(days=1)
    return next_open.strftime("%H:%M UTC")


def compute_entry_time_window(session: str, best_tf: str, entry_ltf: str, bias: str) -> Dict:
    """
    [FIX-F5] Compute the exact recommended entry time window based on:
    - Current session (London / NY_AM / NY_PM / ASIA)
    - HTF narrative timeframe
    - ICT Silver Bullet kill zones
    Returns: next_entry_window, current_readiness, wait_minutes, note
    """
    now   = datetime.datetime.utcnow()
    mins  = now.hour * 60 + now.minute
    wday  = now.weekday()

    if wday >= 5:
        return {
            "entry_window":      "WEEKEND — NO ENTRY",
            "entry_ready":       False,
            "wait_minutes":      0,
            "entry_time_note":   "⛔ Weekend. Next valid window: Monday 02:00 UTC (London SB)",
            "best_kill_zone":    "CLOSED",
            "next_candle_open_utc": "—",
            "signal_basis_note": "Signal based on last closed candle. No entry on weekends.",
        }

    # ICT kill zones with their best TF alignment
    KILL_ZONES = {
        "LONDON_SB":   {"start": 2*60,    "end": 3*60,    "label": "London SB  02:00–03:00 UTC"},
        "LONDON_OPEN": {"start": 7*60,    "end": 10*60+30,"label": "London Open 07:00–10:30 UTC"},
        "NY_AM_SB":    {"start": 10*60,   "end": 11*60,   "label": "NY AM SB   10:00–11:00 UTC"},
        "NY_OPEN":     {"start": 13*60+30,"end": 16*60,   "label": "NY Open    13:30–16:00 UTC"},
        "NY_PM_SB":    {"start": 14*60,   "end": 15*60,   "label": "NY PM SB   14:00–15:00 UTC"},
    }

    # Check if currently inside a kill zone
    active_kz = None
    for kz_name, kz in KILL_ZONES.items():
        if kz["start"] <= mins < kz["end"]:
            active_kz = kz_name
            break

    # Best kill zone for this HTF
    if best_tf in ("4h", "1d"):
        best_kz = "LONDON_OPEN"
    elif best_tf in ("1h",):
        best_kz = "NY_AM_SB"
    else:
        best_kz = "NY_OPEN"

    # FIX-NEXT-CANDLE-WIRE: Compute entry candle open time for every branch.
    # This is the exact UTC timestamp the trader places their limit order —
    # the open of the next exec_tf candle AFTER the signal's last closed candle.
    _next_open   = _compute_next_candle_open(entry_ltf)
    _basis_note  = (
        f"Signal reads last CLOSED {entry_ltf} candle. "
        f"⏰ Place order at {_next_open} candle open."
    )

    if active_kz:
        kz_data   = KILL_ZONES[active_kz]
        mins_left = kz_data["end"] - mins
        return {
            "entry_window":    f"🟢 NOW — {kz_data['label']}",
            "entry_ready":     True,
            "wait_minutes":    0,
            "mins_remaining":  mins_left,
            "next_candle_open_utc": _next_open,
            "signal_basis_note":    _basis_note,
            "entry_time_note": (
                f"✅ INSIDE kill zone: {kz_data['label']}  "
                f"({mins_left}m remaining)\n"
                f"   ⏰ ENTRY: {_next_open} — place {entry_ltf} LIMIT at next candle open\n"
                f"   Signal confirmed on LAST CLOSED {entry_ltf} candle."
            ),
            "best_kill_zone":  active_kz,
        }

    # Not in any kill zone — find next
    future = [(n, kz["start"]) for n, kz in KILL_ZONES.items() if kz["start"] > mins]
    if future:
        next_name, next_start = min(future, key=lambda x: x[1])
        wait = next_start - mins
        h, m = divmod(wait, 60)
        next_time_str = f"{next_start//60:02d}:{next_start%60:02d} UTC"
        return {
            "entry_window":    f"⏳ WAIT — Next: {KILL_ZONES[next_name]['label']}",
            "entry_ready":     False,
            "wait_minutes":    wait,
            "next_candle_open_utc": _next_open,
            "signal_basis_note":    _basis_note,
            "entry_time_note": (
                f"⏳ Next kill zone: {KILL_ZONES[next_name]['label']}\n"
                f"   Wait {h}h {m}m → set alert at {next_time_str}\n"
                f"   ⏰ ENTRY: at {entry_ltf} candle open inside that zone\n"
                f"   Signal confirmed on LAST CLOSED {entry_ltf} candle."
            ),
            "best_kill_zone":  next_name,
        }

    return {
        "entry_window":    "⏳ WAIT — Tomorrow London SB 02:00 UTC",
        "entry_ready":     False,
        "wait_minutes":    (24*60 - mins) + 2*60,
        "next_candle_open_utc": "02:00 UTC (Mon)",
        "signal_basis_note":    _basis_note,
        "entry_time_note": f"⏳ No more kill zones today. Wait for tomorrow London SB 02:00 UTC.",
        "best_kill_zone":  "TOMORROW_LONDON_SB",
    }


def compute_atr_percentile(ohlcv: list, period: int = 14, lookback: int = 50) -> float:
    """ATR percentile vs last 50 ATR values — for regime classification."""
    if len(ohlcv) < lookback + period:
        return 50.0
    atrs = []
    for i in range(lookback):
        subset = ohlcv[-(lookback - i + period):-(lookback - i) or None]
        if len(subset) >= period:
            atrs.append(compute_atr(subset, period))
    current_atr = compute_atr(ohlcv[-period - 1:], period)
    if not atrs:
        return 50.0
    rank = sum(1 for a in atrs if a < current_atr)
    return round(rank / len(atrs) * 100, 1)


def compute_trend_slope(closes: list, period: int = 20) -> float:
    """Linear regression slope normalised to price, returns -1 to +1."""
    if len(closes) < period:
        return 0.0
    xs = list(range(period))
    ys = closes[-period:]
    mean_x = sum(xs) / period
    mean_y = sum(ys) / period
    num = sum((xs[i] - mean_x) * (ys[i] - mean_y) for i in range(period))
    den = sum((xs[i] - mean_x) ** 2 for i in range(period))
    slope = num / max(den, 1e-9)
    return max(-1.0, min(1.0, slope / mean_y * 10))


# ─────────────────────── 3-PHASE CEX INTELLIGENCE ────────────
# Phase 1: probe_coin_listings — lightweight parallel ticker-only
#          probe across all 13 CEXs to find which actually list
#          the pair before committing to full OHLCV fetches.
# Phase 2: rank_listed_exchanges — score every listed CEX by
#          spread + volume + slippage and return a ranked table.
# Phase 3: handled in run_ict_analysis — fetch full OHLCV only
#          from top-ranked CEX (fallback to #2 on candle gate).
# ──────────────────────────────────────────────────────────────

async def probe_coin_listings(base: str) -> List[Dict]:
    """
    Phase 1 — Lightweight ticker-only probe across CEXs.
    Funnel mode runs serial / chunked to avoid a burst of parallel sockets.
    """
    async def _probe_one(session: aiohttp.ClientSession, ex_cfg: dict) -> Optional[Dict]:
        sym        = ex_cfg["symbol_fmt"].format(base=base)
        ticker_url = ex_cfg["ticker_url"].format(symbol=sym)
        try:
            raw = await _fetch(session, ticker_url, timeout=5)
            if raw is None:
                return None
            ticker = parse_ticker(ex_cfg, raw)
            if not ticker or not ticker.get("last") or ticker["last"] <= 0:
                return None
            return {
                "name":       ex_cfg["name"],
                "ex_cfg":     ex_cfg,
                "price":      float(ticker["last"]),
                "volume_usd": float(ticker.get("volume_usd") or 0),
                "listed":     True,
            }
        except Exception as e:
            log.debug(f"[PROBE] {ex_cfg['name']} {base}: {e}")
            return None

    connector_limit = FETCH_FUNNEL_CONNECTOR if FETCH_FUNNEL_MODE else 20
    async with aiohttp.ClientSession(
        headers={"User-Agent": "ICT-Bot/2.0"},
        connector=aiohttp.TCPConnector(limit=connector_limit, ssl=False),
    ) as session:
        if FETCH_FUNNEL_MODE:
            listed = await _run_funnel_workers(
                EXCHANGES,
                lambda ex: _probe_one(session, ex),
                label=f"probe:{base}",
                batch_size=PROBE_FETCH_BATCH,
                timeout_s=5,
            )
        else:
            tasks   = [_probe_one(session, ex) for ex in EXCHANGES]
            results = await asyncio.gather(*tasks, return_exceptions=True)
            listed = [r for r in results if isinstance(r, dict) and r is not None]

    log.info(f"[PROBE] {base}: {len(listed)}/{len(EXCHANGES)} exchanges list this pair "
             f"→ {[r['name'] for r in listed]}")
    return listed


def rank_listed_exchanges(
    listed_probes: List[Dict],
    full_ex_data:  List[Dict],
) -> List[Dict]:
    """
    Phase 2 — Score and rank every exchange that both (a) passed the
    Phase 1 listing probe AND (b) returned valid OHLCV data in Phase 3.

    Composite score (0–100):
        Spread score  35%  — tighter bid/ask = better fills
        Volume score  30%  — deeper liquidity = lower market impact
        Slippage score 35% — simulated $10k market-buy slippage

    Returns ranked list (best first), each entry:
        {
            "name":       str,
            "score":      int,   # 0–100
            "spread":     float, # bid/ask spread %
            "vol":        float, # 24h volume USD (billions)
            "vol_u":      "B",
            "slippage":   float, # % slippage on $10k buy
            "volatility": str,   # Low / Medium / High
            "listed":     True,
        }
    """
    # Build a fast name→probe lookup
    probe_map = {p["name"]: p for p in listed_probes}

    ranked = []
    for d in full_ex_data:
        ex_name = d["ex"]["name"]
        if ex_name not in probe_map:
            continue  # did not pass Phase 1 listing probe — skip
        ticker  = d["ticker"]
        ob      = d.get("ob")
        last    = ticker["last"]
        atr_pct = 0  # atr_pct not available here; volatility tagged later
        score   = score_exchange_live(ticker, ob, last)
        ranked.append({
            "name":       ex_name,
            "score":      score,
            "spread":     compute_spread_pct(ob, last),
            "vol":        round(ticker.get("volume_usd", 0) / 1e9, 4),
            "vol_u":      "B",
            "slippage":   compute_slippage(ob),
            "volatility": "Medium",   # tagged later in run_ict_analysis with real atr_pct
            "listed":     True,
        })

    ranked.sort(key=lambda x: x["score"], reverse=True)
    return ranked


def build_listing_table(base: str, listed_probes: List[Dict], all_probes_count: int) -> str:
    """
    Build the human-readable CEX listing table shown in the Telegram
    thinking message during Phase 1.

    Example output:
        🔍 Checking 13 exchanges for WODUSDT...
        ✅ MEXC      $0.00412   Vol: $2.1M   Spread: —
        ✅ Gate.io   $0.00410   Vol: $0.8M   Spread: —
        ❌ Binance / OKX / Bybit / KuCoin  — not listed (9 others)
    """
    if not listed_probes:
        return (f"🔍 Checked {all_probes_count} exchanges for {base}USDT\n"
                f"❌ Not found on any supported CEX")

    lines = [f"🔍 Found on {len(listed_probes)}/{all_probes_count} exchanges:"]
    for p in sorted(listed_probes, key=lambda x: x["volume_usd"], reverse=True)[:6]:
        vol = p["volume_usd"]
        vol_str = (f"${vol/1e6:.1f}M" if vol < 1e9
                   else f"${vol/1e9:.2f}B")
        price_str = (f"${p['price']:.8f}" if p["price"] < 0.0001
                     else f"${p['price']:.6f}" if p["price"] < 0.01
                     else f"${p['price']:.4f}" if p["price"] < 1
                     else f"${p['price']:,.2f}")
        lines.append(f"  ✅ {p['name']:<14} {price_str:<14} Vol: {vol_str}")
    if len(listed_probes) > 6:
        lines.append(f"  ✅ +{len(listed_probes)-6} more exchange(s)")
    return "\n".join(lines)


