# FRACTAL ENGINE + TREND LINE ENGINE  (v8.2 — Steps 1-5)
# ══════════════════════════════════════════════════════════════════════
# Step 1  detect_fractals_3bar / detect_fractals_5bar
# Step 2  classify_fractal_structure   → HH / HL / LH / LL chain
# Step 3  detect_equal_highs_lows      → EQH / EQL fractal liquidity
# Step 4  fit_trendlines + score_trendline + detect_trendline_break/_retest
# Step 5  detect_fractal_inversion     → ICT T-Spot reversal zone
# ══════════════════════════════════════════════════════════════════════


# ── Step 1 ─────────────────────────────────────────────────────────────
def detect_fractals_3bar(ohlcv: list) -> Dict:
    """
    3-bar fractal detection (LTF / intraday scalp pivots).

    A 3-bar fractal high at index i:   highs[i] > highs[i-1]  AND  highs[i] > highs[i+1]
    A 3-bar fractal low  at index i:   lows[i]  < lows[i-1]   AND  lows[i]  < lows[i+1]

    Returns the last confirmed high and low (index + price), plus the
    full list of all fractal pivots found in the window.
    """
    if len(ohlcv) < 3:
        return {"fractal_high": None, "fractal_low": None,
                "fractal_highs": [], "fractal_lows": [],
                "fractal_count": 0, "fractal_note": "Insufficient data"}

    highs = [c[1] for c in ohlcv]
    lows  = [c[2] for c in ohlcv]
    n     = len(ohlcv)

    frac_highs: list = []   # list of (index, price)
    frac_lows:  list = []

    for i in range(1, n - 1):
        if highs[i] > highs[i - 1] and highs[i] > highs[i + 1]:
            frac_highs.append((i, highs[i]))
        if lows[i] < lows[i - 1] and lows[i] < lows[i + 1]:
            frac_lows.append((i, lows[i]))

    last_fh = frac_highs[-1] if frac_highs else None
    last_fl = frac_lows[-1]  if frac_lows  else None

    return {
        "fractal_high":  last_fh,           # (idx, price) or None
        "fractal_low":   last_fl,
        "fractal_highs": frac_highs,        # all confirmed highs
        "fractal_lows":  frac_lows,
        "fractal_count": len(frac_highs) + len(frac_lows),
        "fractal_note":  f"3-bar: {len(frac_highs)}H {len(frac_lows)}L found",
    }


def detect_fractals_5bar(ohlcv: list) -> Dict:
    """
    5-bar fractal detection — ICT standard confirmed swing pivots.

    A 5-bar fractal high at i:
        highs[i] > highs[i-1] AND highs[i] > highs[i-2]
        AND highs[i] > highs[i+1] AND highs[i] > highs[i+2]

    5-bar fractals require 2 bars on each side, giving stronger
    structural significance than 3-bar pivots. These are the pivots
    ICT uses for order block origin, BOS reference, and OTE calculation.

    Returns last confirmed high, last confirmed low, and full lists.
    """
    if len(ohlcv) < 5:
        return {"fractal_high": None, "fractal_low": None,
                "fractal_highs": [], "fractal_lows": [],
                "fractal_count": 0, "fractal_note": "Insufficient data (need ≥5 bars)"}

    highs = [c[1] for c in ohlcv]
    lows  = [c[2] for c in ohlcv]
    n     = len(ohlcv)

    frac_highs: list = []
    frac_lows:  list = []

    for i in range(2, n - 2):
        if (highs[i] > highs[i - 1] and highs[i] > highs[i - 2]
                and highs[i] > highs[i + 1] and highs[i] > highs[i + 2]):
            frac_highs.append((i, highs[i]))
        if (lows[i] < lows[i - 1] and lows[i] < lows[i - 2]
                and lows[i] < lows[i + 1] and lows[i] < lows[i + 2]):
            frac_lows.append((i, lows[i]))

    last_fh = frac_highs[-1] if frac_highs else None
    last_fl = frac_lows[-1]  if frac_lows  else None

    return {
        "fractal_high":  last_fh,
        "fractal_low":   last_fl,
        "fractal_highs": frac_highs,
        "fractal_lows":  frac_lows,
        "fractal_count": len(frac_highs) + len(frac_lows),
        "fractal_note":  f"5-bar: {len(frac_highs)}H {len(frac_lows)}L found",
    }


# ── Step 2 ─────────────────────────────────────────────────────────────
def classify_fractal_structure(frac_highs: list, frac_lows: list,
                                bias: str = "BULLISH") -> Dict:
    """
    Classify the fractal pivot sequence into HH/HL/LH/LL market structure.

    Uses the last 4 confirmed fractal highs and 4 fractal lows to
    determine whether price is making Higher Highs + Higher Lows (uptrend),
    Lower Highs + Lower Lows (downtrend), or mixed (transition/range).

    Output:
        structure:     "UPTREND" | "DOWNTREND" | "RANGING" | "TRANSITION"
        hh_count:      int — number of consecutive Higher Highs
        hl_count:      int — number of consecutive Higher Lows
        lh_count:      int — number of consecutive Lower Highs
        ll_count:      int — number of consecutive Lower Lows
        fractal_bias:  "BULLISH" | "BEARISH" | "NEUTRAL"
        structure_note: human-readable string
    """
    def _count_sequence(vals: list, ascending: bool) -> int:
        """Count consecutive ascending (HH/HL) or descending (LH/LL) pivots."""
        count = 0
        for i in range(1, len(vals)):
            if ascending:
                if vals[i][1] > vals[i - 1][1]:
                    count += 1
                else:
                    break
            else:
                if vals[i][1] < vals[i - 1][1]:
                    count += 1
                else:
                    break
        return count

    empty = {"structure": "UNKNOWN", "hh_count": 0, "hl_count": 0,
             "lh_count": 0, "ll_count": 0,
             "fractal_bias": "NEUTRAL", "structure_note": "Insufficient fractal data"}
    if len(frac_highs) < 2 or len(frac_lows) < 2:
        return empty

    # Use last 4 of each (oldest→newest)
    recent_h = sorted(frac_highs, key=lambda x: x[0])[-4:]
    recent_l = sorted(frac_lows,  key=lambda x: x[0])[-4:]

    hh = _count_sequence(recent_h, ascending=True)
    lh = _count_sequence(recent_h, ascending=False)
    hl = _count_sequence(recent_l, ascending=True)
    ll = _count_sequence(recent_l, ascending=False)

    if hh >= 1 and hl >= 1:
        structure    = "UPTREND"
        frac_bias    = "BULLISH"
    elif lh >= 1 and ll >= 1:
        structure    = "DOWNTREND"
        frac_bias    = "BEARISH"
    elif hh >= 1 and ll >= 1:
        structure    = "TRANSITION"
        frac_bias    = "NEUTRAL"
    else:
        structure    = "RANGING"
        frac_bias    = "NEUTRAL"

    note = (
        f"Fractal Structure: {structure} | "
        f"HH={hh} HL={hl} LH={lh} LL={ll} → bias={frac_bias}"
    )
    return {
        "structure":      structure,
        "hh_count":       hh,
        "hl_count":       hl,
        "lh_count":       lh,
        "ll_count":       ll,
        "fractal_bias":   frac_bias,
        "structure_note": note,
    }


# ── Step 3 ─────────────────────────────────────────────────────────────
def detect_equal_highs_lows(frac_highs: list, frac_lows: list,
                              price: float, bias: str,
                              tolerance_pct: float = 0.0025) -> Dict:
    """
    Detect Equal Highs (EQH) and Equal Lows (EQL) from fractal pivots.

    ICT defines EQH/EQL as two or more fractal pivots within a tight
    price cluster (default: 0.25% radius). These are Buy-Side Liquidity
    (BSL) pools above EQH and Sell-Side Liquidity (SSL) pools below EQL.

    tolerance_pct: cluster radius as fraction of price (0.0025 = 0.25%)

    Returns:
        eq_highs_levels: list of price levels where EQH clusters exist
        eq_lows_levels:  list of price levels where EQL clusters exist
        bsl_level:       highest EQH above current price (buy-side target)
        ssl_level:       lowest  EQL below current price (sell-side target)
        eqh_count / eql_count: number of distinct clusters found
    """
    tol = price * tolerance_pct

    def _cluster(pivots: list) -> list:
        """Group pivots into price clusters within tolerance."""
        if not pivots:
            return []
        sorted_p = sorted(pivots, key=lambda x: x[1])
        clusters = []
        group    = [sorted_p[0][1]]
        for _, val in sorted_p[1:]:
            if abs(val - group[0]) <= tol:
                group.append(val)
            else:
                if len(group) >= 2:
                    clusters.append(round(sum(group) / len(group), 8))
                group = [val]
        if len(group) >= 2:
            clusters.append(round(sum(group) / len(group), 8))
        return clusters

    eqh_levels = _cluster(frac_highs)   # Equal High clusters
    eql_levels = _cluster(frac_lows)    # Equal Low clusters

    # BSL = highest EQH above price (buy-side liquidity target)
    bsl = max((l for l in eqh_levels if l > price), default=None)
    # SSL = lowest  EQL below price (sell-side liquidity target)
    ssl = min((l for l in eql_levels if l < price), default=None)

    # Bias-aligned primary level
    primary_target = bsl if bias == "BULLISH" else ssl

    note_parts = []
    if eqh_levels:
        note_parts.append(f"EQH: {[round(l,4) for l in eqh_levels[:3]]}")
    if eql_levels:
        note_parts.append(f"EQL: {[round(l,4) for l in eql_levels[:3]]}")
    if bsl:
        note_parts.append(f"BSL@{bsl:.4f}")
    if ssl:
        note_parts.append(f"SSL@{ssl:.4f}")

    return {
        "eq_highs_levels":  eqh_levels,
        "eq_lows_levels":   eql_levels,
        "bsl_level":        bsl,
        "ssl_level":        ssl,
        "primary_target":   primary_target,
        "eqh_count":        len(eqh_levels),
        "eql_count":        len(eql_levels),
        "eql_note":         " | ".join(note_parts) if note_parts else "No EQH/EQL clusters",
    }


# ── Step 4 ─────────────────────────────────────────────────────────────
def _linreg_fit(xs: list, ys: list) -> tuple:
    """
    Pure-Python least-squares linear regression.
    Returns (slope, intercept, r_squared).
    No external dependencies.
    """
    n = len(xs)
    if n < 2:
        return 0.0, ys[0] if ys else 0.0, 0.0
    sx    = sum(xs);        sy    = sum(ys)
    sxy   = sum(x * y for x, y in zip(xs, ys))
    sxx   = sum(x * x for x in xs)
    denom = n * sxx - sx * sx
    if abs(denom) < 1e-12:
        return 0.0, sy / n, 0.0
    slope     = (n * sxy - sx * sy) / denom
    intercept = (sy - slope * sx) / n
    # R²
    y_mean = sy / n
    ss_tot = sum((y - y_mean) ** 2 for y in ys)
    ss_res = sum((y - (slope * x + intercept)) ** 2 for x, y in zip(xs, ys))
    r2     = 1.0 - ss_res / max(ss_tot, 1e-12)
    return slope, intercept, max(0.0, min(1.0, r2))


def score_trendline(slope: float, intercept: float, r2: float,
                    pivots: list, ohlcv: list, atr: float) -> int:
    """
    Score a fitted trend line from 0–100.

    Rubric:
        +40  R² ≥ 0.80 (tight fit — all pivots close to the line)
        +30  3 or more touch confirmations
        +20  No candle body has closed through the line (respected)
        +10  Line is currently active (price within 2×ATR of projection)

    A score ≥ 60 = valid trend line.
    A score ≥ 80 = strong trend line (include in gate scoring).
    """
    score = 0
    n = len(ohlcv)
    if not ohlcv or not pivots or n < 2:
        return 0

    # R² fitness
    if r2 >= 0.85:
        score += 40
    elif r2 >= 0.70:
        score += 25
    elif r2 >= 0.55:
        score += 10

    # Touch count
    touches = len(pivots)
    if touches >= 3:
        score += 30
    elif touches == 2:
        score += 15

    # Body respect — check last 10 candles
    closes = [c[3] for c in ohlcv[-10:]]
    offset = max(0, n - 10)
    broken = False
    for i, cl in enumerate(closes):
        tl_val = slope * (offset + i) + intercept
        if slope > 0 and cl < tl_val * 0.998:   # support broken
            broken = True; break
        if slope < 0 and cl > tl_val * 1.002:   # resistance broken
            broken = True; break
    if not broken:
        score += 20

    # Currently active within 2×ATR
    last_idx  = n - 1
    tl_now    = slope * last_idx + intercept
    last_price = ohlcv[-1][3]
    if abs(last_price - tl_now) <= 2 * atr:
        score += 10

    return min(100, score)


def fit_trendlines(ohlcv: list, frac_highs: list, frac_lows: list,
                   atr: float, bias: str = "BULLISH") -> Dict:
    """
    Step 4 — Fit multi-touch trend lines through fractal pivot highs/lows.

    Support trendline:    linear regression through fractal LOWS
    Resistance trendline: linear regression through fractal HIGHS

    Each trend line is scored (0–100), break-detected, and retest-detected.

    Returns:
        support_tl:    dict with slope, intercept, r2, score, break, retest, …
        resistance_tl: dict with slope, intercept, r2, score, break, retest, …
        primary_tl:    the bias-aligned line (support for BULLISH, resist for BEARISH)
        tl_break:      True if the primary trendline has just been broken
        tl_retest:     True if price is retesting the broken line
        tl_note:       human-readable summary
    """
    _empty_tl = {
        "slope": 0.0, "intercept": 0.0, "r2": 0.0,
        "score": 0, "valid": False,
        "tl_break": False, "tl_retest": False,
        "touches": 0, "current_value": 0.0,
        "note": "Insufficient pivot data",
    }

    def _build_tl(pivots: list, label: str) -> Dict:
        if len(pivots) < 2:
            return dict(_empty_tl, note=f"{label}: <2 pivots")
        xs = [p[0] for p in pivots]
        ys = [p[1] for p in pivots]
        slope, intercept, r2 = _linreg_fit(xs, ys)
        n         = len(ohlcv)
        tl_now    = slope * (n - 1) + intercept
        tl_prev   = slope * (n - 2) + intercept if n >= 2 else tl_now
        last_cl   = ohlcv[-1][3] if ohlcv else 0.0
        prev_cl   = ohlcv[-2][3] if len(ohlcv) >= 2 else last_cl
        sc        = score_trendline(slope, intercept, r2, pivots, ohlcv, atr)

        # Break detection
        if label == "SUPPORT":
            broke = prev_cl >= tl_prev and last_cl < tl_now
        else:
            broke = prev_cl <= tl_prev and last_cl > tl_now

        # Retest: price returned to within 0.4% of line after break
        dist_pct  = abs(last_cl - tl_now) / max(tl_now, 1e-9)
        retest    = dist_pct < 0.004

        return {
            "slope":         round(slope, 8),
            "intercept":     round(intercept, 8),
            "r2":            round(r2, 4),
            "score":         sc,
            "valid":         sc >= 60,
            "strong":        sc >= 80,
            "tl_break":      broke,
            "tl_retest":     retest and not broke,
            "touches":       len(pivots),
            "current_value": round(tl_now, 8),
            "note": (
                f"{label} TL: score={sc}/100 R²={r2:.2f} "
                f"touches={len(pivots)}"
                f"{' | 🔴 BREAK' if broke else ''}"
                f"{' | 🔵 RETEST' if retest and not broke else ''}"
            ),
        }

    support_tl    = _build_tl(frac_lows,  "SUPPORT")
    resistance_tl = _build_tl(frac_highs, "RESISTANCE")
    primary_tl    = support_tl if bias == "BULLISH" else resistance_tl

    notes = []
    if support_tl["valid"]:
        notes.append(support_tl["note"])
    if resistance_tl["valid"]:
        notes.append(resistance_tl["note"])

    return {
        "support_tl":    support_tl,
        "resistance_tl": resistance_tl,
        "primary_tl":    primary_tl,
        "tl_break":      primary_tl["tl_break"],
        "tl_retest":     primary_tl["tl_retest"],
        "tl_score":      primary_tl["score"],
        "tl_valid":      primary_tl["valid"],
        "tl_strong":     primary_tl.get("strong", False),
        "tl_note":       " | ".join(notes) if notes else "No valid trendlines",
    }


# ── Step 5 ─────────────────────────────────────────────────────────────
def detect_fractal_inversion(ohlcv: list, frac_highs: list,
                              frac_lows: list, price: float,
                              bias: str, atr: float) -> Dict:
    """
    ICT Fractal Inversion — T-Spot / Reversal Zone Detection.

    An ICT fractal inversion occurs when:
    1. A 5-bar fractal high/low is formed (the 'origin fractal')
    2. Price breaks through the origin fractal level (structure break)
    3. Price retraces back to test the broken fractal level from the
       other side (the 'T-Spot' — optimal entry zone for reversal)

    BULLISH inversion: fractal LOW broken downward, then price
    retests it from below — origin fractal low acts as new resistance,
    then ICT entry is at the retest of that broken level.

    BEARISH inversion: fractal HIGH broken upward, then price
    retests it from above — origin fractal high acts as support,
    ICT entry is at the retest zone.

    T-Spot quality tiers:
        PREMIUM  — retest within 0.5×ATR of fractal level, high precision
        STANDARD — retest within 1.0×ATR
        MARGINAL — retest within 1.5×ATR
        NONE     — no active inversion detected
    """
    no_inversion = {
        "inversion_active":   False,
        "t_spot_price":       None,
        "t_spot_quality":     "NONE",
        "inversion_bias":     "NONE",
        "origin_fractal":     None,
        "inversion_note":     "No fractal inversion detected",
    }

    if not ohlcv or not frac_highs or not frac_lows or atr <= 0:
        return no_inversion

    last_close = ohlcv[-1][3]
    prev_close = ohlcv[-2][3] if len(ohlcv) >= 2 else last_close

    # Check last 3 fractal lows for BULLISH inversion
    recent_lows = sorted(frac_lows, key=lambda x: x[0])[-3:]
    for idx, lvl in reversed(recent_lows):
        if idx >= len(ohlcv) - 1:
            continue
        # Was the fractal low broken (price dipped below it)?
        candles_after = [c[2] for c in ohlcv[idx:]]  # lows after fractal
        if any(l < lvl for l in candles_after[1:]):
            # Broken — now retesting from below?
            dist = abs(last_close - lvl)
            if dist <= 1.5 * atr and last_close >= lvl * 0.997:
                quality = ("PREMIUM"  if dist <= 0.5 * atr else
                           "STANDARD" if dist <= 1.0 * atr else "MARGINAL")
                return {
                    "inversion_active":  True,
                    "t_spot_price":      round(lvl, 8),
                    "t_spot_quality":    quality,
                    "inversion_bias":    "BULLISH",
                    "origin_fractal":    (idx, lvl),
                    "inversion_note": (
                        f"🔵 BULLISH Fractal Inversion @ {lvl:.4f} | "
                        f"T-Spot Quality: {quality} | dist={dist:.4f} ({dist/atr:.1f}×ATR)"
                    ),
                }

    # Check last 3 fractal highs for BEARISH inversion
    recent_highs = sorted(frac_highs, key=lambda x: x[0])[-3:]
    for idx, lvl in reversed(recent_highs):
        if idx >= len(ohlcv) - 1:
            continue
        candles_after = [c[1] for c in ohlcv[idx:]]  # highs after fractal
        if any(h > lvl for h in candles_after[1:]):
            dist = abs(last_close - lvl)
            if dist <= 1.5 * atr and last_close <= lvl * 1.003:
                quality = ("PREMIUM"  if dist <= 0.5 * atr else
                           "STANDARD" if dist <= 1.0 * atr else "MARGINAL")
                return {
                    "inversion_active":  True,
                    "t_spot_price":      round(lvl, 8),
                    "t_spot_quality":    quality,
                    "inversion_bias":    "BEARISH",
                    "origin_fractal":    (idx, lvl),
                    "inversion_note": (
                        f"🔴 BEARISH Fractal Inversion @ {lvl:.4f} | "
                        f"T-Spot Quality: {quality} | dist={dist:.4f} ({dist/atr:.1f}×ATR)"
                    ),
                }

    return no_inversion


def compute_spread_pct(ob: Optional[Dict], last_price: float) -> float:
    if not ob or not ob["bids"] or not ob["asks"]:
        return 0.1
    best_bid = ob["bids"][0][0]
    best_ask = ob["asks"][0][0]
    mid      = (best_bid + best_ask) / 2
    return round((best_ask - best_bid) / mid * 100, 4)


def compute_slippage(ob: Optional[Dict], trade_usd: float = 10000) -> float:
    """Simulate $10k market buy slippage from live order book."""
    if not ob or not ob["asks"]:
        return 0.05
    remaining = trade_usd
    total_cost = 0.0
    total_qty  = 0.0
    for price, qty in ob["asks"]:
        fill = min(remaining / price, qty)
        total_cost += fill * price
        total_qty  += fill
        remaining  -= fill * price
        if remaining <= 0:
            break
    if total_qty == 0:
        return 0.05
    avg_fill = total_cost / total_qty
    mid = ob["asks"][0][0]
    return round(abs(avg_fill - mid) / mid * 100, 4)


def score_exchange_live(ticker: dict, ob: Optional[Dict], last: float) -> int:
    spread   = compute_spread_pct(ob, last)
    slip     = compute_slippage(ob)
    vol_usd  = ticker["volume_usd"]

    spread_score = max(0, 100 - spread * 1500)
    vol_score    = min(100, vol_usd / 1e9 * 3.5)   # scaled to billions
    slip_score   = max(0, 100 - slip * 5000)
    raw = spread_score * 0.35 + vol_score * 0.30 + slip_score * 0.35
    return max(0, min(100, round(raw)))


def compute_tf_score_real(ohlcv: list) -> int:
    """Score a timeframe from real OHLCV: trend + momentum + volatility confluence."""
    if len(ohlcv) < 20:
        return 50
    closes = [c[3] for c in ohlcv]
    rsi    = compute_rsi(closes)
    adx    = compute_adx(ohlcv)
    atr_pct = compute_atr_percentile(ohlcv)

    # RSI in healthy range (45-65) is best
    rsi_score = max(0, 100 - abs(rsi - 55) * 2.5)
    adx_score = min(100, adx * 2)
    # Medium ATR percentile best for ICT (not extreme)
    atr_score = max(0, 100 - abs(atr_pct - 55) * 1.8)

    return min(100, int(rsi_score * 0.35 + adx_score * 0.35 + atr_score * 0.30))

