# ══════════════════════════════════════════════════════════════
# SAFE TELEGRAM SEND HELPERS — prevent BadRequest on bad markdown
# ══════════════════════════════════════════════════════════════

def strip_markdown(text: str) -> str:
    """Remove all Telegram Markdown v1 formatting characters from a string."""
    import re
    # Remove bold/italic markers
    text = re.sub(r'\*([^*]+)\*', r'\1', text)
    text = re.sub(r'_([^_]+)_',   r'\1', text)
    # Remove inline code
    text = re.sub(r'`([^`]*)`',   r'\1', text)
    # Remove code blocks
    text = re.sub(r'```[^`]*```', lambda m: m.group(0).replace('```',''), text, flags=re.DOTALL)
    return text


TG_MAX_LEN = 4096   # Telegram hard character limit per message

def split_message(text: str, limit: int = TG_MAX_LEN) -> list:
    """
    Split a message that exceeds Telegram's 4096-char limit into clean chunks.
    Splits on newlines to avoid breaking lines mid-word.
    Each chunk stays within `limit` characters.
    """
    if len(text) <= limit:
        return [text]

    chunks  = []
    current = []
    current_len = 0

    for line in text.split("\n"):
        # +1 for the newline we'll re-join with
        line_len = len(line) + 1
        if current_len + line_len > limit:
            if current:
                chunks.append("\n".join(current))
            current     = [line]
            current_len = line_len
        else:
            current.append(line)
            current_len += line_len

    if current:
        chunks.append("\n".join(current))

    return chunks if chunks else [text[:limit]]


async def safe_send(target, text: str, parse_mode=None, **kwargs):
    """
    Send a Telegram message safely.
    - Auto-splits messages that exceed Telegram's 4096-char limit.
    - Falls back to plain text if Markdown parse fails.
    - Retries up to 3× on NetworkError / TimedOut / RetryAfter (fps.ms network drops).
    - Last resort: truncates to 3800 chars plain.
    """
    parts = split_message(text)

    for part in parts:
        for attempt in range(3):
            try:
                await target.reply_text(part, parse_mode=parse_mode, **kwargs)
                break   # sent OK
            except RetryAfter as e:
                wait = max(float(getattr(e, "retry_after", 5)), 1.0)
                log.warning(f"[SAFE_SEND] RetryAfter {wait:.0f}s — attempt {attempt+1}/3")
                await asyncio.sleep(wait)
            except (TelegramNetworkError, TelegramTimedOut) as e:
                if attempt < 2:
                    wait = 1.5 * (attempt + 1)
                    log.warning(f"[SAFE_SEND] Network error (attempt {attempt+1}/3): {e!r} — retry in {wait:.1f}s")
                    await asyncio.sleep(wait)
                else:
                    log.error(f"[SAFE_SEND] Giving up after 3 network errors: {e!r}")
                    # Don't raise — skip this chunk rather than crash the whole pipeline
            except Exception as e:
                err = str(e).lower()
                if "too long" in err or "bad request" in err or "parse" in err or \
                   "entity" in err or "can't parse" in err:
                    plain = strip_markdown(part)
                    if len(plain) > TG_MAX_LEN:
                        plain = plain[:3800] + "\n...[truncated]"
                    try:
                        await target.reply_text(plain, **kwargs)
                    except Exception:
                        try:
                            await target.reply_text(plain[:3000])
                        except Exception as _e:
                            log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
                else:
                    raise
                break





async def safe_edit(message, text: str, parse_mode=None, **kwargs):
    """
    Edit a Telegram message safely.
    - Truncates if too long.
    - Retries up to 3× on NetworkError / TimedOut / RetryAfter.
    - Silently swallows edit failures (progress edits are non-critical).
    """
    if len(text) > TG_MAX_LEN:
        text = text[:4000] + "\n...[truncated]"

    for attempt in range(3):
        try:
            await message.edit_text(text, parse_mode=parse_mode, **kwargs)
            return
        except RetryAfter as e:
            wait = max(float(getattr(e, "retry_after", 5)), 1.0)
            log.warning(f"[SAFE_EDIT] RetryAfter {wait:.0f}s — attempt {attempt+1}/3")
            await asyncio.sleep(wait)
        except (TelegramNetworkError, TelegramTimedOut) as e:
            if attempt < 2:
                wait = 1.0 * (attempt + 1)
                log.warning(f"[SAFE_EDIT] Network error (attempt {attempt+1}/3): {e!r} — retry in {wait:.1f}s")
                await asyncio.sleep(wait)
            else:
                log.warning(f"[SAFE_EDIT] Giving up after 3 network errors — skipping progress edit")
                return   # progress edits are non-critical; don't raise
        except Exception as e:
            err = str(e).lower()
            if "too long" in err or "bad request" in err or "parse" in err or \
               "entity" in err or "can't parse" in err:
                try:
                    plain = strip_markdown(text)[:4000]
                    await message.edit_text(plain, **kwargs)
                except Exception as _e:
                    log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
            elif "message is not modified" in err or "same text" in err:
                pass   # harmless
            else:
                raise
            return



