def generate_tv_checklist(r: dict) -> str:
    """
    [TV-FREE Phase 4] Generate TradingView free plan cross-check checklist
    from a completed slim result dict stored in _LAST_RESULT_CACHE.
    Maps v9 output levels to the 3 TradingView free indicator slots.
    Called automatically after every analysis AND via /tvcheck command.
    """
    try:
        symbol   = r.get("symbol", "?")
        bias     = r.get("bias", "UNKNOWN")
        price    = float(r.get("price", 0) or 0)
        entry    = float(r.get("entry", price) or price)
        sl1      = float(r.get("sl1", 0) or 0)
        tp1      = float(r.get("tp1", 0) or 0)
        tp2      = float(r.get("tp2", 0) or 0)
        tp3      = float(r.get("tp3", 0) or 0)
        ob_low   = float(r.get("ob_low", 0) or 0)
        ob_high  = float(r.get("ob_high", 0) or 0)
        fvg_low  = float(r.get("fvg_low", 0) or 0)
        fvg_high = float(r.get("fvg_high", 0) or 0)
        pdh      = float(r.get("pdh", 0) or 0)
        pdl      = float(r.get("pdl", 0) or 0)
        pwh      = float(r.get("pwh", 0) or 0)
        pwl      = float(r.get("pwl", 0) or 0)
        vwap     = float(r.get("vwap", 0) or 0)
        grade    = r.get("grade", "?")
        conf     = float(r.get("confidence", 0) or 0)

        session  = get_current_session()
        sb       = get_silver_bullet_status()
        kz_active = session not in ("OFF_SESSION", "WEEKEND")

        bias_icon = "🟢" if bias == "BULLISH" else ("🔴" if bias == "BEARISH" else "⚪")
        kz_icon   = "✅" if kz_active else "⏳"
        sb_icon   = "⚡" if sb.get("active") else "💤"

        def _fp(v: float) -> str:
            """Format price with dynamic decimals."""
            if v <= 0:
                return "N/A"
            if v > 10000:
                return f"{v:,.2f}"
            if v > 100:
                return f"{v:.2f}"
            if v > 1:
                return f"{v:.4f}"
            return f"{v:.6f}"

        def _tp_match(tp_val: float, ref_val: float, label: str) -> str:
            if tp_val > 0 and ref_val > 0 and abs(tp_val - ref_val) / max(ref_val, 1e-9) < 0.005:
                return f"← ✅ matches {label}"
            return f"← verify on TV"

        lines = [
            f"📺 TV CROSS-CHECK — {symbol} | Grade {grade} | {conf:.0f}% conf",
            "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━",
            "",
            f"📍 Bias : {bias_icon} {bias} @ {_fp(price)}",
            f"{kz_icon} Session : {session}",
            (f"{sb_icon} Silver Bullet : ACTIVE — {sb['window']} "
             f"({sb.get('minutes_remaining', 0)}m left)")
            if sb.get("active") else
            (f"{sb_icon} Silver Bullet : Inactive "
             f"(next: {sb.get('next_window', '?')})"),
            "",
            "── SLOT 1 CHECK : ICT/SMC All-in-One ───────",
        ]

        if ob_low > 0 and ob_high > 0:
            lines.append(f"  OB Zone  : {_fp(ob_low)} – {_fp(ob_high)}")
            lines.append("  ✔ Verify : Is price inside/approaching this OB on TV?")
        else:
            lines.append("  OB Zone  : Not detected — check TV Slot 1 manually")

        if fvg_low > 0 and fvg_high > 0:
            lines.append(f"  FVG Zone : {_fp(fvg_low)} – {_fp(fvg_high)}")
            lines.append("  ✔ Verify : Is this FVG still open (not fully filled)?")
        else:
            lines.append("  FVG Zone : Not detected — check TV Slot 1 for open gaps")

        lines += [
            "",
            "── SLOT 2 CHECK : Liquidity Levels ─────────",
        ]
        if pdh > 0:
            lines.append(f"  PDH : {_fp(pdh)}  {_tp_match(tp2, pdh, 'TP2')}")
        if pdl > 0:
            lines.append(f"  PDL : {_fp(pdl)}  {_tp_match(tp2, pdl, 'TP2')}")
        if pwh > 0:
            lines.append(f"  PWH : {_fp(pwh)}  {_tp_match(tp3, pwh, 'TP3')}")
        if pwl > 0:
            lines.append(f"  PWL : {_fp(pwl)}  {_tp_match(tp3, pwl, 'TP3')}")
        lines.append("  ✔ Verify : Do TV liquidity lines match bot TP2/TP3?")

        lines += [
            "",
            "── SLOT 3 CHECK : VWAP + Kill Zones ────────",
        ]
        if vwap > 0:
            pos = "ABOVE VWAP ✅" if price > vwap else "BELOW VWAP ⚠️"
            exp = "(good for BULLISH)" if price > vwap else "(caution for BULLISH)"
            lines.append(f"  VWAP : {_fp(vwap)}  | Price is {pos} {exp}")
        lines.append(f"  ✔ Verify : Is current candle inside a Kill Zone box on TV?")
        lines.append(f"  ✔ Verify : Price {'above' if bias=='BULLISH' else 'below'} "
                     f"VWAP matches {bias} bias?")

        lines += [
            "",
            "── BOT TARGET LEVELS (map to TV chart) ─────",
            f"  Entry      : {_fp(entry)}",
            f"  SL1 (OB)   : {_fp(sl1)}" if sl1 > 0 else "  SL1       : N/A",
            f"  TP1 (IRL)  : {_fp(tp1)}" if tp1 > 0 else "  TP1       : N/A",
            f"  TP2 (PDH/PDL): {_fp(tp2)}" if tp2 > 0 else "  TP2       : N/A",
            f"  TP3 (PWH/PWL): {_fp(tp3)}" if tp3 > 0 else "  TP3       : N/A",
            "",
            "── DECISION RULE ────────────────────────────",
            "  ✅ CONFIRM  — TV levels align with bot output",
            "  ❌ SKIP     — TV shows contradicting structure",
            "  ⚡ TIE-BREAK — Trust bot (FOMC gate + regime active)",
            "",
            "Use /pine for TradingView Pine Script backtest",
        ]

        return "\n".join(lines)

    except Exception as e:
        return f"[TV-CHECK] Error generating checklist: {e}"


def generate_tv_pine_script(r: dict = None, symbol: str = "BTC") -> str:
    """
    [TV-FREE Phase 5] Generate Pine Script v5 strategy mirroring v9's core ICT logic.
    Suitable for TradingView free plan Strategy Tester backtesting.
    Covers: OB detection, OTE zone entry (Fib 61.8–79%), PDH/PDL TP, ATR SL,
    Kill Zone filter, MACD/RSI/VWAP gates (mirrors C9/C12/C21 from 50C engine).
    Use /pine SYMBOL to get the script for any coin.
    """
    sym = ((r.get("symbol", symbol) if r else symbol) or symbol).upper()
    sym = sym.replace("USDT", "").replace("USDC", "")
    bias_hint = (r.get("bias", "BOTH") if r else "BOTH")

    # Pine script uses {{ and }} to represent literal { } in Python f-strings
    header = (
        f"//@version=5\n"
        f"// ═══════════════════════════════════════════════════════\n"
        f"// MOP·ICT v9 — TradingView Mirror Strategy\n"
        f"// Symbol  : {sym}USDT\n"
        f"// Bias    : {bias_hint}\n"
        f"// Purpose : Backtest simplified v9 ICT signal (Phase 5)\n"
        f"// Mirrors : C9(MACD) · C12(RSI) · C21(VWAP) · Kill Zone\n"
        f"//           OB detection · OTE Fib 61.8–79% · PDH/PDL TPs\n"
        f"// Slots   : Uses 1 of 3 free TradingView indicator slots\n"
        f"// Setup   : Add to {sym}USDT chart on your exec TF (15m or 1H)\n"
        f"// ═══════════════════════════════════════════════════════\n"
        f"strategy(\"MOP·ICT v9 Mirror [{sym}]\", overlay=true,\n"
        f"         default_qty_type=strategy.percent_of_equity,\n"
        f"         default_qty_value=2, commission_type=strategy.commission.percent,\n"
        f"         commission_value=0.05, slippage=2)\n\n"
    )

    body = (
        "// ── INPUTS ───────────────────────────────────────────\n"
        "atr_len      = input.int(14,    title=\"ATR Period\")\n"
        "atr_mult_sl  = input.float(1.5, title=\"SL ATR Multiplier\")\n"
        "swing_len    = input.int(10,    title=\"Swing Lookback\")\n"
        "ob_lookback  = input.int(5,     title=\"OB Detection Lookback (bars)\")\n"
        "ote_lo_fib   = input.float(0.618, title=\"OTE Low Fib (61.8%)\")\n"
        "ote_hi_fib   = input.float(0.79,  title=\"OTE High Fib (79%)\")\n"
        "tp1_mult     = input.float(1.0,   title=\"TP1 ATR Mult (IRL proxy)\")\n"
        "tp2_mult     = input.float(2.5,   title=\"TP2 ATR Mult (PDH/PDL proxy)\")\n"
        "tp3_mult     = input.float(4.0,   title=\"TP3 ATR Mult (PWH/PWL proxy)\")\n"
        "filter_kz    = input.bool(true,   title=\"Kill Zone Filter (London/NY only)\")\n"
        "min_rr       = input.float(1.5,   title=\"Min R:R [v8-RR hard floor]\")\n\n"

        "// ── CORE INDICATORS ─────────────────────────────────\n"
        "atr          = ta.atr(atr_len)\n"
        "[macdl, sgnl, hist] = ta.macd(close, 12, 26, 9)\n"
        "rsi          = ta.rsi(close, 14)\n"
        "ma50         = ta.sma(close, 50)\n"
        "ma200        = ta.sma(close, 200)\n"
        "vwap_v       = ta.vwap(hlc3)\n\n"

        "// ── BIAS FILTER — mirrors C1/C2/C3 (MA stack) ──────\n"
        "bull_bias = close > ma50 and ma50 > ma200\n"
        "bear_bias = close < ma50 and ma50 < ma200\n\n"

        "// ── SWING POINTS — mirrors find_swing_highs_lows() ─\n"
        "swing_hi = ta.pivothigh(high, swing_len, swing_len)\n"
        "swing_lo = ta.pivotlow(low,  swing_len, swing_len)\n"
        "var float last_shi = na\n"
        "var float last_slo = na\n"
        "if not na(swing_hi)\n"
        "    last_shi := swing_hi\n"
        "if not na(swing_lo)\n"
        "    last_slo := swing_lo\n\n"

        "// ── ORDER BLOCK — mirrors detect_order_blocks() ────\n"
        "// Bullish OB: last bearish candle before a bullish impulse\n"
        "// Bearish OB: last bullish candle before a bearish impulse\n"
        "var float ob_bull_lo = na\n"
        "var float ob_bull_hi = na\n"
        "var float ob_bear_lo = na\n"
        "var float ob_bear_hi = na\n"
        "if close > close[ob_lookback] * 1.005 and close[ob_lookback] < open[ob_lookback]\n"
        "    ob_bull_lo := low[ob_lookback]\n"
        "    ob_bull_hi := high[ob_lookback]\n"
        "if close < close[ob_lookback] * 0.995 and close[ob_lookback] > open[ob_lookback]\n"
        "    ob_bear_lo := low[ob_lookback]\n"
        "    ob_bear_hi := high[ob_lookback]\n\n"

        "// ── OTE ZONE — mirrors compute_ote() Fib 61.8–79% ─\n"
        "ote_bull_lo = not na(last_slo) and not na(last_shi) ?\n"
        "    last_slo + (last_shi - last_slo) * (1 - ote_hi_fib) : na\n"
        "ote_bull_hi = not na(last_slo) and not na(last_shi) ?\n"
        "    last_slo + (last_shi - last_slo) * (1 - ote_lo_fib) : na\n"
        "ote_bear_lo = not na(last_slo) and not na(last_shi) ?\n"
        "    last_slo + (last_shi - last_slo) * ote_lo_fib : na\n"
        "ote_bear_hi = not na(last_slo) and not na(last_shi) ?\n"
        "    last_slo + (last_shi - last_slo) * ote_hi_fib : na\n\n"

        "// ── KILL ZONE FILTER — mirrors get_current_session()\n"
        "bar_hour  = hour(time, \"UTC\")\n"
        "in_london = bar_hour >= 7  and bar_hour < 10\n"
        "in_ny     = bar_hour >= 13 and bar_hour < 16\n"
        "in_ny_pm  = bar_hour >= 18 and bar_hour < 20\n"
        "in_kz     = in_london or in_ny or in_ny_pm\n"
        "kz_ok     = filter_kz ? in_kz : true\n\n"

        "// ── GATE MIRRORS (50C Engine) ───────────────────────\n"
        "// C9  — MACD histogram hard block\n"
        "macd_bull = hist > 0\n"
        "macd_bear = hist < 0\n"
        "// C12 — RSI band gate\n"
        "rsi_bull  = rsi > 40 and rsi < 75\n"
        "rsi_bear  = rsi < 60 and rsi > 25\n"
        "// C21 — VWAP position gate\n"
        "vwap_bull = close > vwap_v\n"
        "vwap_bear = close < vwap_v\n\n"

        "// ── ENTRY CONDITIONS ─────────────────────────────────\n"
        "long_in_ob  = not na(ob_bull_lo) and close >= ob_bull_lo and close <= ob_bull_hi\n"
        "long_in_ote = not na(ote_bull_lo) and close >= ote_bull_lo and close <= ote_bull_hi\n"
        "long_cond   = bull_bias and (long_in_ob or long_in_ote)\n"
        "    and macd_bull and rsi_bull and vwap_bull and kz_ok\n"
        "    and strategy.position_size == 0\n\n"
        "short_in_ob  = not na(ob_bear_lo) and close >= ob_bear_lo and close <= ob_bear_hi\n"
        "short_in_ote = not na(ote_bear_lo) and close >= ote_bear_lo and close <= ote_bear_hi\n"
        "short_cond   = bear_bias and (short_in_ob or short_in_ote)\n"
        "    and macd_bear and rsi_bear and vwap_bear and kz_ok\n"
        "    and strategy.position_size == 0\n\n"

        "// ── SL / TP LEVELS ──────────────────────────────────\n"
        "var float ep  = na\n"
        "var float sl  = na\n"
        "var float tp1 = na\n"
        "var float tp2 = na\n"
        "var float tp3 = na\n\n"
        "if long_cond\n"
        "    ep  := close\n"
        "    sl  := close - atr * atr_mult_sl\n"
        "    tp1 := close + atr * tp1_mult\n"
        "    tp2 := close + atr * tp2_mult\n"
        "    tp3 := close + atr * tp3_mult\n"
        "    rr  = (tp2 - ep) / math.max(ep - sl, 1e-9)\n"
        "    if rr >= min_rr\n"
        "        strategy.entry(\"LONG\", strategy.long)\n\n"
        "if short_cond\n"
        "    ep  := close\n"
        "    sl  := close + atr * atr_mult_sl\n"
        "    tp1 := close - atr * tp1_mult\n"
        "    tp2 := close - atr * tp2_mult\n"
        "    tp3 := close - atr * tp3_mult\n"
        "    rr  = (ep - tp2) / math.max(sl - ep, 1e-9)\n"
        "    if rr >= min_rr\n"
        "        strategy.entry(\"SHORT\", strategy.short)\n\n"

        "// ── EXITS (3-legged: TP1 33% / TP2 33% / TP3 34%) ──\n"
        "if strategy.position_size > 0\n"
        "    strategy.exit(\"L_TP1\", \"LONG\",  qty_percent=33, limit=tp1, stop=sl)\n"
        "    strategy.exit(\"L_TP2\", \"LONG\",  qty_percent=33, limit=tp2, stop=sl)\n"
        "    strategy.exit(\"L_TP3\", \"LONG\",  qty_percent=34, limit=tp3, stop=sl)\n"
        "if strategy.position_size < 0\n"
        "    strategy.exit(\"S_TP1\", \"SHORT\", qty_percent=33, limit=tp1, stop=sl)\n"
        "    strategy.exit(\"S_TP2\", \"SHORT\", qty_percent=33, limit=tp2, stop=sl)\n"
        "    strategy.exit(\"S_TP3\", \"SHORT\", qty_percent=34, limit=tp3, stop=sl)\n\n"

        "// ── VISUAL OVERLAYS ──────────────────────────────────\n"
        "// Kill Zone background shading (matches TV Slot 3)\n"
        "bgcolor(in_london ? color.new(color.blue,  92) : na, title=\"London KZ\")\n"
        "bgcolor(in_ny     ? color.new(color.green, 92) : na, title=\"NY KZ\")\n"
        "bgcolor(in_ny_pm  ? color.new(color.orange,92) : na, title=\"NY PM KZ\")\n"
        "// MA overlays (matches TV default indicators)\n"
        "plot(ma50,  \"MA50\",  color=color.orange, linewidth=1)\n"
        "plot(ma200, \"MA200\", color=color.red,    linewidth=1)\n"
        "// Trade level lines\n"
        "plot(strategy.position_size != 0 ? ep  : na, \"Entry\", color=color.white,  style=plot.style_linebr)\n"
        "plot(strategy.position_size != 0 ? sl  : na, \"SL\",    color=color.red,    style=plot.style_linebr)\n"
        "plot(strategy.position_size != 0 ? tp1 : na, \"TP1\",   color=color.yellow, style=plot.style_linebr)\n"
        "plot(strategy.position_size != 0 ? tp2 : na, \"TP2\",   color=color.lime,   style=plot.style_linebr)\n"
        "plot(strategy.position_size != 0 ? tp3 : na, \"TP3\",   color=color.aqua,   style=plot.style_linebr)\n\n"

        "// ── INFO TABLE (top-right corner) ───────────────────\n"
        "var table t = table.new(position.top_right, 2, 7,\n"
        "    bgcolor=color.new(color.black,70), border_color=color.gray, border_width=1)\n"
        "if barstate.islast\n"
        "    table.cell(t,0,0,\"MOP·ICT v9\",    text_color=color.white,  text_size=size.small)\n"
        "    table.cell(t,1,0,\"Mirror Strategy\",text_color=color.yellow, text_size=size.small)\n"
        "    table.cell(t,0,1,\"Bias\",           text_color=color.gray,   text_size=size.small)\n"
        "    table.cell(t,1,1,bull_bias?\"BULL\":bear_bias?\"BEAR\":\"NEUT\",\n"
        "        text_color=bull_bias?color.lime:color.red, text_size=size.small)\n"
        "    table.cell(t,0,2,\"Kill Zone\",      text_color=color.gray,   text_size=size.small)\n"
        "    table.cell(t,1,2,in_kz?\"ACTIVE\":\"INACTIVE\",\n"
        "        text_color=in_kz?color.lime:color.orange, text_size=size.small)\n"
        "    table.cell(t,0,3,\"MACD\",           text_color=color.gray,   text_size=size.small)\n"
        "    table.cell(t,1,3,hist>0?\"BULL\":\"BEAR\",\n"
        "        text_color=hist>0?color.lime:color.red, text_size=size.small)\n"
        "    table.cell(t,0,4,\"RSI\",            text_color=color.gray,   text_size=size.small)\n"
        "    table.cell(t,1,4,str.tostring(math.round(rsi,1)),\n"
        "        text_color=color.white, text_size=size.small)\n"
        "    table.cell(t,0,5,\"VWAP\",           text_color=color.gray,   text_size=size.small)\n"
        "    table.cell(t,1,5,close>vwap_v?\"ABOVE\":\"BELOW\",\n"
        "        text_color=close>vwap_v?color.lime:color.red, text_size=size.small)\n"
        "    table.cell(t,0,6,\"Min R:R\",        text_color=color.gray,   text_size=size.small)\n"
        "    table.cell(t,1,6,str.tostring(min_rr)+\"x\",\n"
        "        text_color=color.white, text_size=size.small)\n\n"

        "// ── ALERTS ────────────────────────────────────────────\n"
        "alertcondition(long_cond,  \"MOP·ICT LONG\",\n"
        "    \"MOP·ICT v9: LONG signal — run bot for full 50C confluence\")\n"
        "alertcondition(short_cond, \"MOP·ICT SHORT\",\n"
        "    \"MOP·ICT v9: SHORT signal — run bot for full 50C confluence\")\n"
    )

    return header + body


