async def cmd_analyze(update: Update, context: ContextTypes.DEFAULT_TYPE):
    if not context.args:
        await update.message.reply_text(
            "Please provide a symbol.\nExample: /analyze BTC")
        return
    await _run_analysis(update.message, context.args[0].upper())

async def handle_text(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = update.message.text.strip().upper()
    symbol = text.replace("USDT","").replace("USDC","").replace("/","")
    if not symbol.isalpha() or len(symbol) < 2:
        await update.message.reply_text(
            "Please send a valid coin symbol, e.g. BTC, ETH, SOL")
        return
    await _run_analysis(update.message, symbol)

async def _run_analysis_chat(chat, symbol: str, market_type: str = "auto"):
    """
    Wrapper for button callbacks that use a Chat object (not a Message).
    Creates a lightweight proxy so _run_analysis can call .reply_text / .chat.id normally.
    """
    class _ChatProxy:
        """Minimal Message-like proxy backed by a Chat object."""
        def __init__(self, c):
            self._chat = c
            self.chat = type("_ChatIdProxy", (), {"id": c.id})()

        async def reply_text(self, text, **kwargs):
            return await self._chat.send_message(text, **kwargs)

        async def reply_photo(self, **kwargs):
            return await self._chat.send_photo(**kwargs)

    proxy = _ChatProxy(chat)
    await _run_analysis(proxy, symbol, market_type=market_type)


async def _run_analysis(message, symbol: str, market_type: str = "auto"):
    # ── Concurrency gate — enforces MAX_CONCURRENT_ANALYSES = 1 (OOM protection)
    async with _get_semaphore():
        await _run_analysis_inner(message, symbol, market_type=market_type)


async def _run_analysis_inner(message, symbol: str, market_type: str = "auto"):
    # ── Frequency Control removed — unlimited signals
    user_id = str(message.chat.id)

    # ── Market Type Selection: ask user if both spot AND futures exist
    if market_type == "auto":
        checking_msg = await message.reply_text(
            f"🔍 Checking available markets for {symbol}..."
        )
        try:
            markets = await quick_check_markets(symbol)
        except Exception:
            markets = {"has_spot": True, "has_futures": False}

        try:
            await checking_msg.delete()
        except Exception as _e:
            log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")

        if markets["has_spot"] and markets["has_futures"]:
            # Both exist — ask the user
            keyboard = [
                [
                    InlineKeyboardButton("📈 SPOT",    callback_data=f"mkt_spot_{symbol}"),
                    InlineKeyboardButton("📉 FUTURES (Perp)", callback_data=f"mkt_futures_{symbol}"),
                ]
            ]
            markup = InlineKeyboardMarkup(keyboard)
            await message.reply_text(
                f"*{symbol}* is available on both Spot and Futures markets.\n\n"
                f"Which market do you want to analyze?",
                reply_markup=markup,
                parse_mode=ParseMode.MARKDOWN,
            )
            return
        elif markets["has_futures"] and not markets["has_spot"]:
            # Futures only — proceed automatically
            market_type = "futures"
            await message.reply_text(
                f"ℹ️ *{symbol}* is only available on Futures (Perp) markets. Proceeding with Futures analysis.",
                parse_mode=ParseMode.MARKDOWN,
            )
        else:
            # Spot only or unknown — proceed as spot
            market_type = "spot"

    thinking = await message.reply_text(
        f"Analyzing {symbol}USDT [{market_type.upper()}]...\n\n"
        f"Phase 1/7 — Connecting to exchanges + 20-layer pipeline..."
    )

    try:
        await safe_edit(
            thinking,
            f"Analyzing {symbol}USDT...\n\n"
            f"Phase 1/7 — Connections established\n"
            f"Phase 2/7 — L0: Fetching live OHLCV + OB (11 CEX)..."
        )

        result = await run_ict_analysis(symbol, market_type=market_type)

        await safe_edit(
            thinking,
            f"Analyzing {symbol}USDT...\n\n"
            f"Phase 1/7 — Connections established\n"
            f"Phase 2/7 — L0: Live data fetched ({len(result['ex_scored'])} exchanges)\n"
            f"Phase 3/7 — L1-L5: Integrity · DXY · Features · Stats · Regime..."
        )

        await asyncio.sleep(0.3)
        await safe_edit(
            thinking,
            f"Analyzing {symbol}USDT...\n\n"
            f"Phase 1/7 — Data OK · DXY: {(result.get('l2_dxy') or {}).get('dxy_status','—')}\n"
            f"Phase 2/7 — Stats: {(result.get('l5_stats') or {}).get('layer5_note','—')[:28]}\n"
            f"Phase 3/7 — L6-L8: Regime → ICT/SMC → AI Alpha Stack\n"
            f"Phase 4/7 — AI: {(result.get('l8_ai') or {}).get('ensemble',{}).get('ensemble_tier','—')}"
            f"  ({(result.get('l8_ai') or {}).get('ai_score',0)}/100)\n"
            f"Phase 5/7 — L9: Gates {sum(result['gate_pass'])}/10  HMM: {(result.get('hmm_data') or {}).get('hmm_state','...')}..."
        )

        # ── [v8.0] R:R Hard Floor — block signals with R:R < 1.5 ─
        _rr_check_em  = (result["entry_low"] + result["entry_high"]) / 2
        _rr_check_val = round(
            abs(result["tp3"] - _rr_check_em) / max(abs(_rr_check_em - result["inv_sl"]), 1e-9), 2
        )
        if _rr_check_val < 1.5:
            result["all_pass"]    = False
            result["rr_blocked"]  = True
            result["rr_block_val"]= _rr_check_val
            # Force gate_pass[9] so L9 summary reflects block
            result["gate_pass"][9] = False
            log.info(f"[v8.0 RR FLOOR] R:R={_rr_check_val} < 1.5 — output blocked")
        else:
            result["rr_blocked"]  = False
            result["rr_block_val"]= _rr_check_val

        # ── [v8.0] Compute 50-Confluence Score ───────────────
        try:
            _macd_now   = result.get("upg_macd", {})
            _sar_now    = result.get("upg_sar", {})
            _fomc_now   = result.get("upg_fomc", {})
            _sfcvd_now  = result.get("upg_sf_div", {})
            _rpos_now   = result.get("upg_range_pos", {})
            _smc_cf_now = result.get("smc_confluence", {})
            _ma_now     = result.get("ma_stack", {})
            _bos_now    = result.get("bos_data", {})
            _htf_ltf_now= result.get("htf_ltf", {})
            _cvd_now    = result.get("alpha_cvd", {})
            _hurst_now  = result.get("upg_hurst", {})
            _obv_now    = result.get("upg_obv", {})
            _fgi_now    = result.get("upg_fear_greed", {})
            _wdl_now    = result.get("weekly_daily_liq", {})
            _rsi_now    = float(result.get("rsi") or 50)
            _adx_now    = float(result.get("adx") or 0)
            _price_now  = float(result.get("price") or 0)
            _bias_now   = result.get("bias", "BULLISH")
            _ma50_now   = float(_ma_now.get("ma50") or _price_now)
            _ma200_now  = float(_ma_now.get("ma200") or _price_now)
            _ema20_now  = float(_ma_now.get("ema20") or _price_now)
            # DI+/DI- from orderflow or estimate from ADX
            _di_plus    = float(result.get("di_plus") or _adx_now * 0.6)
            _di_minus   = float(result.get("di_minus") or _adx_now * 0.4)
            _fund_z_v   = float((result.get("upg_funding_z") or {}).get("funding_zscore", 0.0))
            _stoch_d    = result.get("upg_stoch", {}) or {}
            _stoch_v    = float(_stoch_d.get("stoch_k", 50.0))
            _stoch_up   = _stoch_d.get("stoch_rising", True)
            _atr_pct_v  = float(result.get("atr_pct") or 1.0)
            _bb_exp     = (result.get("upg_bb") or {}).get("bb_expanding", True)
            _hurst_v    = float((_hurst_now or {}).get("hurst", 0.5))
            _vol_ratio  = float(result.get("volume_ratio") or 1.0)
            _obv_up     = (_obv_now or {}).get("obv_trend", "") in ("UP","RISING") \
                          if _obv_now else (_bias_now == "BULLISH")
            _liq_swept  = (result.get("liq_inst") or {}).get("sweep_confirmed", False)
            _range_pct  = float(_rpos_now.get("range_pos_pct", 50.0))
            _range_ok   = not _rpos_now.get("range_block", False)
            _fvg_ok     = float(result.get("fvg_low") or 0) > 0
            _ob_ok      = float(result.get("ob_low") or 0) > 0
            _ote_ok     = (result.get("ote") or {}).get("valid", False)
            _wyck_ok    = (result.get("upg_wyckoff") or {}).get("wyckoff_ok", True)
            _ell_ok     = (result.get("upg_elliott") or {}).get("wave_3_active", False)
            _daily_bias = result.get("daily_bias", _bias_now)
            _weekly_b   = "BULLISH" if result.get("weekly_veto_active") is False else _bias_now
            _bos_conf   = _bos_now.get("structure_valid", False)
            _macd_hist  = float(_macd_now.get("histogram", 0.0))
            _macd_dif   = float(_macd_now.get("macd", 0.0))
            _macd_dea   = float(_macd_now.get("signal_line", 0.0))
            _macd_div   = _macd_now.get("bias","") != _bias_now and _adx_now > 20
            _rsi_div    = (result.get("upg_rsi_div") or {}).get("rsi_divergence_valid", False)
            _sar_ab     = _sar_now.get("sar_above_price", False)
            _cvd_dir_v  = (_cvd_now or {}).get("divergence_type","NONE")
            _sf_pct     = float(_sfcvd_now.get("sf_divergence_pct", 0.0))
            _vwap_pos   = (result.get("alpha_vwap") or {}).get("deviation_zone","NEAR_VWAP")
            _vol_spike  = result.get("volume_spike_at_break", False)
            _near_pdh   = abs(_price_now - float(_wdl_now.get("pdh",0) or 0)) < _atr_pct_v * _price_now / 100 * 0.5 \
                          if _wdl_now.get("pdh") else False
            _near_pwh   = abs(_price_now - float(_wdl_now.get("pwh",0) or 0)) < _atr_pct_v * _price_now / 100 * 0.5 \
                          if _wdl_now.get("pwh") else False
            _round_near = (result.get("upg_round_num") or {}).get("rn_magnetic", False)
            _htf_match  = _htf_ltf_now.get("aligned", True) if isinstance(_htf_ltf_now, dict) else True
            _daily_can  = result.get("daily_candle_match", True)
            _weekly_tr  = not result.get("weekly_veto_active", False)
            _ma_stk_ok  = _ma_now.get("stack_valid", _ma50_now > _ma200_now if _bias_now == "BULLISH" else _ma50_now < _ma200_now)
            _fomc_blk   = _fomc_now.get("fomc_block", False)
            _macro_blk  = _fomc_now.get("fomc_block_type","") == "MACRO_EVENT_BLOCK"
            _news_ok    = not (result.get("news_filter") or {}).get("in_blackout", False)
            _fgi_bound  = float((_fgi_now or {}).get("fg_value", 50)) in range(0,26) or \
                          float((_fgi_now or {}).get("fg_value", 50)) > 74
            _opex_near  = False  # no OpEx data in current pipeline — conservative default
            conf50_result = compute_50_confluence_score(
                price=_price_now, ma50=_ma50_now, ma200=_ma200_now, ema20=_ema20_now,
                ema50_slope=float(_ma_now.get("ema50_slope",0)), daily_bias=_daily_bias,
                weekly_bias=_weekly_b, bos_confirmed=_bos_conf,
                macd_histogram=_macd_hist, macd_dif=_macd_dif, macd_dea=_macd_dea,
                macd_divergence=_macd_div, rsi=_rsi_now, rsi_divergence=_rsi_div,
                stoch_rsi=_stoch_v, stoch_rising=_stoch_up, sar_above_price=_sar_ab,
                volume_vs_ma20=_vol_ratio, cvd_direction=_cvd_dir_v,
                sf_divergence_pct=_sf_pct, obv_rising=_obv_up,
                price_vs_vwap=_vwap_pos, vol_spike_at_break=_vol_spike, funding_z=_fund_z_v,
                adx=_adx_now, di_plus=_di_plus, di_minus=_di_minus, atr_pct=_atr_pct_v,
                bb_expanding=_bb_exp, hurst=_hurst_v,
                ob_valid=_ob_ok, fvg_present=_fvg_ok, ote_valid=_ote_ok,
                liq_swept=_liq_swept, range_pos_pct=_range_pct,
                # ── [v9.6-FIX2] FVG CE-Respected bonus ──────────────────────────
                # ce_respected confirmed in validate_fvg_quality() but was never
                # wired to conf50. +2.0 bridges 53-54 borderline setups across ≥55.
                # Result capped at 100; C35 gate still requires the final value ≥55.
                smc_score=(lambda _ce=bool((result.get("smc_fvg_quality") or {}).get("ce_respected",False)):
                           min(100.0, float(_smc_cf_now.get("smc_score",0)) + (2.0 if _ce else 0.0)))(),
                wyckoff_ok=_wyck_ok, elliott_ok=_ell_ok,
                range_pos_ok=_range_ok, near_pdh=_near_pdh, near_pwh=_near_pwh, near_round_num=_round_near,
                htf_ltf_match=_htf_match, daily_candle_match=_daily_can,
                weekly_trend_match=_weekly_tr, ma_stack_ok=bool(_ma_stk_ok),
                fomc_block=_fomc_blk, macro_event_block=_macro_blk, news_velocity_ok=_news_ok,
                fgi_boundary=_fgi_bound, opex_near=_opex_near,
                bias=_bias_now,
            )
            result["conf50"] = conf50_result
            # If 50-confluence scores F or hard blocked, suppress signal
            if conf50_result.get("conf50_hard_blocked") or conf50_result.get("conf50_grade") == "F":
                result["all_pass"]   = False
                result["gate_pass"][9] = False
                log.info(f"[v8.0 CONF50] {conf50_result['conf50_note']}")
        except Exception as _c50e:
            result["conf50"] = {"conf50_score": 0, "conf50_grade": "?", "conf50_blocks": [],
                                "conf50_hard_blocked": False, "conf50_signal_state": "UNKNOWN",
                                "conf50_note": f"Conf50 error: {_c50e}"}
            log.warning(f"[v8.0 CONF50 ERROR] {_c50e}")

        messages = build_result_messages(result)

        await asyncio.sleep(0.3)
        await safe_edit(
            thinking,
            f"Analyzing {symbol}USDT...\n\n"
            f"Phase 1/7 — Integrity · DXY OK\n"
            f"Phase 2/7 — Features · Stats · AI OK\n"
            f"Phase 3/7 — Gates {sum(result['gate_pass'])}/10 · AI={(result.get('l8_ai') or {}).get('ai_score',0)}/100\n"
            f"Phase 4/7 — L10-L13: Drift · Portfolio · VaR · Risk Gate\n"
            f"            {(result.get('l13_gate') or {}).get('l13_note','...')[:45]}\n"
            f"Phase 5/7 — Venue: {result['best_ex']['name']}  SCORE={(result.get('trade_score_data') or {}).get('trade_score',0)}/100\n"
            f"Phase 6/7 — L19: Performance attribution ready\n"
            f"Phase 7/7 — Rendering {result['best_tf']} chart (800×480)..."
        )

        # ── Extract caption scalars BEFORE chart render (avoids holding full result during send)
        _direction  = "LONG" if result["bias"] == "BULLISH" else "SHORT"
        _se_cap     = result.get("scaled_entry", {})
        _td_cap     = result.get("timing_data", {})
        _ts_cap     = result.get("trade_score_data", {})
        _l8_cap     = result.get("l8_ai", {})
        _l13_cap    = result.get("l13_gate", {})
        _cap_sym    = result["symbol"]
        _cap_label  = result.get("market_label", "SPOT")
        _cap_tf     = result["best_tf"]
        _cap_ex     = result["best_ex"]["name"]
        _cap_bias   = result["bias"]
        _cap_eh     = result["entry_high"]
        _cap_el     = result["entry_low"]
        _cap_sl     = result["inv_sl"]
        _cap_inv    = result.get("invalidation_level", result["inv_sl"])
        _cap_tp1    = result["tp1"]
        _cap_tp2    = result["tp2"]
        _cap_tp3    = result["tp3"]
        _cap_wp     = result["win_prob"]
        _cap_smc    = (result.get("smc_confluence") or {}).get("smc_score", 0)
        _cap_entry_window = (result.get("entry_time") or {}).get("entry_window", "—")
        _cap_l1     = _se_cap.get("leg1_entry", _cap_eh)
        _cap_l2     = _se_cap.get("leg2_entry", (_cap_el + _cap_eh) / 2)
        _cap_l3     = _se_cap.get("leg3_entry", _cap_el)
        _cap_sl2    = result.get("sl2", _cap_sl)
        _cap_sl3    = result.get("sl3", _cap_sl)
        _cap_buf_reg = (result.get("l13_gate") or {}).get("buffer_regime", "NORMAL")
        _cap_buf_mul = (result.get("l13_gate") or {}).get("buffer_mult", 0.40)
        _rr         = round(abs(_cap_tp3 - (_cap_el + _cap_eh) / 2) / max(abs((_cap_el + _cap_eh) / 2 - _cap_sl), 1e-9), 2)
        caption = (
            f"{_cap_sym} [{_cap_label}] — {_cap_tf} LIVE Chart  [v6.2 FUND-GRADE]\n"
            f"Exchange: {_cap_ex}  Bias: {_cap_bias}  {_direction}\n"
            f"Leg1(40%): {fmt_price(_cap_l1)}  Leg2(35%): {fmt_price(_cap_l2)}  Leg3(25%): {fmt_price(_cap_l3)}\n"
            f"SL1(OB): {fmt_price(_cap_sl)}  SL2(Swing): {fmt_price(_cap_sl2)}  SL3(HTF): {fmt_price(_cap_sl3)}\n"
            f"Buf: {_cap_buf_mul:.2f}×ATR [{_cap_buf_reg}]  |  Inv: {fmt_price(_cap_inv)}\n"
            f"TP1: {fmt_price(_cap_tp1)}  TP2: {fmt_price(_cap_tp2)}  TP3: {fmt_price(_cap_tp3)}\n"
            f"Structure: {_ts_cap.get('trade_score',0)}/100 {_ts_cap.get('trade_grade','?')}  "
            f"Timing: {_td_cap.get('timing_score',0)}/100 {_td_cap.get('timing_grade','?')}  "
            f"★Combined: {_ts_cap.get('combined_score',0)}/100 Grade {_ts_cap.get('combined_grade','?')}\n"
            f"AI: {_l8_cap.get('ai_score',0)}/100 {(_l8_cap.get('ensemble') or {}).get('ensemble_tier','?')}  "
            f"L13: {'✅' if _l13_cap.get('l13_all_pass') else '❌'}  "
            f"Win: {_cap_wp}%  R:R 1:{_rr}  SMC:{_cap_smc}/100\n"
            f"Entry: {_cap_entry_window}"
        )

        # ══════════════════════════════════════════════════════════
        # CHART RENDER — RAM CRITICAL SECTION
        # Extract ONLY the ~25 fields the chart actually reads,
        # then delete the full result dict before PIL allocates.
        # ══════════════════════════════════════════════════════════
        chart_data = {
            "ohlcv_chart":       result.get("ohlcv_chart"),
            "ma_closes_full":    result.get("ma_closes_full"),
            "price":             result["price"],
            "bias":              result["bias"],
            "tp1":               result["tp1"],
            "tp2":               result["tp2"],
            "tp3":               result["tp3"],
            "inv_sl":            result["inv_sl"],
            "sl2":               result.get("sl2", result["inv_sl"]),
            "sl3":               result.get("sl3", result["inv_sl"]),
            "entry_low":         result["entry_low"],
            "entry_high":        result["entry_high"],
            "ob_low":            result.get("ob_low", 0.0),
            "ob_high":           result.get("ob_high", 0.0),
            "fvg_low":           result.get("fvg_low", 0.0),
            "fvg_high":          result.get("fvg_high", 0.0),
            "ote":               result.get("ote", {}),
            "liq_zone_swept":    result.get("liq_zone_swept", 0.0),
            "liq_zone_target":   result.get("liq_zone_target", 0.0),
            "invalidation_level":result.get("invalidation_level", result["inv_sl"]),
            "symbol":            result["symbol"],
            "best_tf":           result["best_tf"],
            "best_ex":           result["best_ex"],
            "market_label":      result.get("market_label", "SPOT"),
            "entry_ltf":         result.get("entry_ltf", "—"),
            "all_pass":          result.get("all_pass", False),
            "gate_pass":         result["gate_pass"],
            "grade":             result.get("grade", "F"),
            "conf":              result.get("conf", 0),
            "win_prob":          result.get("win_prob", 0),
            "atr_pct":           result.get("atr_pct", 0),
            "rsi":               result.get("rsi", 50),
            "adx":               result.get("adx", 0),
            "daily_veto_active": result.get("daily_veto_active", False),
            "l13_gate":          result.get("l13_gate", {}),
            "l8_ai":             result.get("l8_ai", {}),
            "trade_score_data":  result.get("trade_score_data", {}),
            "timing_data":       result.get("timing_data", {}),
            "scaled_entry":      result.get("scaled_entry", {}),
            "entry_time":        result.get("entry_time", {}),
            "upg_sr":            result.get("upg_sr", {}),
            "upg_trendline":     result.get("upg_trendline", {}),
            "upg_vol_profile":   result.get("upg_vol_profile", {}),
            "upg_macd":          result.get("upg_macd", {}),
            "smc_confluence":    result.get("smc_confluence", {}),
            "ma_stack":          result.get("ma_stack", {}),
            "daily_bias":        result.get("daily_bias", "—"),
            "weekly_veto_active":result.get("weekly_veto_active", False),
            # ── 3-Layer MTF Combo fields ──────────────────────────
            "mtf_combo":         result.get("mtf_combo", "—"),
            "mtf_combo_id":      result.get("mtf_combo_id", 16),
            "bias_tf":           result.get("bias_tf", result["best_tf"]),
            "ref_tf":            result.get("ref_tf", "1h"),
            "exec_tf":           result.get("exec_tf", result.get("entry_ltf", "15m")),
            "combo_style":       result.get("combo_style", "Intraday"),
            "combo_kz":          result.get("combo_kz", "London+NY"),
            "combo_tier":        result.get("combo_tier", "VALID"),
            "mtf_3l_valid":      result.get("mtf_3l_valid", {}),
            # ── [C08] Liquidation heatmap cluster levels for chart overlay ─
            "liq_long_10x":  (result.get("upg_liq_heat") or {}).get("nearest_long_liq",  0.0),
            "liq_short_10x": (result.get("upg_liq_heat") or {}).get("nearest_short_liq", 0.0),
            "liq_long_20x":  (result.get("upg_liq_heat") or {}).get("liq_long_levels",  {}).get("20x", 0.0),
            "liq_short_20x": (result.get("upg_liq_heat") or {}).get("liq_short_levels", {}).get("20x", 0.0),
            "liq_long_50x":  (result.get("upg_liq_heat") or {}).get("liq_long_levels",  {}).get("50x", 0.0),
            "liq_short_50x": (result.get("upg_liq_heat") or {}).get("liq_short_levels", {}).get("50x", 0.0),
            # ── [C01] OTE zone for chart ────────────────────────────────────
            "ote_zone_low":  (result.get("ote_new") or {}).get("ote_low",  0.0),
            "ote_zone_high": (result.get("ote_new") or {}).get("ote_high", 0.0),
            "ote_705":       (result.get("ote_new") or {}).get("ote_705",  0.0),
        }
        # ── [TV-FREE] Cache slim result for /tvcheck and /pine commands ──────
        try:
            _wdl_tv = result.get("weekly_daily_liq") or {}
            _se_tv  = result.get("scaled_entry") or {}
            _ts_tv  = result.get("trade_score_data") or {}
            _tv_slim = {
                "symbol":     result["symbol"],
                "bias":       result["bias"],
                "price":      result["price"],
                "entry":      (_se_tv.get("leg1_entry") or result["entry_high"]),
                "sl1":        result["inv_sl"],
                "tp1":        result["tp1"],
                "tp2":        result["tp2"],
                "tp3":        result["tp3"],
                "ob_low":     result.get("ob_low", 0.0),
                "ob_high":    result.get("ob_high", 0.0),
                "fvg_low":    result.get("fvg_low", 0.0),
                "fvg_high":   result.get("fvg_high", 0.0),
                "pdh":        _wdl_tv.get("pdh", 0.0),
                "pdl":        _wdl_tv.get("pdl", 0.0),
                "pwh":        _wdl_tv.get("pwh", 0.0),
                "pwl":        _wdl_tv.get("pwl", 0.0),
                "vwap":       result.get("vwap", 0.0),
                "grade":      _ts_tv.get("trade_grade", result.get("grade", "?")),
                "confidence": float(_ts_tv.get("trade_score", result.get("conf", 0))),
            }
            _LAST_RESULT_CACHE[result["symbol"]] = _tv_slim
            # Cap cache at 20 entries (FIFO)
            if len(_LAST_RESULT_CACHE) > 20:
                _oldest = next(iter(_LAST_RESULT_CACHE))
                del _LAST_RESULT_CACHE[_oldest]
        except Exception as _tvc_e:
            log.debug(f"[TV-FREE] Cache populate failed: {_tvc_e}")

        # ── Release the full result dict now — before PIL allocates
        del result
        gc.collect()

        # MEM-FIX-CHART-1: Strip 10 keys from chart_data that generate_trade_chart
        # never reads. These nested dicts (l8_ai, trade_score_data, upg_sr,
        # smc_confluence, ma_stack, etc.) can each be 5-50 KB and stay resident
        # through the entire PIL render. Removing them frees ~2-8 MB before chart.
        for _unused_key in (
            "l8_ai", "trade_score_data", "timing_data", "scaled_entry",
            "upg_sr", "upg_trendline", "upg_vol_profile", "upg_macd",
            "smc_confluence", "ma_stack",
        ):
            chart_data.pop(_unused_key, None)

        # MEM-FIX-CHART-2: Cap ma_closes_full to last 230 closes.
        # MA200 computation needs 200 closes + 30 display candles = 230 max.
        # Passing 350 closes wastes ~10 KB and runs sma_last_n over more data.
        _mcf = chart_data.get("ma_closes_full")
        if _mcf and len(_mcf) > 230:
            chart_data["ma_closes_full"] = _mcf[-230:]
        del _mcf

        gc.collect()
        await _wait_for_memory("pre-chart", timeout_s=10)
        chart_buf = await asyncio.to_thread(generate_trade_chart, chart_data)
        del chart_data
        gc.collect()

        await thinking.delete()
        record_signal(user_id)

        # ── [C05/C06] Register emitted signal with lifecycle tracker ──
        try:
            _paper = _HUMAN_OVERRIDE.paper_mode if hasattr(_HUMAN_OVERRIDE, "paper_mode") else False
            _trade_id = _TRADE_TRACKER.open_trade(
                symbol     = chart_data.get("symbol", symbol),
                bias       = chart_data.get("bias", "BULLISH"),
                entry_low  = chart_data.get("entry_low",  0.0),
                entry_high = chart_data.get("entry_high", 0.0),
                sl         = chart_data.get("inv_sl",     0.0),
                tp1        = chart_data.get("tp1",        0.0),
                tp2        = chart_data.get("tp2",        0.0),
                tp3        = chart_data.get("tp3",        0.0),
                paper_mode = _paper,
            )
        except Exception as _lce:
            _trade_id = None
            log.debug(f"[C05] Lifecycle open failed: {_lce}")

        # ── [I03] Start WSS stream for this symbol (idempotent) ───────
        try:
            asyncio.create_task(start_wss_stream(symbol, interval="15m"))
        except Exception as _we:
            log.debug(f"[I03 WSS] Task start failed: {_we}")

        # ── [C04] Structured observability log ───────────────────────
        try:
            log_analysis_event(
                symbol   = symbol,
                event    = "signal_emitted",
                grade    = chart_data.get("grade", "?"),
                conf     = float(chart_data.get("conf", 0)),
                gate_pass= chart_data.get("gate_pass", []),
                mem_delta_mb = _analysis_rss() / 1024 / 1024,
            )
        except Exception as _e:
            log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")

        for i, msg_text in enumerate(messages):
            if i in [1, 2, 3]:
                fmt = f"```\n{msg_text}\n```"
            else:
                fmt = msg_text
            await safe_send(message, fmt, parse_mode=ParseMode.MARKDOWN)

            if i == len(messages) - 1:
                await asyncio.sleep(0.3)
                try:
                    await message.reply_photo(photo=chart_buf, caption=caption)
                except Exception as e:
                    log.warning(f"Chart send failed: {e}")
                finally:
                    chart_buf.close()

            if i < len(messages) - 1:
                await asyncio.sleep(0.4)

        # ── Final cleanup — free everything
        del messages
        if 'chart_buf' in dir() and chart_buf is not None:
            try:
                chart_buf.close()
            except Exception as _e:
                log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
            del chart_buf
        gc.collect()

        # ── [TV-FREE Phase 4] Auto-send TV cross-check checklist ─────────────
        try:
            _cached = _LAST_RESULT_CACHE.get(symbol)
            if _cached:
                _tv_msg = generate_tv_checklist(_cached)
                await safe_send(message, f"```\n{_tv_msg}\n```", parse_mode=ParseMode.MARKDOWN)
        except Exception as _tv_e:
            log.debug(f"[TV-FREE] Auto checklist send failed: {_tv_e}")

    except ValueError as e:
        try:
            await thinking.delete()
        except Exception as _e:
            log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
        err_msg = str(e)
        # Distinguish "no data" (network/listing issue) from true symbol errors
        if "No exchange data" in err_msg or "No price data" in err_msg or "Insufficient candle" in err_msg:
            friendly = (
                f"⚠️  Could not fetch data for *{symbol}*\n\n"
                f"`{err_msg}`\n\n"
                f"• Check your internet / API connectivity\n"
                f"• The pair may be delisted or temporarily unavailable\n"
                f"• Try again in a few seconds\n\n"
                f"Common symbols: BTC · ETH · SOL · BNB · XRP"
            )
        else:
            friendly = (
                f"⚠️  Symbol not found or invalid: *{symbol}*\n\n"
                f"`{err_msg}`\n\n"
                f"Try: BTC, ETH, SOL, BNB, XRP"
            )
        await safe_send(message, friendly, parse_mode=ParseMode.MARKDOWN)
    except Exception as e:
        import traceback as _tb
        _trace = _tb.format_exc()
        log.exception(f"Analysis error for {symbol}: {e}\n{_trace}")
        try:
            await thinking.delete()
        except Exception as _e:
            log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
        await safe_send(
            message,
            f"Analysis failed for {symbol}\n\n"
            f"{type(e).__name__}: {str(e)[:200]}\n\n"
            f"Traceback (last 3 lines):\n"
            f"{chr(10).join(_trace.strip().splitlines()[-3:])[:600]}\n\n"
            f"Please try again in a few seconds."
        )

async def cmd_tvsetup(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """[TV-FREE] Send the full TradingView free plan setup guide."""
    await update.message.reply_text(TV_FREE_SETUP_MSG)


async def cmd_tvcheck(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """[TV-FREE Phase 4] Send TV cross-check checklist for last analyzed symbol.
    Usage: /tvcheck  or  /tvcheck BTCUSDT
    """
    sym = None
    if context.args:
        sym = context.args[0].upper().replace("USDT", "").replace("USDC", "")
    if not sym:
        # Default to most recently cached symbol
        if _LAST_RESULT_CACHE:
            sym = list(_LAST_RESULT_CACHE.keys())[-1]
        else:
            await update.message.reply_text(
                "⚠️ No analysis cached yet.\n"
                "Run an analysis first, e.g. send: BTC\n"
                "Then use /tvcheck to get the TV cross-check."
            )
            return
    cached = _LAST_RESULT_CACHE.get(sym)
    if not cached:
        await update.message.reply_text(
            f"⚠️ No cached result for {sym}.\n"
            f"Run /analyze {sym} first, then /tvcheck {sym}."
        )
        return
    msg = generate_tv_checklist(cached)
    await update.message.reply_text(f"```\n{msg}\n```", parse_mode=ParseMode.MARKDOWN)


async def cmd_pine(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """[TV-FREE Phase 5] Generate Pine Script v5 backtest strategy.
    Usage: /pine  or  /pine BTCUSDT
    Paste the output directly into TradingView Pine Editor → Strategy Tester.
    """
    sym = None
    if context.args:
        sym = context.args[0].upper().replace("USDT", "").replace("USDC", "")
    cached = _LAST_RESULT_CACHE.get(sym) if sym else None
    if not cached and _LAST_RESULT_CACHE:
        cached = list(_LAST_RESULT_CACHE.values())[-1]
    script = generate_tv_pine_script(r=cached, symbol=sym or "BTC")

    # Split if > 4000 chars (Telegram message limit)
    header_note = (
        "📺 TRADINGVIEW PINE SCRIPT — MOP·ICT v9 Mirror\n"
        "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
        "1. Open TradingView → Pine Script Editor (bottom panel)\n"
        "2. Paste the script below\n"
        "3. Click 'Add to chart'\n"
        "4. Open Strategy Tester tab → run on 6 months history\n"
        "5. Exec TF: 15m or 1H  |  Symbol: same as bot\n"
        "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
    )
    await update.message.reply_text(header_note)

    # Send script in chunks to avoid Telegram 4096 char limit
    chunk_size = 3900
    for i in range(0, len(script), chunk_size):
        chunk = script[i:i + chunk_size]
        await update.message.reply_text(f"```\n{chunk}\n```", parse_mode=ParseMode.MARKDOWN)


async def cmd_killzone(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """[TV-FREE Phase 2] Report current Kill Zone status with countdown."""
    session = get_current_session()
    sb      = get_silver_bullet_status()
    now_utc = datetime.datetime.utcnow()
    mins    = now_utc.hour * 60 + now_utc.minute

    KZ_SCHEDULE = [
        ("🔵 London Open",  7 * 60,       10 * 60,      "⭐⭐⭐ Best for reversals + trend days"),
        ("🟢 NY Open",      13 * 60 + 30, 16 * 60,      "⭐⭐⭐ Best for continuations + Judas"),
        ("🟡 NY Afternoon", 18 * 60,      20 * 60,      "⭐⭐  Good for scalp completions"),
        ("🟣 Asian",        0,            2 * 60 + 30,  "⭐   Range-building, lower reliability"),
    ]

    current_kz = None
    next_kz    = None
    next_in    = None

    for name, start, end, desc in KZ_SCHEDULE:
        if start <= mins < end:
            current_kz = (name, end - mins, desc)
            break

    if not current_kz:
        future = [(n, s, d) for n, s, e, d in KZ_SCHEDULE if s > mins]
        if future:
            future.sort(key=lambda x: x[1])
            next_kz    = future[0][0]
            next_in    = future[0][1] - mins
            next_desc  = future[0][2]
        else:
            # Past all KZs today — next is tomorrow's Asian
            next_kz   = "🟣 Asian (tomorrow)"
            next_in   = (24 * 60 - mins)
            next_desc = "⭐ Range-building"

    lines = [
        f"⏰ KILL ZONE STATUS — {now_utc.strftime('%H:%M')} UTC",
        "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━",
        "",
    ]

    if current_kz:
        name, rem, desc = current_kz
        h, m = divmod(rem, 60)
        lines += [
            f"✅ ACTIVE : {name}",
            f"   {desc}",
            f"   Closes in: {h}h {m}m",
            "",
            "▶  NOW is the time to run your bot analysis.",
        ]
    else:
        h, m = divmod(next_in, 60)
        lines += [
            f"⏳ OFF SESSION — No active Kill Zone",
            f"   Session  : {session}",
            "",
            f"▶  Next KZ : {next_kz}",
            f"   In       : {h}h {m}m",
            f"   {next_desc}",
            "",
            "   Wait for the Kill Zone before running analysis.",
            "   ICT setups outside Kill Zones have lower probability.",
        ]

    lines += [
        "",
        "── SILVER BULLET WINDOWS (UTC) ──────────",
        "  ⚡ London SB : 02:00 – 03:00",
        "  ⚡ NY AM SB  : 10:00 – 11:00  (most powerful)",
        "  ⚡ NY PM SB  : 14:00 – 15:00",
        "",
    ]

    if sb.get("active"):
        lines.append(f"⚡ SILVER BULLET ACTIVE: {sb['window']} — "
                     f"{sb.get('minutes_remaining', 0)}m left  ← HIGH PRIORITY")
    else:
        lines.append(f"💤 Silver Bullet: Inactive "
                     f"(next: {sb.get('next_window', '?')})")

    lines += [
        "",
        "── KILL ZONE SCHEDULE (UTC) ─────────────",
        "  🔵 London : 07:00 – 10:00",
        "  🟢 NY     : 13:30 – 16:00",
        "  🟡 NY PM  : 18:00 – 20:00",
        "  🟣 Asian  : 00:00 – 02:30",
    ]

    await update.message.reply_text("\n".join(lines))
    query = update.callback_query
    await query.answer()
    data = query.data
    chat = update.effective_chat

    if data == "pipeline":
        msg = build_pipeline_msg()
        await chat.send_message(msg)
    elif data == "help":
        text = (
            "COMMANDS\n\n"
            "/start    — Welcome screen\n"
            "/help     — This help message\n"
            "/pipeline — Show pipeline\n"
            "/analyze SYMBOL — Analyze a coin\n\n"
            "Examples: BTC · ETH · SOL"
        )
        await chat.send_message(text)
    elif data.startswith("sample_"):
        symbol = data.replace("sample_", "")
        await _run_analysis_chat(chat, symbol)
    elif data.startswith("mkt_spot_"):
        symbol = data.replace("mkt_spot_", "")
        try:
            await query.edit_message_text(
                f"✅ Got it — analyzing *{symbol}* on SPOT markets...",
                parse_mode=ParseMode.MARKDOWN
            )
        except Exception as _e:
            log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
        await _run_analysis_chat(chat, symbol, market_type="spot")
    elif data.startswith("mkt_futures_"):
        symbol = data.replace("mkt_futures_", "")
        try:
            await query.edit_message_text(
                f"✅ Got it — analyzing *{symbol}* on FUTURES (Perp) markets...",
                parse_mode=ParseMode.MARKDOWN
            )
        except Exception as _e:
            log.debug(f"[SILENT_EX] {type(_e).__name__}: {_e}")
        await _run_analysis_chat(chat, symbol, market_type="futures")

