async def _post_init(application) -> None:
    """
    [G4] Post-init hook: prefetch economic calendar on startup.
    Runs once after the event loop is running — safe for async fetch.
    Calendar is cached 6 hours; no per-signal latency impact.
    """
    try:
        await fetch_economic_calendar()
        log.info("[G4 CALENDAR] Economic calendar prefetched on startup.")
    except Exception as e:
        log.warning(f"[G4 CALENDAR] Startup prefetch failed: {e} — fallback UTC windows active")


def main():
    global ADMIN_BOT_APP
    if not BOT_TOKEN:
        print("ERROR: BOT_TOKEN env var is not set. Refusing to start Telegram runtime.")
        print("Set BOT_TOKEN or run app.py (the primary entrypoint) instead.")
        return
    print("=" * 72)
    print("  MOP · ICT · QUANT STACK v9.0 FUND-GRADE — 20-Layer Architecture")
    print("  MTF-50 · OTE Fib · Sortino/Calmar/DSR · WSS · Trade Lifecycle")
    print("  Observability · Paper Mode · Catastrophe Suite · BTC Benchmark")
    print("  Starting up...")
    print("=" * 72)

    app = (Application.builder()
           .token(BOT_TOKEN)
           .post_init(_post_init)   # [G4] async calendar prefetch on startup
           .build())
    ADMIN_BOT_APP = app   # [C04] wire admin alert system
    app.add_handler(CommandHandler("start",    cmd_start))
    app.add_handler(CommandHandler("help",     cmd_help))
    app.add_handler(CommandHandler("pipeline", cmd_pipeline))
    app.add_handler(CommandHandler("analyze",  cmd_analyze))
    app.add_handler(CommandHandler("tvsetup",  cmd_tvsetup))
    app.add_handler(CommandHandler("tvcheck",  cmd_tvcheck))
    app.add_handler(CommandHandler("pine",     cmd_pine))
    app.add_handler(CommandHandler("killzone", cmd_killzone))
    app.add_handler(CallbackQueryHandler(button_callback))
    app.add_handler(MessageHandler(filters.TEXT & ~filters.COMMAND, handle_text))

    print("  Bot is running v9.0 FUND-GRADE · 20-Layer Pipeline · MTF-50 ACTIVE!")
    print("  [C04] Structured logs → mop_ict_structured.jsonl")
    print("  [I03] Binance WSS streams: auto-start on first analysis")
    print("  [C05] Trade lifecycle tracker: SQLite rl_state.db")
    print("  Press Ctrl+C to stop.")
    print("=" * 72)
    app.run_polling(allowed_updates=Update.ALL_TYPES)

if __name__ == "__main__":
    main()
